class RecommendationEngine(Protocol):
    def build(self, student: Student, ctx: 'RecommendationContext') -> AIRecommendation:
        ...


@dataclass(slots=True)
class RecommendationContext:
    student: Student
    companies: list[Company]
    recruiters: list[Recruiter]
    jobs: list[Job]
    applications: list[Application]
    interviews: list[Interview]
    offers: list[Offer]
    messages: list[Message]
    notifications: list[Notification]
    career_report: CareerReport | None
    skill_gap: SkillGap | None
    learning_roadmap: LearningRoadmap | None
    resume_analysis: ResumeAnalysis | None
    job_match: JobMatch | None


@dataclass(slots=True)
class AIRecommendationGenerationResult:
    recommendations: list[AIRecommendation]


class DefaultRecommendationEngine:
    def build(self, student: Student, ctx: RecommendationContext) -> AIRecommendation:
        student_profile = self._student_profile(student, ctx)
        top_jobs = self._top_jobs(ctx)
        top_internships = self._top_internships(ctx)
        top_companies = self._top_companies(ctx)
        top_recruiters = self._top_recruiters(ctx)
        mentor_recommendations = self._mentor_recommendations(student_profile, ctx)
        certification_recommendations = self._certification_recommendations(ctx)
        course_recommendations = self._course_recommendations(ctx)
        project_recommendations = self._project_recommendations(ctx)
        hackathons = self._hackathon_recommendations(student_profile, ctx)
        competitions = self._competition_recommendations(student_profile, ctx)
        communities = self._community_recommendations(student_profile)
        networking = self._networking_recommendations(ctx, top_recruiters, communities)
        resume_recommendations = self._resume_recommendations(ctx)
        interview_recommendations = self._interview_recommendations(ctx)
        salary_recommendations = self._salary_recommendations(student, ctx)
        career_goal_recommendations = self._career_goal_recommendations(student, ctx)
        career_recommendations = self._career_recommendations(student_profile, ctx, top_jobs)
        smart_actions = self._smart_actions(top_jobs, certification_recommendations, resume_recommendations, interview_recommendations, networking, ctx)
        business_impact = self._business_impact(ctx, smart_actions)
        daily_assistant = self._daily_ai_assistant(top_jobs, smart_actions, ctx)
        trend_analysis = self._trend_analysis(ctx)
        predictions = self._predictions(ctx, top_jobs)
        ai_explanations = self._ai_explanations(
            career_recommendations=career_recommendations,
            job_recommendations=top_jobs,
            internship_recommendations=top_internships,
            recruiter_recommendations=top_recruiters,
            mentor_recommendations=mentor_recommendations,
            company_recommendations=top_companies,
            certification_recommendations=certification_recommendations,
            course_recommendations=course_recommendations,
            project_recommendations=project_recommendations,
            hackathon_recommendations=hackathons,
            competition_recommendations=competitions,
            community_recommendations=communities,
            networking_recommendations=networking,
            resume_recommendations=resume_recommendations,
            interview_recommendations=interview_recommendations,
            salary_recommendations=salary_recommendations,
            career_goal_recommendations=career_goal_recommendations,
        )

        recommendation = AIRecommendation(
            student=student,
            generated_at=datetime.utcnow(),
            career_recommendations=career_recommendations,
            job_recommendations=top_jobs,
            internship_recommendations=top_internships,
            recruiter_recommendations=top_recruiters,
            mentor_recommendations=mentor_recommendations,
            company_recommendations=top_companies,
            certification_recommendations=certification_recommendations,
            course_recommendations=course_recommendations,
            project_recommendations=project_recommendations,
            hackathon_recommendations=hackathons,
            competition_recommendations=competitions,
            community_recommendations=communities,
            networking_recommendations=networking,
            resume_recommendations=resume_recommendations,
            interview_recommendations=interview_recommendations,
            salary_recommendations=salary_recommendations,
            career_goal_recommendations=career_goal_recommendations,
        )
        recommendation.smart_actions_metadata = smart_actions
        recommendation.business_impact_metadata = business_impact
        recommendation.ai_explanations_metadata = ai_explanations
        recommendation.daily_ai_assistant_metadata = daily_assistant
        recommendation.trend_analysis_metadata = trend_analysis
        recommendation.predictions_metadata = predictions
        recommendation.engine_metadata = {
            'recommendation_engine': self.__class__.__name__,
            'gemini_replaceable': True,
            'frontend_contract_stable': True,
            'services': [
                'CareerRecommendationService',
                'JobRecommendationService',
                'LearningRecommendationService',
                'NetworkingRecommendationService',
                'PredictionService',
            ],
        }
        return recommendation

    def _student_profile(self, student: Student, ctx: RecommendationContext) -> dict[str, Any]:
        return {
            'career_goal': str(getattr(student, 'career_goal', '') or ''),
            'skills': [str(item) for item in self._list_value(getattr(student, 'skills', None))],
            'projects': [str(item) for item in self._list_value(getattr(student, 'projects', None))],
            'experience': [str(item) for item in self._list_value(getattr(student, 'experience', None))],
            'cgpa': getattr(student, 'cgpa', None),
            'preferred_companies': self._preferred_companies(student, ctx),
            'preferred_location': str(getattr(student, 'preferred_location', '') or ''),
            'preferred_salary': self._preferred_salary(student),
            'preferred_work_mode': str(getattr(student, 'preferred_work_type', '') or ''),
            'preferred_industry': str(getattr(student, 'preferred_industry', '') or ''),
            'learning_speed': self._learning_speed(ctx),
            'availability_hours': self._availability_hours(ctx),
            'bucket': self._career_bucket(str(getattr(student, 'career_goal', '') or '')),
        }

    def _top_jobs(self, ctx: RecommendationContext) -> list[dict[str, Any]]:
        if ctx.job_match is None:
            return []
        jobs = list(getattr(ctx.job_match, 'top_job_matches', None) or [])
        return [self._decorate_recommendation_item(item, 'High' if item.get('overall_match_pct', 0) >= 78 else 'Medium', item.get('why_this_match', {}).get('summary', 'Strong role alignment detected.')) for item in jobs[:20]]

    def _top_internships(self, ctx: RecommendationContext) -> list[dict[str, Any]]:
        if ctx.job_match is None:
            return []
        internships = list(getattr(ctx.job_match, 'top_internship_matches', None) or [])
        return [self._decorate_recommendation_item(item, 'High' if item.get('overall_match_pct', 0) >= 72 else 'Medium', item.get('why_this_match', {}).get('summary', 'Internship aligned to current profile and growth stage.')) for item in internships[:20]]

    def _top_companies(self, ctx: RecommendationContext) -> list[dict[str, Any]]:
        if ctx.job_match is None:
            return []
        companies = list(getattr(ctx.job_match, 'top_companies', None) or [])
        decorated = []
        for item in companies[:15]:
            reason = f"Technology fit {item.get('technology_fit', 0)}%, culture fit {item.get('culture_fit', 0)}%, and growth fit {item.get('growth_fit', 0)}%."
            decorated.append(self._decorate_recommendation_item(item, 'High' if item.get('overall_match_pct', 0) >= 75 else 'Medium', reason))
        return decorated

    def _top_recruiters(self, ctx: RecommendationContext) -> list[dict[str, Any]]:
        if ctx.job_match is None:
            return []
        recruiters = list(getattr(ctx.job_match, 'top_recruiters', None) or [])
        decorated = []
        for item in recruiters[:15]:
            reason = f"Likelihood of response {item.get('likelihood_of_response', 0)}% and expected interview chance {item.get('expected_interview_chance', 0)}%."
            decorated.append(self._decorate_recommendation_item(item, 'High' if item.get('recruiter_interest_score', 0) >= 75 else 'Medium', reason))
        return decorated

    def _mentor_recommendations(self, profile: dict[str, Any], ctx: RecommendationContext) -> list[dict[str, Any]]:
        mentor_title = MENTOR_TITLES[profile['bucket']]
        top_skills = self._missing_skills(ctx)[:4]
        recommendations = []
        for index, skill in enumerate(top_skills, start=1):
            recommendations.append({
                'mentor_title': mentor_title,
                'focus_area': skill,
                'priority': 'High' if index <= 2 else 'Medium',
                'reason': f'Mentor support is valuable for accelerating progress in {skill} and improving interview depth.',
                'expected_impact': f'Faster progress on {skill} and better recruiter conversations.',
                'deadline': (date.today() + timedelta(days=7 * index)).isoformat(),
                'estimated_completion_time_hours': 2,
            })
        if not recommendations:
            recommendations.append({
                'mentor_title': mentor_title,
                'focus_area': 'Career strategy',
                'priority': 'Medium',
                'reason': 'Mentor guidance can refine application strategy and prioritization.',
                'expected_impact': 'Sharper targeting and better next-step planning.',
                'deadline': (date.today() + timedelta(days=14)).isoformat(),
                'estimated_completion_time_hours': 1,
            })
        return recommendations

    def _certification_recommendations(self, ctx: RecommendationContext) -> list[dict[str, Any]]:
        recommendations = []
        if ctx.skill_gap is not None:
            metadata = getattr(ctx.skill_gap, 'certification_recommendations_metadata', None) or {}
            for item in metadata.get('recommendations', [])[:6]:
                name = item['name'] if isinstance(item, dict) else str(item)
                provider = item.get('provider', 'Industry') if isinstance(item, dict) else 'Industry'
                recommendations.append({
                    'certification_name': name,
                    'provider': provider,
                    'priority': 'High',
                    'reason': f'{name} closes a current skill gap tied to target roles.',
                    'expected_impact': 'Improves profile trust, ATS relevance, and job match quality.',
                    'deadline': (date.today() + timedelta(days=45 + len(recommendations) * 15)).isoformat(),
                    'estimated_completion_time_hours': 36 + len(recommendations) * 8,
                })
        return recommendations

    def _course_recommendations(self, ctx: RecommendationContext) -> list[dict[str, Any]]:
        courses = []
        missing_skills = self._missing_skills(ctx)
        for skill in missing_skills[:6]:
            courses.append({
                'skill': skill,
                'course_name': COURSE_LIBRARY.get(skill, f'{skill} Career Acceleration Path'),
                'priority': 'High' if skill in missing_skills[:3] else 'Medium',
                'reason': f'{skill} appears in target job requirements and current skill gap analysis.',
                'expected_impact': 'Improves hiring alignment and readiness for role-specific interviews.',
                'deadline': (date.today() + timedelta(days=21 + len(courses) * 7)).isoformat(),
                'estimated_completion_time_hours': 16 + len(courses) * 4,
            })
        return courses

    def _project_recommendations(self, ctx: RecommendationContext) -> list[dict[str, Any]]:
        recommendations = []
        if ctx.learning_roadmap is not None:
            metadata = getattr(ctx.learning_roadmap, 'project_recommendations_metadata', None) or {}
            for item in metadata.get('projects', [])[:6]:
                recommendations.append({
                    'project_title': item.get('project_title', 'Role-Ready Project'),
                    'difficulty': item.get('difficulty', 'Medium'),
                    'priority': 'High' if item.get('difficulty') in {'Medium', 'High'} else 'Medium',
                    'reason': 'Project evidence strengthens portfolio quality, GitHub credibility, and technical interview depth.',
                    'expected_impact': item.get('portfolio_impact', 'Improves portfolio and resume relevance.'),
                    'deadline': (date.today() + timedelta(days=28 + len(recommendations) * 14)).isoformat(),
                    'estimated_completion_time_hours': int(item.get('duration_hours', 24)),
                })
        return recommendations

    def _hackathon_recommendations(self, profile: dict[str, Any], ctx: RecommendationContext) -> list[dict[str, Any]]:
        items = []
        for name in HACKATHONS.get(profile['bucket'], [])[:3]:
            items.append({
                'name': name,
                'priority': 'Medium',
                'reason': 'Hackathons build practical delivery evidence, networking, and project outcomes.',
                'expected_impact': 'Improves project depth, speed of execution, and peer visibility.',
                'deadline': (date.today() + timedelta(days=18 + len(items) * 20)).isoformat(),
                'estimated_completion_time_hours': 12,
            })
        return items

    def _competition_recommendations(self, profile: dict[str, Any], ctx: RecommendationContext) -> list[dict[str, Any]]:
        items = []
        for name in COMPETITIONS.get(profile['bucket'], [])[:3]:
            items.append({
                'name': name,
                'priority': 'Medium',
                'reason': 'Competitions provide measurable achievements and stronger resume differentiation.',
                'expected_impact': 'Improves achievement statements and recruiter recall.',
                'deadline': (date.today() + timedelta(days=25 + len(items) * 15)).isoformat(),
                'estimated_completion_time_hours': 10,
            })
        return items

    def _community_recommendations(self, profile: dict[str, Any]) -> list[dict[str, Any]]:
        items = []
        for name in COMMUNITIES.get(profile['bucket'], [])[:4]:
            items.append({
                'name': name,
                'priority': 'Medium',
                'reason': 'Community participation supports peer learning, referrals, and emerging skill awareness.',
                'expected_impact': 'Improves networking and access to role-specific opportunities.',
                'deadline': (date.today() + timedelta(days=10 + len(items) * 10)).isoformat(),
                'estimated_completion_time_hours': 2,
            })
        return items

    def _networking_recommendations(self, ctx: RecommendationContext, top_recruiters: list[dict[str, Any]], communities: list[dict[str, Any]]) -> list[dict[str, Any]]:
        items = []
        for recruiter in top_recruiters[:3]:
            items.append({
                'action': 'Contact Recruiter',
                'target': recruiter.get('recruiter'),
                'priority': 'High' if recruiter.get('likelihood_of_response', 0) >= 75 else 'Medium',
                'reason': f"Recruiter interest score is {recruiter.get('recruiter_interest_score', 0)}%.",
                'expected_impact': 'Can improve response rate, screening visibility, and interview opportunity.',
                'deadline': (date.today() + timedelta(days=3 + len(items))).isoformat(),
                'estimated_completion_time_hours': 1,
            })
        for community in communities[:2]:
            items.append({
                'action': 'Join Community',
                'target': community['name'],
                'priority': 'Medium',
                'reason': 'Community activity supports networking and staying current with market expectations.',
                'expected_impact': 'More referrals, peer support, and market visibility.',
                'deadline': (date.today() + timedelta(days=7 + len(items))).isoformat(),
                'estimated_completion_time_hours': 1,
            })
        return items

    def _resume_recommendations(self, ctx: RecommendationContext) -> list[dict[str, Any]]:
        items = []
        if ctx.resume_analysis is not None:
            metadata = getattr(ctx.resume_analysis, 'resume_improvements_metadata', None) or {}
            for key in [
                'improve_summary', 'improve_experience', 'improve_projects', 'improve_skills',
                'improve_certifications', 'improve_portfolio', 'improve_github', 'improve_achievements',
                'improve_formatting', 'improve_keywords',
            ]:
                value = metadata.get(key)
                if value:
                    items.append({
                        'type': key,
                        'recommendation': value['recommendation'],
                        'priority': 'High' if key in {'improve_summary', 'improve_experience', 'improve_projects', 'improve_skills', 'improve_keywords'} else 'Medium',
                        'reason': value['why'],
                        'expected_impact': value['impact'],
                        'deadline': (date.today() + timedelta(days=5 + len(items) * 3)).isoformat(),
                        'estimated_completion_time_hours': 2 if key not in {'improve_portfolio', 'improve_github'} else 5,
                    })
        return items[:10]

    def _interview_recommendations(self, ctx: RecommendationContext) -> list[dict[str, Any]]:
        items = []
        if ctx.learning_roadmap is not None:
            metadata = getattr(ctx.learning_roadmap, 'interview_preparation_metadata', None) or {}
            for timeline_item in metadata.get('preparation_timeline', [])[:4]:
                items.append({
                    'focus': timeline_item['focus'],
                    'task': timeline_item['task'],
                    'priority': 'Critical' if timeline_item['week'] == 1 and metadata.get('days_until_next_interview', 999) <= 14 else 'High',
                    'reason': 'Interview preparation timeline is aligned to expected recruiter and company requirements.',
                    'expected_impact': 'Improves interview readiness and conversion potential.',
                    'deadline': (date.today() + timedelta(days=timeline_item['week'] * 7)).isoformat(),
                    'estimated_completion_time_hours': 4,
                })
        if ctx.interviews:
            items.insert(0, {
                'focus': 'Take Mock Interview',
                'task': 'Schedule and complete a mock interview before the next live interview.',
                'priority': 'Critical',
                'reason': 'Upcoming interviews increase urgency for practice and calibrated feedback.',
                'expected_impact': 'Reduces performance risk and improves confidence.',
                'deadline': (date.today() + timedelta(days=3)).isoformat(),
                'estimated_completion_time_hours': 2,
            })
        return items[:8]

    def _salary_recommendations(self, student: Student, ctx: RecommendationContext) -> list[dict[str, Any]]:
        preferred_salary = self._preferred_salary(student)
        predicted_salary = self._predicted_salary(ctx)
        return [{
            'current_target_salary': preferred_salary,
            'recommended_salary_range': predicted_salary,
            'priority': 'Medium',
            'reason': 'Salary recommendation is based on current match quality, job market alignment, and target roles.',
            'expected_impact': 'Better alignment improves acceptance probability and negotiation readiness.',
            'deadline': (date.today() + timedelta(days=21)).isoformat(),
            'estimated_completion_time_hours': 1,
        }]

    def _career_goal_recommendations(self, student: Student, ctx: RecommendationContext) -> list[dict[str, Any]]:
        goal = str(getattr(student, 'career_goal', '') or '')
        top_roles = []
        if ctx.job_match is not None:
            top_roles = list(getattr(ctx.job_match, 'top_job_matches', None) or [])
        recommendations = [{
            'current_career_goal': goal,
            'recommended_focus_roles': [item.get('job_title') for item in top_roles[:5]],
            'priority': 'High' if top_roles and top_roles[0].get('overall_match_pct', 0) >= 75 else 'Medium',
            'reason': 'Career goal alignment is strongest where role match, skill fit, and salary fit overlap.',
            'expected_impact': 'More focused applications and faster progress toward offers.',
            'deadline': (date.today() + timedelta(days=14)).isoformat(),
            'estimated_completion_time_hours': 1,
        }]
        return recommendations

    def _career_recommendations(self, profile: dict[str, Any], ctx: RecommendationContext, top_jobs: list[dict[str, Any]]) -> list[dict[str, Any]]:
        recommendations = []
        top_roles = [item.get('job_title') for item in top_jobs[:5]]
        missing_skills = self._missing_skills(ctx)
        if top_roles:
            recommendations.append({
                'type': 'Career Direction',
                'priority': 'High',
                'reason': 'Top matching roles show consistent fit across skills, resume strength, and job demand.',
                'expected_impact': 'Sharper targeting and better conversion from application to interview.',
                'deadline': (date.today() + timedelta(days=10)).isoformat(),
                'estimated_completion_time_hours': 1,
                'recommended_roles': top_roles,
            })
        if missing_skills:
            recommendations.append({
                'type': 'Skill Acceleration',
                'priority': 'Critical' if len(missing_skills) >= 5 else 'High',
                'reason': 'Closing the top missing skills directly improves match quality and employability.',
                'expected_impact': 'Higher ATS scores, better recruiter response, and stronger job match.',
                'deadline': (date.today() + timedelta(days=30)).isoformat(),
                'estimated_completion_time_hours': 20,
                'skills': missing_skills[:5],
            })
        return recommendations

    def _smart_actions(
        self,
        top_jobs: list[dict[str, Any]],
        certification_recommendations: list[dict[str, Any]],
        resume_recommendations: list[dict[str, Any]],
        interview_recommendations: list[dict[str, Any]],
        networking_recommendations: list[dict[str, Any]],
        ctx: RecommendationContext,
    ) -> dict[str, Any]:
        actions = []
        for job in top_jobs[:3]:
            actions.append(self._action(
                action='Apply to this job',
                reason=job.get('reason', 'High match opportunity.'),
                priority='Critical' if job.get('overall_match_pct', 0) >= 85 else 'High',
                impact='Directly improves application momentum and offer opportunity.',
                deadline=(date.today() + timedelta(days=2)).isoformat(),
                hours=1,
                target=job.get('job_title'),
            ))
        for cert in certification_recommendations[:2]:
            actions.append(self._action(
                action=f"Complete {cert['certification_name']}",
                reason=cert['reason'],
                priority=cert['priority'],
                impact='Improves skill validation and job match potential.',
                deadline=cert['deadline'],
                hours=cert['estimated_completion_time_hours'],
                target=cert['certification_name'],
            ))
        for resume in resume_recommendations[:2]:
            actions.append(self._action(
                action='Update Resume',
                reason=resume['reason'],
                priority=resume['priority'],
                impact=resume['expected_impact'],
                deadline=resume['deadline'],
                hours=resume['estimated_completion_time_hours'],
                target=resume['type'],
            ))
        for interview in interview_recommendations[:2]:
            actions.append(self._action(
                action='Take Mock Interview' if 'Mock Interview' in interview.get('focus', '') else 'Practice Interview Topic',
                reason=interview['reason'],
                priority=interview['priority'],
                impact=interview['expected_impact'],
                deadline=interview['deadline'],
                hours=interview['estimated_completion_time_hours'],
                target=interview.get('focus'),
            ))
        for networking in networking_recommendations[:2]:
            actions.append(self._action(
                action=networking['action'],
                reason=networking['reason'],
                priority=networking['priority'],
                impact=networking['expected_impact'],
                deadline=networking['deadline'],
                hours=networking['estimated_completion_time_hours'],
                target=networking.get('target'),
            ))
        actions.sort(key=lambda item: self._priority_rank(item['priority']))
        return {'actions': actions[:12]}

    def _business_impact(self, ctx: RecommendationContext, smart_actions: dict[str, Any]) -> dict[str, Any]:
        action_count = len(smart_actions.get('actions', []))
        base_career = int(getattr(ctx.career_report, 'career_score', 0) or 0) if ctx.career_report is not None else 50
        base_ats = int(getattr(ctx.resume_analysis, 'ats_score', 0) or 0) if ctx.resume_analysis is not None else 50
        base_job_match = 0
        if ctx.job_match is not None:
            matches = list(getattr(ctx.job_match, 'top_job_matches', None) or [])
            if matches:
                base_job_match = round(mean([item.get('overall_match_pct', 0) for item in matches[:5]]))
        placement_probability = int((getattr(ctx.career_report, 'predictions_metadata', None) or {}).get('placement_probability', 0) or 0) if ctx.career_report is not None else 45
        return {
            'career_score_increase': min(100, 6 + action_count * 2 + max(0, 100 - base_career) // 8),
            'ats_score_increase': min(100, 5 + action_count + max(0, 100 - base_ats) // 10),
            'job_match_increase': min(100, 8 + action_count * 2 + max(0, 100 - base_job_match) // 8),
            'interview_readiness_increase': min(100, 7 + len([a for a in smart_actions.get('actions', []) if 'Interview' in a['action']]) * 8),
            'salary_increase': Decimal(str(900 + action_count * 225)).quantize(Decimal('1.00')),
            'offer_probability_increase': min(100, 6 + action_count * 3),
            'placement_probability_increase': min(100, 5 + max(0, 100 - placement_probability) // 10 + action_count * 2),
        }

    def _daily_ai_assistant(self, top_jobs: list[dict[str, Any]], smart_actions: dict[str, Any], ctx: RecommendationContext) -> dict[str, Any]:
        actions = smart_actions.get('actions', [])
        urgent = [item for item in actions if item['priority'] in {'Critical', 'High'}][:5]
        notifications = sorted(
            [self._notification_due(item) for item in (getattr(ctx.notifications[0], 'items', None) or [])] if ctx.notifications and hasattr(ctx.notifications[0], 'items') else [],
            key=lambda item: item['deadline']
        ) if False else []
        reminders = getattr(ctx.learning_roadmap, 'learning_reminders_metadata', None) or {}
        upcoming_interviews = []
        for interview in ctx.interviews[:3]:
            scheduled_at = getattr(interview, 'scheduled_at', None)
            if isinstance(scheduled_at, datetime):
                upcoming_interviews.append({'type': 'Interview', 'deadline': scheduled_at.date().isoformat()})
        upcoming_deadlines = [{'type': item['action'], 'deadline': item['deadline']} for item in urgent] + upcoming_interviews
        upcoming_deadlines.sort(key=lambda item: item['deadline'])
        return {
            'todays_focus': urgent[0]['action'] if urgent else 'Review top job matches and close one skill gap task.',
            'weekly_goal': 'Complete the top two high-priority actions and apply to at least one strong-fit role.',
            'monthly_goal': 'Improve match quality through one project, one resume upgrade, and one recruiter outreach sequence.',
            'urgent_tasks': urgent,
            'upcoming_deadlines': upcoming_deadlines[:8],
            'learning_reminder': reminders.get('daily_reminder', 'Complete today\'s planned study block.'),
            'interview_reminder': 'Review company-specific topics and complete one mock round.' if ctx.interviews else 'Keep weekly interview practice active.',
            'application_reminder': 'Tailor resume and apply to the highest-ranked open role this week.' if top_jobs else 'Refresh profile and wait for new match opportunities.',
        }

    def _trend_analysis(self, ctx: RecommendationContext) -> dict[str, Any]:
        emerging = []
        regional = Counter()
        industries = Counter()
        skills = Counter()
        if ctx.job_match is not None:
            analytics = getattr(ctx.job_match, 'analytics_metadata', None) or {}
            emerging = list(analytics.get('trending_technologies', []))[:10]
            for item in analytics.get('regional_demand', []):
                regional[item['location']] += int(item.get('demand_score', 0) or 0)
            for industry in analytics.get('top_industries', []):
                industries[industry] += 1
        for job in ctx.jobs:
            for skill in self._normalized_list(getattr(job, 'skills_required', None) or getattr(job, 'preferred_skills', None) or []):
                skills[skill] += 1
            company = getattr(job, 'company', None)
            if company is not None:
                industries[str(getattr(company, 'industry', 'Technology'))] += 1
            regional[self._job_location(job)] += 1
        salary_values = []
        for job in ctx.jobs:
            salary_max = Decimal(str(getattr(job, 'salary_max', 0) or 0))
            if salary_max > 0:
                salary_values.append(salary_max)
        return {
            'emerging_skills': emerging or [skill for skill, _ in skills.most_common(8)],
            'declining_skills': DECLINING_SKILLS,
            'hot_technologies': HOT_TECHNOLOGIES,
            'hiring_trends': [f'{skill} demand remains strong in current matched roles.' for skill, _ in skills.most_common(5)],
            'salary_trends': {
                'average_top_salary': (sum(salary_values, Decimal('0.00')) / Decimal(str(len(salary_values)))).quantize(Decimal('1.00')) if salary_values else Decimal('0.00'),
                'trend': 'Positive' if len(salary_values) >= 5 else 'Stable',
            },
            'regional_demand': [{'region': region, 'demand_score': score} for region, score in regional.most_common(8)],
            'industry_growth': [{'industry': industry, 'signal': 'High' if count >= 3 else 'Moderate'} for industry, count in industries.most_common(8)],
        }

    def _predictions(self, ctx: RecommendationContext, top_jobs: list[dict[str, Any]]) -> dict[str, Any]:
        if top_jobs:
            interview_probability = round(mean([item.get('interview_probability', 0) for item in top_jobs[:5]]))
            offer_probability = round(mean([item.get('hiring_probability', 0) for item in top_jobs[:5]]) * 0.72)
            expected_salary = sum((Decimal(str(item.get('expected_salary', 0) or 0)) for item in top_jobs[:5]), Decimal('0.00')) / Decimal(str(max(1, len(top_jobs[:5]))))
            hiring_timeline = round(mean([item.get('expected_joining_time_days', 35) for item in top_jobs[:5]]))
            promotion_scores = [item.get('promotion_potential', {}).get('score', 0) for item in top_jobs[:5]]
            career_growth = 'High' if mean([item.get('overall_match_pct', 0) for item in top_jobs[:5]]) >= 78 else 'Moderate'
        else:
            interview_probability = int((getattr(ctx.career_report, 'predictions_metadata', None) or {}).get('interview_probability', 0) or 0) if ctx.career_report is not None else 0
            offer_probability = int((getattr(ctx.career_report, 'predictions_metadata', None) or {}).get('offer_probability', 0) or 0) if ctx.career_report is not None else 0
            expected_salary = Decimal('0.00')
            hiring_timeline = 45
            promotion_scores = [50]
            career_growth = 'Moderate'
        return {
            'interview_probability': min(100, interview_probability),
            'offer_probability': min(100, offer_probability),
            'promotion_potential': 'High' if mean(promotion_scores) >= 72 else 'Moderate',
            'career_growth': career_growth,
            'expected_salary': expected_salary.quantize(Decimal('1.00')),
            'expected_hiring_timeline_days': hiring_timeline,
        }

    def _ai_explanations(self, **recommendation_groups: Any) -> dict[str, Any]:
        items = []
        for group_name, group in recommendation_groups.items():
            if isinstance(group, list):
                for entry in group[:8]:
                    items.append({
                        'category': group_name,
                        'recommendation': entry.get('action') or entry.get('name') or entry.get('job_title') or entry.get('company') or entry.get('recruiter') or entry.get('type') or entry.get('focus') or entry.get('certification_name') or entry.get('project_title') or entry.get('course_name') or 'Recommendation',
                        'why_generated': entry.get('reason', 'Derived from the current profile, market alignment, and progression data.'),
                        'supporting_evidence': self._supporting_evidence(entry),
                        'confidence_score': self._confidence_score(entry),
                        'expected_outcome': entry.get('expected_impact', 'Improves employability and recommendation relevance.'),
                        'alternative_options': self._alternative_options(entry, group),
                    })
        return {'items': items[:80]}

    def _preferred_companies(self, student: Student, ctx: RecommendationContext) -> list[str]:
        value = getattr(student, 'preferred_companies', None)
        if isinstance(value, (list, tuple, set)):
            return [str(item) for item in value if str(item).strip()]
        if value not in (None, ''):
            return [str(value)]
        if ctx.job_match is not None:
            companies = list(getattr(ctx.job_match, 'top_companies', None) or [])
            return [item.get('company') for item in companies[:5] if item.get('company')]
        return []

    def _preferred_salary(self, student: Student) -> dict[str, Decimal]:
        min_salary = Decimal(str(getattr(student, 'expected_salary_min', None) or 0))
        max_salary = Decimal(str(getattr(student, 'expected_salary_max', None) or 0))
        expected = getattr(student, 'expected_salary', None)
        if min_salary == 0 and max_salary == 0 and expected not in (None, ''):
            try:
                amount = Decimal(str(expected))
                min_salary = amount * Decimal('0.9')
                max_salary = amount * Decimal('1.1')
            except Exception:
                pass
        return {'min': min_salary.quantize(Decimal('1.00')), 'max': max_salary.quantize(Decimal('1.00'))}

    def _learning_speed(self, ctx: RecommendationContext) -> str:
        if ctx.learning_roadmap is None:
            return 'steady'
        return str(getattr(ctx.learning_roadmap, 'learning_speed', None) or (getattr(ctx.learning_roadmap, 'ai_personalization_metadata', None) or {}).get('learning_speed', 'steady'))

    def _availability_hours(self, ctx: RecommendationContext) -> int:
        if ctx.learning_roadmap is None:
            return 8
        return int(getattr(ctx.learning_roadmap, 'available_study_time_hours', None) or (getattr(ctx.learning_roadmap, 'learning_schedule_metadata', None) or {}).get('study_hours_per_week', 8) or 8)

    def _career_bucket(self, career_goal: str) -> str:
        goal = career_goal.lower()
        if any(term in goal for term in ('frontend', 'ui')):
            return 'frontend'
        if any(term in goal for term in ('data', 'analytics', 'analyst')):
            return 'data'
        if any(term in goal for term in ('ai', 'ml', 'machine learning')):
            return 'ai'
        if any(term in goal for term in ('cloud', 'devops', 'platform')):
            return 'cloud'
        if any(term in goal for term in ('security', 'cyber')):
            return 'security'
        return 'backend'

    def _missing_skills(self, ctx: RecommendationContext) -> list[str]:
        if ctx.skill_gap is None:
            return []
        items = getattr(ctx.skill_gap, 'ranked_skills_metadata', None) or []
        if isinstance(items, dict):
            items = items.get('items', items.get('skills', []))
        return [str(item.get('skill')) for item in items[:10] if isinstance(item, dict) and item.get('skill')]

    def _predicted_salary(self, ctx: RecommendationContext) -> dict[str, Decimal]:
        if ctx.job_match is not None:
            predictions = getattr(ctx.job_match, 'predictions_metadata', None) or {}
            value = predictions.get('expected_salary')
            if isinstance(value, Decimal):
                return {'min': (value * Decimal('0.95')).quantize(Decimal('1.00')), 'max': (value * Decimal('1.08')).quantize(Decimal('1.00'))}
            if isinstance(value, dict):
                return {
                    'min': Decimal(str(value.get('min', 0) or 0)).quantize(Decimal('1.00')),
                    'max': Decimal(str(value.get('max', 0) or 0)).quantize(Decimal('1.00')),
                }
        return {'min': Decimal('0.00'), 'max': Decimal('0.00')}

    def _action(self, action: str, reason: str, priority: str, impact: str, deadline: str, hours: int, target: Any) -> dict[str, Any]:
        return {
            'action': action,
            'target': target,
            'priority': priority,
            'reason': reason,
            'expected_impact': impact,
            'deadline': deadline,
            'estimated_completion_time_hours': hours,
        }

    def _priority_rank(self, priority: str) -> int:
        order = {'Critical': 0, 'High': 1, 'Medium': 2, 'Low': 3, 'Future': 4}
        return order.get(priority, 5)

    def _decorate_recommendation_item(self, item: dict[str, Any], priority: str, reason: str) -> dict[str, Any]:
        result = dict(item)
        result['priority'] = priority
        result['reason'] = reason
        result['expected_impact'] = self._expected_impact_text(item)
        result['deadline'] = self._deadline_for_priority(priority)
        result['estimated_completion_time_hours'] = self._estimated_hours(item)
        return result

    def _expected_impact_text(self, item: dict[str, Any]) -> str:
        if 'overall_match_pct' in item:
            return f"Could improve application outcomes with current match of {item.get('overall_match_pct', 0)}% and hiring probability of {item.get('hiring_probability', 0)}%."
        if 'culture_fit' in item:
            return 'Supports long-term fit, growth, and better retention potential.'
        if 'recruiter_interest_score' in item:
            return 'Can improve response rate and interview access through targeted outreach.'
        return 'Improves momentum toward better career outcomes.'

    def _deadline_for_priority(self, priority: str) -> str:
        days = {'Critical': 2, 'High': 7, 'Medium': 14, 'Low': 30, 'Future': 60}.get(priority, 14)
        return (date.today() + timedelta(days=days)).isoformat()

    def _estimated_hours(self, item: dict[str, Any]) -> int:
        if 'job_title' in item or 'company' in item or 'recruiter' in item:
            return 1
        if 'certification_name' in item:
            return 40
        if 'course_name' in item:
            return 16
        if 'project_title' in item:
            return int(item.get('duration_hours', 24) or 24)
        return 2

    def _supporting_evidence(self, entry: dict[str, Any]) -> list[str]:
        evidence = []
        if 'overall_match_pct' in entry:
            evidence.append(f"Overall match: {entry.get('overall_match_pct', 0)}%.")
        if 'hiring_probability' in entry:
            evidence.append(f"Hiring probability: {entry.get('hiring_probability', 0)}%.")
        if 'reason' in entry:
            evidence.append(entry['reason'])
        if 'expected_impact' in entry:
            evidence.append(entry['expected_impact'])
        return evidence[:4]

    def _confidence_score(self, entry: dict[str, Any]) -> int:
        if 'overall_match_pct' in entry:
            return min(99, max(55, int(entry.get('overall_match_pct', 0)) + 8))
        if 'recruiter_interest_score' in entry:
            return min(99, max(55, int(entry.get('recruiter_interest_score', 0)) + 6))
        if entry.get('priority') == 'Critical':
            return 88
        if entry.get('priority') == 'High':
            return 80
        return 72

    def _alternative_options(self, entry: dict[str, Any], group: list[dict[str, Any]]) -> list[str]:
        options = []
        current_name = entry.get('job_title') or entry.get('company') or entry.get('recruiter') or entry.get('name') or entry.get('project_title') or entry.get('course_name') or entry.get('certification_name') or entry.get('action')
        for item in group:
            name = item.get('job_title') or item.get('company') or item.get('recruiter') or item.get('name') or item.get('project_title') or item.get('course_name') or item.get('certification_name') or item.get('action')
            if name and name != current_name:
                options.append(str(name))
            if len(options) >= 3:
                break
        return options

    def _job_location(self, job: Job) -> str:
        city = str(getattr(job, 'location_city', '') or '').strip()
        country = str(getattr(job, 'location_country', '') or '').strip()
        location = str(getattr(job, 'location', '') or '').strip()
        if city or country:
            return ', '.join([item for item in [city, country] if item])
        return location or 'Unspecified'

    def _notification_due(self, item: Any) -> dict[str, Any]:
        return {'type': 'Notification', 'deadline': date.today().isoformat()}

    def _normalized_list(self, value: Any) -> list[str]:
        if isinstance(value, dict):
            value = list(value.keys())
        elif isinstance(value, str):
            value = [value]
        elif value is None:
            value = []
        elif not isinstance(value, (list, tuple, set)):
            value = [value]
        return [str(item).strip() for item in value if str(item).strip()]

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])


class AIRecommendationGenerator:
    def __init__(self, config: AppConfig = CONFIG, engine: RecommendationEngine | None = None) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 14000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 14000)
            self.faker.seed_instance(config.generation.seed + 14000)
        self.engine = engine or DefaultRecommendationEngine()

    def generate(
        self,
        students: Sequence[Student],
        companies: Sequence[Company],
        recruiters: Sequence[Recruiter],
        jobs: Sequence[Job],
        applications: Sequence[Application],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
        messages: Sequence[Message],
        notifications: Sequence[Notification],
        career_reports: Sequence[CareerReport],
        skill_gaps: Sequence[SkillGap],
        learning_roadmaps: Sequence[LearningRoadmap],
        resume_analyses: Sequence[ResumeAnalysis],
        job_matches: Sequence[JobMatch],
    ) -> AIRecommendationGenerationResult:
        if not students:
            raise ValueError('AI recommendation generation requires students.')

        reports_by_student = {self._student_key(report.student): report for report in career_reports if getattr(report, 'student', None) is not None}
        skill_gaps_by_student = {self._student_key(gap.student): gap for gap in skill_gaps if getattr(gap, 'student', None) is not None}
        roadmaps_by_student = {self._student_key(roadmap.student): roadmap for roadmap in learning_roadmaps if getattr(roadmap, 'student', None) is not None}
        resumes_by_student = {self._student_key(analysis.student): analysis for analysis in resume_analyses if getattr(analysis, 'student', None) is not None}
        matches_by_student = {self._student_key(match.student): match for match in job_matches if getattr(match, 'student', None) is not None}
        jobs_by_student = self._jobs_by_student(students, jobs, applications)
        companies_by_student = self._companies_by_student(applications, companies, jobs_by_student)
        recruiters_by_student = self._recruiters_by_student(applications, recruiters, jobs_by_student)
        applications_by_student = self._records_by_student(applications, 'student')
        interviews_by_student = self._records_by_student(interviews, 'student', application_fallback=True)
        offers_by_student = self._records_by_student(offers, 'student', application_fallback=True)
        messages_by_student = self._messages_by_student(messages)
        notifications_by_student = self._notifications_by_student(notifications)

        results: list[AIRecommendation] = []
        for student in students:
            key = self._student_key(student)
            ctx = RecommendationContext(
                student=student,
                companies=companies_by_student.get(key, []),
                recruiters=recruiters_by_student.get(key, []),
                jobs=jobs_by_student.get(key, []),
                applications=applications_by_student.get(key, []),
                interviews=interviews_by_student.get(key, []),
                offers=offers_by_student.get(key, []),
                messages=messages_by_student.get(key, []),
                notifications=notifications_by_student.get(key, []),
                career_report=reports_by_student.get(key),
                skill_gap=skill_gaps_by_student.get(key),
                learning_roadmap=roadmaps_by_student.get(key),
                resume_analysis=resumes_by_student.get(key),
                job_match=matches_by_student.get(key),
            )
            results.append(self.engine.build(student, ctx))
        return AIRecommendationGenerationResult(recommendations=results)

    def _jobs_by_student(self, students: Sequence[Student], jobs: Sequence[Job], applications: Sequence[Application]) -> dict[str, list[Job]]:
        mapping: dict[str, list[Job]] = defaultdict(list)
        for application in applications:
            student = getattr(application, 'student', None)
            job = getattr(application, 'job', None)
            if student is None or job is None:
                continue
            mapping[self._student_key(student)].append(job)
        for student in students:
            key = self._student_key(student)
            if not mapping.get(key):
                mapping[key] = self._best_candidate_jobs(student, jobs)
            else:
                existing = {str(getattr(job, 'id', None) or getattr(job, 'job_id', None) or id(job)) for job in mapping[key]}
                for candidate in self._best_candidate_jobs(student, jobs):
                    candidate_id = str(getattr(candidate, 'id', None) or getattr(candidate, 'job_id', None) or id(candidate))
                    if candidate_id not in existing:
                        mapping[key].append(candidate)
                        existing.add(candidate_id)
                    if len(mapping[key]) >= 100:
                        break
        return mapping

    def _companies_by_student(self, applications: Sequence[Application], companies: Sequence[Company], jobs_by_student: dict[str, list[Job]]) -> dict[str, list[Company]]:
        mapping: dict[str, list[Company]] = defaultdict(list)
        company_lookup = {str(getattr(company, 'name', '')): company for company in companies}
        for application in applications:
            student = getattr(application, 'student', None)
            company = getattr(application, 'company', None) or getattr(getattr(application, 'job', None), 'company', None)
            if student is None or company is None:
                continue
            mapping[self._student_key(student)].append(company)
        for student_key, jobs in jobs_by_student.items():
            seen = {str(getattr(company, 'name', '')) for company in mapping.get(student_key, [])}
            for job in jobs:
                name = str(getattr(getattr(job, 'company', None), 'name', None) or getattr(job, 'company_name', '') or '')
                if name and name in company_lookup and name not in seen:
                    mapping[student_key].append(company_lookup[name])
                    seen.add(name)
        return mapping

    def _recruiters_by_student(self, applications: Sequence[Application], recruiters: Sequence[Recruiter], jobs_by_student: dict[str, list[Job]]) -> dict[str, list[Recruiter]]:
        mapping: dict[str, list[Recruiter]] = defaultdict(list)
        recruiter_lookup = {str(getattr(recruiter, 'name', '')): recruiter for recruiter in recruiters}
        for application in applications:
            student = getattr(application, 'student', None)
            recruiter = getattr(application, 'recruiter', None)
            if student is None or recruiter is None:
                continue
            mapping[self._student_key(student)].append(recruiter)
        for student_key, jobs in jobs_by_student.items():
            seen = {str(getattr(recruiter, 'name', '')) for recruiter in mapping.get(student_key, [])}
            for job in jobs:
                recruiter = getattr(job, 'recruiter', None)
                recruiter_name = str(getattr(recruiter, 'name', None) or getattr(job, 'recruiter_name', '') or getattr(job, 'recruiter', '') or '')
                if recruiter is not None and recruiter_name not in seen:
                    mapping[student_key].append(recruiter)
                    seen.add(recruiter_name)
                elif recruiter_name and recruiter_name in recruiter_lookup and recruiter_name not in seen:
                    mapping[student_key].append(recruiter_lookup[recruiter_name])
                    seen.add(recruiter_name)
        return mapping

    def _records_by_student(self, records: Sequence[Any], student_attr: str, application_fallback: bool = False) -> dict[str, list[Any]]:
        mapping: dict[str, list[Any]] = defaultdict(list)
        for record in records:
            student = getattr(record, student_attr, None)
            if student is None and application_fallback:
                application = getattr(record, 'application', None)
                student = getattr(application, 'student', None) if application is not None else None
            if student is None:
                continue
            mapping[self._student_key(student)].append(record)
        return mapping

    def _messages_by_student(self, messages: Sequence[Message]) -> dict[str, list[Message]]:
        mapping: dict[str, list[Message]] = defaultdict(list)
        for message in messages:
            student = getattr(message, 'student', None)
            if student is None:
                student = getattr(getattr(message, 'sender', None), 'student', None)
            if student is None:
                student = getattr(getattr(message, 'recipient', None), 'student', None)
            if student is None:
                continue
            mapping[self._student_key(student)].append(message)
        return mapping

    def _notifications_by_student(self, notifications: Sequence[Notification]) -> dict[str, list[Notification]]:
        mapping: dict[str, list[Notification]] = defaultdict(list)
        for notification in notifications:
            student = getattr(notification, 'student', None)
            if student is None:
                continue
            mapping[self._student_key(student)].append(notification)
        return mapping

    def _best_candidate_jobs(self, student: Student, jobs: Sequence[Job]) -> list[Job]:
        skills = {str(item).strip().lower() for item in self._list_value(getattr(student, 'skills', None)) if str(item).strip()}
        preferred_location = str(getattr(student, 'preferred_location', '') or '').lower()
        preferred_work = str(getattr(student, 'preferred_work_type', '') or '').lower()
        ranked: list[tuple[int, Job]] = []
        for job in jobs:
            required = {str(item).strip().lower() for item in self._list_value(getattr(job, 'skills_required', None)) if str(item).strip()}
            preferred = {str(item).strip().lower() for item in self._list_value(getattr(job, 'preferred_skills', None)) if str(item).strip()}
            score = len(skills & required) * 4 + len(skills & preferred)
            location = f"{getattr(job, 'location_city', '')} {getattr(job, 'location_country', '')}".lower()
            if preferred_location and preferred_location in location:
                score += 4
            work_model = str(getattr(job, 'work_model', None) or getattr(job, 'work_type', None) or '').lower()
            if preferred_work and preferred_work in work_model:
                score += 3
            ranked.append((score, job))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [job for _, job in ranked[:100]]

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])


def generate_ai_recommendations(
    students: Sequence[Student],
    companies: Sequence[Company],
    recruiters: Sequence[Recruiter],
    jobs: Sequence[Job],
    applications: Sequence[Application],
    interviews: Sequence[Interview],
    offers: Sequence[Offer],
    messages: Sequence[Message],
    notifications: Sequence[Notification],
    career_reports: Sequence[CareerReport],
    skill_gaps: Sequence[SkillGap],
    learning_roadmaps: Sequence[LearningRoadmap],
    resume_analyses: Sequence[ResumeAnalysis],
    job_matches: Sequence[JobMatch],
    config: AppConfig = CONFIG,
) -> AIRecommendationGenerationResult:
    generator = AIRecommendationGenerator(config=config)
    return generator.generate(
        students=students,
        companies=companies,
        recruiters=recruiters,
        jobs=jobs,
        applications=applications,
        interviews=interviews,
        offers=offers,
        messages=messages,
        notifications=notifications,
        career_reports=career_reports,
        skill_gaps=skill_gaps,
        learning_roadmaps=learning_roadmaps,
        resume_analyses=resume_analyses,
        job_matches=job_matches,
    )


