@dataclass(slots=True)
class ApplicationGenerationResult:
    applications: list[Application]


class ApplicationGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 4000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 4000)
            self.faker.seed_instance(config.generation.seed + 4000)

    def generate(
        self,
        students: Sequence[Student],
        companies: Sequence[Company],
        recruiters: Sequence[Recruiter],
        jobs: Sequence[Job],
    ) -> ApplicationGenerationResult:
        if not students:
            raise ValueError('Application generation requires students.')
        if not companies:
            raise ValueError('Application generation requires companies.')
        if not recruiters:
            raise ValueError('Application generation requires recruiters.')
        if not jobs:
            raise ValueError('Application generation requires jobs.')

        recruiters_by_company = self._group_recruiters_by_company(recruiters)
        eligible_jobs = [job for job in jobs if getattr(job, 'company', None) is not None and recruiters_by_company.get(self._company_key(job.company))]
        if not eligible_jobs:
            raise ValueError('Application generation requires jobs linked to companies with recruiters.')

        weighted_jobs = self._weighted_jobs(eligible_jobs)
        applications: list[Application] = []

        for index in range(self.config.counts.applications):
            student = self.random.choice(list(students))
            job = self.random.choices([item[0] for item in weighted_jobs], weights=[item[1] for item in weighted_jobs], k=1)[0]
            company = job.company
            recruiter_pool = recruiters_by_company[self._company_key(company)]
            recruiter = self._resolve_recruiter(job, recruiter_pool)
            application = self._build_application(index, student, company, recruiter, job)
            applications.append(application)

        return ApplicationGenerationResult(applications=applications)

    def _group_recruiters_by_company(self, recruiters: Sequence[Recruiter]) -> dict[str, list[Recruiter]]:
        grouped: dict[str, list[Recruiter]] = {}
        for recruiter in recruiters:
            company = getattr(recruiter, 'company', None)
            if company is None:
                continue
            grouped.setdefault(self._company_key(company), []).append(recruiter)
        return grouped

    def _company_key(self, company: Company) -> str:
        value = getattr(company, 'id', None) or getattr(company, 'name', None)
        return str(value)

    def _weighted_jobs(self, jobs: Sequence[Job]) -> list[tuple[Job, float]]:
        weighted: list[tuple[Job, float]] = []
        for job in jobs:
            openings = int(getattr(job, 'openings_count', 1) or 1)
            experience_min = int(getattr(job, 'experience_min_years', 0) or 0)
            base = openings + max(1, 4 - experience_min)
            if str(getattr(job, 'employment_type', '')).lower() in {'internship', 'graduate'}:
                base += 5
            weighted.append((job, float(base)))
        return weighted

    def _resolve_recruiter(self, job: Job, recruiter_pool: Sequence[Recruiter]) -> Recruiter:
        linked = getattr(job, 'recruiter', None)
        if linked is not None:
            return linked
        return self.random.choice(list(recruiter_pool))

    def _build_application(
        self,
        index: int,
        student: Student,
        company: Company,
        recruiter: Recruiter,
        job: Job,
    ) -> Application:
        status = self._final_status()
        timeline = self._timeline(status)
        posting_reference = getattr(job, 'job_reference', None) or f'JOB-{index + 1:05d}'
        company_name = getattr(company, 'name', 'Company')
        expected_salary = self._expected_salary(job)
        preferred_location = self._preferred_location(student, job)
        ats = self._ats_data(job, student)
        interview_readiness = self._interview_readiness(job)
        ai_analysis = self._ai_analysis(job, ats, interview_readiness)
        review = self._recruiter_review(status, job)
        history = self._application_history(status, timeline, recruiter)
        documents = self._documents(student, job, timeline['submitted_at'])
        notifications = self._notifications(status, timeline, company_name, posting_reference)
        employer_experience = self._employer_experience(status, ats)
        university_experience = self._university_experience(status)
        admin_experience = self._admin_experience(status, timeline)
        current_status = self._status_label(status)
        source = self._application_source()
        referral = self._referral(company_name, recruiter)
        cover_letter = self._cover_letter(student, company_name, job)
        portfolio = self._portfolio(student)
        work_authorization = self._work_authorization(job)
        availability_date = self._availability_date(timeline['submitted_at'])
        resume_version = self._resume_version(student, timeline['submitted_at'])

        application = Application(
            student=student,
            job=job,
            company=company,
            recruiter=recruiter,
            applied_at=timeline['submitted_at'],
            status=current_status,
            source=source,
            resume_version=resume_version,
            cover_letter=cover_letter,
            portfolio_url=portfolio,
            expected_salary=expected_salary,
            preferred_location=preferred_location,
            availability_date=availability_date,
            work_authorization=work_authorization,
            last_updated_at=timeline['last_updated_at'],
        )
        application.application_reference = f'APP-{posting_reference}-{index + 1:06d}'
        application.referral = referral
        application.timeline_metadata = timeline
        application.ats_metadata = ats
        application.ai_analysis_metadata = ai_analysis
        application.interview_readiness_metadata = interview_readiness
        application.recruiter_review_metadata = review
        application.application_history_metadata = history
        application.documents_metadata = documents
        application.notifications_metadata = notifications
        application.student_experience_metadata = {
            'tracker_stage': current_status,
            'career_dashboard_impact': self.random.randint(52, 93),
            'application_detail_completeness': self.random.randint(86, 100),
            'student_analytics': {
                'job_match_percent': ats['overall_match'],
                'resume_match_percent': ats['resume_match_pct'],
                'ats_match_percent': ats['ats_score'],
                'interview_readiness_percent': interview_readiness['overall_interview_score'],
            },
        }
        application.employer_experience_metadata = employer_experience
        application.university_experience_metadata = university_experience
        application.admin_experience_metadata = admin_experience
        return application

    def _final_status(self) -> str:
        return self.random.choices(
            population=list(STATUS_FLOW),
            weights=[2, 2, 10, 12, 10, 8, 8, 7, 5, 3, 20, 6, 7],
            k=1,
        )[0]

    def _timeline(self, status: str) -> dict[str, object]:
        now = datetime.utcnow()
        submitted_at = now - timedelta(days=self.random.randint(2, 120), hours=self.random.randint(0, 20), minutes=self.random.randint(0, 59))
        timeline: dict[str, object] = {
            'saved_at': submitted_at - timedelta(days=self.random.randint(0, 5), hours=self.random.randint(1, 20)),
            'started_at': submitted_at - timedelta(days=self.random.randint(0, 3), hours=self.random.randint(0, 12)),
            'submitted_at': submitted_at,
        }

        ordered_progression = {
            'saved': ['saved_at'],
            'started': ['saved_at', 'started_at'],
            'submitted': ['saved_at', 'started_at', 'submitted_at'],
            'viewed': ['saved_at', 'started_at', 'submitted_at', 'viewed_at'],
            'shortlisted': ['saved_at', 'started_at', 'submitted_at', 'viewed_at', 'shortlisted_at'],
            'assessment': ['saved_at', 'started_at', 'submitted_at', 'viewed_at', 'shortlisted_at', 'assessment_at'],
            'interview_scheduled': ['saved_at', 'started_at', 'submitted_at', 'viewed_at', 'shortlisted_at', 'assessment_at', 'interview_scheduled_at'],
            'interview_completed': ['saved_at', 'started_at', 'submitted_at', 'viewed_at', 'shortlisted_at', 'assessment_at', 'interview_scheduled_at', 'interview_completed_at'],
            'offer_extended': ['saved_at', 'started_at', 'submitted_at', 'viewed_at', 'shortlisted_at', 'assessment_at', 'interview_scheduled_at', 'interview_completed_at', 'offer_extended_at'],
            'accepted': ['saved_at', 'started_at', 'submitted_at', 'viewed_at', 'shortlisted_at', 'assessment_at', 'interview_scheduled_at', 'interview_completed_at', 'offer_extended_at', 'accepted_at'],
            'rejected': ['saved_at', 'started_at', 'submitted_at', 'viewed_at', 'shortlisted_at', 'rejected_at'],
            'withdrawn': ['saved_at', 'started_at', 'submitted_at', 'withdrawn_at'],
            'expired': ['saved_at', 'started_at', 'submitted_at', 'expired_at'],
        }

        if status in {'viewed', 'shortlisted', 'assessment', 'interview_scheduled', 'interview_completed', 'offer_extended', 'accepted', 'rejected'}:
            timeline['viewed_at'] = submitted_at + timedelta(days=self.random.randint(1, 10), hours=self.random.randint(0, 8))
        if status in {'shortlisted', 'assessment', 'interview_scheduled', 'interview_completed', 'offer_extended', 'accepted', 'rejected'}:
            base = timeline['viewed_at']
            timeline['shortlisted_at'] = base + timedelta(days=self.random.randint(1, 7), hours=self.random.randint(0, 8))
        if status in {'assessment', 'interview_scheduled', 'interview_completed', 'offer_extended', 'accepted'}:
            base = timeline['shortlisted_at']
            timeline['assessment_at'] = base + timedelta(days=self.random.randint(1, 6), hours=self.random.randint(0, 8))
        if status in {'interview_scheduled', 'interview_completed', 'offer_extended', 'accepted'}:
            base = timeline.get('assessment_at', timeline['shortlisted_at'])
            timeline['interview_scheduled_at'] = base + timedelta(days=self.random.randint(1, 8), hours=self.random.randint(0, 8))
        if status in {'interview_completed', 'offer_extended', 'accepted'}:
            base = timeline['interview_scheduled_at']
            timeline['interview_completed_at'] = base + timedelta(days=self.random.randint(1, 10), hours=self.random.randint(1, 8))
        if status in {'offer_extended', 'accepted'}:
            base = timeline['interview_completed_at']
            timeline['offer_extended_at'] = base + timedelta(days=self.random.randint(1, 7), hours=self.random.randint(0, 6))
        if status == 'accepted':
            base = timeline['offer_extended_at']
            timeline['accepted_at'] = base + timedelta(days=self.random.randint(1, 6), hours=self.random.randint(0, 4))
        if status == 'rejected':
            base = timeline.get('shortlisted_at') or timeline.get('viewed_at') or submitted_at
            timeline['rejected_at'] = base + timedelta(days=self.random.randint(1, 9), hours=self.random.randint(0, 6))
        if status == 'withdrawn':
            timeline['withdrawn_at'] = submitted_at + timedelta(days=self.random.randint(1, 12), hours=self.random.randint(0, 8))
        if status == 'expired':
            timeline['expired_at'] = submitted_at + timedelta(days=self.random.randint(15, 45), hours=self.random.randint(0, 8))

        valid_keys = ordered_progression[status]
        timeline['last_updated_at'] = max(timeline[key] for key in valid_keys if key in timeline)
        timeline['current_status'] = self._status_label(status)
        return timeline

    def _ats_data(self, job: Job, student: Student) -> dict[str, object]:
        employment_type = str(getattr(job, 'employment_type', '')).lower()
        base = 68 if employment_type in {'internship', 'graduate'} else 62
        ats_score = self._bounded_int(base + self.random.randint(-10, 22), 38, 97)
        resume_match = self._bounded_int(ats_score + self.random.randint(-8, 8), 35, 98)
        skill_match = self._bounded_int(ats_score + self.random.randint(-10, 10), 32, 98)
        education_match = self._bounded_int(base + self.random.randint(-5, 25), 40, 100)
        experience_match = self._bounded_int(base + self.random.randint(-12, 18), 25, 96)
        certification_match = self._bounded_int(base + self.random.randint(-15, 20), 20, 95)
        portfolio_match = self._bounded_int(base + self.random.randint(-10, 22), 25, 98)
        overall_match = int(round((resume_match + skill_match + education_match + experience_match + certification_match + portfolio_match + ats_score) / 7))
        job_title = str(getattr(job, 'title', '')).lower()
        bucket = self._job_bucket(job_title)
        missing_pool = list(MISSING_SKILL_POOL.get(bucket, MISSING_SKILL_POOL['general']))
        strengths = self.random.sample(list(RECRUITER_STRENGTHS), k=2)
        weaknesses = self.random.sample(list(RECRUITER_CONCERNS), k=2)
        return {
            'ats_score': ats_score,
            'resume_match_pct': resume_match,
            'skill_match_pct': skill_match,
            'education_match_pct': education_match,
            'experience_match_pct': experience_match,
            'certification_match_pct': certification_match,
            'portfolio_match_pct': portfolio_match,
            'overall_match': overall_match,
            'missing_skills': missing_pool[: self.random.randint(2, min(4, len(missing_pool)))],
            'strengths': strengths,
            'weaknesses': weaknesses,
        }

    def _ai_analysis(self, job: Job, ats: dict[str, object], interview_readiness: dict[str, object]) -> dict[str, object]:
        overall_match = int(ats['overall_match'])
        study_hours = self.random.randint(18, 120)
        missing_skills = list(ats['missing_skills'])
        return {
            'ai_recommendation': self.random.choice(AI_RECOMMENDATIONS),
            'resume_feedback': self.random.sample(list(RESUME_FEEDBACK_LINES), k=2),
            'skill_gap': [{'skill': skill, 'priority': self.random.choice(['High', 'Medium'])} for skill in missing_skills],
            'interview_readiness': interview_readiness['overall_interview_score'],
            'career_suggestions': self.random.sample(list(CAREER_SUGGESTIONS), k=2),
            'improvement_plan': [
                f'Deepen project-based evidence in {missing_skills[0]}.',
                'Refine resume bullets to highlight measurable outcomes and technical ownership.',
                'Practice structured interview responses using role-specific scenarios.',
            ],
            'recommended_certifications': self.random.sample(list(CERTIFICATION_LIBRARY), k=2),
            'recommended_courses': self.random.sample(list(RECRUITER_COURSE_LIBRARY), k=3),
            'estimated_study_hours': study_hours,
            'job_match_projection': self._bounded_int(overall_match + self.random.randint(2, 10), 45, 98),
        }

    def _interview_readiness(self, job: Job) -> dict[str, object]:
        title = str(getattr(job, 'title', '')).lower()
        coding_bias = 10 if any(token in title for token in ('engineer', 'developer', 'data')) else 0
        system_design_bias = 8 if any(token in title for token in ('platform', 'backend', 'cloud', 'ml')) else 0
        communication = self._bounded_int(58 + self.random.randint(-10, 22), 35, 97)
        coding = self._bounded_int(55 + coding_bias + self.random.randint(-12, 18), 30, 98)
        problem_solving = self._bounded_int(60 + self.random.randint(-10, 20), 35, 98)
        system_design = self._bounded_int(48 + system_design_bias + self.random.randint(-12, 22), 25, 97)
        behavioral = self._bounded_int(59 + self.random.randint(-10, 18), 35, 97)
        leadership = self._bounded_int(52 + self.random.randint(-12, 16), 28, 95)
        confidence = self._bounded_int(57 + self.random.randint(-11, 18), 30, 97)
        overall = int(round((communication + coding + problem_solving + system_design + behavioral + leadership + confidence) / 7))
        return {
            'communication': communication,
            'coding': coding,
            'problem_solving': problem_solving,
            'system_design': system_design,
            'behavioral': behavioral,
            'leadership': leadership,
            'confidence': confidence,
            'overall_interview_score': overall,
        }

    def _recruiter_review(self, status: str, job: Job) -> dict[str, object]:
        recommendation = self.random.choice(RECOMMENDATION_LINES)
        if status in {'accepted', 'offer_extended', 'interview_completed', 'interview_scheduled'}:
            recommendation = 'Proceed to next stage.'
        elif status in {'rejected', 'withdrawn', 'expired'}:
            recommendation = self.random.choice(['Keep warm for future openings.', 'Do not progress in current cycle.'])
        return {
            'recruiter_notes': f'Candidate evaluated for {getattr(job, "title", "the role")} with attention to role alignment, project quality, and communication clarity.',
            'strengths': self.random.sample(list(RECRUITER_STRENGTHS), k=2),
            'concerns': self.random.sample(list(RECRUITER_CONCERNS), k=2),
            'decision_reason': self.random.choice(DECISION_REASONS),
            'recommendation': recommendation,
            'hiring_manager_notes': 'Candidate appears aligned to the core role scope. Final decision should consider depth, consistency, and team-level calibration.',
        }

    def _application_history(self, status: str, timeline: dict[str, object], recruiter: Recruiter) -> list[dict[str, object]]:
        logs: list[dict[str, object]] = []
        actor_name = getattr(recruiter, 'full_name', None) or getattr(recruiter, 'email', 'Recruiter')
        status_map = [
            ('saved_at', 'Application saved', 'student'),
            ('started_at', 'Application started', 'student'),
            ('submitted_at', 'Application submitted', 'student'),
            ('viewed_at', 'Resume viewed', actor_name),
            ('shortlisted_at', 'Recruiter reviewed profile', actor_name),
            ('assessment_at', 'Assessment invited', actor_name),
            ('interview_scheduled_at', 'Interview invited', actor_name),
            ('interview_completed_at', 'Interview completed', actor_name),
            ('offer_extended_at', 'Offer created', actor_name),
            ('accepted_at', 'Offer accepted', 'student'),
            ('rejected_at', 'Application rejected', actor_name),
            ('withdrawn_at', 'Application withdrawn', 'student'),
            ('expired_at', 'Application expired', 'system'),
        ]
        for key, action, actor in status_map:
            if key in timeline:
                logs.append({'timestamp': timeline[key].isoformat(), 'action': action, 'actor': actor})
        return logs

    def _documents(self, student: Student, job: Job, submitted_at: datetime) -> dict[str, object]:
        student_key = self._student_key(student)
        slug = self._slug(getattr(job, 'title', 'job'))
        stamp = submitted_at.strftime('%Y%m%d')
        return {
            'resume': {'file_name': f'{student_key}_resume_{stamp}.pdf', 'version': f'v{self.random.randint(2, 9)}.{self.random.randint(0, 3)}'},
            'cover_letter': {'file_name': f'{student_key}_{slug}_cover_letter_{stamp}.pdf', 'included': self.random.random() < 0.72},
            'portfolio': {'url': f'https://portfolio.example.dev/{student_key}', 'quality': self.random.choice(['Basic', 'Good', 'Strong'])},
            'certificates': [f'{self._slug(name)}.pdf' for name in self.random.sample(list(CERTIFICATION_LIBRARY), k=2)],
            'github': f'https://github.example.dev/{student_key}',
            'linkedin_placeholder': f'https://careerbridge.example.dev/in/{student_key}',
            'transcript': {'file_name': f'{student_key}_transcript.pdf', 'verified': self.random.random() < 0.84},
        }

    def _notifications(self, status: str, timeline: dict[str, object], company_name: str, posting_reference: str) -> list[dict[str, object]]:
        notifications: list[dict[str, object]] = []
        mapping = [
            ('submitted_at', 'Application received', f'Your application for {posting_reference} at {company_name} has been received.'),
            ('viewed_at', 'Application viewed', f'Your profile was viewed by the hiring team at {company_name}.'),
            ('assessment_at', 'Assessment update', f'You have been invited to complete the next assessment for {posting_reference}.'),
            ('interview_scheduled_at', 'Interview scheduled', f'An interview has been scheduled for your {posting_reference} application.'),
            ('interview_completed_at', 'Interview reminder', f'Thank you for completing your interview for {posting_reference}.'),
            ('offer_extended_at', 'Offer update', f'An offer has been extended for your application at {company_name}.'),
            ('rejected_at', 'Application rejected', f'The hiring process for {posting_reference} has concluded for this role.'),
            ('accepted_at', 'Application accepted', f'Congratulations. You have accepted the offer for {posting_reference}.'),
        ]
        for key, label, message in mapping:
            if key in timeline:
                notifications.append({'type': label, 'timestamp': timeline[key].isoformat(), 'message': message})
        if status in {'submitted', 'viewed', 'shortlisted', 'assessment', 'interview_scheduled'} and 'interview_scheduled_at' in timeline:
            notifications.append({'type': 'Interview reminder', 'timestamp': (timeline['interview_scheduled_at'] - timedelta(hours=24)).isoformat(), 'message': 'Reminder: please confirm your availability and preparation checklist.'})
        return notifications

    def _employer_experience(self, status: str, ats: dict[str, object]) -> dict[str, object]:
        stage_rank = {
            'Saved': 1,
            'Started': 2,
            'Submitted': 3,
            'Viewed': 4,
            'Shortlisted': 5,
            'Assessment': 6,
            'Interview Scheduled': 7,
            'Interview Completed': 8,
            'Offer Extended': 9,
            'Accepted': 10,
            'Rejected': 0,
            'Withdrawn': 0,
            'Expired': 0,
        }
        current = self._status_label(status)
        return {
            'recruiter_queue_priority': self.random.choice(['High', 'Medium', 'Normal']) if ats['overall_match'] >= 72 else self.random.choice(['Medium', 'Normal', 'Low']),
            'candidate_ranking_score': ats['overall_match'],
            'pipeline_stage': current,
            'hiring_progress': stage_rank[current] * 10,
            'interview_queue_ready': current in {'Interview Scheduled', 'Interview Completed', 'Offer Extended', 'Accepted'},
            'shortlist_bucket': 'Yes' if current in {'Shortlisted', 'Assessment', 'Interview Scheduled', 'Interview Completed', 'Offer Extended', 'Accepted'} else 'No',
        }

    def _university_experience(self, status: str) -> dict[str, object]:
        offered = status in {'accepted', 'offer_extended'}
        accepted = status == 'accepted'
        return {
            'placement_metrics': {'counted_in_placement_cycle': status not in {'saved', 'started'}},
            'department_success': self.random.randint(48, 92),
            'offer_rate': self.random.randint(12, 46) if offered else self.random.randint(4, 28),
            'placement_history': {
                'included_in_reports': status not in {'saved', 'started', 'withdrawn'},
                'successful_outcome': accepted,
            },
        }

    def _admin_experience(self, status: str, timeline: dict[str, object]) -> dict[str, object]:
        submitted_time = timeline['submitted_at']
        last_updated = timeline['last_updated_at']
        cycle_days = max(1, (last_updated - submitted_time).days)
        return {
            'application_analytics': {
                'cycle_time_days': cycle_days,
                'active': status in ACTIVE_ENDINGS,
            },
            'hiring_funnel': {
                'entered_funnel': status not in {'saved', 'started'},
                'reached_interview': status in {'interview_scheduled', 'interview_completed', 'offer_extended', 'accepted'},
                'reached_offer': status in {'offer_extended', 'accepted'},
            },
            'success_rate': self.random.randint(18, 78),
            'acceptance_rate': self.random.randint(46, 88) if status in {'offer_extended', 'accepted'} else self.random.randint(18, 55),
            'drop_off_analysis': {
                'drop_stage': self._status_label(status) if status in {'withdrawn', 'rejected', 'expired'} else None,
                'drop_reason_cluster': self.random.choice(['Competition', 'Compensation mismatch', 'Readiness gap', 'Role alignment']) if status in {'withdrawn', 'rejected', 'expired'} else None,
            },
        }

    def _application_source(self) -> str:
        return self.random.choice(APPLICATION_SOURCES)

    def _referral(self, company_name: str, recruiter: Recruiter) -> dict[str, object] | None:
        if self.random.random() >= 0.22:
            return None
        contact = getattr(recruiter, 'full_name', None) or getattr(recruiter, 'email', 'Recruiter')
        return {
            'referral_type': self.random.choice(['Employee referral', 'University referral', 'Community referral']),
            'referrer': contact,
            'organization': company_name,
        }

    def _cover_letter(self, student: Student, company_name: str, job: Job) -> str:
        student_name = getattr(student, 'full_name', None) or getattr(student, 'name', None) or 'the candidate'
        title = getattr(job, 'title', 'the role')
        return (
            f'I am excited to apply for the {title} opportunity at {company_name}. '
            f'My academic work, practical projects, and structured problem-solving approach have prepared me to contribute effectively in this role. '
            f'I am particularly interested in the opportunity to learn quickly, work on meaningful problems, and grow through close collaboration with the team.'
        )

    def _portfolio(self, student: Student) -> str:
        key = self._student_key(student)
        return f'https://portfolio.example.dev/{key}'

    def _work_authorization(self, job: Job) -> str:
        country = getattr(job, 'location_country', None) or 'United States'
        if country == 'India':
            return 'Authorized to work without sponsorship'
        return self.random.choice(WORK_AUTHORIZATION_OPTIONS)

    def _availability_date(self, submitted_at: datetime) -> datetime:
        return submitted_at + timedelta(days=self.random.randint(7, 75))

    def _resume_version(self, student: Student, submitted_at: datetime) -> str:
        version_major = 1 + (submitted_at.month % 4)
        version_minor = self.random.randint(0, 6)
        return f'resume_v{version_major}.{version_minor}'

    def _expected_salary(self, job: Job) -> Decimal:
        salary_min = getattr(job, 'salary_min', None)
        salary_max = getattr(job, 'salary_max', None)
        if salary_min is None and salary_max is None:
            return Decimal('0')
        if salary_min is None:
            salary_min = salary_max
        if salary_max is None:
            salary_max = salary_min
        lower = Decimal(salary_min)
        upper = Decimal(salary_max)
        midpoint = lower + ((upper - lower) * Decimal(str(self.random.uniform(0.38, 0.72))))
        return midpoint.quantize(Decimal('1.00'))

    def _preferred_location(self, student: Student, job: Job) -> str:
        student_location = getattr(student, 'preferred_location', None) or getattr(student, 'location', None)
        if student_location:
            return str(student_location)
        city = getattr(job, 'location_city', None) or 'Remote'
        country = getattr(job, 'location_country', None) or ''
        return f'{city}, {country}'.strip(', ')

    def _status_label(self, status: str) -> str:
        return status.replace('_', ' ').title()

    def _job_bucket(self, title: str) -> str:
        lowered = title.lower()
        if any(token in lowered for token in ('frontend', 'ui', 'web')):
            return 'frontend'
        if any(token in lowered for token in ('machine learning', 'ai', 'ml')):
            return 'ai'
        if any(token in lowered for token in ('data', 'analytics', 'bi')):
            return 'data'
        if any(token in lowered for token in ('product',)):
            return 'product'
        if any(token in lowered for token in ('design',)):
            return 'design'
        if any(token in lowered for token in ('cloud', 'platform', 'devops', 'infrastructure')):
            return 'cloud'
        if any(token in lowered for token in ('security',)):
            return 'security'
        if any(token in lowered for token in ('finance', 'financial', 'risk')):
            return 'finance'
        if any(token in lowered for token in ('operations', 'support')):
            return 'operations'
        if any(token in lowered for token in ('engineer', 'developer', 'software')):
            return 'engineering'
        return 'general'

    def _student_key(self, student: Student) -> str:
        value = getattr(student, 'student_id', None) or getattr(student, 'id', None) or getattr(student, 'email', None) or 'student'
        return self._slug(str(value))

    def _slug(self, value: str) -> str:
        slug = re.sub(r'[^a-z0-9]+', '-', value.lower()).strip('-')
        return slug or 'item'

    def _bounded_int(self, value: int, low: int, high: int) -> int:
        return max(low, min(high, value))


def generate_applications(
    students: Sequence[Student],
    companies: Sequence[Company],
    recruiters: Sequence[Recruiter],
    jobs: Sequence[Job],
    config: AppConfig = CONFIG,
) -> ApplicationGenerationResult:
    generator = ApplicationGenerator(config=config)
    return generator.generate(students, companies, recruiters, jobs)


