class DefaultResumeAnalysisEngine:
    def analyze(self, student: Student, ctx: StudentCareerContext) -> dict[str, Any]:
        headline = bool(getattr(student, 'headline', None))
        bio = bool(getattr(student, 'bio', None))
        skills = self._list_value(getattr(student, 'skills', None))
        projects = self._list_value(getattr(student, 'projects', None))
        experience = self._list_value(getattr(student, 'experience', None))
        certifications = self._list_value(getattr(student, 'certifications', None))
        languages = self._list_value(getattr(student, 'languages', None))
        portfolio = bool(getattr(student, 'portfolio_url', None) or getattr(student, 'portfolio', None))
        github = bool(getattr(student, 'github_url', None) or getattr(student, 'github', None))
        quant_bullets = sum(1 for item in projects + experience if any(ch.isdigit() for ch in str(item)))
        keyword_hits = self._keyword_hits(skills, ctx.jobs)
        formatting_score = min(100, 48 + len(projects) * 8 + len(experience) * 10 + (12 if headline else 0) + (8 if bio else 0))
        action_verb_score = min(100, 40 + quant_bullets * 12)
        grammar_score = min(100, 58 + (10 if bio else 0) + (8 if headline else 0) + min(18, len(languages) * 3))
        present_sections = {
            'headline': headline,
            'summary': bio,
            'education': bool(getattr(student, 'degree', None) and getattr(student, 'university', None)),
            'skills': len(skills) > 0,
            'projects': len(projects) > 0,
            'experience': len(experience) > 0,
            'certifications': len(certifications) > 0,
            'languages': len(languages) > 0,
            'portfolio': portfolio,
            'github': github,
        }
        completeness = round(sum(1 for v in present_sections.values() if v) / len(present_sections) * 100)
        ats_keyword_match = min(100, round(keyword_hits * 100))
        weak_sections = [name for name, ok in present_sections.items() if not ok][:4]
        missing_sections = [name for name, ok in present_sections.items() if not ok]
        improvement_suggestions: list[str] = []
        if 'projects' in missing_sections:
            improvement_suggestions.append('Add 2 to 3 project entries with measurable outcomes and clear ownership.')
        if 'experience' in missing_sections:
            improvement_suggestions.append('Highlight internships, freelance work, or leadership roles to improve credibility.')
        if 'portfolio' in missing_sections:
            improvement_suggestions.append('Add a portfolio link that showcases your best role-relevant work.')
        if ats_keyword_match < 65:
            improvement_suggestions.append('Align skill and project terminology more closely with target job descriptions.')
        if action_verb_score < 60:
            improvement_suggestions.append('Rewrite bullets using action verbs and include scope, impact, or performance metrics.')
        resume_score = round((completeness * 0.34) + (ats_keyword_match * 0.28) + (formatting_score * 0.14) + (action_verb_score * 0.12) + (grammar_score * 0.12))
        return {
            'resume_score': max(0, min(100, resume_score)),
            'resume_completeness': completeness,
            'ats_keyword_match': ats_keyword_match,
            'formatting_score': formatting_score,
            'action_verb_score': action_verb_score,
            'grammar_score': grammar_score,
            'missing_sections': missing_sections,
            'weak_sections': weak_sections,
            'improvement_suggestions': improvement_suggestions,
            'evidence': {
                'skills_count': len(skills),
                'projects_count': len(projects),
                'experience_count': len(experience),
                'certification_count': len(certifications),
            },
        }

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])

    def _keyword_hits(self, skills: list[Any], jobs: Sequence[Job]) -> float:
        if not jobs:
            return 0.0
        student_skills = {str(skill).strip().lower() for skill in skills if str(skill).strip()}
        if not student_skills:
            return 0.0
        role_keywords: list[str] = []
        for job in jobs[:20]:
            required = getattr(job, 'skills_required', None) or getattr(job, 'skills_required_metadata', None) or []
            preferred = getattr(job, 'preferred_skills', None) or []
            if isinstance(required, str):
                required = [required]
            if isinstance(preferred, str):
                preferred = [preferred]
            role_keywords.extend([str(item).strip().lower() for item in list(required) + list(preferred) if str(item).strip()])
        if not role_keywords:
            return 0.0
        unique_keywords = set(role_keywords)
        return min(1.0, len(student_skills & unique_keywords) / max(4, min(12, len(unique_keywords))))


class DefaultSkillGapEngine:
    def analyze(self, student: Student, ctx: StudentCareerContext) -> dict[str, Any]:
        student_skills = {str(skill).strip() for skill in self._list_value(getattr(student, 'skills', None)) if str(skill).strip()}
        target_skills = Counter()
        for job in ctx.jobs[:30]:
            for field in ('skills_required', 'preferred_skills'):
                items = getattr(job, field, None) or []
                if isinstance(items, str):
                    items = [items]
                for item in items:
                    skill = str(item).strip()
                    if skill:
                        target_skills[skill] += 2 if field == 'skills_required' else 1
        missing = [skill for skill, _ in target_skills.most_common(8) if skill not in student_skills]
        total_target = len({skill for skill in target_skills if skill}) or 1
        skill_gap_pct = round(len(missing) / total_target * 100)
        priority_skills = missing[:5]
        learning_order = []
        estimated_total = 0
        for idx, skill in enumerate(priority_skills, start=1):
            meta = LEARNING_CATALOG.get(skill, DEFAULT_LEARNING)
            hours = int(meta['hours'])
            estimated_total += hours
            learning_order.append({
                'order': idx,
                'skill': skill,
                'estimated_learning_hours': hours,
                'difficulty_level': self._difficulty(hours),
            })
        return {
            'missing_skills': missing,
            'skill_gap_pct': min(100, skill_gap_pct),
            'priority_skills': priority_skills,
            'estimated_learning_hours': estimated_total,
            'difficulty_level': self._difficulty(estimated_total // max(1, len(priority_skills))) if priority_skills else 'low',
            'learning_order': learning_order,
        }

    def _difficulty(self, hours: int) -> str:
        if hours <= 16:
            return 'low'
        if hours <= 28:
            return 'medium'
        return 'high'

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])


class DefaultLearningRecommendationEngine:
    def recommend(self, student: Student, ctx: StudentCareerContext, skill_gap: dict[str, Any]) -> dict[str, Any]:
        recommendations: list[dict[str, Any]] = []
        for skill in skill_gap.get('priority_skills', [])[:4]:
            meta = LEARNING_CATALOG.get(skill, DEFAULT_LEARNING)
            recommendations.append({
                'skill': skill,
                'course': meta['course'],
                'certification': meta['certification'],
                'book': meta['book'],
                'project': meta['project'],
                'practice_questions': [
                    f'Explain core concepts of {skill} with one practical example.',
                    f'Discuss trade-offs and typical interview questions related to {skill}.',
                ],
                'coding_challenges': [
                    f'Build a small feature or workflow using {skill}.',
                    f'Debug and optimize an implementation related to {skill}.',
                ],
                'open_source_projects': [
                    f'Contribute documentation or bug fixes to a {skill}-related project.',
                    f'Add a small improvement to a public repository using {skill}.',
                ],
                'hackathons': [f'{skill} Challenge Sprint', 'CareerBridge Innovation Hack'],
                'why': f'Recommended because {skill} is missing from the student profile and appears frequently in target jobs.',
                'confidence_pct': 70 + min(25, len(skill_gap.get('priority_skills', [])) * 4),
                'expected_improvement': 6 + min(12, int(meta['hours']) // 3),
                'estimated_timeline_days': max(7, int(meta['hours']) // 2),
            })
        return {'recommendations': recommendations}


class DefaultJobMatchingEngine:
    def match(self, student: Student, ctx: StudentCareerContext) -> dict[str, Any]:
        student_skills = {str(skill).strip().lower() for skill in self._list_value(getattr(student, 'skills', None)) if str(skill).strip()}
        preferred_location = str(getattr(student, 'preferred_location', '') or '').lower()
        preferred_work_type = str(getattr(student, 'preferred_work_type', '') or '').lower()
        expected_salary = self._expected_salary(student)
        ranked_jobs: list[dict[str, Any]] = []
        recruiter_counter: Counter[str] = Counter()
        company_counter: Counter[str] = Counter()
        industry_counter: Counter[str] = Counter()
        location_counter: Counter[str] = Counter()
        salary_bands: list[tuple[Decimal, Decimal]] = []
        for job in ctx.jobs:
            required = self._normalized_set(getattr(job, 'skills_required', None) or getattr(job, 'skills_required_metadata', None) or [])
            preferred = self._normalized_set(getattr(job, 'preferred_skills', None) or [])
            required_match = len(student_skills & required) / max(1, len(required))
            preferred_match = len(student_skills & preferred) / max(1, len(preferred)) if preferred else 0.0
            location_text = f"{getattr(job, 'location_city', '')} {getattr(job, 'location_country', '')}".strip().lower()
            location_score = 1.0 if preferred_location and preferred_location in location_text else (0.55 if not preferred_location else 0.2)
            work_model = str(getattr(job, 'work_model', '') or '').lower()
            work_score = 1.0 if preferred_work_type and preferred_work_type == work_model else (0.6 if not preferred_work_type else 0.35)
            salary_min = Decimal(getattr(job, 'salary_min', 0) or 0)
            salary_max = Decimal(getattr(job, 'salary_max', salary_min) or salary_min)
            salary_fit = self._salary_fit(expected_salary, salary_min, salary_max)
            score = round(((required_match * 0.45) + (preferred_match * 0.15) + (location_score * 0.12) + (work_score * 0.10) + (salary_fit * 0.18)) * 100)
            ranked_jobs.append({
                'job': job,
                'match_pct': max(0, min(100, score)),
                'reasoning': self._job_reasoning(required_match, preferred_match, location_score, work_score, salary_fit),
            })
        ranked_jobs.sort(key=lambda item: item['match_pct'], reverse=True)
        top_jobs = ranked_jobs[:5]
        for item in top_jobs:
            job = item['job']
            company_name = getattr(getattr(job, 'company', None), 'name', None) or getattr(job, 'company_name', 'Company')
            company_counter[company_name] += 1
            recruiter_name = getattr(getattr(job, 'recruiter', None), 'full_name', None) or getattr(getattr(job, 'recruiter', None), 'email', None) or 'Recruiter'
            recruiter_counter[str(recruiter_name)] += 1
            industry_counter[str(getattr(getattr(job, 'company', None), 'industry', 'Technology'))] += 1
            location_counter[f"{getattr(job, 'location_city', 'Remote')}, {getattr(job, 'location_country', 'Global')}"] += 1
            salary_bands.append((Decimal(getattr(job, 'salary_min', 0) or 0), Decimal(getattr(job, 'salary_max', 0) or 0)))
        best_salary_range = self._salary_band(salary_bands)
        return {
            'best_matching_jobs': [
                {
                    'job_title': getattr(item['job'], 'title', getattr(item['job'], 'role_title', 'Role')),
                    'company': getattr(getattr(item['job'], 'company', None), 'name', getattr(item['job'], 'company_name', 'Company')),
                    'match_pct': item['match_pct'],
                    'reasoning': item['reasoning'],
                }
                for item in top_jobs
            ],
            'best_companies': [name for name, _ in company_counter.most_common(5)],
            'best_recruiters': [name for name, _ in recruiter_counter.most_common(5)],
            'best_industries': [name for name, _ in industry_counter.most_common(4)],
            'best_locations': [name for name, _ in location_counter.most_common(4)],
            'best_salary_range': best_salary_range,
            'job_match_score': round(mean([item['match_pct'] for item in top_jobs])) if top_jobs else 0,
        }

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])

    def _normalized_set(self, value: Any) -> set[str]:
        if isinstance(value, dict):
            value = list(value.keys())
        if isinstance(value, str):
            value = [value]
        if not isinstance(value, (list, tuple, set)):
            return set()
        return {str(item).strip().lower() for item in value if str(item).strip()}

    def _expected_salary(self, student: Student) -> Decimal:
        salary = getattr(student, 'expected_salary', None)
        if salary is None:
            salary_min = Decimal(getattr(student, 'expected_salary_min', 0) or 0)
            salary_max = Decimal(getattr(student, 'expected_salary_max', salary_min) or salary_min)
            if salary_min or salary_max:
                return (salary_min + salary_max) / Decimal('2')
            return Decimal('0')
        if isinstance(salary, Decimal):
            return salary
        return Decimal(str(salary))

    def _salary_fit(self, expected_salary: Decimal, salary_min: Decimal, salary_max: Decimal) -> float:
        if expected_salary <= 0 or (salary_min <= 0 and salary_max <= 0):
            return 0.65
        if salary_min <= expected_salary <= salary_max:
            return 1.0
        diff = min(abs(expected_salary - salary_min), abs(expected_salary - salary_max))
        baseline = max(expected_salary, Decimal('1'))
        return max(0.2, 1.0 - float(diff / baseline))

    def _job_reasoning(self, required_match: float, preferred_match: float, location_score: float, work_score: float, salary_fit: float) -> str:
        reasons: list[str] = []
        if required_match >= 0.6:
            reasons.append('strong overlap with required skills')
        elif required_match >= 0.35:
            reasons.append('partial alignment with required skills')
        if preferred_match >= 0.4:
            reasons.append('good overlap with preferred skills')
        if location_score >= 0.8:
            reasons.append('matches preferred location')
        if work_score >= 0.8:
            reasons.append('fits preferred work mode')
        if salary_fit >= 0.85:
            reasons.append('salary is aligned with expectation')
        return ', '.join(reasons[:4]) or 'general alignment across skills and preferences'

    def _salary_band(self, salary_bands: list[tuple[Decimal, Decimal]]) -> dict[str, Any]:
        if not salary_bands:
            return {'min': Decimal('0.00'), 'max': Decimal('0.00')}
        mins = [band[0] for band in salary_bands if band[0] > 0]
        maxs = [band[1] for band in salary_bands if band[1] > 0]
        if not mins or not maxs:
            return {'min': Decimal('0.00'), 'max': Decimal('0.00')}
        return {'min': min(mins), 'max': max(maxs)}


class DefaultInterviewAnalysisEngine:
    def analyze(self, student: Student, ctx: StudentCareerContext) -> dict[str, Any]:
        interviews = ctx.interviews
        completed = [item for item in interviews if str(getattr(item, 'status', '')).lower() == 'completed']
        feedback_scores: list[int] = []
        communication_scores: list[int] = []
        leadership_scores: list[int] = []
        problem_scores: list[int] = []
        coding_scores: list[int] = []
        system_scores: list[int] = []
        for interview in interviews:
            feedback = getattr(interview, 'feedback_metadata', None) or {}
            ai_analysis = getattr(interview, 'ai_analysis_metadata', None) or {}
            feedback_scores.append(int(feedback.get('technical_score', ai_analysis.get('interview_readiness', 0) or 0) or 0))
            communication_scores.append(int(feedback.get('communication_score', ai_analysis.get('confidence_prediction', 0) or 0) or 0))
            leadership_scores.append(int(feedback.get('leadership', 0) or 0))
            problem_scores.append(int(feedback.get('problem_solving', 0) or 0))
            coding_scores.append(int(feedback.get('coding_score', 0) or 0))
            system_scores.append(int(feedback.get('system_design_score', 0) or 0))
        technical_readiness = self._score_or_default(feedback_scores, 38 + len(completed) * 8)
        behavioral_readiness = self._score_or_default(communication_scores, 44 + len(interviews) * 4)
        system_design_readiness = self._score_or_default(system_scores, 28 + len([i for i in interviews if 'system' in str(getattr(i, 'interview_type', '')).lower()]) * 10)
        confidence = round((behavioral_readiness * 0.45) + (technical_readiness * 0.25) + (len(completed) * 4))
        return {
            'technical_readiness': min(100, technical_readiness),
            'behavioral_readiness': min(100, behavioral_readiness),
            'system_design_readiness': min(100, system_design_readiness),
            'communication': min(100, self._score_or_default(communication_scores, 52)),
            'confidence': min(100, confidence),
            'leadership': min(100, self._score_or_default(leadership_scores, 36 + len(interviews) * 3)),
            'problem_solving': min(100, self._score_or_default(problem_scores, 42 + len(completed) * 5)),
            'coding_readiness': min(100, self._score_or_default(coding_scores, 34 + len([i for i in interviews if 'coding' in str(getattr(i, 'interview_type', '')).lower()]) * 10)),
        }

    def _score_or_default(self, values: list[int], default: int) -> int:
        cleaned = [value for value in values if value > 0]
        return round(mean(cleaned)) if cleaned else max(0, min(100, default))


class DefaultCareerAnalysisEngine:
    def __init__(
        self,
        resume_engine: ResumeAnalysisEngine,
        skill_gap_engine: SkillGapEngine,
        learning_engine: LearningRecommendationEngine,
        job_match_engine: JobMatchingEngine,
        interview_engine: InterviewAnalysisEngine,
    ) -> None:
        self.resume_engine = resume_engine
        self.skill_gap_engine = skill_gap_engine
        self.learning_engine = learning_engine
        self.job_match_engine = job_match_engine
        self.interview_engine = interview_engine

    def build_report(self, student: Student, ctx: StudentCareerContext, peer_ctx: PeerContext) -> CareerReport:
        resume = self.resume_engine.analyze(student, ctx)
        skill_gap = self.skill_gap_engine.analyze(student, ctx)
        learning = self.learning_engine.recommend(student, ctx, skill_gap)
        job_match = self.job_match_engine.match(student, ctx)
        interview = self.interview_engine.analyze(student, ctx)

        profile_completion = self._profile_completion(student)
        networking_score = self._networking_score(student, ctx)
        learning_progress = self._learning_progress(student, ctx, learning)
        project_strength = self._project_strength(student)
        experience_strength = self._experience_strength(student)
        certification_strength = self._certification_strength(student)
        portfolio_quality = self._portfolio_quality(student)
        github_activity = self._github_activity(student)
        communication_score = self._communication_score(student, ctx, interview)
        leadership_score = self._leadership_score(student, ctx, interview)
        problem_solving_score = self._problem_solving_score(student, ctx, interview)
        ats_score = self._ats_score(resume, student, job_match)
        interview_readiness = round(mean([
            interview['technical_readiness'],
            interview['behavioral_readiness'],
            interview['coding_readiness'],
            interview['communication'],
        ]))
        offer_probability = self._offer_probability(ctx, job_match, interview, resume)
        interview_probability = self._interview_probability(ctx, job_match, resume)
        placement_probability = self._placement_probability(offer_probability, interview_probability, profile_completion)
        expected_salary = self._expected_salary(student, job_match)
        expected_joining_time = self._expected_joining_time(ctx)
        promotion_readiness = self._promotion_readiness(experience_strength, leadership_score, communication_score)
        overall_employability = round(mean([
            ats_score,
            interview_readiness,
            job_match['job_match_score'],
            networking_score,
            project_strength,
            experience_strength,
            communication_score,
        ]))
        career_score = round(
            (resume['resume_score'] * 0.14)
            + (ats_score * 0.10)
            + (interview_readiness * 0.12)
            + (job_match['job_match_score'] * 0.16)
            + (profile_completion * 0.10)
            + (networking_score * 0.07)
            + (learning_progress * 0.07)
            + (project_strength * 0.06)
            + (experience_strength * 0.06)
            + (certification_strength * 0.04)
            + (portfolio_quality * 0.03)
            + (github_activity * 0.02)
            + (communication_score * 0.02)
            + (leadership_score * 0.01)
        )
        career_score = max(0, min(100, career_score))

        market_insights = self._market_insights(ctx, student, expected_salary)
        roadmap = self._career_roadmap(skill_gap)
        predictions = {
            'offer_probability': offer_probability,
            'interview_probability': interview_probability,
            'placement_probability': placement_probability,
            'expected_salary': expected_salary,
            'expected_joining_time_days': expected_joining_time,
            'promotion_readiness': promotion_readiness,
        }
        explanations = self._ai_explanations(
            resume=resume,
            skill_gap=skill_gap,
            learning=learning,
            job_match=job_match,
            interview=interview,
            career_score=career_score,
            overall_employability=overall_employability,
        )
        history = self._history(student, career_score, resume['resume_score'], interview_readiness)
        analytics = self._analytics(student, career_score, peer_ctx, ctx)

        report = CareerReport(
            student=student,
            generated_at=datetime.utcnow(),
            career_score=career_score,
            resume_score=resume['resume_score'],
            ats_score=ats_score,
            interview_readiness=interview_readiness,
            job_match_score=job_match['job_match_score'],
            profile_completion=profile_completion,
            networking_score=networking_score,
            learning_progress=learning_progress,
            project_strength=project_strength,
            experience_strength=experience_strength,
            certification_strength=certification_strength,
            portfolio_quality=portfolio_quality,
            github_activity=github_activity,
            communication_score=communication_score,
            leadership_score=leadership_score,
            problem_solving_score=problem_solving_score,
            overall_employability=overall_employability,
        )
        report.skill_gap_metadata = skill_gap
        report.career_roadmap_metadata = roadmap
        report.job_matching_metadata = job_match
        report.resume_analysis_metadata = resume
        report.interview_analysis_metadata = interview
        report.learning_recommendations_metadata = learning
        report.market_insights_metadata = market_insights
        report.predictions_metadata = predictions
        report.ai_explanations_metadata = explanations
        report.history_metadata = history
        report.analytics_metadata = analytics
        report.engine_metadata = {
            'career_analysis_engine': self.__class__.__name__,
            'resume_analysis_engine': self.resume_engine.__class__.__name__,
            'skill_gap_engine': self.skill_gap_engine.__class__.__name__,
            'learning_recommendation_engine': self.learning_engine.__class__.__name__,
            'job_matching_engine': self.job_match_engine.__class__.__name__,
            'interview_analysis_engine': self.interview_engine.__class__.__name__,
            'replaceable_with_gemini': True,
        }
        return report

    def _profile_completion(self, student: Student) -> int:
        fields = [
            getattr(student, 'headline', None),
            getattr(student, 'bio', None),
            getattr(student, 'university', None),
            getattr(student, 'degree', None),
            getattr(student, 'department', None),
            getattr(student, 'cgpa', None),
            getattr(student, 'skills', None),
            getattr(student, 'projects', None),
            getattr(student, 'experience', None),
            getattr(student, 'certifications', None),
            getattr(student, 'languages', None),
            getattr(student, 'portfolio_url', None) or getattr(student, 'portfolio', None),
            getattr(student, 'github_url', None) or getattr(student, 'github', None),
            getattr(student, 'preferred_location', None),
            getattr(student, 'preferred_work_type', None),
            getattr(student, 'career_goal', None),
        ]
        filled = 0
        for field in fields:
            if isinstance(field, (list, tuple, set, dict)):
                filled += 1 if len(field) > 0 else 0
            else:
                filled += 1 if field not in (None, '', []) else 0
        return round(filled / len(fields) * 100)

    def _networking_score(self, student: Student, ctx: StudentCareerContext) -> int:
        total_messages = len(ctx.messages)
        recruiter_threads = sum(1 for msg in ctx.messages if 'recruiter' in self._participant_signature(msg).lower())
        mentor_threads = sum(1 for msg in ctx.messages if 'mentor' in self._participant_signature(msg).lower())
        notifications = [n for n in ctx.notifications if CATEGORY_MAP_SAFE(str(getattr(n, 'category', '') or getattr(n, 'notification_type', ''))) in {'network', 'messages', 'community'}]
        raw = 28 + min(32, recruiter_threads * 4) + min(18, mentor_threads * 5) + min(12, total_messages // 3) + min(10, len(notifications) * 2)
        return min(100, raw)

    def _learning_progress(self, student: Student, ctx: StudentCareerContext, learning: dict[str, Any]) -> int:
        certs = len(self._list_value(getattr(student, 'certifications', None)))
        learning_notifications = len([n for n in ctx.notifications if str(getattr(n, 'category', '')).lower() in {'learning', 'career_ai'}])
        recommendations = len(learning.get('recommendations', []))
        return min(100, 26 + certs * 10 + learning_notifications * 3 + recommendations * 6)

    def _project_strength(self, student: Student) -> int:
        projects = [str(item) for item in self._list_value(getattr(student, 'projects', None))]
        if not projects:
            return 0
        quantified = sum(1 for project in projects if any(ch.isdigit() for ch in project))
        tech_hits = sum(1 for project in projects if any(skill.lower() in project.lower() for skill in TECH_SKILLS))
        return min(100, 35 + len(projects) * 12 + quantified * 6 + tech_hits * 3)

    def _experience_strength(self, student: Student) -> int:
        experience = [str(item) for item in self._list_value(getattr(student, 'experience', None))]
        if not experience:
            return 0
        quantified = sum(1 for item in experience if any(ch.isdigit() for ch in item))
        intern_hits = sum(1 for item in experience if any(term in item.lower() for term in ('intern', 'engineer', 'analyst', 'assistant', 'lead')))
        return min(100, 30 + len(experience) * 16 + quantified * 6 + intern_hits * 4)

    def _certification_strength(self, student: Student) -> int:
        certifications = self._list_value(getattr(student, 'certifications', None))
        return min(100, len(certifications) * 18 + 22) if certifications else 0

    def _portfolio_quality(self, student: Student) -> int:
        portfolio = getattr(student, 'portfolio_url', None) or getattr(student, 'portfolio', None)
        website = getattr(student, 'website', None) or getattr(student, 'website_url', None)
        projects = self._list_value(getattr(student, 'projects', None))
        if not portfolio and not website:
            return 0
        return min(100, 48 + (18 if portfolio else 0) + (10 if website else 0) + min(24, len(projects) * 5))

    def _github_activity(self, student: Student) -> int:
        github = getattr(student, 'github_url', None) or getattr(student, 'github', None)
        projects = self._list_value(getattr(student, 'projects', None))
        coding_projects = sum(1 for item in projects if any(skill.lower() in str(item).lower() for skill in ('python', 'java', 'react', 'node', 'api', 'ml', 'sql')))
        if not github:
            return 0
        return min(100, 40 + coding_projects * 10)

    def _communication_score(self, student: Student, ctx: StudentCareerContext, interview: dict[str, Any]) -> int:
        bio = str(getattr(student, 'bio', '') or '')
        languages = len(self._list_value(getattr(student, 'languages', None)))
        message_count = len(ctx.messages)
        base = 36 + min(16, len(bio.split()) // 15) + min(12, languages * 4) + min(16, message_count * 2)
        return min(100, round((base * 0.45) + (interview['communication'] * 0.55)))

    def _leadership_score(self, student: Student, ctx: StudentCareerContext, interview: dict[str, Any]) -> int:
        achievements = len(self._list_value(getattr(student, 'achievements', None)))
        experience = [str(item) for item in self._list_value(getattr(student, 'experience', None))]
        lead_terms = sum(1 for item in experience if any(term in item.lower() for term in ('lead', 'captain', 'coordinator', 'president', 'head', 'mentor')))
        return min(100, round((interview['leadership'] * 0.6) + (achievements * 8) + (lead_terms * 12) + 18))

    def _problem_solving_score(self, student: Student, ctx: StudentCareerContext, interview: dict[str, Any]) -> int:
        skills = {str(skill).strip().lower() for skill in self._list_value(getattr(student, 'skills', None))}
        hard_skill_hits = len(skills & {skill.lower() for skill in ('data structures', 'algorithms', 'system design', 'sql', 'python', 'java', 'dbms', 'oop')})
        project_terms = sum(1 for item in self._list_value(getattr(student, 'projects', None)) if any(term in str(item).lower() for term in ('optimiz', 'scal', 'analyt', 'predict', 'autom', 'debug')))
        return min(100, round((interview['problem_solving'] * 0.58) + hard_skill_hits * 6 + project_terms * 5 + 18))

    def _ats_score(self, resume: dict[str, Any], student: Student, job_match: dict[str, Any]) -> int:
        skill_count = len(self._list_value(getattr(student, 'skills', None)))
        return min(100, round(
            (resume['ats_keyword_match'] * 0.48)
            + (resume['resume_completeness'] * 0.20)
            + (resume['formatting_score'] * 0.12)
            + (job_match['job_match_score'] * 0.12)
            + min(8, skill_count) * 1.0
        ))

    def _offer_probability(self, ctx: StudentCareerContext, job_match: dict[str, Any], interview: dict[str, Any], resume: dict[str, Any]) -> int:
        interviews = len(ctx.interviews)
        offers = len(ctx.offers)
        accepted = len([offer for offer in ctx.offers if str(getattr(offer, 'status', '')).lower() == 'accepted'])
        empirical = 0
        if interviews > 0:
            empirical += min(28, round((offers / interviews) * 40))
        empirical += min(10, accepted * 6)
        score = round((job_match['job_match_score'] * 0.32) + (interview['technical_readiness'] * 0.24) + (resume['resume_score'] * 0.18) + empirical + 8)
        return min(100, score)

    def _interview_probability(self, ctx: StudentCareerContext, job_match: dict[str, Any], resume: dict[str, Any]) -> int:
        applications = len(ctx.applications)
        interviews = len(ctx.interviews)
        interview_rate = (interviews / applications) if applications else 0.0
        empirical = min(24, round(interview_rate * 50))
        score = round((job_match['job_match_score'] * 0.40) + (resume['resume_score'] * 0.34) + empirical + 10)
        return min(100, score)

    def _placement_probability(self, offer_probability: int, interview_probability: int, profile_completion: int) -> int:
        return min(100, round((offer_probability * 0.46) + (interview_probability * 0.34) + (profile_completion * 0.20)))

    def _expected_salary(self, student: Student, job_match: dict[str, Any]) -> dict[str, Any]:
        preferred = job_match.get('best_salary_range', {'min': Decimal('0.00'), 'max': Decimal('0.00')})
        student_expectation = getattr(student, 'expected_salary', None)
        if student_expectation is None:
            student_expectation = (Decimal(getattr(student, 'expected_salary_min', 0) or 0) + Decimal(getattr(student, 'expected_salary_max', 0) or 0)) / Decimal('2')
        if not isinstance(student_expectation, Decimal):
            student_expectation = Decimal(str(student_expectation or 0))
        midpoint = ((preferred['min'] + preferred['max']) / Decimal('2')) if preferred['min'] or preferred['max'] else student_expectation
        return {'expected': midpoint.quantize(Decimal('1.00')), 'student_expectation': student_expectation.quantize(Decimal('1.00'))}

    def _expected_joining_time(self, ctx: StudentCareerContext) -> int:
        joining_days: list[int] = []
        for offer in ctx.offers:
            issue_date = getattr(offer, 'issue_date', None)
            joining_date = getattr(offer, 'joining_date', None)
            if isinstance(issue_date, date) and isinstance(joining_date, date):
                joining_days.append((joining_date - issue_date).days)
        return round(mean(joining_days)) if joining_days else 45

    def _promotion_readiness(self, experience_strength: int, leadership_score: int, communication_score: int) -> int:
        return min(100, round((experience_strength * 0.50) + (leadership_score * 0.25) + (communication_score * 0.25)))

    def _market_insights(self, ctx: StudentCareerContext, student: Student, expected_salary: dict[str, Any]) -> dict[str, Any]:
        company_industries = Counter(str(getattr(company, 'industry', 'Technology')) for company in ctx.companies)
        regional = Counter(f"{getattr(job, 'location_city', 'Remote')}, {getattr(job, 'location_country', 'Global')}" for job in ctx.jobs)
        salary_values = [
            Decimal(getattr(job, 'salary_min', 0) or 0)
            for job in ctx.jobs if Decimal(getattr(job, 'salary_min', 0) or 0) > 0
        ]
        salary_forecast = Decimal(str(round(mean([float(value) for value in salary_values]), 2))) if salary_values else expected_salary['expected']
        return {
            'trending_skills': list(TRENDING_SKILLS[:6]),
            'emerging_technologies': list(EMERGING_TECH[:5]),
            'salary_forecast': {
                'market_average': salary_forecast.quantize(Decimal('1.00')) if isinstance(salary_forecast, Decimal) else Decimal(str(salary_forecast)).quantize(Decimal('1.00')),
                'student_expected': expected_salary['expected'],
            },
            'hiring_trends': [
                {'industry': industry, 'openings_signal': count * 3, 'trend': 'up' if count >= 2 else 'stable'}
                for industry, count in company_industries.most_common(5)
            ],
            'industry_growth': [
                {'industry': industry, 'growth_score': min(100, 45 + count * 8)}
                for industry, count in company_industries.most_common(5)
            ],
            'regional_demand': [
                {'location': location, 'demand_score': min(100, 40 + count * 10)}
                for location, count in regional.most_common(5)
            ],
        }

    def _career_roadmap(self, skill_gap: dict[str, Any]) -> dict[str, Any]:
        roadmap_items = []
        today = date.today()
        for week_index, item in enumerate(skill_gap.get('learning_order', [])[:4], start=1):
            meta = LEARNING_CATALOG.get(item['skill'], DEFAULT_LEARNING)
            roadmap_items.append({
                'week': week_index,
                'focus': item['skill'],
                'milestone': f'Complete {meta["course"]} and finish one practice artifact.',
                'deadline': (today + timedelta(days=week_index * 7)).isoformat(),
                'progress': 0 if week_index > 1 else 20,
                'completion': False,
            })
        return {'roadmap': roadmap_items}

    def _ai_explanations(self, **kwargs: Any) -> dict[str, Any]:
        resume = kwargs['resume']
        skill_gap = kwargs['skill_gap']
        learning = kwargs['learning']
        job_match = kwargs['job_match']
        interview = kwargs['interview']
        career_score = kwargs['career_score']
        overall_employability = kwargs['overall_employability']
        recommendations = []
        for item in learning.get('recommendations', [])[:4]:
            recommendations.append({
                'recommendation': item['skill'],
                'why': item['why'],
                'supporting_evidence': {
                    'missing_skills': skill_gap.get('missing_skills', [])[:5],
                    'job_match_score': job_match.get('job_match_score', 0),
                    'resume_score': resume.get('resume_score', 0),
                },
                'confidence_pct': item['confidence_pct'],
                'expected_improvement': item['expected_improvement'],
                'estimated_timeline_days': item['estimated_timeline_days'],
            })
        return {
            'career_score_explanation': {
                'why': 'Calculated from resume quality, ATS strength, interview readiness, job match, profile completeness, networking, and practical proof of work.',
                'supporting_evidence': {
                    'career_score': career_score,
                    'overall_employability': overall_employability,
                    'job_match_score': job_match.get('job_match_score', 0),
                    'resume_score': resume.get('resume_score', 0),
                    'technical_readiness': interview.get('technical_readiness', 0),
                },
                'confidence_pct': 84,
                'expected_improvement': 8,
                'estimated_timeline_days': 30,
            },
            'recommendations': recommendations,
        }

    def _history(self, student: Student, career_score: int, resume_score: int, interview_readiness: int) -> dict[str, Any]:
        previous_reports = []
        base_career = max(20, career_score - 10)
        base_resume = max(18, resume_score - 8)
        base_interview = max(16, interview_readiness - 10)
        for month_offset in range(3, 0, -1):
            previous_reports.append({
                'period': (date.today().replace(day=1) - timedelta(days=30 * month_offset)).isoformat(),
                'career_score': max(0, base_career + month_offset * 2),
                'resume_score': max(0, base_resume + month_offset * 2),
                'interview_readiness': max(0, base_interview + month_offset * 3),
            })
        monthly_progress = [
            {'month': item['period'], 'career_growth': career_score - item['career_score'], 'resume_improvement': resume_score - item['resume_score'], 'interview_improvement': interview_readiness - item['interview_readiness']}
            for item in previous_reports
        ]
        return {
            'previous_reports': previous_reports,
            'monthly_progress': monthly_progress,
            'career_growth': career_score - previous_reports[0]['career_score'] if previous_reports else 0,
            'skill_growth': max(0, round((career_score - previous_reports[0]['career_score']) * 0.8)) if previous_reports else 0,
            'resume_improvement': resume_score - previous_reports[0]['resume_score'] if previous_reports else 0,
            'interview_improvement': interview_readiness - previous_reports[0]['interview_readiness'] if previous_reports else 0,
        }

    def _analytics(self, student: Student, career_score: int, peer_ctx: PeerContext, ctx: StudentCareerContext) -> dict[str, Any]:
        weekly_progress = self._weekly_progress(ctx)
        monthly_progress = self._monthly_progress(ctx)
        university_delta = career_score - round(peer_ctx.university_avg_career_score)
        department_delta = career_score - round(peer_ctx.department_avg_career_score)
        university_rank = max(1, peer_ctx.university_rank_base)
        department_rank = max(1, peer_ctx.department_rank_base)
        return {
            'charts_metadata': {
                'career_trend_line': [item['score'] for item in weekly_progress],
                'monthly_trend_line': [item['score'] for item in monthly_progress],
                'peer_comparison': {
                    'student': career_score,
                    'university_average': round(peer_ctx.university_avg_career_score),
                    'department_average': round(peer_ctx.department_avg_career_score),
                },
            },
            'trend_lines': {
                'weekly': weekly_progress,
                'monthly': monthly_progress,
            },
            'weekly_progress': weekly_progress,
            'monthly_progress': monthly_progress,
            'comparison_against_peers': {
                'university_delta': university_delta,
                'department_delta': department_delta,
                'percentile_estimate': self._percentile_estimate(career_score, peer_ctx),
            },
            'university_ranking': university_rank,
            'department_ranking': department_rank,
        }

    def _weekly_progress(self, ctx: StudentCareerContext) -> list[dict[str, Any]]:
        today = date.today()
        rows = []
        for offset in range(4, 0, -1):
            week_start = today - timedelta(days=offset * 7)
            interactions = sum(1 for msg in ctx.messages if getattr(msg, 'sent_at', datetime.utcnow()).date() >= week_start)
            signals = len(ctx.applications) * 3 + len(ctx.interviews) * 5 + len(ctx.offers) * 7 + min(12, interactions)
            rows.append({'week_start': week_start.isoformat(), 'score': min(100, 28 + signals)})
        return rows

    def _monthly_progress(self, ctx: StudentCareerContext) -> list[dict[str, Any]]:
        today = date.today()
        rows = []
        for offset in range(3, 0, -1):
            month_anchor = today - timedelta(days=offset * 30)
            signals = len(ctx.applications) * 4 + len(ctx.interviews) * 6 + len(ctx.offers) * 8 + len(ctx.notifications)
            rows.append({'month': month_anchor.strftime('%Y-%m'), 'score': min(100, 24 + signals // 2)})
        return rows

    def _percentile_estimate(self, career_score: int, peer_ctx: PeerContext) -> int:
        delta = career_score - round(peer_ctx.university_avg_career_score)
        percentile = 50 + delta
        return max(1, min(99, percentile))

    def _participant_signature(self, message: Message) -> str:
        sender = getattr(message, 'sender', None)
        recipient = getattr(message, 'recipient', None)
        return f"{self._role(sender)}-{self._role(recipient)}"

    def _role(self, person: Any) -> str:
        if person is None:
            return 'unknown'
        role = getattr(person, 'role', None)
        value = getattr(role, 'value', None) if role is not None else None
        if value is None:
            value = getattr(person, 'user_type', None)
        return str(value or '').lower()

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])


class CareerReportGenerator:
    def __init__(
        self,
        config: AppConfig = CONFIG,
        career_engine: CareerAnalysisEngine | None = None,
        resume_engine: ResumeAnalysisEngine | None = None,
        skill_gap_engine: SkillGapEngine | None = None,
        learning_engine: LearningRecommendationEngine | None = None,
        job_match_engine: JobMatchingEngine | None = None,
        interview_engine: InterviewAnalysisEngine | None = None,
    ) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 9000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 9000)
            self.faker.seed_instance(config.generation.seed + 9000)
        self.resume_engine = resume_engine or DefaultResumeAnalysisEngine()
        self.skill_gap_engine = skill_gap_engine or DefaultSkillGapEngine()
        self.learning_engine = learning_engine or DefaultLearningRecommendationEngine()
        self.job_match_engine = job_match_engine or DefaultJobMatchingEngine()
        self.interview_engine = interview_engine or DefaultInterviewAnalysisEngine()
        self.career_engine = career_engine or DefaultCareerAnalysisEngine(
            resume_engine=self.resume_engine,
            skill_gap_engine=self.skill_gap_engine,
            learning_engine=self.learning_engine,
            job_match_engine=self.job_match_engine,
            interview_engine=self.interview_engine,
        )

    def generate(
        self,
        students: Sequence[Student],
        companies: Sequence[Company],
        recruiters: Sequence[Recruiter],
        jobs: Sequence[Job],
        applications: Sequence[Application],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
        messages: Sequence[Message],
        notifications: Sequence[Notification],
    ) -> CareerReportGenerationResult:
        if not students:
            raise ValueError('Career report generation requires students.')

        apps_by_student = defaultdict(list)
        interviews_by_student = defaultdict(list)
        offers_by_student = defaultdict(list)
        messages_by_student = defaultdict(list)
        notifications_by_student = defaultdict(list)
        jobs_by_student = defaultdict(list)
        companies_by_student = defaultdict(list)
        recruiters_by_student = defaultdict(list)

        for application in applications:
            student = getattr(application, 'student', None)
            if student is None:
                continue
            key = self._student_key(student)
            apps_by_student[key].append(application)
            job = getattr(application, 'job', None)
            company = getattr(application, 'company', None) or getattr(job, 'company', None)
            recruiter = getattr(application, 'recruiter', None) or getattr(job, 'recruiter', None)
            if job is not None:
                jobs_by_student[key].append(job)
            if company is not None:
                companies_by_student[key].append(company)
            if recruiter is not None:
                recruiters_by_student[key].append(recruiter)

        for interview in interviews:
            student = getattr(interview, 'student', None) or getattr(getattr(interview, 'application', None), 'student', None)
            if student is None:
                continue
            interviews_by_student[self._student_key(student)].append(interview)

        for offer in offers:
            student = getattr(offer, 'student', None) or getattr(getattr(offer, 'application', None), 'student', None)
            if student is None:
                continue
            offers_by_student[self._student_key(student)].append(offer)

        for message in messages:
            for actor in (getattr(message, 'sender', None), getattr(message, 'recipient', None)):
                if actor is None:
                    continue
                if 'student' in self._role(actor):
                    messages_by_student[self._student_key(actor)].append(message)

        for notification in notifications:
            user = getattr(notification, 'user', None)
            if user is None:
                continue
            if 'student' in self._role(user):
                notifications_by_student[self._student_key(user)].append(notification)

        reports: list[CareerReport] = []
        preliminary_scores: dict[str, float] = {}
        contexts: dict[str, StudentCareerContext] = {}

        for student in students:
            key = self._student_key(student)
            student_jobs = jobs_by_student[key] or list(jobs[:20])
            student_companies = companies_by_student[key] or list(companies[:10])
            student_recruiters = recruiters_by_student[key] or list(recruiters[:10])
            contexts[key] = StudentCareerContext(
                student=student,
                applications=apps_by_student[key],
                interviews=interviews_by_student[key],
                offers=offers_by_student[key],
                messages=messages_by_student[key],
                notifications=notifications_by_student[key],
                companies=student_companies,
                recruiters=student_recruiters,
                jobs=student_jobs,
            )
            resume = self.resume_engine.analyze(student, contexts[key])
            skill_gap = self.skill_gap_engine.analyze(student, contexts[key])
            learning = self.learning_engine.recommend(student, contexts[key], skill_gap)
            job_match = self.job_match_engine.match(student, contexts[key])
            interview_analysis = self.interview_engine.analyze(student, contexts[key])
            profile_completion = DefaultCareerAnalysisEngine(
                self.resume_engine, self.skill_gap_engine, self.learning_engine, self.job_match_engine, self.interview_engine
            )._profile_completion(student)
            preliminary_scores[key] = round((resume['resume_score'] * 0.28) + (job_match['job_match_score'] * 0.26) + (profile_completion * 0.16) + (interview_analysis['technical_readiness'] * 0.14) + (interview_analysis['communication'] * 0.08) + (min(100, len(apps_by_student[key]) * 8) * 0.08))

        university_buckets: dict[str, list[float]] = defaultdict(list)
        department_buckets: dict[str, list[float]] = defaultdict(list)
        for student in students:
            key = self._student_key(student)
            university_buckets[self._university(student)].append(preliminary_scores[key])
            department_buckets[self._department(student)].append(preliminary_scores[key])

        for student in students:
            key = self._student_key(student)
            university = self._university(student)
            department = self._department(student)
            uni_scores = sorted(university_buckets[university], reverse=True)
            dept_scores = sorted(department_buckets[department], reverse=True)
            peer_ctx = PeerContext(
                university_avg_career_score=mean(university_buckets[university]) if university_buckets[university] else 0.0,
                department_avg_career_score=mean(department_buckets[department]) if department_buckets[department] else 0.0,
                university_rank_base=1 + sum(1 for score in uni_scores if score > preliminary_scores[key]),
                department_rank_base=1 + sum(1 for score in dept_scores if score > preliminary_scores[key]),
                total_students=len(students),
            )
            report = self.career_engine.build_report(student, contexts[key], peer_ctx)
            reports.append(report)

        return CareerReportGenerationResult(reports=reports)

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))

    def _role(self, person: Any) -> str:
        role = getattr(person, 'role', None)
        value = getattr(role, 'value', None) if role is not None else None
        if value is None:
            value = getattr(person, 'user_type', None)
        return str(value or '').lower()

    def _university(self, student: Student) -> str:
        university = getattr(student, 'university', None)
        if hasattr(university, 'name'):
            return str(getattr(university, 'name'))
        return str(university or 'Unknown University')

    def _department(self, student: Student) -> str:
        return str(getattr(student, 'department', None) or 'General')


def CATEGORY_MAP_SAFE(value: str) -> str:
    normalized = value.lower().strip()
    if normalized in {'network', 'messages', 'community'}:
        return normalized
    mapping = {
        'recruiter message': 'messages',
        'mentor message': 'messages',
        'connection request': 'network',
        'connection accepted': 'network',
        'community invitation': 'community',
        'community update': 'community',
    }
    return mapping.get(normalized, normalized)


def generate_career_reports(
    students: Sequence[Student],
    companies: Sequence[Company],
    recruiters: Sequence[Recruiter],
    jobs: Sequence[Job],
    applications: Sequence[Application],
    interviews: Sequence[Interview],
    offers: Sequence[Offer],
    messages: Sequence[Message],
    notifications: Sequence[Notification],
    config: AppConfig = CONFIG,
) -> CareerReportGenerationResult:
    generator = CareerReportGenerator(config=config)
    return generator.generate(
        students=students,
        companies=companies,
        recruiters=recruiters,
        jobs=jobs,
        applications=applications,
        interviews=interviews,
        offers=offers,
        messages=messages,
        notifications=notifications,
    )


