@dataclass(slots=True)
class CompanyGenerationResult:
    companies: list[Company]


class CompanyGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 1000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 1000)
            self.faker.seed_instance(config.generation.seed + 1000)
        self._used_names: set[str] = set()
        self._used_slugs: set[str] = set()

    def generate(self) -> CompanyGenerationResult:
        companies: list[Company] = []
        target = self.config.counts.companies
        references = list(PUBLIC_COMPANY_REFERENCES)

        for ref in references[:target]:
            company = self._build_reference_company(ref)
            companies.append(company)

        while len(companies) < target:
            company = self._build_synthetic_company(len(companies))
            companies.append(company)

        return CompanyGenerationResult(companies=companies)

    def _build_reference_company(self, reference: dict[str, object]) -> Company:
        name = str(reference['name'])
        slug = self._unique_slug(name)
        self._used_names.add(name.lower())
        industry = str(reference['industry'])
        size_label = str(reference['company_size'])
        employee_count = self._employee_count(reference['employee_count_range'])
        work_mode = self._derive_work_mode(industry, size_label)
        description = self._expand_description(reference, industry)
        offices = self._generate_offices(str(reference['headquarters_country']), str(reference['headquarters_city']), size_label)
        profile = self._industry_profile(industry)
        benefits = self._generate_benefits(size_label, work_mode)
        hiring_categories = self._generate_hiring_categories(industry, size_label)
        tech_stack = self._generate_tech_stack(industry)
        metadata = self._metadata_payload(reference, industry, size_label, employee_count, offices, profile, tech_stack, hiring_categories, benefits)
        company = Company(
            name=name,
            slug=slug,
            description=description,
            industry=industry,
            website_url=str(reference['website']),
            headquarters_city=str(reference['headquarters_city']),
            headquarters_country=str(reference['headquarters_country']),
            work_model=work_mode,
            company_size=size_label,
            benefits=benefits,
            hiring_categories=hiring_categories,
            tech_stack=metadata['tech_stack'],
            career_page_url=str(reference.get('career_page') or reference['website']),
        )
        company.legal_name = metadata['legal_name']
        company.logo_placeholder_url = metadata['logo_placeholder_url']
        company.founded_year = metadata['founded_year']
        company.employee_count = metadata['employee_count']
        company.is_public_company = metadata['is_public_company']
        company.metadata_json = metadata
        return company

    def _build_synthetic_company(self, index: int) -> Company:
        name = self._generate_unique_synthetic_name(index)
        industry = self.random.choice(tuple(INDUSTRY_PROFILE_TEMPLATES.keys()))
        country = self.random.choice(self.config.generation.target_countries + ('Ireland',))
        city = self.random.choice(COUNTRY_CITY_MAP.get(country, ('Remote',)))
        founded_year = self.random.randint(2004, 2024)
        company_size = self._synthetic_company_size(founded_year)
        employee_count = self._synthetic_employee_count(company_size)
        work_mode = self._derive_work_mode(industry, company_size)
        website = self._website_for_name(name)
        career_page = f'{website}/careers'
        legal_name = self._legal_name(name)
        description = self._synthetic_description(name, industry, city)
        offices = self._generate_offices(country, city, company_size)
        tech_stack = self._generate_tech_stack(industry)
        benefits = self._generate_benefits(company_size, work_mode)
        hiring_categories = self._generate_hiring_categories(industry, company_size)
        profile = self._industry_profile(industry)
        metadata = self._metadata_payload(
            {
                'name': name,
                'legal_name': legal_name,
                'website': website,
                'headquarters_country': country,
                'headquarters_city': city,
                'description': description,
                'founded_year': founded_year,
                'is_public': company_size == 'Enterprise' and self.random.random() < 0.45,
                'specialties': tuple(profile['skills'][:4]),
            },
            industry,
            company_size,
            employee_count,
            offices,
            profile,
            tech_stack,
            hiring_categories,
            benefits,
        )
        company = Company(
            name=name,
            slug=self._unique_slug(name),
            description=description,
            industry=industry,
            website_url=website,
            headquarters_city=city,
            headquarters_country=country,
            work_model=work_mode,
            company_size=company_size,
            benefits=benefits,
            hiring_categories=hiring_categories,
            tech_stack=metadata['tech_stack'],
            career_page_url=career_page,
        )
        company.legal_name = legal_name
        company.logo_placeholder_url = metadata['logo_placeholder_url']
        company.founded_year = founded_year
        company.employee_count = employee_count
        company.is_public_company = metadata['is_public_company']
        company.metadata_json = metadata
        return company

    def _generate_unique_synthetic_name(self, index: int) -> str:
        while True:
            prefix = self.random.choice(SYNTHETIC_COMPANY_PREFIXES)
            suffix = self.random.choice(SYNTHETIC_COMPANY_SUFFIXES)
            infix = ''
            if self.random.random() < 0.35:
                infix = self.random.choice(('One', 'Edge', 'Grid', 'Flow', 'Prime', 'Bridge', 'Core')) + ' '
            name = f'{prefix} {infix}{suffix}'.replace('  ', ' ').strip()
            if name.lower() not in self._used_names:
                self._used_names.add(name.lower())
                return name
            index += 1
            name = f'{prefix} {suffix} {index + 1}'
            if name.lower() not in self._used_names:
                self._used_names.add(name.lower())
                return name

    def _expand_description(self, reference: dict[str, object], industry: str) -> str:
        base = str(reference['description']).strip()
        profile = self._industry_profile(industry)
        specialities = ', '.join(reference.get('specialties', profile['skills'][:3]))
        sentence = f' The company invests in graduate talent across {specialities.lower()} and maintains delivery standards aligned with its sector.'
        return base + sentence

    def _synthetic_description(self, name: str, industry: str, city: str) -> str:
        profile = self._industry_profile(industry)
        specialties = profile['skills'][:4]
        return (
            f'{name} is a {industry.lower()} organization based in {city} building scalable products and operational platforms for modern businesses. '
            f'The company focuses on {", ".join(specialties[:-1])}, and {specialties[-1]} while hiring early-career talent for roles with meaningful ownership and structured mentorship.'
        )

    def _employee_count(self, count_range: object) -> int:
        low, high = count_range
        return self.random.randint(int(low), int(high))

    def _synthetic_employee_count(self, size_label: str) -> int:
        ranges = {
            'Startup': (30, 180),
            'Growth': (180, 800),
            'Mid-Market': (800, 5000),
            'Large': (5000, 25000),
            'Enterprise': (25000, 220000),
        }
        low, high = ranges[size_label]
        return self.random.randint(low, high)

    def _synthetic_company_size(self, founded_year: int) -> str:
        age = 2026 - founded_year
        if age <= 4:
            return self.random.choices(['Startup', 'Growth'], weights=[0.65, 0.35], k=1)[0]
        if age <= 8:
            return self.random.choices(['Growth', 'Mid-Market', 'Large'], weights=[0.45, 0.4, 0.15], k=1)[0]
        if age <= 16:
            return self.random.choices(['Mid-Market', 'Large', 'Enterprise'], weights=[0.45, 0.4, 0.15], k=1)[0]
        return self.random.choices(['Large', 'Enterprise', 'Mid-Market'], weights=[0.4, 0.4, 0.2], k=1)[0]

    def _derive_work_mode(self, industry: str, company_size: str) -> WorkMode:
        if industry in {'Cloud Infrastructure', 'SaaS', 'Software', 'EdTech'}:
            return self.random.choices([WorkMode.hybrid, WorkMode.remote, WorkMode.onsite], weights=[0.55, 0.3, 0.15], k=1)[0]
        if company_size == 'Enterprise':
            return self.random.choices([WorkMode.hybrid, WorkMode.onsite, WorkMode.remote], weights=[0.55, 0.3, 0.15], k=1)[0]
        return self.random.choices([WorkMode.hybrid, WorkMode.remote, WorkMode.onsite], weights=[0.5, 0.25, 0.25], k=1)[0]

    def _generate_offices(self, country: str, headquarters_city: str, company_size: str) -> list[dict[str, object]]:
        cities = [city for city in COUNTRY_CITY_MAP.get(country, (headquarters_city,)) if city != headquarters_city]
        office_count = {
            'Startup': self.random.randint(1, 2),
            'Growth': self.random.randint(2, 3),
            'Mid-Market': self.random.randint(2, 4),
            'Large': self.random.randint(3, 5),
            'Enterprise': self.random.randint(4, 7),
        }[company_size]
        selected = [headquarters_city]
        if cities:
            sample_size = min(len(cities), max(0, office_count - 1))
            selected.extend(self.random.sample(cities, k=sample_size))
        offices = []
        for idx, city in enumerate(selected):
            offices.append(
                {
                    'city': city,
                    'country': country,
                    'is_headquarters': idx == 0,
                    'office_type': 'Headquarters' if idx == 0 else self.random.choice(['Engineering Hub', 'Sales Office', 'Operations Center', 'Campus Hiring Hub']),
                }
            )
        return offices

    def _generate_benefits(self, company_size: str, work_mode: WorkMode) -> dict[str, object]:
        selected = set(BENEFIT_LIBRARY['core'])
        selected.update(self.random.sample(BENEFIT_LIBRARY['growth'], k=2))
        selected.update(self.random.sample(BENEFIT_LIBRARY['wellbeing'], k=2))
        if company_size in {'Large', 'Enterprise', 'Mid-Market'}:
            selected.update(self.random.sample(BENEFIT_LIBRARY['competitive'], k=2 if company_size == 'Mid-Market' else 3))
        if work_mode in {WorkMode.hybrid, WorkMode.remote}:
            selected.add('Remote work support')
        return {
            'insurance': 'Health insurance' in selected,
            'pto': 'Paid time off' in selected,
            'hybrid': work_mode == WorkMode.hybrid,
            'remote': work_mode == WorkMode.remote,
            'learning_budget': 'Learning budget' in selected,
            'wellness': any(item in selected for item in ('Wellness allowance', 'Mental health support')),
            'stock_options': 'Stock options' in selected,
            'relocation': 'Relocation support' in selected,
            'signing_bonus': 'Signing bonus' in selected,
            'items': sorted(selected),
        }

    def _generate_tech_stack(self, industry: str) -> dict[str, object]:
        stack_profile = INDUSTRY_STACKS.get(industry, INDUSTRY_STACKS['Software'])
        backend = list(self.random.sample(stack_profile['backend'], k=min(len(stack_profile['backend']), 3)))
        frontend = list(self.random.sample(stack_profile['frontend'], k=min(len(stack_profile['frontend']), 2)))
        data = list(self.random.sample(stack_profile['data'], k=min(len(stack_profile['data']), 3)))
        cloud = list(self.random.sample(stack_profile['cloud'], k=min(len(stack_profile['cloud']), 3)))
        frequently_hired = sorted(set((backend + frontend + data + cloud)[:8]))
        return {
            'backend': backend,
            'frontend': frontend,
            'data': data,
            'cloud': cloud,
            'devops': sorted(set(tool for tool in cloud if tool in {'Docker', 'Kubernetes', 'Terraform'})),
            'frequently_hired_skills': frequently_hired,
        }

    def _industry_profile(self, industry: str) -> dict[str, object]:
        return INDUSTRY_PROFILE_TEMPLATES.get(industry, INDUSTRY_PROFILE_TEMPLATES['Software'])

    def _generate_hiring_categories(self, industry: str, company_size: str) -> dict[str, object]:
        profile = self._industry_profile(industry)
        categories = list(profile['hiring_categories'])
        active_jobs = self._active_job_count(company_size, industry)
        internship_program = company_size != 'Startup' or self.random.random() < 0.45
        graduate_program = company_size in {'Mid-Market', 'Large', 'Enterprise'} or industry in {'Enterprise IT', 'Consulting'}
        campus_enabled = graduate_program or internship_program or industry in {'EdTech', 'Enterprise IT', 'Consulting', 'Software'}
        remote_hiring = self.random.random() < (0.72 if industry in {'SaaS', 'Software', 'Cloud Infrastructure'} else 0.48)
        visa_sponsorship = self.random.random() < (0.42 if company_size in {'Large', 'Enterprise'} else 0.14)
        return {
            'hiring_status': self.random.choice(['Active', 'Selective', 'Expanding']),
            'active_jobs': active_jobs,
            'categories': categories,
            'internship_program': internship_program,
            'graduate_program': graduate_program,
            'campus_hiring_enabled': campus_enabled,
            'remote_hiring': remote_hiring,
            'visa_sponsorship': visa_sponsorship,
        }

    def _active_job_count(self, company_size: str, industry: str) -> int:
        base = {
            'Startup': (3, 18),
            'Growth': (8, 35),
            'Mid-Market': (18, 85),
            'Large': (40, 180),
            'Enterprise': (90, 420),
        }[company_size]
        low, high = base
        multiplier = 1.15 if industry in {'Enterprise IT', 'Consulting', 'Software', 'SaaS'} else 1.0
        return max(1, int(self.random.randint(low, high) * multiplier))

    def _metadata_payload(
        self,
        reference: dict[str, object],
        industry: str,
        company_size: str,
        employee_count: int,
        offices: list[dict[str, object]],
        profile: dict[str, object],
        tech_stack: dict[str, object],
        hiring_categories: dict[str, object],
        benefits: dict[str, object],
    ) -> dict[str, object]:
        founded_year = int(reference.get('founded_year') or self.random.randint(2000, 2024))
        avg_salary = self._average_salary(industry, reference.get('headquarters_country'))
        interview_difficulty = self._difficulty(industry, company_size)
        offer_rate = self._bounded_percent(self.random.randint(9, 32) + (4 if company_size in {'Large', 'Enterprise'} else 0))
        acceptance_rate = self._bounded_percent(self.random.randint(48, 86))
        time_to_hire = self.random.randint(14, 52 if company_size in {'Startup', 'Growth'} else 68)
        intern_conversion = self._bounded_percent(self.random.randint(22, 68))
        campus_score = self._bounded_score(self.random.randint(42, 94) + (6 if hiring_categories['campus_hiring_enabled'] else -8))
        ai_hiring_score = self._bounded_score(self.random.randint(44, 92))
        skill_demand_index = self._bounded_score(self.random.randint(48, 95))
        technology_growth_index = self._bounded_score(self.random.randint(45, 94))
        recruitment_confidence = self._bounded_score(self.random.randint(46, 93))
        hiring_forecast = self.random.choice(HIRING_TRENDS)
        preferred_universities = self._preferred_universities(reference.get('headquarters_country'))
        diversity_goals = self._diversity_goals(company_size)
        branding_assets = self._branding_assets(reference['name'])
        metadata = {
            'legal_name': str(reference.get('legal_name') or self._legal_name(str(reference['name']))),
            'logo_placeholder_url': branding_assets['logo_placeholder_url'],
            'brand_color': branding_assets['brand_color'],
            'brand_banner_url': branding_assets['brand_banner_url'],
            'founded_year': founded_year,
            'employee_count': employee_count,
            'is_public_company': bool(reference.get('is_public', False)),
            'offices': offices,
            'mission': profile['mission'],
            'vision': profile['vision'],
            'core_values': list(profile['core_values']),
            'work_culture': profile['work_culture'],
            'engineering_culture': profile['engineering_culture'],
            'diversity_statement': profile['diversity'],
            'learning_philosophy': profile['learning'],
            'hiring_metrics': {
                'average_interview_difficulty': interview_difficulty,
                'offer_rate_pct': offer_rate,
                'acceptance_rate_pct': acceptance_rate,
                'average_time_to_hire_days': time_to_hire,
                'average_salary': avg_salary,
                'intern_conversion_rate_pct': intern_conversion,
                'hiring_trend': hiring_forecast,
                'campus_hiring_score': campus_score,
            },
            'ai_readiness': {
                'ai_hiring_score': ai_hiring_score,
                'skill_demand_index': skill_demand_index,
                'technology_growth_index': technology_growth_index,
                'hiring_forecast': hiring_forecast,
                'recruitment_confidence': recruitment_confidence,
            },
            'preferred_candidate_profile': profile['preferred_profile'],
            'preferred_universities': preferred_universities,
            'frequently_hired_skills': tech_stack['frequently_hired_skills'],
            'skill_demand_trend': self._skill_demand_trend(tech_stack['frequently_hired_skills']),
            'hiring_seasonality': self.random.choice(HIRING_SEASONALITY_OPTIONS),
            'internship_intake_periods': self._internship_intake_periods(),
            'graduate_hiring_calendar': self.random.choice(GRADUATE_CALENDAR_OPTIONS),
            'diversity_hiring_goals': diversity_goals,
            'remote_work_policy': self.random.choice(REMOTE_POLICY_LIBRARY),
            'work_authorization_requirements': self.random.choice(WORK_AUTHORIZATION_POLICIES),
            'candidate_evaluation_criteria': list(profile['evaluation']),
            'branding_assets': branding_assets,
            'specialties': list(reference.get('specialties', ())),
            'tech_stack': tech_stack,
            'benefits_profile': benefits,
            'hiring_profile': hiring_categories,
            'future_relationships': {
                'supports_recruiters': True,
                'supports_jobs': True,
                'supports_campus_drives': True,
                'supports_applications': True,
                'supports_interviews': True,
                'supports_offers': True,
                'supports_messages': True,
                'supports_notifications': True,
                'supports_analytics': True,
                'supports_ai_matching': True,
            },
        }
        return metadata

    def _preferred_universities(self, country: object) -> list[str]:
        country_name = str(country or 'India')
        mapping = {
            'India': ['IIT Madras', 'Anna University', 'BITS Pilani', 'VIT', 'SRM Institute of Science and Technology'],
            'United States': ['University of Illinois Urbana-Champaign', 'Georgia Tech', 'University of Michigan', 'Purdue University'],
            'United Kingdom': ['Imperial College London', 'University of Manchester', 'University of Bristol'],
            'Germany': ['Technical University of Munich', 'RWTH Aachen University'],
            'Singapore': ['National University of Singapore', 'Nanyang Technological University'],
            'Australia': ['University of Melbourne', 'UNSW Sydney'],
            'Canada': ['University of Waterloo', 'University of Toronto'],
            'United Arab Emirates': ['American University of Sharjah', 'Khalifa University'],
            'Ireland': ['Trinity College Dublin', 'University College Dublin'],
        }
        preferred = mapping.get(country_name, mapping['India'])
        k = min(len(preferred), self.random.randint(2, min(5, len(preferred))))
        return self.random.sample(preferred, k=k)

    def _branding_assets(self, name: str) -> dict[str, str]:
        slug = self._safe_slug(name)
        color = self.random.choice(['#0F6FFF', '#01696F', '#4F46E5', '#0B7285', '#C2410C', '#7C3AED', '#047857'])
        return {
            'logo_placeholder_url': f'https://logo.example.dev/{slug}.svg',
            'brand_banner_url': f'https://brand.example.dev/banners/{slug}.png',
            'brand_color': color,
        }

    def _difficulty(self, industry: str, company_size: str) -> str:
        scale = {
            'Fintech': ['Moderate', 'Moderate-High', 'High'],
            'Cloud Infrastructure': ['Moderate-High', 'High', 'High'],
            'Software': ['Moderate', 'Moderate-High', 'High'],
            'SaaS': ['Moderate', 'Moderate-High', 'High'],
            'Enterprise IT': ['Moderate', 'Moderate', 'Moderate-High'],
            'Consulting': ['Moderate', 'Moderate', 'Moderate-High'],
        }
        options = scale.get(industry, ['Moderate', 'Moderate-High', 'High'])
        if company_size == 'Startup':
            return options[1 if len(options) > 1 else 0]
        if company_size == 'Enterprise':
            return options[-1]
        return self.random.choice(options)

    def _average_salary(self, industry: str, country: object) -> dict[str, object]:
        country_name = str(country or 'India')
        currency_map = {
            'India': ('INR', 760000, 1900000),
            'United States': ('USD', 82000, 165000),
            'United Kingdom': ('GBP', 36000, 85000),
            'Canada': ('CAD', 62000, 120000),
            'Germany': ('EUR', 52000, 92000),
            'Singapore': ('SGD', 56000, 110000),
            'Australia': ('AUD', 70000, 130000),
            'United Arab Emirates': ('AED', 120000, 300000),
            'Ireland': ('EUR', 48000, 90000),
        }
        currency, low, high = currency_map.get(country_name, ('USD', 60000, 120000))
        multiplier = {
            'Fintech': 1.12,
            'Cloud Infrastructure': 1.18,
            'Software': 1.08,
            'SaaS': 1.04,
            'Media Technology': 1.06,
            'Enterprise IT': 0.96,
            'Consulting': 0.95,
            'Manufacturing': 0.9,
        }.get(industry, 1.0)
        midpoint = int(((low + high) / 2) * multiplier)
        return {'currency': currency, 'amount': midpoint}

    def _skill_demand_trend(self, skills: Sequence[str]) -> list[dict[str, object]]:
        trends = []
        for skill in skills[:6]:
            trends.append(
                {
                    'skill': skill,
                    'trend': self.random.choice(['rising', 'stable', 'high_priority']),
                    'quarterly_change_pct': self.random.randint(4, 28),
                }
            )
        return trends

    def _internship_intake_periods(self) -> list[dict[str, str]]:
        periods = [
            {'season': 'Summer', 'window': 'April-July'},
            {'season': 'Winter', 'window': 'November-January'},
        ]
        if self.random.random() < 0.35:
            periods.append({'season': 'Rolling', 'window': 'Year-round for selected teams'})
        return periods

    def _diversity_goals(self, company_size: str) -> dict[str, object]:
        return {
            'goal_statement': 'Expand candidate pipelines through broader campus outreach, structured evaluations, and inclusive hiring practices.',
            'focus_areas': ['Gender representation', 'First-generation graduates', 'Regional diversity', 'Skills-first hiring'],
            'measurement_frequency': 'Quarterly' if company_size in {'Large', 'Enterprise'} else 'Biannual',
        }

    def _website_for_name(self, name: str) -> str:
        slug = self._safe_slug(name)
        return f'https://www.{slug}.com'

    def _safe_slug(self, value: str) -> str:
        slug = re.sub(r'[^a-z0-9]+', '-', value.lower()).strip('-')
        return slug or 'company'

    def _legal_name(self, name: str) -> str:
        suffix = self.random.choice(['Technologies Private Limited', 'Labs Private Limited', 'Digital Solutions Limited', 'Systems Inc.', 'Software Pvt. Ltd.'])
        if any(token in name for token in ('Limited', 'Inc.', 'Corporation', 'SE', 'plc')):
            return name
        return f'{name} {suffix}'

    def _unique_slug(self, name: str) -> str:
        base = self._safe_slug(name)
        slug = base
        counter = 2
        while slug in self._used_slugs:
            slug = f'{base}-{counter}'
            counter += 1
        self._used_slugs.add(slug)
        return slug

    def _bounded_percent(self, value: int) -> int:
        return max(1, min(99, value))

    def _bounded_score(self, value: int) -> int:
        return max(1, min(100, value))


def generate_companies(config: AppConfig = CONFIG) -> CompanyGenerationResult:
    generator = CompanyGenerator(config=config)
    return generator.generate()


