@dataclass(slots=True)
class InterviewGenerationResult:
    interviews: list[Interview]


class InterviewGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 5000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 5000)
            self.faker.seed_instance(config.generation.seed + 5000)

    def generate(self, applications: Sequence[Application]) -> InterviewGenerationResult:
        if not applications:
            raise ValueError('Interview generation requires applications.')

        eligible = [application for application in applications if getattr(application, 'job', None) is not None and getattr(application, 'company', None) is not None and getattr(application, 'recruiter', None) is not None]
        if not eligible:
            raise ValueError('Interview generation requires applications linked to job, company, and recruiter.')

        weighted = self._weighted_applications(eligible)
        interviews: list[Interview] = []

        for index in range(self.config.counts.interviews):
            application = self.random.choices([item[0] for item in weighted], weights=[item[1] for item in weighted], k=1)[0]
            interview = self._build_interview(index, application)
            interviews.append(interview)

        return InterviewGenerationResult(interviews=interviews)

    def _weighted_applications(self, applications: Sequence[Application]) -> list[tuple[Application, float]]:
        weighted: list[tuple[Application, float]] = []
        for application in applications:
            status = str(getattr(application, 'status', '')).lower()
            weight = 1.0
            if 'interview' in status:
                weight += 6.0
            elif 'offer' in status or 'accepted' in status:
                weight += 8.0
            elif 'shortlisted' in status or 'assessment' in status:
                weight += 4.0
            elif 'viewed' in status or 'submitted' in status:
                weight += 2.0
            weighted.append((application, weight))
        return weighted

    def _build_interview(self, index: int, application: Application) -> Interview:
        job = application.job
        recruiter = application.recruiter
        company = application.company
        student = application.student
        bucket = self._job_bucket(str(getattr(job, 'title', '')))
        pipeline = self._company_pipeline(company, bucket)
        interview_type = self.random.choice(pipeline)
        interview_round = pipeline.index(interview_type) + 1
        interview_status = self._status_for_application(application)
        timezone = TIMEZONE_BY_COUNTRY.get(getattr(company, 'headquarters_country', None) or getattr(job, 'location_country', None) or '', self.config.generation.timezone)
        interview_mode = self._interview_mode(job)
        platform = self._platform(interview_mode)
        scheduled_at = self._scheduled_at(application, interview_status)
        duration = self._duration_for_type(interview_type)
        agenda = self._agenda(interview_type, job)
        meeting_link, meeting_id, passcode = self._meeting_details(platform, company, interview_type, index)
        location = self._location(interview_mode, company, job)
        room = self._room(interview_mode)
        panel = self._panel(company, recruiter, interview_type)
        questions = self._questions(bucket, interview_type)
        mock_interview = self._mock_interview(bucket, interview_type)
        feedback = self._feedback(interview_status, interview_type)
        ai_analysis = self._ai_analysis(feedback, questions)
        history = self._history(interview_status, scheduled_at)
        notifications = self._notifications(interview_status, scheduled_at, interview_type, company)
        analytics = self._analytics(interview_status, duration, interview_type)
        future_ai = self._future_ai_support(feedback)
        scheduling = self._scheduling_metadata(scheduled_at, duration, interview_status, timezone)
        notes = self._meeting_notes(interview_status, interview_type, company)
        documents = self._interview_documents(job, interview_type)
        instructions = self._instructions(interview_mode, platform, interview_type)

        interview = Interview(
            application=application,
            student=student,
            recruiter=recruiter,
            company=company,
            job=job,
            interview_type=interview_type,
            interview_round=interview_round,
            interview_mode=interview_mode,
            status=interview_status,
            timezone=timezone,
            meeting_platform=platform,
            meeting_link=meeting_link,
            meeting_id=meeting_id,
            passcode=passcode,
            scheduled_at=scheduled_at,
            duration_minutes=duration,
            location=location,
            room=room,
            instructions=instructions,
        )
        interview.interview_reference = f'INT-{self._slug(getattr(company, "name", "company"))[:6].upper()}-{index + 1:06d}'
        interview.scheduled_date = scheduled_at.date()
        interview.scheduled_time = scheduled_at.time()
        interview.scheduling_metadata = scheduling
        interview.meeting_metadata = {
            'calendar_invite': f'https://calendar.example.dev/invite/{interview.interview_reference.lower()}',
            'meeting_notes': notes,
            'agenda': agenda,
            'interview_documents': documents,
        }
        interview.panel_metadata = panel
        interview.questions_metadata = questions
        interview.mock_interview_metadata = mock_interview
        interview.feedback_metadata = feedback
        interview.ai_analysis_metadata = ai_analysis
        interview.history_metadata = history
        interview.notifications_metadata = notifications
        interview.analytics_metadata = analytics
        interview.future_ai_metadata = future_ai
        return interview

    def _company_pipeline(self, company, bucket: str) -> list[str]:
        name = str(getattr(company, 'name', '')).lower()
        if 'google' in name:
            return ['Recruiter Call', 'Coding Interview', 'Technical Interview', 'System Design', 'Behavioral Round', 'Final Round']
        if 'microsoft' in name:
            return ['Recruiter Call', 'Technical Interview', 'Coding Interview', 'Manager Round', 'Final Round']
        if 'amazon' in name:
            return ['Recruiter Call', 'Technical Interview', 'Behavioral Round', 'Manager Round', 'Final Round']
        if 'stripe' in name:
            return ['Recruiter Call', 'Technical Interview', 'System Design', 'Manager Round', 'Culture Fit', 'Final Round']
        if 'openai' in name:
            return ['Recruiter Call', 'Technical Interview', 'Machine Learning', 'System Design', 'Executive Round', 'Final Round']
        if 'netflix' in name:
            return ['Recruiter Call', 'Technical Interview', 'Manager Round', 'Culture Fit', 'Final Round']
        if 'zoho' in name:
            return ['Recruiter Call', 'Coding Interview', 'Technical Interview', 'HR Screening', 'Final Round']
        if 'infosys' in name or 'tcs' in name:
            return ['Recruiter Call', 'Aptitude Round', 'Technical Interview', 'HR Screening', 'Final Round']
        return INTERVIEW_TYPE_BANK.get(bucket, INTERVIEW_TYPE_BANK['general'])

    def _status_for_application(self, application: Application) -> str:
        app_status = str(getattr(application, 'status', '')).lower()
        if 'accepted' in app_status or 'offer' in app_status or 'completed' in app_status:
            return self.random.choices(['completed', 'rescheduled'], weights=[8, 1], k=1)[0]
        if 'scheduled' in app_status or 'interview' in app_status:
            return self.random.choices(['scheduled', 'completed', 'rescheduled', 'cancelled'], weights=[4, 3, 1, 1], k=1)[0]
        if 'rejected' in app_status or 'withdrawn' in app_status or 'expired' in app_status:
            return self.random.choices(['cancelled', 'completed', 'no_show'], weights=[5, 2, 2], k=1)[0]
        return self.random.choice(INTERVIEW_STATUSES)

    def _interview_mode(self, job) -> str:
        work_model = str(getattr(job, 'work_model', '')).lower()
        if work_model == 'remote':
            return self.random.choices(['virtual', 'hybrid'], weights=[9, 1], k=1)[0]
        if work_model == 'onsite':
            return self.random.choices(['onsite', 'hybrid', 'virtual'], weights=[6, 2, 1], k=1)[0]
        return self.random.choices(['virtual', 'hybrid', 'onsite'], weights=[5, 3, 2], k=1)[0]

    def _platform(self, interview_mode: str) -> str:
        if interview_mode == 'onsite':
            return 'In Person'
        return self.random.choice(PLATFORM_OPTIONS)

    def _scheduled_at(self, application: Application, interview_status: str) -> datetime:
        timeline = getattr(application, 'timeline_metadata', None) or {}
        baseline = timeline.get('interview_scheduled_at') or timeline.get('assessment_at') or timeline.get('shortlisted_at') or timeline.get('submitted_at') or datetime.utcnow()
        if isinstance(baseline, str):
            baseline = datetime.fromisoformat(baseline)
        if interview_status == 'completed':
            dt = baseline + timedelta(days=self.random.randint(1, 12), hours=self.random.randint(9, 16))
            return min(dt, datetime.utcnow() - timedelta(hours=self.random.randint(2, 36)))
        if interview_status == 'cancelled':
            return baseline + timedelta(days=self.random.randint(1, 10), hours=self.random.randint(9, 16))
        if interview_status == 'rescheduled':
            return datetime.utcnow() + timedelta(days=self.random.randint(2, 18), hours=self.random.randint(9, 16))
        if interview_status == 'no_show':
            return datetime.utcnow() - timedelta(days=self.random.randint(1, 10), hours=-self.random.randint(9, 16))
        return datetime.utcnow() + timedelta(days=self.random.randint(1, 20), hours=self.random.randint(9, 16))

    def _duration_for_type(self, interview_type: str) -> int:
        mapping = {
            'Recruiter Call': (20, 30),
            'HR Screening': (25, 35),
            'Behavioral Round': (40, 60),
            'Technical Interview': (45, 60),
            'Coding Interview': (60, 90),
            'System Design': (60, 90),
            'Machine Learning': (60, 90),
            'Frontend Interview': (50, 75),
            'Backend Interview': (50, 75),
            'Product Round': (45, 60),
            'Manager Round': (45, 60),
            'Director Round': (45, 60),
            'Executive Round': (45, 60),
            'Final Round': (45, 75),
            'Portfolio Review': (45, 60),
            'Design Critique': (45, 75),
        }
        low, high = mapping.get(interview_type, (30, 60))
        return self.random.randint(low, high)

    def _agenda(self, interview_type: str, job) -> list[str]:
        title = getattr(job, 'title', 'the role')
        if interview_type in {'Technical Interview', 'Coding Interview', 'System Design', 'Machine Learning', 'Frontend Interview', 'Backend Interview'}:
            return [
                f'Introductions and context setting for the {title} role.',
                'Role-specific technical discussion and problem solving.',
                'Candidate questions and next steps.',
            ]
        return [
            f'Overview of the {title} opportunity and team context.',
            'Behavioral and collaboration-focused discussion.',
            'Candidate questions and process next steps.',
        ]

    def _meeting_details(self, platform: str, company, interview_type: str, index: int) -> tuple[str, str, str]:
        if platform == 'In Person':
            return '', '', ''
        company_slug = self._slug(getattr(company, 'name', 'company'))
        token = ''.join(self.random.choices(string.ascii_lowercase + string.digits, k=10))
        meeting_id = ''.join(self.random.choices(string.digits, k=10))
        passcode = ''.join(self.random.choices(string.ascii_uppercase + string.digits, k=6))
        base = 'zoom' if platform == 'Zoom' else 'meet' if platform == 'Google Meet' else 'teams'
        link = f'https://{base}.example.dev/{company_slug}/{self._slug(interview_type)}/{token}-{index + 1}'
        return link, meeting_id, passcode

    def _location(self, interview_mode: str, company, job) -> str:
        if interview_mode == 'virtual':
            return 'Virtual'
        office = getattr(job, 'office_location', None) or f"{getattr(company, 'headquarters_city', 'Office')}, {getattr(company, 'headquarters_country', '')}".strip(', ')
        return office

    def _room(self, interview_mode: str) -> str:
        if interview_mode == 'virtual':
            return ''
        floor = self.random.randint(2, 12)
        room = self.random.randint(1, 28)
        return f'Level {floor} / Room {room:02d}'

    def _panel(self, company, recruiter, interview_type: str) -> dict[str, object]:
        country = getattr(company, 'headquarters_country', None) or 'United States'
        local_faker = Faker('en_IN' if country == 'India' else 'en_US')
        if self.config.generation.deterministic:
            local_faker.seed_instance(self.random.randint(1, 10_000_000))
        lead = getattr(recruiter, 'full_name', None) or local_faker.name()
        panel_size = 1 if interview_type in {'Recruiter Call', 'HR Screening'} else self.random.randint(2, 4)
        panel = {
            'lead_interviewer': lead,
            'co_interviewer': local_faker.name() if panel_size >= 2 else None,
            'hiring_manager': local_faker.name(),
            'observer': local_faker.name() if panel_size >= 4 else None,
            'hr_representative': local_faker.name() if interview_type in {'HR Screening', 'Final Round', 'Culture Fit'} or panel_size >= 3 else None,
            'panel_size': panel_size,
        }
        return panel

    def _questions(self, bucket: str, interview_type: str) -> list[dict[str, object]]:
        categories = QUESTION_CATEGORIES_BY_BUCKET.get(bucket, QUESTION_CATEGORIES_BY_BUCKET['general'])
        if interview_type in {'Recruiter Call', 'HR Screening', 'Behavioral Round', 'Culture Fit'}:
            categories = ['Behavioral']
        elif interview_type in {'System Design'}:
            categories = ['System Design', 'Behavioral']
        elif interview_type in {'Machine Learning'}:
            categories = ['ML', 'AI', 'Python']
        elif interview_type in {'Frontend Interview'}:
            categories = ['React', 'Behavioral']
        elif interview_type in {'Backend Interview'}:
            categories = ['Java', 'Node', 'DBMS', 'Operating Systems']
        elif interview_type in {'Coding Interview'}:
            categories = [c for c in categories if c in {'Java', 'Python', 'Node', 'SQL', 'OOP', 'DBMS'}] or ['Python', 'OOP']
        selected_categories = self.random.sample(categories, k=min(len(categories), self.random.randint(1, min(3, len(categories)))))
        questions: list[dict[str, object]] = []
        for category in selected_categories:
            pool = QUESTION_BANK[category]
            picked = self.random.sample(pool, k=min(len(pool), self.random.randint(1, 2)))
            for item in picked:
                questions.append(
                    {
                        'category': category,
                        'question': item['question'],
                        'difficulty': item['difficulty'],
                        'expected_answer': item['expected_answer'],
                        'evaluation_criteria': item['evaluation'],
                        'weightage': item['weightage'],
                    }
                )
        return questions

    def _mock_interview(self, bucket: str, interview_type: str) -> dict[str, object]:
        categories = QUESTION_CATEGORIES_BY_BUCKET.get(bucket, QUESTION_CATEGORIES_BY_BUCKET['general'])
        mock_category = self.random.choice(categories)
        mock_question = self.random.choice(QUESTION_BANK[mock_category])
        return {
            'mock_questions': [mock_question['question']],
            'practice_sessions': self.random.randint(2, 8),
            'difficulty_levels': list({item['difficulty'] for item in QUESTION_BANK[mock_category]}),
            'voice_placeholder': 'voice-analysis-pending',
            'video_placeholder': 'video-analysis-pending',
            'coding_challenges': ['Timed implementation exercise', 'Debugging challenge'] if interview_type in {'Coding Interview', 'Technical Interview', 'Backend Interview', 'Frontend Interview'} else [],
            'time_limits_minutes': self.random.randint(20, 75),
            'hints': ['Structure the answer clearly.', 'Use concrete examples.', 'Explain trade-offs when relevant.'],
            'evaluation_metrics': ['Clarity', 'Accuracy', 'Reasoning', 'Confidence'],
        }

    def _feedback(self, interview_status: str, interview_type: str) -> dict[str, object]:
        completed = interview_status in {'completed', 'no_show'}
        technical = self._score(52, 94) if completed and interview_type not in {'Recruiter Call', 'HR Screening', 'Behavioral Round', 'Culture Fit'} else None
        coding = self._score(48, 95) if completed and interview_type in {'Coding Interview', 'Technical Interview', 'Backend Interview', 'Frontend Interview', 'Machine Learning'} else None
        system_design = self._score(45, 94) if completed and interview_type in {'System Design', 'Machine Learning', 'Backend Interview', 'Cloud Interview'} else None
        communication = self._score(55, 96) if completed else None
        problem_solving = self._score(50, 95) if completed else None
        leadership = self._score(45, 92) if completed else None
        confidence = self._score(50, 96) if completed else None
        culture_fit = self._score(55, 97) if completed else None
        available_scores = [score for score in [technical, coding, system_design, communication, problem_solving, leadership, confidence, culture_fit] if score is not None]
        overall = int(round(sum(available_scores) / len(available_scores))) if available_scores else None
        recommendation = 'Pending' if not completed else self.random.choices(['Strong Hire', 'Hire', 'Leaning Hire', 'Leaning No Hire', 'No Hire'], weights=[2, 4, 3, 2, 1], k=1)[0]
        if interview_status == 'no_show':
            recommendation = 'No Hire'
        return {
            'technical_score': technical,
            'communication_score': communication,
            'problem_solving': problem_solving,
            'leadership': leadership,
            'confidence': confidence,
            'culture_fit': culture_fit,
            'coding_score': coding,
            'system_design_score': system_design,
            'overall_recommendation': recommendation,
            'strengths': self.random.sample([
                'Communicates clearly under pressure.',
                'Demonstrates good role-specific fundamentals.',
                'Explains trade-offs with reasonable structure.',
                'Shows strong ownership and practical thinking.',
            ], k=2) if completed else [],
            'weaknesses': self.random.sample([
                'Needs more depth in edge-case handling.',
                'Can improve clarity when structuring answers.',
                'Should quantify project outcomes more strongly.',
                'Requires better prioritization in ambiguous scenarios.',
            ], k=2) if completed else [],
            'detailed_feedback': 'Candidate showed promising fundamentals and professional communication.' if completed else 'Feedback will be available after the interview is completed.',
        }

    def _ai_analysis(self, feedback: dict[str, object], questions: list[dict[str, object]]) -> dict[str, object]:
        overall = feedback.get('technical_score') or feedback.get('communication_score') or 62
        return {
            'interview_readiness': self._score(55, 96),
            'confidence_prediction': self._score(50, 94),
            'hiring_probability': self._score(35, 92),
            'improvement_suggestions': [
                'Use a clearer structure before diving into details.',
                'Back responses with specific examples and measurable outcomes.',
                'Practice explaining trade-offs more explicitly.',
            ],
            'recommended_practice': [question['category'] for question in questions[:3]],
            'skill_gap': ['Communication structure', 'Scenario-based reasoning'],
            'learning_resources': ['Behavioral response framework guide', 'Mock interview drills', 'Role-specific practice sets'],
            'next_interview_focus': 'Improve answer structure, confidence, and evidence-backed problem solving.',
        }

    def _history(self, interview_status: str, scheduled_at: datetime) -> list[dict[str, object]]:
        history = [
            {'event': 'Interview Created', 'timestamp': (scheduled_at - timedelta(days=4, hours=2)).isoformat()},
            {'event': 'Reminder Sent', 'timestamp': (scheduled_at - timedelta(hours=24)).isoformat()},
        ]
        if interview_status in {'completed', 'no_show'}:
            history.extend([
                {'event': 'Candidate Joined', 'timestamp': (scheduled_at + timedelta(minutes=1)).isoformat() if interview_status == 'completed' else scheduled_at.isoformat()},
                {'event': 'Interview Started', 'timestamp': (scheduled_at + timedelta(minutes=2)).isoformat() if interview_status == 'completed' else scheduled_at.isoformat()},
                {'event': 'Interview Ended', 'timestamp': (scheduled_at + timedelta(minutes=self.random.randint(28, 85))).isoformat() if interview_status == 'completed' else scheduled_at.isoformat()},
                {'event': 'Feedback Submitted', 'timestamp': (scheduled_at + timedelta(hours=4)).isoformat()},
                {'event': 'Decision Made', 'timestamp': (scheduled_at + timedelta(days=2)).isoformat()},
            ])
        if interview_status == 'completed' and self.random.random() < 0.28:
            history.append({'event': 'Offer Created', 'timestamp': (scheduled_at + timedelta(days=4)).isoformat()})
        if interview_status == 'rescheduled':
            history.append({'event': 'Interview Rescheduled', 'timestamp': (scheduled_at - timedelta(days=1)).isoformat()})
        if interview_status == 'cancelled':
            history.append({'event': 'Interview Cancelled', 'timestamp': (scheduled_at - timedelta(hours=10)).isoformat()})
        return history

    def _notifications(self, interview_status: str, scheduled_at: datetime, interview_type: str, company) -> list[dict[str, object]]:
        company_name = getattr(company, 'name', 'the company')
        notifications = [
            {'type': 'Interview Scheduled', 'timestamp': (scheduled_at - timedelta(days=3)).isoformat(), 'message': f'Your {interview_type} with {company_name} has been scheduled.'},
            {'type': 'Reminder', 'timestamp': (scheduled_at - timedelta(hours=24)).isoformat(), 'message': f'Reminder: your {interview_type} is scheduled soon.'},
        ]
        if interview_status == 'rescheduled':
            notifications.append({'type': 'Rescheduled', 'timestamp': (scheduled_at - timedelta(days=1)).isoformat(), 'message': 'Your interview schedule has been updated.'})
        if interview_status == 'cancelled':
            notifications.append({'type': 'Cancelled', 'timestamp': (scheduled_at - timedelta(hours=10)).isoformat(), 'message': 'This interview has been cancelled. Watch for next steps.'})
        if interview_status == 'completed':
            notifications.append({'type': 'Feedback Available', 'timestamp': (scheduled_at + timedelta(hours=6)).isoformat(), 'message': 'Interview feedback is now available.'})
            notifications.append({'type': 'Decision Available', 'timestamp': (scheduled_at + timedelta(days=2)).isoformat(), 'message': 'A hiring decision update is available.'})
        return notifications

    def _analytics(self, interview_status: str, duration: int, interview_type: str) -> dict[str, object]:
        pass_rate = self.random.randint(32, 78)
        hr_bias = 10 if interview_type in {'Recruiter Call', 'HR Screening', 'Behavioral Round', 'Culture Fit'} else 0
        technical_bias = 10 if interview_type in {'Technical Interview', 'Coding Interview', 'System Design', 'Machine Learning', 'Backend Interview', 'Frontend Interview'} else 0
        return {
            'average_interview_duration': duration,
            'pass_rate': pass_rate,
            'fail_rate': 100 - pass_rate,
            'reschedule_rate': self.random.randint(4, 18),
            'no_show_rate': self.random.randint(1, 10),
            'technical_pass_pct': self._score(38 + technical_bias, 86),
            'hr_pass_pct': self._score(45 + hr_bias, 90),
            'offer_conversion_pct': self._score(18, 52),
            'status_distribution_anchor': interview_status,
        }

    def _future_ai_support(self, feedback: dict[str, object]) -> dict[str, object]:
        confidence = feedback.get('confidence') or self._score(48, 90)
        return {
            'voice_analysis': 'pending-voice-analysis',
            'facial_analysis_placeholder': 'pending-facial-analysis',
            'emotion_analysis_placeholder': 'pending-emotion-analysis',
            'speech_rate_wpm': self.random.randint(118, 172),
            'eye_contact_placeholder': 'pending-eye-contact-analysis',
            'confidence_trend': [self._score(48, 90), confidence, self._score(50, 92)],
            'keyword_detection': ['ownership', 'clarity', 'trade-offs', 'impact'],
            'communication_quality': self._score(54, 94),
            'answer_relevance': self._score(55, 96),
        }

    def _scheduling_metadata(self, scheduled_at: datetime, duration: int, interview_status: str, timezone: str) -> dict[str, object]:
        available_slots = []
        base_day = scheduled_at.date()
        for delta in range(-2, 3):
            day = base_day + timedelta(days=delta)
            for hour in (10, 11, 14, 16):
                available_slots.append(f'{day.isoformat()}T{hour:02d}:00:00 {timezone}')
        confirmed_slot = scheduled_at.isoformat()
        rescheduled = interview_status == 'rescheduled'
        cancelled = interview_status == 'cancelled'
        reminders = [
            (scheduled_at - timedelta(hours=24)).isoformat(),
            (scheduled_at - timedelta(hours=2)).isoformat(),
        ]
        return {
            'available_slots': available_slots[:10],
            'confirmed_slot': confirmed_slot,
            'rescheduled_interview': rescheduled,
            'cancelled_interview': cancelled,
            'reminder_times': reminders,
            'timezone': timezone,
            'meeting_duration': duration,
            'interview_priority': self.random.choice(PRIORITY_LEVELS),
        }

    def _meeting_notes(self, interview_status: str, interview_type: str, company) -> str:
        company_name = getattr(company, 'name', 'the company')
        if interview_status == 'completed':
            return f'{interview_type} completed with discussion centered on role fit, communication, and functional depth for {company_name}.'
        if interview_status == 'cancelled':
            return f'{interview_type} was cancelled and may be rebooked depending on recruiter availability.'
        if interview_status == 'rescheduled':
            return f'{interview_type} was moved to accommodate scheduling changes for the panel and candidate.'
        return f'{interview_type} is scheduled with the hiring panel at {company_name}. Candidate should review the agenda and preparation guidance.'

    def _interview_documents(self, job, interview_type: str) -> list[str]:
        title_slug = self._slug(getattr(job, 'title', 'role'))
        docs = [f'{title_slug}-role-brief.pdf', f'{title_slug}-evaluation-rubric.pdf']
        if interview_type in {'Coding Interview', 'Technical Interview', 'System Design', 'Machine Learning', 'Frontend Interview', 'Backend Interview'}:
            docs.append(f'{title_slug}-technical-prep-guide.pdf')
        return docs

    def _instructions(self, interview_mode: str, platform: str, interview_type: str) -> str:
        if interview_mode == 'onsite':
            return f'Please arrive 15 minutes early, carry a valid ID, and check in with reception before the {interview_type.lower()}.'
        return f'Please join the {platform} link 10 minutes early, ensure a stable connection, and keep a quiet environment for the {interview_type.lower()}.'

    def _job_bucket(self, title: str) -> str:
        lowered = title.lower()
        if 'frontend' in lowered:
            return 'frontend'
        if 'backend' in lowered:
            return 'backend'
        if any(token in lowered for token in ('machine learning', 'ai', 'ml')):
            return 'ai'
        if any(token in lowered for token in ('data', 'analytics', 'bi')):
            return 'data'
        if 'product' in lowered:
            return 'product'
        if 'design' in lowered:
            return 'design'
        if any(token in lowered for token in ('cloud', 'platform', 'devops', 'infrastructure')):
            return 'cloud'
        if 'security' in lowered:
            return 'security'
        if any(token in lowered for token in ('finance', 'financial', 'risk')):
            return 'finance'
        if any(token in lowered for token in ('operations', 'support')):
            return 'operations'
        if any(token in lowered for token in ('software', 'engineer', 'developer')):
            return 'engineering'
        return 'general'

    def _slug(self, value: str) -> str:
        slug = re.sub(r'[^a-z0-9]+', '-', value.lower()).strip('-')
        return slug or 'item'

    def _score(self, low: int, high: int) -> int:
        return self.random.randint(max(0, low), min(100, high))


def generate_interviews(applications: Sequence[Application], config: AppConfig = CONFIG) -> InterviewGenerationResult:
    generator = InterviewGenerator(config=config)
    return generator.generate(applications)


