@dataclass(slots=True)
class JobGenerationResult:
    jobs: list[Job]


class JobGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 3000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 3000)
            self.faker.seed_instance(config.generation.seed + 3000)

    def generate(self, companies: Sequence[Company], recruiters: Sequence[Recruiter]) -> JobGenerationResult:
        if not companies:
            raise ValueError('Job generation requires at least one company.')
        if not recruiters:
            raise ValueError('Job generation requires at least one recruiter.')

        recruiters_by_company = self._group_recruiters_by_company(recruiters)
        eligible_companies = [company for company in companies if recruiters_by_company.get(self._company_key(company))]
        if not eligible_companies:
            raise ValueError('Job generation requires recruiters mapped to existing companies.')

        weighted_companies = self._company_weights(eligible_companies)
        jobs: list[Job] = []

        for index in range(self.config.counts.jobs):
            company = self.random.choices([item[0] for item in weighted_companies], weights=[item[1] for item in weighted_companies], k=1)[0]
            recruiter = self.random.choice(recruiters_by_company[self._company_key(company)])
            job = self._build_job(index, company, recruiter)
            jobs.append(job)

        return JobGenerationResult(jobs=jobs)

    def _group_recruiters_by_company(self, recruiters: Sequence[Recruiter]) -> dict[str, list[Recruiter]]:
        grouped: dict[str, list[Recruiter]] = {}
        for recruiter in recruiters:
            company = getattr(recruiter, 'company', None)
            if company is None:
                continue
            grouped.setdefault(self._company_key(company), []).append(recruiter)
        return grouped

    def _company_key(self, company: Company) -> str:
        value = getattr(company, 'id', None) or getattr(company, 'name', None)
        return str(value)

    def _company_weights(self, companies: Sequence[Company]) -> list[tuple[Company, float]]:
        weighted: list[tuple[Company, float]] = []
        for company in companies:
            meta = self._company_meta(company)
            employee_count = int(meta.get('employee_count', 1000) or 1000)
            active_jobs = int(meta.get('hiring_profile', {}).get('active_jobs', 8) or 8)
            hiring_score = float(meta.get('campus_hiring_score', 70) or 70)
            weight = max(1.0, (employee_count / 2000.0) + (active_jobs / 10.0) + (hiring_score / 100.0))
            weighted.append((company, weight))
        return weighted

    def _company_meta(self, company: Company) -> dict:
        metadata = getattr(company, 'metadata_json', None)
        return metadata if isinstance(metadata, dict) else {}

    def _role_template(self, company: Company) -> dict[str, object]:
        meta = self._company_meta(company)
        categories = meta.get('hiring_profile', {}).get('categories', []) or []
        ordered_functions: list[str] = []
        for category in categories:
            for key, function_name in CATEGORY_TO_FUNCTION.items():
                if key.lower() in str(category).lower() and function_name not in ordered_functions:
                    ordered_functions.append(function_name)
        if not ordered_functions:
            ordered_functions = ['Engineering', 'Data', 'AI', 'Product', 'Design', 'Operations']
        function_name = self.random.choice(ordered_functions)
        return self.random.choice(ROLE_TEMPLATES[function_name])

    def _build_job(self, index: int, company: Company, recruiter: Recruiter) -> Job:
        template = self._role_template(company)
        meta = self._company_meta(company)
        company_country = getattr(company, 'headquarters_country', None) or 'India'
        company_city = getattr(company, 'headquarters_city', None) or 'Chennai'
        company_name = getattr(company, 'name', 'CareerBridge Company')
        work_model = self._resolve_work_model(company)
        employment_type = self._employment_type(company, template)
        experience_min, experience_max = self._experience_band(employment_type, template)
        salary_min, salary_max = self._salary_range(company_country, template['category'], experience_min, employment_type)
        posting_date = self._posting_date()
        deadline = posting_date + timedelta(days=self.random.randint(7, 45))
        joining_date = deadline + timedelta(days=self.random.randint(14, 60))
        tech_stack = self._tech_stack(company, template)
        preferred_skills = self._preferred_skills(template, tech_stack)
        nice_to_have = self._nice_to_have(template, tech_stack)
        certifications = self._certifications(template)
        benefits = self._benefits(company, template)
        languages = self._languages(company_country)
        office_location = self._office_location(company, company_city, company_country)
        description = self._job_description(company, template, employment_type, work_model, office_location)
        responsibilities = self._responsibilities(template, company_name)
        requirements = self._requirements(template, experience_min, employment_type)
        preferred_qualifications = self._preferred_qualifications(template)
        team_overview = self._about_team(template, company_name)
        company_overview = self._about_company(company)
        hiring_process = self._hiring_process(template, company)
        analytics = self._analytics(company, template, salary_min, salary_max)
        ai_metadata = self._ai_metadata(template, employment_type)
        matching_metadata = self._matching_metadata(company, template)
        pipeline = self._application_pipeline(company, employment_type)
        skill_gap = self._skill_gap_support(template, tech_stack, certifications)
        career_report = self._career_report_support(template, ai_metadata)
        location_timezone = TIMEZONE_BY_COUNTRY.get(company_country, self.config.generation.timezone)
        title = self._job_title(template, employment_type)
        job_ref = self._job_reference(company_name, title, index)

        job = Job(
            company=company,
            recruiter=recruiter,
            title=title,
            description=description,
            department=str(template['department']),
            location_city=company_city,
            location_country=company_country,
            work_model=work_model,
            employment_type=employment_type,
            experience_min_years=experience_min,
            experience_max_years=experience_max,
            salary_min=salary_min,
            salary_max=salary_max,
            currency=CURRENCY_BY_COUNTRY.get(company_country, 'USD'),
            required_skills=tech_stack,
            preferred_skills=preferred_skills,
            application_deadline=deadline,
            posted_at=datetime.combine(posting_date, datetime.min.time()),
            openings_count=self._openings_count(employment_type),
            is_active=True,
        )
        job.job_reference = job_ref
        job.category = str(template['category'])
        job.minimum_education = str(template['education'])
        job.required_gpa = self._required_gpa(employment_type)
        job.benefits = benefits
        job.responsibilities = responsibilities
        job.requirements = requirements
        job.preferred_qualifications = preferred_qualifications
        job.nice_to_have_skills = nice_to_have
        job.certifications = certifications
        job.languages = languages
        job.expected_joining_date = joining_date
        job.hiring_manager_name = self._hiring_manager(company_country)
        job.office_location = office_location
        job.timezone = location_timezone
        job.about_team = team_overview
        job.about_company = company_overview
        job.hiring_process = hiring_process
        job.ai_metadata = ai_metadata
        job.matching_metadata = matching_metadata
        job.application_pipeline_metadata = pipeline
        job.skill_gap_metadata = skill_gap
        job.career_report_metadata = career_report
        job.analytics_metadata = analytics
        return job

    def _resolve_work_model(self, company: Company) -> str:
        work_model = getattr(company, 'work_model', None)
        if work_model is None:
            return self.random.choice(['onsite', 'hybrid', 'remote'])
        value = getattr(work_model, 'value', None) or getattr(work_model, 'name', None) or str(work_model)
        return str(value).lower()

    def _employment_type(self, company: Company, template: dict[str, object]) -> str:
        company_meta = self._company_meta(company)
        profile = company_meta.get('hiring_profile', {})
        internship_program = bool(profile.get('internship_program', False))
        graduate_program = bool(profile.get('graduate_program', False))
        options = ['full_time', 'full_time', 'full_time', 'contract']
        if internship_program:
            options.extend(['internship', 'internship'])
        if graduate_program:
            options.append('graduate')
        if 'Associate' in str(template['title']) or 'Analyst' in str(template['title']):
            options.append('graduate')
        return self.random.choice(options)

    def _experience_band(self, employment_type: str, template: dict[str, object]) -> tuple[int, int]:
        if employment_type == 'internship':
            return 0, 0
        if employment_type == 'graduate':
            return 0, 1
        if 'Associate' in str(template['title']) or 'Analyst' in str(template['title']):
            return 0, 2
        if 'Senior' in str(template['title']):
            return 3, 6
        return 1, 3

    def _salary_range(self, country: str, category: str, experience_min: int, employment_type: str) -> tuple[Decimal, Decimal]:
        base_map = {
            'India': {'base': 700000, 'internship': 25000, 'graduate': 650000},
            'United States': {'base': 110000, 'internship': 5500, 'graduate': 98000},
            'United Kingdom': {'base': 52000, 'internship': 2200, 'graduate': 42000},
            'Canada': {'base': 85000, 'internship': 4200, 'graduate': 72000},
            'Germany': {'base': 62000, 'internship': 2400, 'graduate': 52000},
            'Singapore': {'base': 78000, 'internship': 3200, 'graduate': 62000},
            'Australia': {'base': 95000, 'internship': 4300, 'graduate': 76000},
            'United Arab Emirates': {'base': 180000, 'internship': 4500, 'graduate': 150000},
            'Ireland': {'base': 58000, 'internship': 2300, 'graduate': 47000},
        }
        category_multiplier = 1.0
        lowered = category.lower()
        if 'ai' in lowered or 'machine learning' in lowered:
            category_multiplier = 1.22
        elif 'platform' in lowered or 'cloud' in lowered or 'security' in lowered:
            category_multiplier = 1.15
        elif 'design' in lowered or 'marketing' in lowered or 'operations' in lowered:
            category_multiplier = 0.92
        elif 'finance' in lowered:
            category_multiplier = 1.04
        country_base = base_map.get(country, base_map['United States'])
        if employment_type == 'internship':
            minimum = int(country_base['internship'] * self.random.uniform(0.9, 1.15))
            maximum = int(minimum * self.random.uniform(1.15, 1.45))
            return Decimal(minimum), Decimal(maximum)
        if employment_type == 'graduate':
            base = int(country_base['graduate'] * category_multiplier)
        else:
            base = int(country_base['base'] * category_multiplier * (1 + experience_min * 0.08))
        minimum = int(base * self.random.uniform(0.88, 0.98))
        maximum = int(base * self.random.uniform(1.08, 1.28))
        return Decimal(minimum), Decimal(maximum)

    def _posting_date(self) -> date:
        return date.today() - timedelta(days=self.random.randint(0, 30))

    def _tech_stack(self, company: Company, template: dict[str, object]) -> list[str]:
        meta = self._company_meta(company)
        stack = meta.get('tech_stack', {}).get('technologies') or meta.get('tech_stack_technologies') or []
        combined = list(dict.fromkeys(list(template['core_skills']) + list(stack) + list(template['nice_to_have'])))
        limit = min(len(combined), self.random.randint(6, min(10, len(combined))))
        return combined[:limit]

    def _preferred_skills(self, template: dict[str, object], tech_stack: list[str]) -> list[str]:
        extras = [skill for skill in list(template['core_skills']) + tech_stack if skill not in tech_stack[:4]]
        merged = list(dict.fromkeys(extras + list(template['nice_to_have'])))
        return merged[: self.random.randint(4, min(7, len(merged)))]

    def _nice_to_have(self, template: dict[str, object], tech_stack: list[str]) -> list[str]:
        pool = list(dict.fromkeys(list(template['nice_to_have']) + [skill for skill in tech_stack if skill not in template['core_skills']]))
        return pool[: self.random.randint(min(3, len(pool)), max(min(6, len(pool)), min(3, len(pool))))] if pool else []

    def _certifications(self, template: dict[str, object]) -> list[str]:
        certifications = list(template['certifications'])
        return certifications[: self.random.randint(1, len(certifications))]

    def _benefits(self, company: Company, template: dict[str, object]) -> list[str]:
        meta = self._company_meta(company)
        company_benefits = meta.get('benefits') or []
        merged = list(dict.fromkeys(list(template['benefits']) + list(company_benefits)))
        return merged[: self.random.randint(4, min(8, len(merged)))]

    def _languages(self, country: str) -> list[str]:
        languages = ['English']
        if country == 'Germany' and self.random.random() < 0.5:
            languages.append('German')
        elif country == 'India' and self.random.random() < 0.35:
            languages.append(self.random.choice(['Tamil', 'Hindi', 'Telugu', 'Kannada']))
        elif self.random.random() < 0.2:
            languages.append(self.random.choice([lang for lang in LANGUAGE_REQUIREMENTS if lang != 'English']))
        return list(dict.fromkeys(languages))

    def _office_location(self, company: Company, city: str, country: str) -> str:
        meta = self._company_meta(company)
        offices = meta.get('offices') or []
        if offices:
            office = self.random.choice(offices)
            return f"{office['city']}, {office['country']}"
        return f'{city}, {country}'

    def _job_description(self, company: Company, template: dict[str, object], employment_type: str, work_model: str, office_location: str) -> str:
        company_name = getattr(company, 'name', 'the company')
        title = str(template['title'])
        category = str(template['category'])
        team_focus = self.random.choice(template['projects'])
        type_label = {'full_time': 'full-time', 'contract': 'contract', 'internship': 'internship', 'graduate': 'graduate'}[employment_type]
        work_label = {'remote': 'remote-first', 'hybrid': 'hybrid', 'onsite': 'onsite'}.get(work_model, work_model)
        return (
            f'{company_name} is hiring a {title} to help build and improve {team_focus}. '
            f'This is a {type_label} opportunity within the {category.lower()} space, with a {work_label} working model based in {office_location}. '
            f'The role is suited for candidates who enjoy solving practical product and platform problems, collaborating across functions, and shipping reliable outcomes with strong attention to quality, performance, and user impact.'
        )

    def _responsibilities(self, template: dict[str, object], company_name: str) -> list[str]:
        title = str(template['title'])
        category = str(template['category'])
        project = self.random.choice(template['projects'])
        return [
            f'Design, build, and improve solutions that support {project} across the {category.lower()} roadmap.',
            f'Partner with product, design, analytics, and engineering stakeholders to translate business needs into clear execution plans.',
            f'Write maintainable, well-tested deliverables and contribute to code, process, or documentation quality within the team.',
            f'Identify bottlenecks, propose improvements, and help raise the overall execution standard for {title.lower()} work at {company_name}.',
            'Participate in reviews, planning sessions, and team discussions with a focus on clear communication and steady delivery.',
        ]

    def _requirements(self, template: dict[str, object], experience_min: int, employment_type: str) -> list[str]:
        degree = str(template['education'])
        skills = list(template['core_skills'])
        lines = [degree, f'{experience_min}+ years of relevant experience.' if employment_type not in {'internship', 'graduate'} else 'Strong academic or project experience demonstrating core job readiness.']
        lines.extend([
            f'Hands-on exposure to {skills[0]}, {skills[1]}, and {skills[2]} in coursework, internships, or production settings.',
            'Ability to communicate clearly, collaborate effectively, and work through ambiguous problems with structure.',
            'Comfort with ownership, feedback, and iterative improvement in a team environment.',
        ])
        return lines

    def _preferred_qualifications(self, template: dict[str, object]) -> list[str]:
        projects = list(template['projects'])
        nice = list(template['nice_to_have'])
        return [
            f'Experience contributing to {projects[0]} or closely related projects.',
            f'Working knowledge of {nice[0]} and {nice[1]} in production or advanced academic projects.',
            'Evidence of strong problem solving through internships, hackathons, open-source work, or competitive projects.',
        ]

    def _about_team(self, template: dict[str, object], company_name: str) -> str:
        project = self.random.choice(template['projects'])
        return (
            f'The team works on {project} and partners closely with product, design, business, and platform stakeholders. '
            f'You will join a collaborative environment at {company_name} that values thoughtful execution, solid engineering or functional fundamentals, and a strong bias for learning.'
        )

    def _about_company(self, company: Company) -> str:
        description = getattr(company, 'description', '') or f'{company.name} builds products and services used by customers across multiple markets.'
        return description

    def _hiring_process(self, template: dict[str, object], company: Company) -> list[dict[str, object]]:
        process = list(template['process'])
        if getattr(company, 'company_size', '').lower() == 'startup' and 'Hiring Manager' in process and self.random.random() < 0.5:
            process.remove('Hiring Manager')
        if getattr(company, 'company_size', '').lower() == 'enterprise' and 'HR Discussion' not in process and self.random.random() < 0.6:
            process.insert(-1, 'HR Discussion')
        result = []
        for idx, stage in enumerate(process, start=1):
            result.append(
                {
                    'stage_order': idx,
                    'stage_name': stage,
                    'estimated_duration_days': self.random.randint(1, 6) if stage != 'Offer' else self.random.randint(2, 5),
                    'elimination_stage': stage not in {'Offer'},
                }
            )
        return result

    def _analytics(self, company: Company, template: dict[str, object], salary_min: Decimal, salary_max: Decimal) -> dict[str, object]:
        difficulty = self.random.randint(48, 92)
        demand = self.random.randint(56, 96)
        velocity = self.random.randint(42, 90)
        competition = self.random.randint(38, 94)
        acceptance_trend = self.random.randint(52, 88)
        return {
            'popularity_score': self.random.randint(50, 97),
            'hiring_difficulty': difficulty,
            'competition_level': competition,
            'market_demand': demand,
            'hiring_velocity': velocity,
            'offer_acceptance_trend': acceptance_trend,
            'salary_benchmark': {
                'min': float(salary_min),
                'median': float((salary_min + salary_max) / 2),
                'max': float(salary_max),
            },
            'ai_demand_forecast': self.random.randint(max(55, demand - 8), min(99, demand + 6)),
        }

    def _ai_metadata(self, template: dict[str, object], employment_type: str) -> dict[str, object]:
        role_name = str(template['title']).lower()
        coding_weight = round(self.random.uniform(0.18, 0.34), 2) if any(token in role_name for token in ('engineer', 'developer', 'analyst')) else round(self.random.uniform(0.06, 0.16), 2)
        communication_weight = round(self.random.uniform(0.10, 0.18), 2)
        experience_weight = round(self.random.uniform(0.12, 0.22), 2)
        education_weight = round(self.random.uniform(0.08, 0.15), 2)
        certification_weight = round(self.random.uniform(0.04, 0.10), 2)
        portfolio_weight = round(self.random.uniform(0.05, 0.14), 2)
        resume_weight = round(self.random.uniform(0.14, 0.22), 2)
        allocated = coding_weight + communication_weight + experience_weight + education_weight + certification_weight + portfolio_weight + resume_weight
        skill_weight = round(max(0.1, 1.0 - allocated), 2)
        return {
            'ai_match_threshold': self.random.randint(60, 88) if employment_type != 'internship' else self.random.randint(54, 76),
            'ats_keywords': list(dict.fromkeys(list(template['core_skills']) + list(template['nice_to_have'])))[:10],
            'skill_importance_weights': {skill: round(self.random.uniform(0.08, 0.22), 2) for skill in list(template['core_skills'])[:6]},
            'resume_weight': resume_weight,
            'coding_weight': coding_weight,
            'communication_weight': communication_weight,
            'experience_weight': experience_weight,
            'education_weight': education_weight,
            'certification_weight': certification_weight,
            'portfolio_weight': portfolio_weight,
            'skill_weight': skill_weight,
        }

    def _matching_metadata(self, company: Company, template: dict[str, object]) -> dict[str, object]:
        meta = self._company_meta(company)
        company_universities = meta.get('preferred_universities') or []
        ideal_persona = self.random.choice([
            'Hands-on builder with strong fundamentals and structured communication.',
            'Curious problem solver who learns quickly and thrives in collaborative teams.',
            'Execution-focused candidate with strong academic grounding and practical project depth.',
            'High-agency early-career professional with clear ownership and attention to detail.',
        ])
        return {
            'ideal_candidate_persona': ideal_persona,
            'preferred_universities': company_universities[: self.random.randint(min(3, len(company_universities)), max(min(6, len(company_universities)), min(3, len(company_universities)))) ] if company_universities else [],
            'preferred_degrees': list(template['degrees'])[: self.random.randint(2, min(4, len(template['degrees'])))],
            'preferred_certifications': list(template['certifications'])[: self.random.randint(1, len(template['certifications']))],
            'preferred_projects': list(template['projects'])[: self.random.randint(2, min(3, len(template['projects'])))],
            'preferred_hackathons': self.random.sample(list(HACKATHON_PREFERENCES), k=2),
            'preferred_open_source_contributions': self.random.sample(list(OPEN_SOURCE_PREFERENCES), k=2),
            'preferred_github_activity': self.random.choice(GITHUB_ACTIVITY_LEVELS),
            'preferred_portfolio_quality': self.random.choice(PORTFOLIO_LEVELS),
        }

    def _application_pipeline(self, company: Company, employment_type: str) -> dict[str, object]:
        applicant_base = {'internship': (120, 420), 'graduate': (80, 260), 'full_time': (30, 180), 'contract': (20, 90)}
        low, high = applicant_base[employment_type]
        applicants = self.random.randint(low, high)
        views = applicants + self.random.randint(40, 280)
        saves = int(applicants * self.random.uniform(0.18, 0.46))
        shortlists = max(1, int(applicants * self.random.uniform(0.08, 0.24)))
        interviews = max(1, int(shortlists * self.random.uniform(0.45, 0.78)))
        offers = max(1, int(interviews * self.random.uniform(0.18, 0.45)))
        acceptance = self.random.randint(52, 86)
        return {
            'current_applicants': applicants,
            'views': views,
            'saves': saves,
            'shortlists': shortlists,
            'interviews_planned': interviews,
            'offers_planned': offers,
            'offer_acceptance_rate': acceptance,
            'hiring_progress': self.random.randint(18, 92),
        }

    def _skill_gap_support(self, template: dict[str, object], tech_stack: list[str], certifications: list[str]) -> dict[str, object]:
        missing_skills = tech_stack[: self.random.randint(min(3, len(tech_stack)), max(min(5, len(tech_stack)), min(3, len(tech_stack))))] if tech_stack else []
        learning = []
        for skill in missing_skills:
            learning.append({'skill': skill, 'suggestion': f'Complete guided practice and applied project work in {skill}.', 'estimated_learning_hours': self.random.randint(12, 60)})
        return {
            'missing_skills_mapping': [{'skill': skill, 'importance': self.random.choice(['High', 'Medium'])} for skill in missing_skills],
            'learning_suggestions': learning,
            'certification_suggestions': certifications,
            'practice_resources': list(template['practice_resources'])[: self.random.randint(2, len(template['practice_resources']))],
            'estimated_learning_hours': sum(item['estimated_learning_hours'] for item in learning),
        }

    def _career_report_support(self, template: dict[str, object], ai_metadata: dict[str, object]) -> dict[str, object]:
        return {
            'career_score': self.random.randint(52, 91),
            'job_match_pct': self.random.randint(ai_metadata['ai_match_threshold'] - 8, min(98, ai_metadata['ai_match_threshold'] + 8)),
            'interview_readiness': self.random.randint(48, 90),
            'resume_match': self.random.randint(50, 93),
            'ats_match': self.random.randint(54, 95),
            'growth_areas': list(template['nice_to_have'])[: self.random.randint(2, min(4, len(template['nice_to_have'])))],
            'learning_roadmap': [
                f'Strengthen applied knowledge of {template["core_skills"][0]} through practical assignments.',
                f'Build a visible project around {self.random.choice(template["projects"])}.',
                'Practice interview communication with structured examples and measurable outcomes.',
            ],
        }

    def _job_title(self, template: dict[str, object], employment_type: str) -> str:
        base = str(template['title'])
        if employment_type == 'internship' and 'Intern' not in base:
            return f'{base} Intern'
        if employment_type == 'graduate' and 'Associate' not in base and 'Analyst' not in base:
            return f'Graduate {base}'
        return base

    def _job_reference(self, company_name: str, title: str, index: int) -> str:
        company_code = re.sub(r'[^A-Z]', '', company_name.upper())[:5] or 'COMP'
        title_code = re.sub(r'[^A-Z]', '', title.upper())[:4] or 'ROLE'
        return f'{company_code}-{title_code}-{index + 1:05d}'

    def _openings_count(self, employment_type: str) -> int:
        if employment_type == 'internship':
            return self.random.randint(3, 20)
        if employment_type == 'graduate':
            return self.random.randint(2, 12)
        return self.random.randint(1, 6)

    def _required_gpa(self, employment_type: str) -> Decimal | None:
        if employment_type in {'internship', 'graduate'} or self.random.random() < 0.45:
            return Decimal(str(round(self.random.uniform(6.0, 8.5), 1)))
        return None

    def _hiring_manager(self, country: str) -> str:
        local_faker = Faker('en_IN' if country == 'India' else 'en_US')
        if self.config.generation.deterministic:
            local_faker.seed_instance(self.random.randint(1, 10_000_000))
        return local_faker.name()


def generate_jobs(companies: Sequence[Company], recruiters: Sequence[Recruiter], config: AppConfig = CONFIG) -> JobGenerationResult:
    generator = JobGenerator(config=config)
    return generator.generate(companies, recruiters)


