# from __future__ import annotations

import random
from collections import Counter, defaultdict
from dataclasses import dataclass
from datetime import date, datetime, timedelta
from decimal import Decimal
from statistics import mean
from typing import Any, Protocol, Sequence

from faker import Faker

from careerbridge_seed_engine.config import AppConfig, CONFIG
from careerbridge_seed_engine.models import (
    Application,
    CareerReport,
    Company,
    Interview,
    Job,
    JobMatch,
    LearningRoadmap,
    Offer,
    Recruiter,
    ResumeAnalysis,
    SkillGap,
    Student,
)

SOFT_SKILLS = {'communication', 'leadership', 'problem solving', 'collaboration', 'ownership', 'adaptability', 'presentation'}
INTERNSHIP_MARKERS = ('intern', 'internship', 'trainee', 'apprentice', 'graduate intern', 'student')
WORK_MODE_ALIASES = {
    'remote': {'remote', 'work from home', 'distributed'},
    'hybrid': {'hybrid'},
    'onsite': {'onsite', 'on-site', 'office', 'in-office'},
}
CATEGORY_THRESHOLDS = [
    (88, 'Apply Immediately'),
    (78, 'Highly Recommended'),
    (68, 'Good Match'),
    (58, 'Stretch Opportunity'),
    (45, 'Needs Improvement'),
    (0, 'Not Recommended'),
]
CERT_PRIORITY = {
    'docker': 'Docker Certified Associate',
    'kubernetes': 'Certified Kubernetes Application Developer',
    'aws': 'AWS Developer Associate',
    'azure': 'Azure Developer Associate',
    'google cloud': 'Google Cloud Professional Data Engineer',
    'tensorflow': 'TensorFlow Developer Certificate',
    'pytorch': 'PyTorch for Deep Learning Certification Path',
    'security': 'CompTIA Security+',
}


class JobMatchingEngine(Protocol):
    def build(self, student: Student, ctx: 'JobMatchingContext') -> JobMatch:
        ...


@dataclass(slots=True)
class JobMatchingContext:
    student: Student
    companies: list[Company]
    recruiters: list[Recruiter]
    jobs: list[Job]
    applications: list[Application]
    interviews: list[Interview]
    offers: list[Offer]
    career_report: CareerReport | None
    skill_gap: SkillGap | None
    learning_roadmap: LearningRoadmap | None
    resume_analysis: ResumeAnalysis | None


@dataclass(slots=True)
class JobMatchingGenerationResult:
    job_matches: list[JobMatch]


class DefaultJobMatchingBuilder:
    def build(self, student: Student, ctx: JobMatchingContext) -> JobMatch:
        ranked_jobs = self._rank_jobs(student, ctx)
        top_50 = ranked_jobs[:50]
        internships = [item for item in ranked_jobs if item['is_internship']][:20]
        top_companies = self._top_companies(top_50, ctx)
        top_recruiters = self._top_recruiters(top_50, ctx)
        analytics = self._analytics(top_50, ctx)
        recruiter_matching = self._recruiter_matching(top_recruiters, ctx)
        company_matching = self._company_matching(top_companies, ctx)
        application_strategy = self._application_strategy(student, top_50, ctx)
        predictions = self._career_predictions(top_50, ctx)
        explanations = self._ai_explanations(top_50, ctx)

        match = JobMatch(
            student=student,
            generated_at=datetime.utcnow(),
            top_job_matches=top_50,
            top_internship_matches=internships,
            top_companies=top_companies,
            top_recruiters=top_recruiters,
            top_industries=analytics['top_industries'],
            top_locations=analytics['top_locations'],
            top_remote_jobs=[item for item in top_50 if item['work_mode'] == 'Remote'][:20],
            top_hybrid_jobs=[item for item in top_50 if item['work_mode'] == 'Hybrid'][:20],
            top_onsite_jobs=[item for item in top_50 if item['work_mode'] == 'Onsite'][:20],
        )
        match.match_scores_metadata = {'jobs': top_50}
        match.skill_gap_impact_metadata = self._skill_gap_impact(top_50, ctx)
        match.ai_recommendations_metadata = {'jobs': [{'job_id': item['job_id'], 'category': item['recommendation_category']} for item in top_50]}
        match.recruiter_matching_metadata = recruiter_matching
        match.company_matching_metadata = company_matching
        match.application_strategy_metadata = application_strategy
        match.predictions_metadata = predictions
        match.analytics_metadata = analytics
        match.ai_explanations_metadata = explanations
        match.engine_metadata = {
            'matching_engine': self.__class__.__name__,
            'gemini_replaceable': True,
            'frontend_contract_stable': True,
        }
        return match

    def _rank_jobs(self, student: Student, ctx: JobMatchingContext) -> list[dict[str, Any]]:
        ranked = []
        skill_gap_items = self._skill_gap_items(ctx.skill_gap)
        roadmap_progress = self._learning_progress_match(ctx.learning_roadmap)
        student_skills = {item.lower() for item in self._list_value(getattr(student, 'skills', None))}
        student_projects = [str(item) for item in self._list_value(getattr(student, 'projects', None))]
        student_experience = [str(item) for item in self._list_value(getattr(student, 'experience', None))]
        certifications = [str(item) for item in self._list_value(getattr(student, 'certifications', None))]
        soft_skill_text = ' '.join(student_projects + student_experience + [str(getattr(student, 'bio', '') or '')]).lower()
        for job in ctx.jobs:
            job_company = getattr(job, 'company', None)
            company = job_company if job_company is not None else self._company_for_job(job, ctx.companies)
            recruiter = self._recruiter_for_job(job, ctx.recruiters)
            required = {item.lower() for item in self._normalized_list(getattr(job, 'skills_required', None) or [])}
            preferred = {item.lower() for item in self._normalized_list(getattr(job, 'preferred_skills', None) or [])}
            combined = required | preferred
            matched_skills = sorted(student_skills & combined)
            missing_skills = sorted(required - student_skills)
            skill_match = self._skill_match(student_skills, required, preferred)
            experience_match = self._experience_match(student_experience, job)
            education_match = self._education_match(student, job)
            certification_match = self._certification_match(certifications, combined)
            resume_match = int(getattr(ctx.resume_analysis, 'resume_quality', 0) or 0) if ctx.resume_analysis is not None else 50
            ats_match = int(getattr(ctx.resume_analysis, 'ats_score', 0) or 0) if ctx.resume_analysis is not None else 50
            culture_match = self._culture_match(student, company, soft_skill_text)
            location_match = self._location_match(student, job)
            salary_match = self._salary_match(student, job)
            career_goal_match = self._career_goal_match(student, job, company)
            learning_progress_match = min(100, round((roadmap_progress * 0.6) + ((100 - len(missing_skills) * 8) * 0.4)))
            overall = round(
                skill_match * 0.22 +
                experience_match * 0.10 +
                education_match * 0.08 +
                certification_match * 0.05 +
                resume_match * 0.10 +
                ats_match * 0.08 +
                culture_match * 0.05 +
                location_match * 0.07 +
                salary_match * 0.06 +
                career_goal_match * 0.10 +
                learning_progress_match * 0.04 +
                self._career_score(ctx) * 0.05
            )
            category = self._category(overall)
            matched_projects = self._projects_increasing_score(student_projects, required, preferred)
            helpful_certs = self._helpful_certifications(missing_skills)
            hiring_probability = min(100, round(overall * 0.68 + ats_match * 0.12 + experience_match * 0.10))
            interview_probability = min(100, round(overall * 0.62 + resume_match * 0.14 + culture_match * 0.08))
            expected_salary = self._expected_salary(job, overall)
            salary_growth = max(Decimal('0.00'), expected_salary - self._student_salary_floor(student))
            ranked.append({
                'job_id': str(getattr(job, 'id', None) or getattr(job, 'job_id', None) or id(job)),
                'job_title': str(getattr(job, 'title', getattr(job, 'role_title', 'Role'))),
                'company': str(getattr(company, 'name', None) or getattr(job, 'company_name', 'Company')),
                'company_id': str(getattr(company, 'id', None) or getattr(company, 'company_id', None) or '') if company is not None else '',
                'recruiter': str(getattr(recruiter, 'name', 'Recruiter')) if recruiter is not None else None,
                'recruiter_id': str(getattr(recruiter, 'id', None) or getattr(recruiter, 'recruiter_id', None) or '') if recruiter is not None else '',
                'industry': str(getattr(company, 'industry', None) or 'Technology'),
                'location': self._job_location(job),
                'work_mode': self._job_work_mode(job),
                'employment_type': str(getattr(job, 'employment_type', None) or 'Full-time'),
                'overall_match_pct': max(0, min(100, overall)),
                'skill_match_pct': skill_match,
                'experience_match_pct': experience_match,
                'education_match_pct': education_match,
                'certification_match_pct': certification_match,
                'resume_match_pct': resume_match,
                'ats_match_pct': ats_match,
                'culture_match_pct': culture_match,
                'location_match_pct': location_match,
                'salary_match_pct': salary_match,
                'career_goal_match_pct': career_goal_match,
                'learning_progress_match_pct': learning_progress_match,
                'matched_skills': matched_skills[:16],
                'missing_skills': missing_skills[:12],
                'helpful_certifications': helpful_certs,
                'projects_increasing_score': matched_projects,
                'expected_career_growth': self._expected_career_growth(company, job),
                'expected_salary_growth': salary_growth.quantize(Decimal('1.00')),
                'hiring_probability': hiring_probability,
                'interview_probability': interview_probability,
                'expected_salary': expected_salary.quantize(Decimal('1.00')),
                'expected_joining_time_days': self._expected_joining_time_days(job),
                'promotion_potential': self._promotion_potential(company, job),
                'recommendation_category': category,
                'why_this_match': self._why_this_match(job, company, matched_skills, missing_skills, helpful_certs, matched_projects, overall),
                'improvement_path': self._improvement_path(missing_skills, skill_gap_items),
                'confidence_level': self._confidence_level(overall, matched_skills, missing_skills),
                'is_internship': self._is_internship(job),
            })
        ranked.sort(key=lambda item: (item['overall_match_pct'], item['hiring_probability'], item['skill_match_pct']), reverse=True)
        return ranked

    def _top_companies(self, ranked_jobs: list[dict[str, Any]], ctx: JobMatchingContext) -> list[dict[str, Any]]:
        grouped: dict[str, list[dict[str, Any]]] = defaultdict(list)
        for item in ranked_jobs:
            grouped[item['company']].append(item)
        results = []
        for company_name, items in grouped.items():
            company = next((comp for comp in ctx.companies if str(getattr(comp, 'name', '')) == company_name), None)
            avg_match = round(mean([job['overall_match_pct'] for job in items]))
            culture_fit = round(mean([job['culture_match_pct'] for job in items]))
            technology_fit = round(mean([job['skill_match_pct'] for job in items]))
            growth_fit = round(mean([job['expected_career_growth']['score'] for job in items]))
            salary_fit = round(mean([job['salary_match_pct'] for job in items]))
            learning_fit = round(mean([job['learning_progress_match_pct'] for job in items]))
            results.append({
                'company': company_name,
                'company_id': str(getattr(company, 'id', None) or getattr(company, 'company_id', None) or '') if company is not None else '',
                'overall_match_pct': avg_match,
                'culture_fit': culture_fit,
                'technology_fit': technology_fit,
                'growth_fit': growth_fit,
                'salary_fit': salary_fit,
                'learning_fit': learning_fit,
            })
        results.sort(key=lambda item: item['overall_match_pct'], reverse=True)
        return results[:20]

    def _top_recruiters(self, ranked_jobs: list[dict[str, Any]], ctx: JobMatchingContext) -> list[dict[str, Any]]:
        grouped: dict[str, list[dict[str, Any]]] = defaultdict(list)
        for item in ranked_jobs:
            if item['recruiter']:
                grouped[item['recruiter']].append(item)
        results = []
        for recruiter_name, items in grouped.items():
            recruiter = next((rec for rec in ctx.recruiters if str(getattr(rec, 'name', '')) == recruiter_name), None)
            avg_match = round(mean([job['overall_match_pct'] for job in items]))
            likelihood = min(100, round(avg_match * 0.72 + len(items) * 2))
            interest = min(100, round(avg_match * 0.68 + len([job for job in items if job['recommendation_category'] in {'Apply Immediately', 'Highly Recommended'}]) * 4))
            preferred_candidate = min(100, round(avg_match * 0.60 + mean([job['ats_match_pct'] for job in items]) * 0.25))
            interview_chance = min(100, round(avg_match * 0.58 + mean([job['interview_probability'] for job in items]) * 0.25))
            results.append({
                'recruiter': recruiter_name,
                'recruiter_id': str(getattr(recruiter, 'id', None) or getattr(recruiter, 'recruiter_id', None) or '') if recruiter is not None else '',
                'likelihood_of_response': likelihood,
                'recruiter_interest_score': interest,
                'preferred_candidate_score': preferred_candidate,
                'expected_interview_chance': interview_chance,
            })
        results.sort(key=lambda item: item['recruiter_interest_score'], reverse=True)
        return results[:20]

    def _skill_gap_impact(self, ranked_jobs: list[dict[str, Any]], ctx: JobMatchingContext) -> dict[str, Any]:
        priority_skills = []
        items = self._skill_gap_items(ctx.skill_gap)
        forced = ['docker', 'aws', 'system design']
        selected = []
        for name in forced:
            found = next((item for item in items if item['skill'].lower() == name), None)
            if found is not None:
                selected.append(found)
            else:
                selected.append({'skill': name.title() if name != 'aws' else 'AWS', 'job_match_improvement': 8, 'career_score_improvement': 6})
        baseline = round(mean([item['overall_match_pct'] for item in ranked_jobs[:10]])) if ranked_jobs else 0
        current = baseline
        for item in selected:
            current = min(100, current + int(item.get('job_match_improvement', 8)))
            priority_skills.append({
                'skill': item['skill'],
                'current_match': baseline if not priority_skills else priority_skills[-1]['new_match_pct'],
                'new_match_pct': current,
            })
        return {'projected_improvements': priority_skills}

    def _recruiter_matching(self, top_recruiters: list[dict[str, Any]], ctx: JobMatchingContext) -> dict[str, Any]:
        return {'best_recruiters': top_recruiters}

    def _company_matching(self, top_companies: list[dict[str, Any]], ctx: JobMatchingContext) -> dict[str, Any]:
        return {'best_companies': top_companies}

    def _application_strategy(self, student: Student, ranked_jobs: list[dict[str, Any]], ctx: JobMatchingContext) -> dict[str, Any]:
        top_jobs = ranked_jobs[:10]
        best_time = 'Within 24 hours of job discovery' if top_jobs and top_jobs[0]['overall_match_pct'] >= 85 else 'Within 3 days after tailoring the resume'
        projects = []
        if ctx.learning_roadmap is not None:
            metadata = getattr(ctx.learning_roadmap, 'project_recommendations_metadata', None) or {}
            for item in metadata.get('projects', [])[:4]:
                projects.append(item['project_title'])
        certifications = []
        if ctx.skill_gap is not None:
            cert_meta = getattr(ctx.skill_gap, 'certification_recommendations_metadata', None) or {}
            for item in cert_meta.get('recommendations', [])[:4]:
                certifications.append(item['name'] if isinstance(item, dict) else str(item))
        return {
            'best_resume_version': self._best_resume_version(ctx),
            'best_cover_letter': self._best_cover_letter(top_jobs[0] if top_jobs else None),
            'recommended_projects': projects,
            'recommended_certifications': certifications,
            'best_time_to_apply': best_time,
            'application_priority': [
                {'job_id': item['job_id'], 'job_title': item['job_title'], 'priority': item['recommendation_category']}
                for item in top_jobs
            ],
        }

    def _career_predictions(self, ranked_jobs: list[dict[str, Any]], ctx: JobMatchingContext) -> dict[str, Any]:
        if not ranked_jobs:
            return {
                'offer_probability': 0,
                'interview_probability': 0,
                'expected_salary': Decimal('0.00'),
                'expected_joining_time_days': 0,
                'career_growth': 'Insufficient match data',
                'promotion_potential': 'Unknown',
            }
        top = ranked_jobs[:10]
        return {
            'offer_probability': min(100, round(mean([item['hiring_probability'] for item in top]) * 0.72)),
            'interview_probability': min(100, round(mean([item['interview_probability'] for item in top]) * 0.84)),
            'expected_salary': (sum((item['expected_salary'] for item in top), Decimal('0.00')) / Decimal(str(len(top)))).quantize(Decimal('1.00')),
            'expected_joining_time_days': round(mean([item['expected_joining_time_days'] for item in top])),
            'career_growth': 'Strong' if mean([item['expected_career_growth']['score'] for item in top]) >= 75 else 'Moderate',
            'promotion_potential': 'High' if mean([item['promotion_potential']['score'] for item in top]) >= 72 else 'Moderate',
        }

    def _analytics(self, ranked_jobs: list[dict[str, Any]], ctx: JobMatchingContext) -> dict[str, Any]:
        top = ranked_jobs[:50]
        industries = Counter(item['industry'] for item in top)
        roles = Counter(item['job_title'] for item in top)
        locations = Counter(item['location'] for item in top)
        technologies = Counter()
        for item in top:
            for skill in item['matched_skills'][:5] + item['missing_skills'][:3]:
                technologies[skill] += 1
        competition = round(mean([100 - item['overall_match_pct'] for item in top])) if top else 0
        return {
            'top_industries': [name for name, _ in industries.most_common(10)],
            'top_locations': [name for name, _ in locations.most_common(10)],
            'top_roles': [name for name, _ in roles.most_common(10)],
            'regional_demand': [{'location': name, 'demand_score': count * 10} for name, count in locations.most_common(10)],
            'market_competition': max(0, min(100, competition)),
            'trending_technologies': [name for name, _ in technologies.most_common(12)],
            'hiring_demand': min(100, 45 + len(top)),
        }

    def _ai_explanations(self, ranked_jobs: list[dict[str, Any]], ctx: JobMatchingContext) -> dict[str, Any]:
        items = []
        for item in ranked_jobs[:20]:
            missing_count = len(item['missing_skills'])
            estimated_improvement = min(100, missing_count * 5 + 8)
            items.append({
                'job_id': item['job_id'],
                'why_recommendation_exists': item['why_this_match']['summary'],
                'how_to_improve': item['improvement_path'],
                'estimated_improvement': estimated_improvement,
                'confidence_level': item['confidence_level'],
            })
        return {'items': items}

    def _skill_match(self, student_skills: set[str], required: set[str], preferred: set[str]) -> int:
        if not required and not preferred:
            return 50
        required_score = (len(student_skills & required) / max(1, len(required))) * 100 if required else 70
        preferred_score = (len(student_skills & preferred) / max(1, len(preferred))) * 100 if preferred else 60
        return round(required_score * 0.75 + preferred_score * 0.25)

    def _experience_match(self, experiences: list[str], job: Job) -> int:
        if not experiences:
            return 35 if self._is_internship(job) else 20
        title_text = str(getattr(job, 'title', getattr(job, 'role_title', ''))).lower()
        evidence = 0
        for item in experiences:
            lowered = item.lower()
            if any(term in lowered for term in ('intern', 'engineer', 'developer', 'analyst', 'assistant', 'research')):
                evidence += 1
            if any(term in lowered for term in title_text.split()[:3]):
                evidence += 1
            if self._contains_metric(item):
                evidence += 1
        base = 35 if self._is_internship(job) else 45
        return min(100, base + evidence * 12)

    def _education_match(self, student: Student, job: Job) -> int:
        degree = str(getattr(student, 'degree', '') or '').lower()
        department = str(getattr(student, 'department', '') or '').lower()
        description = ' '.join([
            str(getattr(job, 'description', '') or ''),
            str(getattr(job, 'requirements', '') or ''),
            str(getattr(job, 'title', getattr(job, 'role_title', '')) or ''),
        ]).lower()
        score = 45
        if degree and any(term in degree for term in ('b.tech', 'b.e', 'bsc', 'm.tech', 'msc', 'mba')):
            score += 15
        if department and department in description:
            score += 20
        cgpa = getattr(student, 'cgpa', None)
        try:
            if cgpa is not None and float(cgpa) >= 8.0:
                score += 12
            elif cgpa is not None and float(cgpa) >= 7.0:
                score += 8
        except (TypeError, ValueError):
            pass
        return min(100, score)

    def _certification_match(self, certifications: list[str], combined_skills: set[str]) -> int:
        if not certifications:
            return 30
        lower_certs = ' '.join(certifications).lower()
        hits = 0
        for skill in combined_skills:
            cert = CERT_PRIORITY.get(skill)
            if cert and cert.lower() in lower_certs:
                hits += 1
        return min(100, 35 + hits * 18 + len(certifications) * 6)

    def _culture_match(self, student: Student, company: Company | None, soft_skill_text: str) -> int:
        score = 48
        if company is not None:
            work_model = str(getattr(company, 'work_model', '') or '').lower()
            if work_model and str(getattr(student, 'preferred_work_type', '') or '').lower() in work_model:
                score += 12
            benefits = ' '.join(self._normalized_list(getattr(company, 'benefits', None) or []))
            if 'learning' in benefits.lower() or 'mentorship' in benefits.lower():
                score += 8
        soft_hits = sum(1 for skill in SOFT_SKILLS if skill in soft_skill_text)
        score += min(20, soft_hits * 4)
        return min(100, score)

    def _location_match(self, student: Student, job: Job) -> int:
        preferred_location = str(getattr(student, 'preferred_location', '') or '').lower()
        if not preferred_location:
            return 60
        job_location = self._job_location(job).lower()
        if preferred_location in job_location:
            return 100
        if self._job_work_mode(job).lower() == 'remote':
            return 88
        return 35

    def _salary_match(self, student: Student, job: Job) -> int:
        target_min, target_max = self._student_salary_range(student)
        job_min = Decimal(str(getattr(job, 'salary_min', 0) or 0))
        job_max = Decimal(str(getattr(job, 'salary_max', 0) or 0))
        if target_min == 0 and target_max == 0:
            return 60
        if job_max >= target_min and (target_max == 0 or job_min <= target_max):
            return 100
        if job_max < target_min:
            gap = float(target_min - job_max)
            return max(20, 100 - round(gap / max(1.0, float(target_min)) * 100))
        return 65

    def _career_goal_match(self, student: Student, job: Job, company: Company | None) -> int:
        goal = str(getattr(student, 'career_goal', '') or '').lower()
        title = str(getattr(job, 'title', getattr(job, 'role_title', '')) or '').lower()
        description = str(getattr(job, 'description', '') or '').lower()
        industry = str(getattr(company, 'industry', '') or '').lower() if company is not None else ''
        score = 25
        if goal and any(term in title for term in goal.split()[:3]):
            score += 35
        if goal and goal in description:
            score += 20
        preferred_industry = str(getattr(student, 'preferred_industry', '') or '').lower()
        if preferred_industry and preferred_industry in industry:
            score += 20
        return min(100, score)

    def _learning_progress_match(self, roadmap: LearningRoadmap | None) -> int:
        if roadmap is None:
            return 40
        tracking = getattr(roadmap, 'progress_tracking_metadata', None) or {}
        completion = int(tracking.get('completion_pct', 0) or 0)
        consistency = int(tracking.get('consistency_score', 0) or 0)
        velocity = float(tracking.get('learning_velocity', 0) or 0)
        return min(100, round(completion * 0.45 + consistency * 0.35 + min(20, velocity * 2)))

    def _career_score(self, ctx: JobMatchingContext) -> int:
        return int(getattr(ctx.career_report, 'career_score', 0) or 0) if ctx.career_report is not None else 50

    def _projects_increasing_score(self, projects: list[str], required: set[str], preferred: set[str]) -> list[str]:
        combined = required | preferred
        matched = []
        for project in projects:
            lowered = project.lower()
            if any(skill in lowered for skill in combined):
                matched.append(project)
        return matched[:5] if matched else projects[:2]

    def _helpful_certifications(self, missing_skills: list[str]) -> list[str]:
        certs = []
        for skill in missing_skills:
            cert = CERT_PRIORITY.get(skill.lower())
            if cert and cert not in certs:
                certs.append(cert)
        return certs[:4]

    def _expected_career_growth(self, company: Company | None, job: Job) -> dict[str, Any]:
        score = 58
        if company is not None:
            size = str(getattr(company, 'company_size', '') or '').lower()
            if any(term in size for term in ('500', '1000', 'enterprise', 'large')):
                score += 10
            if 'startup' in size or '1-50' in size or '51-200' in size:
                score += 6
            benefits = ' '.join(self._normalized_list(getattr(company, 'benefits', None) or []))
            if 'learning' in benefits.lower() or 'career' in benefits.lower() or 'mentorship' in benefits.lower():
                score += 8
        if any(term in str(getattr(job, 'title', '')).lower() for term in ('engineer', 'developer', 'analyst', 'associate')):
            score += 8
        label = 'High' if score >= 78 else 'Moderate' if score >= 62 else 'Limited'
        return {'score': min(100, score), 'label': label}

    def _expected_salary(self, job: Job, overall: int) -> Decimal:
        job_min = Decimal(str(getattr(job, 'salary_min', 0) or 0))
        job_max = Decimal(str(getattr(job, 'salary_max', 0) or 0))
        if job_min <= 0 and job_max <= 0:
            return Decimal(str(overall * 1000)).quantize(Decimal('1.00'))
        if job_max <= 0:
            return job_min.quantize(Decimal('1.00'))
        band = job_max - job_min
        return (job_min + (band * Decimal(str(overall / 100)))).quantize(Decimal('1.00'))

    def _student_salary_range(self, student: Student) -> tuple[Decimal, Decimal]:
        minimum = Decimal(str(getattr(student, 'expected_salary_min', None) or 0))
        maximum = Decimal(str(getattr(student, 'expected_salary_max', None) or 0))
        expected = getattr(student, 'expected_salary', None)
        if maximum == 0 and expected not in (None, ''):
            try:
                amount = Decimal(str(expected))
                minimum = amount * Decimal('0.9') if minimum == 0 else minimum
                maximum = amount * Decimal('1.1')
            except Exception:
                pass
        return minimum.quantize(Decimal('1.00')), maximum.quantize(Decimal('1.00'))

    def _student_salary_floor(self, student: Student) -> Decimal:
        minimum, maximum = self._student_salary_range(student)
        if minimum > 0:
            return minimum
        if maximum > 0:
            return maximum * Decimal('0.9')
        return Decimal('0.00')

    def _promotion_potential(self, company: Company | None, job: Job) -> dict[str, Any]:
        score = 50
        if company is not None:
            size = str(getattr(company, 'company_size', '') or '').lower()
            if any(term in size for term in ('enterprise', '1000', '5000', '10000')):
                score += 14
            if 'learning' in ' '.join(self._normalized_list(getattr(company, 'benefits', None) or [])).lower():
                score += 8
        title = str(getattr(job, 'title', getattr(job, 'role_title', '')) or '').lower()
        if any(term in title for term in ('engineer', 'analyst', 'associate', 'developer')):
            score += 10
        return {'score': min(100, score), 'label': 'High' if score >= 75 else 'Moderate' if score >= 60 else 'Limited'}

    def _expected_joining_time_days(self, job: Job) -> int:
        deadline = getattr(job, 'deadline', None) or getattr(job, 'deadline_date', None)
        if isinstance(deadline, datetime):
            delta = (deadline.date() - date.today()).days
            return max(14, min(90, delta + 15))
        if isinstance(deadline, date):
            delta = (deadline - date.today()).days
            return max(14, min(90, delta + 15))
        return 35

    def _why_this_match(
        self,
        job: Job,
        company: Company | None,
        matched_skills: list[str],
        missing_skills: list[str],
        helpful_certs: list[str],
        matched_projects: list[str],
        overall: int,
    ) -> dict[str, Any]:
        title = str(getattr(job, 'title', getattr(job, 'role_title', 'Role')))
        company_name = str(getattr(company, 'name', 'Company')) if company is not None else str(getattr(job, 'company_name', 'Company'))
        summary = f'{title} at {company_name} matches the current profile through overlapping skills, role alignment, and market-ready potential.'
        return {
            'summary': summary,
            'skills_matched': matched_skills[:10],
            'skills_missing': missing_skills[:8],
            'certifications_help': helpful_certs,
            'projects_increasing_score': matched_projects,
            'expected_career_growth': 'Higher trajectory when core missing skills are closed.',
            'expected_salary_growth': 'Improves as stronger projects, skills, and certifications raise offer quality.',
            'hiring_probability': min(100, round(overall * 0.7 + 8)),
        }

    def _improvement_path(self, missing_skills: list[str], skill_gap_items: list[dict[str, Any]]) -> dict[str, Any]:
        recommendations = []
        lower_missing = {skill.lower() for skill in missing_skills}
        for item in skill_gap_items:
            if item['skill'].lower() in lower_missing:
                recommendations.append({
                    'skill': item['skill'],
                    'priority': item.get('priority', 'High'),
                    'estimated_hours': item.get('estimated_hours', 16),
                    'expected_match_gain': item.get('job_match_improvement', 8),
                })
        return {
            'recommended_improvements': recommendations[:5],
            'summary': 'Close the highest-priority missing skills and update the resume with proof through projects, certifications, and quantified outcomes.',
        }

    def _confidence_level(self, overall: int, matched_skills: list[str], missing_skills: list[str]) -> int:
        confidence = overall + len(matched_skills) * 2 - len(missing_skills)
        return max(35, min(99, confidence))

    def _category(self, score: int) -> str:
        for threshold, label in CATEGORY_THRESHOLDS:
            if score >= threshold:
                return label
        return 'Not Recommended'

    def _best_resume_version(self, ctx: JobMatchingContext) -> str:
        ats = int(getattr(ctx.resume_analysis, 'ats_score', 0) or 0) if ctx.resume_analysis is not None else 0
        resume_quality = int(getattr(ctx.resume_analysis, 'resume_quality', 0) or 0) if ctx.resume_analysis is not None else 0
        if ats >= 80:
            return 'ATS-Optimized Resume Version'
        if resume_quality >= 75:
            return 'Project-Forward Resume Version'
        return 'Balanced Resume Version with stronger skills and keywords section'

    def _best_cover_letter(self, top_job: dict[str, Any] | None) -> dict[str, Any]:
        if top_job is None:
            return {'style': 'Targeted', 'focus': 'Career goal, relevant skills, and one strong project.'}
        return {
            'style': 'Targeted',
            'focus': f"Connect {top_job['job_title']} requirements to matching skills, one relevant project, and a clear reason for interest in {top_job['company']}.",
        }

    def _skill_gap_items(self, skill_gap: SkillGap | None) -> list[dict[str, Any]]:
        if skill_gap is None:
            return []
        metadata = getattr(skill_gap, 'ranked_skills_metadata', None) or {}
        if isinstance(metadata, list):
            return metadata
        if isinstance(metadata, dict):
            return list(metadata.get('items', metadata.get('skills', []))) if ('items' in metadata or 'skills' in metadata) else []
        return []

    def _job_location(self, job: Job) -> str:
        city = str(getattr(job, 'location_city', '') or '').strip()
        country = str(getattr(job, 'location_country', '') or '').strip()
        location = str(getattr(job, 'location', '') or '').strip()
        if city or country:
            return ', '.join([item for item in [city, country] if item])
        return location or 'Unspecified'

    def _job_work_mode(self, job: Job) -> str:
        work_model = str(getattr(job, 'work_model', None) or getattr(job, 'work_type', None) or getattr(job, 'preferred_work_type', None) or '').lower()
        for label, aliases in WORK_MODE_ALIASES.items():
            if any(alias in work_model for alias in aliases):
                return label.capitalize() if label != 'onsite' else 'Onsite'
        if 'remote' in self._job_location(job).lower():
            return 'Remote'
        return 'Onsite'

    def _is_internship(self, job: Job) -> bool:
        text = ' '.join([
            str(getattr(job, 'title', getattr(job, 'role_title', '')) or ''),
            str(getattr(job, 'employment_type', '') or ''),
            str(getattr(job, 'description', '') or ''),
        ]).lower()
        return any(marker in text for marker in INTERNSHIP_MARKERS)

    def _company_for_job(self, job: Job, companies: Sequence[Company]) -> Company | None:
        job_company_name = str(getattr(job, 'company_name', '') or getattr(getattr(job, 'company', None), 'name', '') or '')
        for company in companies:
            if str(getattr(company, 'name', '')) == job_company_name:
                return company
        return None

    def _recruiter_for_job(self, job: Job, recruiters: Sequence[Recruiter]) -> Recruiter | None:
        direct = getattr(job, 'recruiter', None)
        if direct is not None:
            return direct
        recruiter_name = str(getattr(job, 'recruiter_name', '') or getattr(job, 'recruiter', '') or '')
        for recruiter in recruiters:
            if str(getattr(recruiter, 'name', '')) == recruiter_name:
                return recruiter
        return recruiters[0] if recruiters else None

    def _contains_metric(self, text: str) -> bool:
        return any(char.isdigit() for char in text)

    def _normalized_list(self, value: Any) -> list[str]:
        if isinstance(value, dict):
            value = list(value.keys())
        elif isinstance(value, str):
            value = [value]
        elif value is None:
            value = []
        elif not isinstance(value, (list, tuple, set)):
            value = [value]
        return [str(item).strip() for item in value if str(item).strip()]

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])


class JobMatchingGenerator:
    def __init__(self, config: AppConfig = CONFIG, engine: JobMatchingEngine | None = None) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 13000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 13000)
            self.faker.seed_instance(config.generation.seed + 13000)
        self.engine = engine or DefaultJobMatchingBuilder()

    def generate(
        self,
        students: Sequence[Student],
        companies: Sequence[Company],
        recruiters: Sequence[Recruiter],
        jobs: Sequence[Job],
        applications: Sequence[Application],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
        career_reports: Sequence[CareerReport],
        skill_gaps: Sequence[SkillGap],
        learning_roadmaps: Sequence[LearningRoadmap],
        resume_analyses: Sequence[ResumeAnalysis],
    ) -> JobMatchingGenerationResult:
        if not students:
            raise ValueError('Job matching generation requires students.')
        if not jobs:
            raise ValueError('Job matching generation requires jobs.')

        reports_by_student = {self._student_key(report.student): report for report in career_reports if getattr(report, 'student', None) is not None}
        skill_gaps_by_student = {self._student_key(gap.student): gap for gap in skill_gaps if getattr(gap, 'student', None) is not None}
        roadmaps_by_student = {self._student_key(roadmap.student): roadmap for roadmap in learning_roadmaps if getattr(roadmap, 'student', None) is not None}
        resume_by_student = {self._student_key(analysis.student): analysis for analysis in resume_analyses if getattr(analysis, 'student', None) is not None}
        jobs_by_student = self._jobs_by_student(students, jobs, applications)
        companies_by_student = self._companies_by_student(applications, companies, jobs_by_student)
        recruiters_by_student = self._recruiters_by_student(applications, recruiters, jobs_by_student)
        applications_by_student = self._records_by_student(applications, 'student')
        interviews_by_student = self._records_by_student(interviews, 'student', application_fallback=True)
        offers_by_student = self._records_by_student(offers, 'student', application_fallback=True)

        results: list[JobMatch] = []
        for student in students:
            key = self._student_key(student)
            ctx = JobMatchingContext(
                student=student,
                companies=companies_by_student.get(key, []),
                recruiters=recruiters_by_student.get(key, []),
                jobs=jobs_by_student.get(key, []),
                applications=applications_by_student.get(key, []),
                interviews=interviews_by_student.get(key, []),
                offers=offers_by_student.get(key, []),
                career_report=reports_by_student.get(key),
                skill_gap=skill_gaps_by_student.get(key),
                learning_roadmap=roadmaps_by_student.get(key),
                resume_analysis=resume_by_student.get(key),
            )
            results.append(self.engine.build(student, ctx))
        return JobMatchingGenerationResult(job_matches=results)

    def _jobs_by_student(self, students: Sequence[Student], jobs: Sequence[Job], applications: Sequence[Application]) -> dict[str, list[Job]]:
        mapping: dict[str, list[Job]] = defaultdict(list)
        for application in applications:
            student = getattr(application, 'student', None)
            job = getattr(application, 'job', None)
            if student is None or job is None:
                continue
            mapping[self._student_key(student)].append(job)
        for student in students:
            key = self._student_key(student)
            if not mapping.get(key):
                mapping[key] = self._best_candidate_jobs(student, jobs)
            else:
                existing_ids = {str(getattr(job, 'id', None) or getattr(job, 'job_id', None) or id(job)) for job in mapping[key]}
                for candidate in self._best_candidate_jobs(student, jobs):
                    candidate_id = str(getattr(candidate, 'id', None) or getattr(candidate, 'job_id', None) or id(candidate))
                    if candidate_id not in existing_ids:
                        mapping[key].append(candidate)
                        existing_ids.add(candidate_id)
                    if len(mapping[key]) >= 100:
                        break
        return mapping

    def _companies_by_student(self, applications: Sequence[Application], companies: Sequence[Company], jobs_by_student: dict[str, list[Job]]) -> dict[str, list[Company]]:
        mapping: dict[str, list[Company]] = defaultdict(list)
        company_lookup = {str(getattr(company, 'name', '')): company for company in companies}
        for application in applications:
            student = getattr(application, 'student', None)
            company = getattr(application, 'company', None) or getattr(getattr(application, 'job', None), 'company', None)
            if student is None or company is None:
                continue
            mapping[self._student_key(student)].append(company)
        for student_key, jobs in jobs_by_student.items():
            known = {str(getattr(company, 'name', '')) for company in mapping.get(student_key, [])}
            for job in jobs:
                name = str(getattr(getattr(job, 'company', None), 'name', None) or getattr(job, 'company_name', '') or '')
                if name and name in company_lookup and name not in known:
                    mapping[student_key].append(company_lookup[name])
                    known.add(name)
        return mapping

    def _recruiters_by_student(self, applications: Sequence[Application], recruiters: Sequence[Recruiter], jobs_by_student: dict[str, list[Job]]) -> dict[str, list[Recruiter]]:
        mapping: dict[str, list[Recruiter]] = defaultdict(list)
        recruiter_lookup = {str(getattr(recruiter, 'name', '')): recruiter for recruiter in recruiters}
        for application in applications:
            student = getattr(application, 'student', None)
            recruiter = getattr(application, 'recruiter', None)
            if student is None or recruiter is None:
                continue
            mapping[self._student_key(student)].append(recruiter)
        for student_key, jobs in jobs_by_student.items():
            known = {str(getattr(recruiter, 'name', '')) for recruiter in mapping.get(student_key, [])}
            for job in jobs:
                recruiter = getattr(job, 'recruiter', None)
                recruiter_name = str(getattr(recruiter, 'name', None) or getattr(job, 'recruiter_name', '') or getattr(job, 'recruiter', '') or '')
                if recruiter is not None and recruiter_name not in known:
                    mapping[student_key].append(recruiter)
                    known.add(recruiter_name)
                elif recruiter_name and recruiter_name in recruiter_lookup and recruiter_name not in known:
                    mapping[student_key].append(recruiter_lookup[recruiter_name])
                    known.add(recruiter_name)
        return mapping

    def _records_by_student(self, records: Sequence[Any], student_attr: str, application_fallback: bool = False) -> dict[str, list[Any]]:
        mapping: dict[str, list[Any]] = defaultdict(list)
        for record in records:
            student = getattr(record, student_attr, None)
            if student is None and application_fallback:
                application = getattr(record, 'application', None)
                student = getattr(application, 'student', None) if application is not None else None
            if student is None:
                continue
            mapping[self._student_key(student)].append(record)
        return mapping

    def _best_candidate_jobs(self, student: Student, jobs: Sequence[Job]) -> list[Job]:
        student_skills = {str(item).strip().lower() for item in self._list_value(getattr(student, 'skills', None)) if str(item).strip()}
        preferred_location = str(getattr(student, 'preferred_location', '') or '').lower()
        preferred_work = str(getattr(student, 'preferred_work_type', '') or '').lower()
        preferred_industry = str(getattr(student, 'preferred_industry', '') or '').lower()
        ranked: list[tuple[int, Job]] = []
        for job in jobs:
            required = {str(item).strip().lower() for item in self._list_value(getattr(job, 'skills_required', None)) if str(item).strip()}
            preferred = {str(item).strip().lower() for item in self._list_value(getattr(job, 'preferred_skills', None)) if str(item).strip()}
            score = len(student_skills & required) * 4 + len(student_skills & preferred)
            location_text = f"{getattr(job, 'location_city', '')} {getattr(job, 'location_country', '')}".lower()
            if preferred_location and preferred_location in location_text:
                score += 4
            work_model = str(getattr(job, 'work_model', None) or getattr(job, 'work_type', None) or '').lower()
            if preferred_work and preferred_work in work_model:
                score += 3
            company = getattr(job, 'company', None)
            industry = str(getattr(company, 'industry', '') or '').lower() if company is not None else ''
            if preferred_industry and preferred_industry in industry:
                score += 3
            ranked.append((score, job))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [job for _, job in ranked[:100]]

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])


def generate_job_matches(
    students: Sequence[Student],
    companies: Sequence[Company],
    recruiters: Sequence[Recruiter],
    jobs: Sequence[Job],
    applications: Sequence[Application],
    interviews: Sequence[Interview],
    offers: Sequence[Offer],
    career_reports: Sequence[CareerReport],
    skill_gaps: Sequence[SkillGap],
    learning_roadmaps: Sequence[LearningRoadmap],
    resume_analyses: Sequence[ResumeAnalysis],
    config: AppConfig = CONFIG,
) -> JobMatchingGenerationResult:
    generator = JobMatchingGenerator(config=config)
    return generator.generate(
        students=students,
        companies=companies,
        recruiters=recruiters,
        jobs=jobs,
        applications=applications,
        interviews=interviews,
        offers=offers,
        career_reports=career_reports,
        skill_gaps=skill_gaps,
        learning_roadmaps=learning_roadmaps,
        resume_analyses=resume_analyses,
    )


