class LearningRoadmapEngine(Protocol):
    def build(self, student: Student, ctx: 'RoadmapContext') -> LearningRoadmap:
        ...


@dataclass(slots=True)
class RoadmapContext:
    student: Student
    jobs: list[Job]
    companies: list[Company]
    recruiters: list[Recruiter]
    applications: list[Application]
    interviews: list[Interview]
    offers: list[Offer]
    career_report: CareerReport | None
    skill_gap: SkillGap | None


@dataclass(slots=True)
class LearningRoadmapGenerationResult:
    roadmaps: list[LearningRoadmap]


class DefaultLearningRoadmapEngine:
    def build(self, student: Student, ctx: RoadmapContext) -> LearningRoadmap:
        adaptive_inputs = self._adaptive_inputs(student, ctx)
        ranked_skills = self._ranked_skills(ctx.skill_gap)
        study_profile = self._study_profile(student, ctx, adaptive_inputs)
        learning_plan = self._learning_plan(ranked_skills, ctx)
        project_recommendations = self._project_recommendations(student, ranked_skills)
        certification_roadmap = self._certification_roadmap(ctx.skill_gap)
        interview_preparation = self._interview_preparation(student, ctx, ranked_skills)
        schedule = self._learning_schedule(study_profile, ranked_skills, certification_roadmap, project_recommendations)
        progress_tracking = self._progress_tracking(student, ctx, schedule, project_recommendations, certification_roadmap)
        roadmap_structure = self._roadmap_structure(ranked_skills, project_recommendations, certification_roadmap, schedule)
        reminders = self._reminders(schedule, certification_roadmap, project_recommendations)
        achievements = self._achievements(progress_tracking, roadmap_structure)
        analytics = self._analytics(ctx, ranked_skills, schedule, certification_roadmap)
        explanations = self._ai_explanations(ranked_skills, ctx, certification_roadmap, project_recommendations)
        future_ai = self._future_ai_metadata()

        roadmap = LearningRoadmap(
            student=student,
            generated_at=datetime.utcnow(),
            current_skill_level=adaptive_inputs['current_skill_level'],
            career_goal=str(getattr(student, 'career_goal', None) or ''),
            learning_speed=adaptive_inputs['learning_speed'],
            available_study_time_hours=study_profile['weekly_study_hours'],
            target_company=adaptive_inputs['target_company'],
            preferred_industry=adaptive_inputs['preferred_industry'],
            interview_timeline_days=adaptive_inputs['interview_timeline_days'],
            graduation_date=adaptive_inputs['graduation_date'],
        )
        roadmap.roadmap_structure_metadata = roadmap_structure
        roadmap.learning_plan_metadata = learning_plan
        roadmap.project_recommendations_metadata = project_recommendations
        roadmap.certification_roadmap_metadata = certification_roadmap
        roadmap.learning_schedule_metadata = schedule
        roadmap.progress_tracking_metadata = progress_tracking
        roadmap.ai_personalization_metadata = adaptive_inputs
        roadmap.adaptive_roadmap_metadata = self._adaptive_roadmap_events(ctx, ranked_skills)
        roadmap.interview_preparation_metadata = interview_preparation
        roadmap.learning_reminders_metadata = reminders
        roadmap.achievements_metadata = achievements
        roadmap.analytics_metadata = analytics
        roadmap.ai_explanations_metadata = explanations
        roadmap.engine_metadata = {
            'roadmap_engine': self.__class__.__name__,
            'replaceable_with_gemini': True,
            'frontend_contract_stable': True,
        }
        roadmap.future_ai_metadata = future_ai
        return roadmap

    def _adaptive_inputs(self, student: Student, ctx: RoadmapContext) -> dict[str, Any]:
        career_score = int(getattr(ctx.career_report, 'career_score', 0) or 0) if ctx.career_report is not None else 0
        current_skill_level = 'advanced' if career_score >= 78 else 'intermediate' if career_score >= 56 else 'beginner'
        preferred_tech = list(self._student_skills(student))[:8]
        available_study_time = self._available_study_time(student, ctx)
        interview_timeline_days = self._interview_timeline_days(ctx)
        target_company = self._target_company(ctx)
        preferred_industry = self._preferred_industry(ctx)
        return {
            'current_skill_level': current_skill_level,
            'career_goal': str(getattr(student, 'career_goal', '') or ''),
            'learning_speed': self._learning_speed(available_study_time, ctx),
            'available_study_time_hours': available_study_time,
            'preferred_technologies': preferred_tech,
            'interview_timeline_days': interview_timeline_days,
            'graduation_date': self._graduation_date(student),
            'target_company': target_company,
            'preferred_industry': preferred_industry,
        }

    def _study_profile(self, student: Student, ctx: RoadmapContext, adaptive_inputs: dict[str, Any]) -> dict[str, Any]:
        weekly_study_hours = adaptive_inputs['available_study_time_hours']
        daily_time = round(weekly_study_hours / 6, 1)
        break_days = ['Sunday'] if weekly_study_hours >= 8 else ['Saturday', 'Sunday']
        weekly_schedule = {
            'Monday': 'Core learning module',
            'Tuesday': 'Hands-on lab and notes',
            'Wednesday': 'Practice problems and coding challenge',
            'Thursday': 'Project implementation',
            'Friday': 'Revision and reflection',
            'Saturday': 'Mock interview or capstone work' if 'Saturday' not in break_days else 'Break day',
            'Sunday': 'Break day' if 'Sunday' in break_days else 'Open source or portfolio work',
        }
        revision_sessions = max(1, math.ceil(weekly_study_hours / 6))
        practice_sessions = max(2, math.ceil(weekly_study_hours / 5))
        return {
            'weekly_study_hours': weekly_study_hours,
            'daily_time_hours': daily_time,
            'weekly_schedule': weekly_schedule,
            'break_days': break_days,
            'revision_sessions_per_week': revision_sessions,
            'practice_sessions_per_week': practice_sessions,
            'mock_interviews_per_month': 2 if adaptive_inputs['interview_timeline_days'] <= 45 else 1,
        }

    def _learning_plan(self, ranked_skills: list[dict[str, Any]], ctx: RoadmapContext) -> dict[str, Any]:
        plans = []
        for item in ranked_skills[:8]:
            library = SKILL_LEARNING_LIBRARY.get(item['skill'], DEFAULT_LIBRARY)
            plans.append({
                'skill': item['skill'],
                'course': library['course'],
                'official_documentation': library['documentation'],
                'hands_on_labs': library['labs'],
                'practice_problems': library['practice'],
                'coding_challenges': [library['challenge']],
                'projects': [library['project']],
                'capstone_projects': [library['capstone']],
                'github_contributions': [library['github']],
                'portfolio_improvements': [f'Add a case study showing how you applied {item["skill"]}.'],
                'books': [library['book']],
                'videos': library['videos'],
                'articles': library['articles'],
                'open_source_contributions': [library['github']],
            })
        return {'items': plans}

    def _project_recommendations(self, student: Student, ranked_skills: list[dict[str, Any]]) -> dict[str, Any]:
        projects = []
        career_goal = str(getattr(student, 'career_goal', '') or '')
        for item in ranked_skills[:6]:
            library = SKILL_LEARNING_LIBRARY.get(item['skill'], DEFAULT_LIBRARY)
            duration = max(12, int(item['estimated_hours']) + 8)
            projects.append({
                'project_title': library['project'],
                'difficulty': item['difficulty'],
                'duration_hours': duration,
                'technologies': self._project_technologies(item['skill'], career_goal),
                'learning_outcome': f'Apply {item["skill"]} in a role-relevant workflow and document trade-offs, architecture, and results.',
                'portfolio_impact': f'High value for demonstrating practical depth in {item["skill"]}.',
                'resume_impact': f'Stronger project evidence for {item["skill"]}-aligned roles.',
                'interview_value': f'Provides concrete examples for behavioral and technical interviews around {item["skill"]}.',
                'github_value': 'Creates visible repository evidence and commit history.',
            })
        return {'projects': projects}

    def _certification_roadmap(self, skill_gap: SkillGap | None) -> dict[str, Any]:
        recommendations = []
        names = []
        if skill_gap is not None:
            metadata = getattr(skill_gap, 'certification_recommendations_metadata', None) or {}
            for item in metadata.get('recommendations', []):
                names.append(item['name'] if isinstance(item, dict) else str(item))
        for name in names[:5]:
            details = CERTIFICATION_DETAILS.get(name)
            if details is None:
                continue
            recommendations.append({
                'certification_name': name,
                'provider': details['provider'],
                'difficulty': details['difficulty'],
                'prerequisites': details['prerequisites'],
                'estimated_study_hours': details['hours'],
                'expected_completion': (date.today() + timedelta(days=max(21, details['hours'] // 2))).isoformat(),
                'career_value': details['career_value'],
                'salary_impact': details['salary_impact'],
                'industry_recognition': details['industry_recognition'],
            })
        return {'certifications': recommendations}

    def _learning_schedule(
        self,
        study_profile: dict[str, Any],
        ranked_skills: list[dict[str, Any]],
        certification_roadmap: dict[str, Any],
        project_recommendations: dict[str, Any],
    ) -> dict[str, Any]:
        project_deadlines = []
        for index, project in enumerate(project_recommendations.get('projects', [])[:4], start=1):
            project_deadlines.append({
                'project_title': project['project_title'],
                'deadline': (date.today() + timedelta(days=index * 21)).isoformat(),
            })
        certification_exams = []
        for index, cert in enumerate(certification_roadmap.get('certifications', [])[:3], start=1):
            certification_exams.append({
                'certification_name': cert['certification_name'],
                'exam_target_date': (date.today() + timedelta(days=30 + index * 20)).isoformat(),
            })
        return {
            'study_hours_per_week': study_profile['weekly_study_hours'],
            'daily_time_hours': study_profile['daily_time_hours'],
            'weekly_schedule': study_profile['weekly_schedule'],
            'break_days': study_profile['break_days'],
            'revision_sessions': study_profile['revision_sessions_per_week'],
            'practice_sessions': study_profile['practice_sessions_per_week'],
            'mock_interviews': study_profile['mock_interviews_per_month'],
            'project_deadlines': project_deadlines,
            'certification_exams': certification_exams,
        }

    def _progress_tracking(
        self,
        student: Student,
        ctx: RoadmapContext,
        schedule: dict[str, Any],
        project_recommendations: dict[str, Any],
        certification_roadmap: dict[str, Any],
    ) -> dict[str, Any]:
        completed_projects = len(self._list_value(getattr(student, 'projects', None)))
        completed_courses = len(self._list_value(getattr(student, 'certifications', None)))
        certifications_completed = len(self._list_value(getattr(student, 'certifications', None)))
        study_hours = completed_courses * 14 + completed_projects * 18 + len(ctx.interviews) * 4
        completion_pct = min(100, 8 + completed_projects * 8 + completed_courses * 6)
        current_streak = min(45, 3 + len(ctx.applications) + len(ctx.interviews))
        longest_streak = max(current_streak, current_streak + len(ctx.offers))
        learning_velocity = round((study_hours / max(1, len(project_recommendations.get('projects', []) + certification_roadmap.get('certifications', [])))) , 1) if (project_recommendations.get('projects') or certification_roadmap.get('certifications')) else 0.0
        consistency_score = min(100, 45 + current_streak + schedule['revision_sessions'] * 3)
        return {
            'completion_pct': completion_pct,
            'current_streak': current_streak,
            'longest_streak': longest_streak,
            'study_hours': study_hours,
            'projects_completed': completed_projects,
            'courses_completed': completed_courses,
            'certifications_completed': certifications_completed,
            'learning_velocity': learning_velocity,
            'consistency_score': consistency_score,
        }

    def _roadmap_structure(
        self,
        ranked_skills: list[dict[str, Any]],
        project_recommendations: dict[str, Any],
        certification_roadmap: dict[str, Any],
        schedule: dict[str, Any],
    ) -> dict[str, Any]:
        today = date.today()
        daily_tasks = []
        for item in ranked_skills[:5]:
            daily_tasks.append({
                'task': f'Spend focused time on {item["skill"]} through practice and documentation review.',
                'duration_minutes': 60,
            })
        weekly_goals = []
        for week, item in enumerate(ranked_skills[:6], start=1):
            weekly_goals.append({'week': week, 'goal': f'Build working proficiency in {item["skill"]} and complete one evidence artifact.'})
        monthly_goals = [
            {'month': 1, 'goal': 'Close top one or two critical skill gaps and publish one portfolio project.'},
            {'month': 2, 'goal': 'Complete one certification preparation track and improve interview readiness.'},
            {'month': 3, 'goal': 'Strengthen GitHub visibility and complete a capstone project.'},
        ]
        quarterly_goals = [
            {'quarter': 'Q1', 'goal': 'Improve job match and ATS alignment through skill proof and certification progress.'},
            {'quarter': 'Q2', 'goal': 'Convert stronger profile quality into interview opportunities and project credibility.'},
        ]
        annual_goals = [
            {'goal': 'Reach stable employability for target roles with portfolio, certifications, interviews, and job conversion evidence.'}
        ]
        career_milestones = [
            {'milestone': 'First strong portfolio-ready role-aligned project', 'target_date': (today + timedelta(days=30)).isoformat()},
            {'milestone': 'One recognized certification completed', 'target_date': (today + timedelta(days=75)).isoformat()},
            {'milestone': 'Mock interview readiness above role threshold', 'target_date': (today + timedelta(days=45)).isoformat()},
        ]
        learning_milestones = [
            {'milestone': f'Complete {item["skill"]} core learning path', 'target_date': (today + timedelta(days=7 * idx)).isoformat()}
            for idx, item in enumerate(ranked_skills[:5], start=2)
        ]
        project_milestones = [
            {'project': item['project_title'], 'target_date': (today + timedelta(days=idx * 20)).isoformat()}
            for idx, item in enumerate(project_recommendations.get('projects', [])[:4], start=1)
        ]
        return {
            'daily_tasks': daily_tasks,
            'weekly_goals': weekly_goals,
            'monthly_goals': monthly_goals,
            'quarterly_goals': quarterly_goals,
            'annual_goals': annual_goals,
            'career_milestones': career_milestones,
            'learning_milestones': learning_milestones,
            'project_milestones': project_milestones,
        }

    def _adaptive_roadmap_events(self, ctx: RoadmapContext, ranked_skills: list[dict[str, Any]]) -> dict[str, Any]:
        return {
            'student_gains_skill': 'Recalculate learning order and reduce duplicate study tasks once a missing skill is verified.',
            'student_completes_project': 'Shift focus from learning basics to interview articulation and portfolio presentation.',
            'student_earns_certification': 'Advance to deeper projects and remove covered certification preparation tasks.',
            'student_receives_interview_feedback': 'Increase emphasis on weak interview dimensions such as coding, system design, or communication.',
            'student_changes_career_goal': 'Re-rank skills, certifications, and projects using the new role family and company signals.',
            'student_accepts_offer': 'Transition roadmap toward onboarding readiness and early-career excellence.',
            'top_skill_watchlist': [item['skill'] for item in ranked_skills[:5]],
        }

    def _interview_preparation(self, student: Student, ctx: RoadmapContext, ranked_skills: list[dict[str, Any]]) -> dict[str, Any]:
        bucket = self._career_bucket(str(getattr(student, 'career_goal', '') or ''))
        topics = INTERVIEW_FOCUS_MAP[bucket]
        nearest_interview_days = self._interview_timeline_days(ctx)
        timeline = []
        for week in range(1, 5):
            focus = topics[(week - 1) % len(topics)]
            timeline.append({'week': week, 'focus': focus, 'task': f'Practice {focus} with timed exercises and concise explanations.'})
        company_topics = self._company_specific_topics(ctx)
        return {
            'preparation_timeline': timeline,
            'company_specific_topics': company_topics,
            'coding_practice': [item['skill'] for item in ranked_skills if item['skill'] in {'Python', 'Java', 'Node.js', 'React', 'SQL'}][:5],
            'sql_practice': ['Joins', 'Window functions', 'Aggregation', 'Data cleaning'] if bucket in {'data', 'backend', 'ai'} else ['Basic querying', 'Filtering', 'Sorting'],
            'system_design': ['API design', 'Scalability basics', 'Data modeling'] if bucket in {'backend', 'cloud', 'ai'} else ['Component architecture', 'Flow design'],
            'behavioral_questions': ['Ownership example', 'Conflict resolution', 'Learning from failure', 'Cross-team collaboration'],
            'communication_exercises': ['Explain a project in 2 minutes', 'Present trade-offs clearly', 'Practice structured STAR responses'],
            'days_until_next_interview': nearest_interview_days,
        }

    def _reminders(self, schedule: dict[str, Any], certification_roadmap: dict[str, Any], project_recommendations: dict[str, Any]) -> dict[str, Any]:
        daily = 'Complete your planned study block and log one concrete takeaway.'
        weekly = 'Review progress, close one pending practice item, and plan the next week.'
        deadline = [
            {'label': 'Project Deadline', 'date': item['deadline']} for item in schedule.get('project_deadlines', [])
        ]
        certification = [
            {'label': 'Certification Reminder', 'date': item['exam_target_date']} for item in schedule.get('certification_exams', [])
        ]
        project = [
            {'label': 'Project Reminder', 'project_title': item['project_title']} for item in project_recommendations.get('projects', [])[:4]
        ]
        revision = f"Complete {schedule.get('revision_sessions', 1)} revision session(s) this week and summarize weak spots."
        return {
            'daily_reminder': daily,
            'weekly_reminder': weekly,
            'deadline_reminder': deadline,
            'certification_reminder': certification,
            'project_reminder': project,
            'revision_reminder': revision,
        }

    def _achievements(self, progress_tracking: dict[str, Any], roadmap_structure: dict[str, Any]) -> dict[str, Any]:
        projects_completed = progress_tracking['projects_completed']
        certifications_completed = progress_tracking['certifications_completed']
        badges = []
        if progress_tracking['current_streak'] >= 7:
            badges.append('7-Day Learning Streak')
        if projects_completed >= 2:
            badges.append('Portfolio Builder')
        if certifications_completed >= 1:
            badges.append('Certified Learner')
        milestones = [item['milestone'] for item in roadmap_structure['career_milestones'][:3]]
        achievements = badges + [f'Completed {projects_completed} role-aligned projects', f'Completed {certifications_completed} certifications']
        learning_level = 'Advanced' if progress_tracking['completion_pct'] >= 75 else 'Intermediate' if progress_tracking['completion_pct'] >= 40 else 'Foundation'
        leaderboard_points = progress_tracking['study_hours'] + (projects_completed * 60) + (certifications_completed * 100)
        xp = leaderboard_points * 2
        rewards = ['Priority mentor session unlock'] if progress_tracking['consistency_score'] >= 70 else ['Keep streak active to unlock rewards']
        return {
            'badges': badges,
            'milestones': milestones,
            'achievements': achievements,
            'learning_level': learning_level,
            'leaderboard_points': leaderboard_points,
            'xp': xp,
            'rewards': rewards,
        }

    def _analytics(
        self,
        ctx: RoadmapContext,
        ranked_skills: list[dict[str, Any]],
        schedule: dict[str, Any],
        certification_roadmap: dict[str, Any],
    ) -> dict[str, Any]:
        total_career_improvement = sum(item['career_score_improvement'] for item in ranked_skills[:5])
        total_ats_improvement = sum(item['ats_improvement'] for item in ranked_skills[:5])
        total_job_match_improvement = sum(item['job_match_improvement'] for item in ranked_skills[:5])
        avg_salary_gain = sum(Decimal(str(item['expected_salary_improvement'])) for item in ranked_skills[:5]) / Decimal(str(max(1, len(ranked_skills[:5])))) if ranked_skills else Decimal('0.00')
        base_placement = 0
        if ctx.career_report is not None:
            predictions = getattr(ctx.career_report, 'predictions_metadata', None) or {}
            base_placement = int(predictions.get('placement_probability', 0) or 0)
        learning_effectiveness = min(100, 52 + schedule['study_hours_per_week'] * 2 + len(certification_roadmap.get('certifications', [])) * 4)
        return {
            'learning_effectiveness': learning_effectiveness,
            'estimated_career_score_improvement': min(100, total_career_improvement),
            'estimated_ats_improvement': min(100, total_ats_improvement),
            'estimated_job_match_improvement': min(100, total_job_match_improvement),
            'estimated_salary_growth': avg_salary_gain.quantize(Decimal('1.00')),
            'estimated_placement_probability': min(100, base_placement + round(total_job_match_improvement * 0.45)),
        }

    def _ai_explanations(
        self,
        ranked_skills: list[dict[str, Any]],
        ctx: RoadmapContext,
        certification_roadmap: dict[str, Any],
        project_recommendations: dict[str, Any],
    ) -> dict[str, Any]:
        company_names = sorted({str(getattr(company, 'name', 'Company')) for company in ctx.companies})[:6]
        job_titles = sorted({str(getattr(job, 'title', getattr(job, 'role_title', 'Role'))) for job in ctx.jobs})[:6]
        items = []
        for item in ranked_skills[:6]:
            items.append({
                'recommendation': item['skill'],
                'why_selected': f'{item["skill"]} is missing from current evidence and appears across target jobs or company requirements.',
                'jobs_requiring_it': item['jobs_requiring_it'],
                'companies_valuing_it': item['companies_requiring_it'],
                'expected_career_impact': {
                    'career_score_improvement': item['career_score_improvement'],
                    'job_match_improvement': item['job_match_improvement'],
                    'ats_improvement': item['ats_improvement'],
                },
                'estimated_completion_benefit': f'Expected to improve employability after {item["estimated_hours"]} focused learning hours and one proof project.',
            })
        return {
            'items': items,
            'certification_summary': {
                'recommended_certifications': [item['certification_name'] for item in certification_roadmap.get('certifications', [])],
                'why': 'Selected to close market-relevant gaps aligned with target role families and hiring expectations.',
            },
            'project_summary': {
                'recommended_projects': [item['project_title'] for item in project_recommendations.get('projects', [])],
                'why': 'Projects provide practical evidence for recruiters, ATS scoring, portfolio quality, and interview discussion depth.',
            },
            'context': {
                'jobs_considered': job_titles,
                'companies_considered': company_names,
            },
        }

    def _future_ai_metadata(self) -> dict[str, Any]:
        return {
            'gemini_replaceable': True,
            'stable_contract': {
                'roadmap_structure': True,
                'learning_plan': True,
                'project_recommendations': True,
                'certification_roadmap': True,
                'learning_schedule': True,
                'progress_tracking': True,
                'ai_explanations': True,
            },
            'engine_switch_strategy': 'Swap backend recommendation engine while preserving output fields consumed by frontend clients.',
        }

    def _ranked_skills(self, skill_gap: SkillGap | None) -> list[dict[str, Any]]:
        if skill_gap is None:
            return []
        metadata = getattr(skill_gap, 'ranked_skills_metadata', None) or {}
        if isinstance(metadata, dict):
            return list(metadata.get('items', metadata.get('skills', []))) if ('items' in metadata or 'skills' in metadata) else []
        if isinstance(metadata, list):
            return metadata
        return []

    def _student_skills(self, student: Student) -> list[str]:
        value = getattr(student, 'skills', None)
        if isinstance(value, (list, tuple, set)):
            return [str(item) for item in value if str(item).strip()]
        if value in (None, ''):
            return []
        return [str(value)]

    def _available_study_time(self, student: Student, ctx: RoadmapContext) -> int:
        skill_count = len(self._student_skills(student))
        active_interviews = len(ctx.interviews)
        active_offers = len(ctx.offers)
        if active_offers > 0:
            return 6
        if active_interviews >= 2:
            return 8
        if skill_count <= 5:
            return 12
        if skill_count <= 10:
            return 10
        return 8

    def _interview_timeline_days(self, ctx: RoadmapContext) -> int:
        scheduled_dates = []
        for interview in ctx.interviews:
            scheduled_at = getattr(interview, 'scheduled_at', None)
            if isinstance(scheduled_at, datetime) and scheduled_at > datetime.utcnow():
                scheduled_dates.append((scheduled_at.date() - date.today()).days)
        return min(scheduled_dates) if scheduled_dates else 45

    def _target_company(self, ctx: RoadmapContext) -> str | None:
        company_counts = Counter(str(getattr(company, 'name', 'Company')) for company in ctx.companies)
        return company_counts.most_common(1)[0][0] if company_counts else None

    def _preferred_industry(self, ctx: RoadmapContext) -> str | None:
        industries = Counter(str(getattr(company, 'industry', 'Technology')) for company in ctx.companies)
        return industries.most_common(1)[0][0] if industries else None

    def _learning_speed(self, available_study_time: int, ctx: RoadmapContext) -> str:
        if available_study_time >= 12:
            return 'fast'
        if available_study_time >= 8:
            return 'steady'
        return 'balanced'

    def _graduation_date(self, student: Student) -> str | None:
        value = getattr(student, 'graduation_date', None)
        if isinstance(value, (date, datetime)):
            return value.date().isoformat() if isinstance(value, datetime) else value.isoformat()
        grad_year = getattr(student, 'graduation_year', None)
        if grad_year:
            return date(int(grad_year), 6, 30).isoformat()
        return None

    def _project_technologies(self, skill: str, career_goal: str) -> list[str]:
        base = [skill]
        goal = career_goal.lower()
        if any(term in goal for term in ('backend', 'software', 'developer')):
            base.extend(['APIs', 'PostgreSQL'])
        if any(term in goal for term in ('frontend', 'ui')):
            base.extend(['React', 'TypeScript'])
        if any(term in goal for term in ('data', 'ai', 'ml')):
            base.extend(['Python', 'SQL'])
        if any(term in goal for term in ('cloud', 'devops')):
            base.extend(['Docker', 'Cloud'])
        deduped: list[str] = []
        for item in base:
            if item not in deduped:
                deduped.append(item)
        return deduped[:5]

    def _career_bucket(self, career_goal: str) -> str:
        goal = career_goal.lower()
        if any(term in goal for term in ('frontend', 'ui')):
            return 'frontend'
        if any(term in goal for term in ('data', 'analytics', 'analyst')):
            return 'data'
        if any(term in goal for term in ('ai', 'ml', 'machine learning')):
            return 'ai'
        if any(term in goal for term in ('cloud', 'devops', 'platform')):
            return 'cloud'
        if any(term in goal for term in ('security', 'cyber')):
            return 'security'
        return 'backend'

    def _company_specific_topics(self, ctx: RoadmapContext) -> list[dict[str, Any]]:
        topics = []
        for company in ctx.companies[:5]:
            tech_stack = getattr(company, 'tech_stack', None) or getattr(company, 'recruiting_focus', None) or []
            if isinstance(tech_stack, str):
                tech_stack = [tech_stack]
            topics.append({
                'company': str(getattr(company, 'name', 'Company')),
                'topics': [str(item) for item in list(tech_stack)[:5]] or ['Behavioral fit', 'Role fundamentals'],
            })
        return topics

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])


class LearningRoadmapGenerator:
    def __init__(self, config: AppConfig = CONFIG, engine: LearningRoadmapEngine | None = None) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 11000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 11000)
            self.faker.seed_instance(config.generation.seed + 11000)
        self.engine = engine or DefaultLearningRoadmapEngine()

    def generate(
        self,
        students: Sequence[Student],
        jobs: Sequence[Job],
        companies: Sequence[Company],
        recruiters: Sequence[Recruiter],
        career_reports: Sequence[CareerReport],
        skill_gaps: Sequence[SkillGap],
        applications: Sequence[Application],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
    ) -> LearningRoadmapGenerationResult:
        if not students:
            raise ValueError('Learning roadmap generation requires students.')

        reports_by_student = {self._student_key(report.student): report for report in career_reports if getattr(report, 'student', None) is not None}
        skill_gap_by_student = {self._student_key(gap.student): gap for gap in skill_gaps if getattr(gap, 'student', None) is not None}
        jobs_by_student = self._jobs_by_student(students, jobs, applications)
        companies_by_student = self._companies_by_student(applications, companies)
        recruiters_by_student = self._recruiters_by_student(applications, recruiters)
        applications_by_student = self._records_by_student(applications, 'student')
        interviews_by_student = self._records_by_student(interviews, 'student', application_fallback=True)
        offers_by_student = self._records_by_student(offers, 'student', application_fallback=True)

        roadmaps: list[LearningRoadmap] = []
        for student in students:
            key = self._student_key(student)
            ctx = RoadmapContext(
                student=student,
                jobs=jobs_by_student.get(key, []),
                companies=companies_by_student.get(key, []),
                recruiters=recruiters_by_student.get(key, []),
                applications=applications_by_student.get(key, []),
                interviews=interviews_by_student.get(key, []),
                offers=offers_by_student.get(key, []),
                career_report=reports_by_student.get(key),
                skill_gap=skill_gap_by_student.get(key),
            )
            roadmap = self.engine.build(student, ctx)
            roadmaps.append(roadmap)
        return LearningRoadmapGenerationResult(roadmaps=roadmaps)

    def _jobs_by_student(self, students: Sequence[Student], jobs: Sequence[Job], applications: Sequence[Application]) -> dict[str, list[Job]]:
        mapping: dict[str, list[Job]] = defaultdict(list)
        for application in applications:
            student = getattr(application, 'student', None)
            job = getattr(application, 'job', None)
            if student is None or job is None:
                continue
            mapping[self._student_key(student)].append(job)
        for student in students:
            key = self._student_key(student)
            if not mapping.get(key):
                mapping[key] = self._best_candidate_jobs(student, jobs)
        return mapping

    def _companies_by_student(self, applications: Sequence[Application], companies: Sequence[Company]) -> dict[str, list[Company]]:
        mapping: dict[str, list[Company]] = defaultdict(list)
        for application in applications:
            student = getattr(application, 'student', None)
            company = getattr(application, 'company', None) or getattr(getattr(application, 'job', None), 'company', None)
            if student is None or company is None:
                continue
            mapping[self._student_key(student)].append(company)
        return mapping

    def _recruiters_by_student(self, applications: Sequence[Application], recruiters: Sequence[Recruiter]) -> dict[str, list[Recruiter]]:
        mapping: dict[str, list[Recruiter]] = defaultdict(list)
        for application in applications:
            student = getattr(application, 'student', None)
            recruiter = getattr(application, 'recruiter', None)
            if student is None or recruiter is None:
                continue
            mapping[self._student_key(student)].append(recruiter)
        return mapping

    def _records_by_student(self, records: Sequence[Any], student_attr: str, application_fallback: bool = False) -> dict[str, list[Any]]:
        mapping: dict[str, list[Any]] = defaultdict(list)
        for record in records:
            student = getattr(record, student_attr, None)
            if student is None and application_fallback:
                application = getattr(record, 'application', None)
                student = getattr(application, 'student', None) if application is not None else None
            if student is None:
                continue
            mapping[self._student_key(student)].append(record)
        return mapping

    def _best_candidate_jobs(self, student: Student, jobs: Sequence[Job]) -> list[Job]:
        skills = {str(item).strip().lower() for item in self._list_value(getattr(student, 'skills', None)) if str(item).strip()}
        preferred_location = str(getattr(student, 'preferred_location', '') or '').lower()
        ranked: list[tuple[int, Job]] = []
        for job in jobs:
            required = {str(item).strip().lower() for item in self._list_value(getattr(job, 'skills_required', None)) if str(item).strip()}
            preferred = {str(item).strip().lower() for item in self._list_value(getattr(job, 'preferred_skills', None)) if str(item).strip()}
            score = len(skills & required) * 3 + len(skills & preferred)
            location_text = f"{getattr(job, 'location_city', '')} {getattr(job, 'location_country', '')}".lower()
            if preferred_location and preferred_location in location_text:
                score += 2
            ranked.append((score, job))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [job for _, job in ranked[:20]]

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])


def generate_learning_roadmaps(
    students: Sequence[Student],
    jobs: Sequence[Job],
    companies: Sequence[Company],
    recruiters: Sequence[Recruiter],
    career_reports: Sequence[CareerReport],
    skill_gaps: Sequence[SkillGap],
    applications: Sequence[Application],
    interviews: Sequence[Interview],
    offers: Sequence[Offer],
    config: AppConfig = CONFIG,
) -> LearningRoadmapGenerationResult:
    generator = LearningRoadmapGenerator(config=config)
    return generator.generate(
        students=students,
        jobs=jobs,
        companies=companies,
        recruiters=recruiters,
        career_reports=career_reports,
        skill_gaps=skill_gaps,
        applications=applications,
        interviews=interviews,
        offers=offers,
    )


