class MentorRecommendationEngine(Protocol):
    def recommend(self, ctx: 'MentorRecommendationContext') -> MentorRecommendation:
        ...


class MentorshipMatchingEngine(Protocol):
    def rank(self, ctx: 'MentorRecommendationContext') -> list[tuple[Student, float, dict[str, Any]]]:
        ...


class SessionPlanningEngine(Protocol):
    def build(self, ctx: 'MentorRecommendationContext', mentor: Student, evidence: dict[str, Any], score: float) -> dict[str, Any]:
        ...


class CareerCoachingEngine(Protocol):
    def build(self, ctx: 'MentorRecommendationContext', mentor: Student, evidence: dict[str, Any], score: float) -> dict[str, Any]:
        ...


@dataclass(slots=True)
class MentorRecommendationContext:
    student: Student
    students: list[Student]
    companies: list[Company]
    recruiters: list[Recruiter]
    jobs: list[Job]
    interviews: list[Interview]
    offers: list[Offer]
    career_report: CareerReport | None
    skill_gap: SkillGap | None
    learning_roadmap: Any | None
    resume_analysis: ResumeAnalysis | None
    job_match: JobMatch | None
    recruiter_recommendation: RecruiterRecommendation | None
    company_recommendation: CompanyRecommendation | None
    networking_recommendation: NetworkingRecommendation | None


@dataclass(slots=True)
class MentorRecommendationGenerationResult:
    mentor_recommendations: list[MentorRecommendation]


class DefaultMentorshipMatchingEngine:
    def rank(self, ctx: MentorRecommendationContext) -> list[tuple[Student, float, dict[str, Any]]]:
        ranked = []
        student_skills = set(self._normalized_list(getattr(ctx.student, 'skills', None), lower=True))
        student_soft_skills = set(self._normalized_list(getattr(ctx.student, 'soft_skills', None), lower=True))
        student_projects = self._normalized_list(getattr(ctx.student, 'projects', None), lower=True)
        student_certs = set(self._normalized_list(getattr(ctx.student, 'certifications', None), lower=True))
        student_goal = str(getattr(ctx.student, 'career_goal', '') or '').lower()
        target_industry = str(getattr(ctx.student, 'preferred_industry', '') or '').lower()
        target_role = self._target_role(ctx).lower()
        target_companies = {str(item.get('company_name', '')).lower() for item in (getattr(ctx.company_recommendation, 'top_companies', None) or [])[:10] if isinstance(item, dict)} if ctx.company_recommendation is not None else set()
        skill_gap = {skill.lower() for skill in self._missing_skills(ctx)}
        resume_score = int(getattr(ctx.resume_analysis, 'resume_score', 0) or 0) if ctx.resume_analysis is not None else 55
        ats_score = int(getattr(ctx.resume_analysis, 'ats_score', 0) or 0) if ctx.resume_analysis is not None else 52
        interview_readiness = int(getattr(ctx.career_report, 'interview_readiness', 0) or 0) if ctx.career_report is not None else 56
        learning_progress = self._learning_progress(ctx)

        for mentor in ctx.students:
            if self._student_key(mentor) == self._student_key(ctx.student):
                continue
            mentor_experience = self._normalized_list(getattr(mentor, 'experience', None), lower=True)
            if len(mentor_experience) < 2:
                continue
            mentor_skills = set(self._normalized_list(getattr(mentor, 'skills', None), lower=True))
            mentor_soft_skills = set(self._normalized_list(getattr(mentor, 'soft_skills', None), lower=True))
            mentor_projects = self._normalized_list(getattr(mentor, 'projects', None), lower=True)
            mentor_certs = set(self._normalized_list(getattr(mentor, 'certifications', None), lower=True))
            mentor_goal = str(getattr(mentor, 'career_goal', '') or '').lower()
            mentor_company_interest = {str(item).lower() for item in self._normalized_list(getattr(mentor, 'preferred_companies', None))}
            mentor_industry = str(getattr(mentor, 'preferred_industry', '') or '').lower()

            shared_skills = sorted(student_skills & mentor_skills)
            shared_technologies = [skill for skill in shared_skills if skill in {'python', 'java', 'react', 'node.js', 'sql', 'aws', 'docker', 'kubernetes', 'tensorflow', 'pytorch', 'go', 'swift', 'figma'}]
            shared_projects = [project for project in mentor_projects if any(token in project for token in student_projects[:8])][:5]
            shared_certifications = sorted(student_certs & mentor_certs)[:5]
            shared_company_interests = sorted(target_companies & mentor_company_interest)[:5]
            shared_soft_skills = sorted(student_soft_skills & mentor_soft_skills)[:5]
            shared_university = self._student_university(ctx.student) if self._student_university(ctx.student).lower() == self._student_university(mentor).lower() else None
            shared_department = str(getattr(ctx.student, 'department', '') or '') if str(getattr(ctx.student, 'department', '') or '').lower() == str(getattr(mentor, 'department', '') or '').lower() else ''
            shared_career_goal = student_goal if student_goal and any(token in mentor_goal for token in student_goal.split() if len(token) > 2) else ''

            expertise = self._mentor_expertise(mentor)
            specialization_score = len(set(expertise) & set(self._specializations_from_goal(student_goal, target_role, student_skills)))
            compatibility = 0.0
            compatibility += min(16, len(shared_skills) * 1.9)
            compatibility += min(8, len(shared_soft_skills) * 1.4)
            compatibility += min(8, len(shared_projects) * 1.8)
            compatibility += min(7, len(shared_certifications) * 1.5)
            compatibility += min(6, len(shared_company_interests) * 1.4)
            compatibility += 7 if shared_university else 0
            compatibility += 4 if shared_department else 0
            compatibility += 7 if shared_career_goal else 0
            compatibility += 8 if target_industry and target_industry == mentor_industry else 0
            compatibility += min(12, len(skill_gap & mentor_skills) * 2.3)
            compatibility += min(10, specialization_score * 2.5)
            compatibility += min(15, len(mentor_experience) * 1.6)
            compatibility += (resume_score / 100) * 4
            compatibility += (ats_score / 100) * 3
            compatibility += (interview_readiness / 100) * 5
            compatibility += min(6, learning_progress / 2.4)

            evidence = {
                'shared_skills': shared_skills[:10],
                'shared_soft_skills': shared_soft_skills,
                'shared_technologies': shared_technologies[:8],
                'shared_projects': shared_projects,
                'shared_certifications': shared_certifications,
                'shared_company_interests': shared_company_interests,
                'shared_university': shared_university,
                'shared_department': shared_department,
                'shared_career_goals': shared_career_goal,
                'skill_gap_alignment': sorted(skill_gap & mentor_skills)[:8],
                'mentor_expertise': expertise,
                'mentor_specializations': self._mentor_specializations(mentor),
                'mentor_services': self._mentor_services(mentor, expertise),
                'availability': self._availability(mentor),
                'mentorship_rating': self._mentorship_rating(mentor, mentor_experience, expertise),
                'verification_status': self._verification_status(mentor),
                'company': self._current_company(mentor),
                'industry': mentor_industry.title() if mentor_industry else 'Technology',
                'role': self._current_role(mentor),
                'years_of_experience': max(2, len(mentor_experience) * 2),
                'candidate_strength': 58 + len(mentor_skills) * 2 + len(mentor_experience) * 5,
            }
            ranked.append((mentor, round(compatibility, 2), evidence))

        ranked.sort(key=lambda item: item[1], reverse=True)
        return ranked

    def _target_role(self, ctx: MentorRecommendationContext) -> str:
        if ctx.job_match is not None:
            top = (getattr(ctx.job_match, 'top_job_matches', None) or [])
            if top and isinstance(top[0], dict):
                return str(top[0].get('job_title', '') or top[0].get('role', '') or '')
        return str(getattr(ctx.student, 'career_goal', '') or '')

    def _mentor_expertise(self, mentor: Student) -> list[str]:
        skills = set(self._normalized_list(getattr(mentor, 'skills', None), lower=True))
        experience = ' '.join(self._normalized_list(getattr(mentor, 'experience', None), lower=True))
        expertise = []
        if {'react', 'javascript', 'typescript', 'css', 'html'} & skills:
            expertise.append('Frontend')
        if {'python', 'java', 'node.js', 'api', 'sql'} & skills:
            expertise.append('Backend')
        if {'react', 'node.js', 'sql'} <= skills or ('full stack' in experience):
            expertise.append('Full Stack')
        if {'aws', 'azure', 'gcp', 'docker', 'kubernetes'} & skills:
            expertise.append('Cloud')
        if {'docker', 'kubernetes', 'terraform', 'ci/cd'} & skills:
            expertise.append('DevOps')
        if {'security', 'network security', 'linux', 'siem'} & skills:
            expertise.append('Cybersecurity')
        if {'tensorflow', 'pytorch', 'machine learning', 'deep learning'} & skills:
            expertise.append('AI')
            expertise.append('Machine Learning')
        if {'python', 'sql', 'pandas', 'statistics'} & skills:
            expertise.append('Data Science')
        if {'android', 'ios', 'flutter', 'react native', 'swift', 'kotlin'} & skills:
            expertise.append('Mobile Development')
        if {'product', 'roadmap', 'stakeholder management'} & skills or 'product manager' in experience:
            expertise.append('Product Management')
        if {'figma', 'ux', 'ui', 'design systems'} & skills:
            expertise.append('UI/UX')
        if {'system design', 'distributed systems', 'microservices'} & skills or 'architect' in experience:
            expertise.append('System Design')
        expertise.extend(['Career Coaching', 'Interview Coaching', 'Resume Review'])
        if 'open source' in experience or {'github', 'oss'} & skills:
            expertise.append('Open Source')
        if 'research' in experience:
            expertise.append('Research')
        deduped = []
        for item in expertise:
            if item not in deduped:
                deduped.append(item)
        return deduped[:10]

    def _mentor_specializations(self, mentor: Student) -> list[str]:
        skills = set(self._normalized_list(getattr(mentor, 'skills', None), lower=True))
        experience = ' '.join(self._normalized_list(getattr(mentor, 'experience', None), lower=True))
        specializations = []
        for key, values in MENTOR_SPECIALIZATIONS.items():
            if key in experience or key in skills:
                specializations.extend(values)
        if not specializations:
            specializations = ['Career Coaching', 'Interview Coaching', 'Resume Review']
        deduped = []
        for item in specializations:
            if item not in deduped:
                deduped.append(item)
        return deduped[:8]

    def _mentor_services(self, mentor: Student, expertise: list[str]) -> list[str]:
        services = ['Career Guidance', 'Resume Review', 'Mock Interview']
        if 'Frontend' in expertise or 'UI/UX' in expertise:
            services.append('Portfolio Review')
        if 'Open Source' in expertise:
            services.append('GitHub Review')
        if 'Cloud' in expertise or 'DevOps' in expertise or 'AI' in expertise:
            services.append('Certification Planning')
        if 'Product Management' in expertise:
            services.append('Leadership Coaching')
            services.append('Startup Mentoring')
        services.append('Learning Roadmap')
        services.append('Project Feedback')
        services.append('Industry Guidance')
        deduped = []
        for item in services:
            if item not in deduped:
                deduped.append(item)
        return deduped[:10]

    def _availability(self, mentor: Student) -> dict[str, Any]:
        experience_count = len(self._normalized_list(getattr(mentor, 'experience', None)))
        free = experience_count <= 3
        slots = ['Tuesday 19:00-20:00', 'Thursday 20:00-21:00'] if free else ['Saturday 10:00-11:00', 'Sunday 18:00-19:00']
        duration = 30 if free else 45
        session_type = SESSION_TYPES[experience_count % len(SESSION_TYPES)]
        pricing = 0 if free else min(75, 20 + experience_count * 8)
        return {
            'available_slots': slots,
            'session_duration_minutes': duration,
            'meeting_platform': MEETING_PLATFORMS[experience_count % len(MEETING_PLATFORMS)],
            'session_type': session_type,
            'pricing': pricing,
            'pricing_model': 'Free' if pricing == 0 else 'Paid',
        }

    def _mentorship_rating(self, mentor: Student, experience: list[str], expertise: list[str]) -> float:
        return round(min(5.0, 3.8 + len(experience) * 0.18 + len(expertise) * 0.04), 2)

    def _verification_status(self, mentor: Student) -> str:
        for field in ('verification_status', 'verified'):
            value = getattr(mentor, field, None)
            if isinstance(value, bool):
                return 'Verified' if value else 'Pending'
            if value:
                return str(value)
        return 'Verified'

    def _current_company(self, mentor: Student) -> str:
        companies = self._normalized_list(getattr(mentor, 'preferred_companies', None))
        if companies:
            return companies[0]
        experience = self._normalized_list(getattr(mentor, 'experience', None))
        if experience:
            return experience[0].split(' - ')[0][:60]
        return 'Independent Mentor'

    def _current_role(self, mentor: Student) -> str:
        headline = str(getattr(mentor, 'headline', None) or '').strip()
        if headline:
            return headline[:80]
        goal = str(getattr(mentor, 'career_goal', None) or '').strip()
        if goal:
            return goal[:80]
        return 'Senior Professional'

    def _specializations_from_goal(self, career_goal: str, target_role: str, skills: set[str]) -> list[str]:
        source = f'{career_goal} {target_role} {" ".join(sorted(skills))}'.lower()
        specializations = []
        for key, values in MENTOR_SPECIALIZATIONS.items():
            if key in source:
                specializations.extend(values)
        if not specializations:
            specializations = ['Career Coaching', 'Interview Coaching', 'Resume Review']
        deduped = []
        for item in specializations:
            if item not in deduped:
                deduped.append(item)
        return deduped[:8]

    def _missing_skills(self, ctx: MentorRecommendationContext) -> list[str]:
        if ctx.skill_gap is None:
            return []
        metadata = getattr(ctx.skill_gap, 'ranked_skills_metadata', None) or []
        if isinstance(metadata, dict):
            metadata = metadata.get('items', metadata.get('skills', []))
        return [str(item.get('skill')) for item in metadata if isinstance(item, dict) and item.get('skill')]

    def _learning_progress(self, ctx: MentorRecommendationContext) -> int:
        if ctx.career_report is not None:
            return int(getattr(ctx.career_report, 'weekly_progress', 6) or 6)
        return 6

    def _student_university(self, student: Student) -> str:
        return str(getattr(student, 'university', None) or getattr(getattr(student, 'university_ref', None), 'name', None) or '')

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))

    def _normalized_list(self, value: Any, lower: bool = False) -> list[str]:
        if isinstance(value, dict):
            items = [str(key) for key in value.keys() if str(key).strip()]
        elif isinstance(value, (list, tuple, set)):
            items = [str(item) for item in value if str(item).strip()]
        elif value in (None, ''):
            items = []
        else:
            items = [str(value)]
        return [item.lower() if lower else item for item in items]


class DefaultSessionPlanningEngine:
    def build(self, ctx: MentorRecommendationContext, mentor: Student, evidence: dict[str, Any], score: float) -> dict[str, Any]:
        availability = evidence['availability']
        learning_objectives = []
        if evidence['skill_gap_alignment']:
            learning_objectives.append(f"Close skill gaps in {', '.join(evidence['skill_gap_alignment'][:3])}.")
        if evidence['shared_career_goals']:
            learning_objectives.append(f"Clarify path toward {evidence['shared_career_goals']} roles.")
        if evidence['shared_company_interests']:
            learning_objectives.append(f"Discuss readiness for companies like {', '.join(evidence['shared_company_interests'][:2])}.")
        if not learning_objectives:
            learning_objectives.append('Prioritize the next 90 days of career preparation and execution.')
        questions = [
            'Which skills should I prioritize in the next 60 days?',
            'What projects best demonstrate readiness for my target role?',
            'How should I improve my resume and portfolio for recruiter screening?',
            'What interview gaps should I address first?',
        ]
        checklist = [
            'Review the mentor profile and recent experience.',
            'Prepare resume, portfolio, and GitHub links.',
            'List target roles, companies, and current blockers.',
            'Bring 2-3 projects and specific questions for feedback.',
        ]
        agenda = [
            'Career goals and current profile review',
            'Skill gap and project discussion',
            'Interview and application strategy',
            'Action plan and follow-up tasks',
        ]
        follow_up_tasks = [
            'Update resume using mentor feedback.',
            'Refine one project case study with measurable impact.',
            'Complete one learning milestone before the next session.',
            'Send progress update within one week.',
        ]
        return {
            'available_slots': availability['available_slots'],
            'session_duration_minutes': availability['session_duration_minutes'],
            'meeting_platform': availability['meeting_platform'],
            'session_type': availability['session_type'],
            'suggested_introduction': self._introduction(ctx, mentor, evidence),
            'session_agenda': agenda,
            'questions_to_ask': questions,
            'preparation_checklist': checklist,
            'learning_objectives': learning_objectives,
            'follow_up_tasks': follow_up_tasks,
            'pricing': availability['pricing'],
            'pricing_model': availability['pricing_model'],
        }

    def _introduction(self, ctx: MentorRecommendationContext, mentor: Student, evidence: dict[str, Any]) -> str:
        mentor_name = self._student_name(mentor)
        goal = evidence['shared_career_goals'] or str(getattr(ctx.student, 'career_goal', None) or 'my target role')
        skills = ', '.join(evidence['shared_skills'][:3]) if evidence['shared_skills'] else 'relevant technical skills'
        return f"Hi {mentor_name}, I\'m building toward {goal} and noticed our overlap in {skills}. I\'d value your guidance on improving my profile, projects, and interview readiness."

    def _student_name(self, student: Student) -> str:
        for field in ('full_name', 'name'):
            value = getattr(student, field, None)
            if value:
                return str(value)
        first = getattr(student, 'first_name', None)
        last = getattr(student, 'last_name', None)
        if first or last:
            return ' '.join([part for part in [str(first or '').strip(), str(last or '').strip()] if part])
        return 'Mentor'


class DefaultCareerCoachingEngine:
    def build(self, ctx: MentorRecommendationContext, mentor: Student, evidence: dict[str, Any], score: float) -> dict[str, Any]:
        career_score_improvement = min(18, max(4, round(score * 0.14)))
        interview_improvement = min(16, 5 + len(evidence['shared_technologies']) + len(evidence['skill_gap_alignment']))
        resume_improvement = min(14, 4 + len(evidence['shared_skills']) // 2 + (2 if 'Resume Review' in evidence['mentor_services'] else 0))
        networking_improvement = min(15, 5 + len(evidence['shared_company_interests']) * 2 + (2 if evidence['shared_university'] else 0))
        job_match_improvement = min(16, 5 + len(evidence['shared_skills']) + len(evidence['shared_projects']))
        offer_probability_improvement = min(14, 4 + len(evidence['shared_company_interests']) * 2 + len(evidence['shared_certifications']))
        career_benefits = [
            'Sharper career direction and prioritization.',
            'Better project framing and portfolio positioning.',
            'Stronger recruiter-facing narrative and networking strategy.',
            'Improved readiness for interviews and offers.',
        ]
        return {
            'career_score_improvement': career_score_improvement,
            'interview_readiness_improvement': interview_improvement,
            'resume_score_improvement': resume_improvement,
            'networking_improvement': networking_improvement,
            'job_match_improvement': job_match_improvement,
            'offer_probability_improvement': offer_probability_improvement,
            'expected_learning_value': 'High' if score >= 72 else 'Moderate',
            'career_benefits': career_benefits,
        }


class DefaultMentorRecommendationEngine:
    def __init__(
        self,
        matching_engine: MentorshipMatchingEngine | None = None,
        session_planning_engine: SessionPlanningEngine | None = None,
        career_coaching_engine: CareerCoachingEngine | None = None,
    ) -> None:
        self.matching_engine = matching_engine or DefaultMentorshipMatchingEngine()
        self.session_planning_engine = session_planning_engine or DefaultSessionPlanningEngine()
        self.career_coaching_engine = career_coaching_engine or DefaultCareerCoachingEngine()

    def recommend(self, ctx: MentorRecommendationContext) -> MentorRecommendation:
        ranked = self.matching_engine.rank(ctx)
        top_items = [self._mentor_payload(ctx, mentor, score, evidence) for mentor, score, evidence in ranked[:50]]
        recommendation = MentorRecommendation(
            student=ctx.student,
            generated_at=datetime.utcnow(),
            top_mentors=top_items,
        )
        recommendation.mentorship_services_metadata = {item['mentor_name']: item['mentorship_services'] for item in top_items[:20]}
        recommendation.session_information_metadata = {item['mentor_name']: item['session_information'] for item in top_items[:20]}
        recommendation.success_predictions_metadata = {item['mentor_name']: item['success_predictions'] for item in top_items[:20]}
        recommendation.smart_assistance_metadata = {item['mentor_name']: item['smart_assistance'] for item in top_items[:20]}
        recommendation.mentor_insights_metadata = {item['mentor_name']: item['mentor_insights'] for item in top_items[:20]}
        recommendation.ai_explanations_metadata = self._ai_explanations(top_items)
        recommendation.engine_metadata = {
            'mentor_recommendation_engine': self.__class__.__name__,
            'mentorship_matching_engine': self.matching_engine.__class__.__name__,
            'session_planning_engine': self.session_planning_engine.__class__.__name__,
            'career_coaching_engine': self.career_coaching_engine.__class__.__name__,
            'gemini_replaceable': True,
            'frontend_contract_stable': True,
        }
        return recommendation

    def _mentor_payload(self, ctx: MentorRecommendationContext, mentor: Student, score: float, evidence: dict[str, Any]) -> dict[str, Any]:
        session_info = self.session_planning_engine.build(ctx, mentor, evidence, score)
        coaching = self.career_coaching_engine.build(ctx, mentor, evidence, score)
        mentor_name = self._student_name(mentor)
        payload = {
            'mentor_name': mentor_name,
            'company': evidence['company'],
            'role': evidence['role'],
            'industry': evidence['industry'],
            'years_of_experience': evidence['years_of_experience'],
            'current_position': evidence['role'],
            'expertise': evidence['mentor_expertise'],
            'specializations': evidence['mentor_specializations'],
            'availability': evidence['availability']['pricing_model'],
            'languages': self._normalized_list(getattr(mentor, 'languages', None))[:6],
            'timezone': self._timezone(mentor),
            'location': str(getattr(mentor, 'preferred_location', None) or getattr(mentor, 'location', None) or 'Remote'),
            'mentorship_rating': evidence['mentorship_rating'],
            'verification_status': evidence['verification_status'],
            'mentor_compatibility_score': int(min(98, max(40, round(score)))),
            'mentorship_services': evidence['mentor_services'],
            'session_information': session_info,
            'why_this_mentor': self._why_this_mentor(evidence, coaching),
            'success_predictions': coaching,
            'smart_assistance': session_info,
            'mentor_insights': self._mentor_insights(mentor, evidence),
        }
        return payload

    def _why_this_mentor(self, evidence: dict[str, Any], coaching: dict[str, Any]) -> dict[str, Any]:
        reasons = []
        if evidence['shared_skills']:
            reasons.append(f"Shared skills include {', '.join(evidence['shared_skills'][:3])}.")
        if evidence['shared_career_goals']:
            reasons.append('Career goals are closely aligned.')
        if evidence['shared_technologies']:
            reasons.append(f"Shared technologies include {', '.join(evidence['shared_technologies'][:3])}.")
        if evidence['industry']:
            reasons.append(f"Relevant industry context in {evidence['industry']}.")
        if evidence['shared_company_interests']:
            reasons.append(f"Shared company interests include {', '.join(evidence['shared_company_interests'][:2])}.")
        if evidence['shared_projects']:
            reasons.append('Project experience overlap supports hands-on guidance.')
        if evidence['shared_certifications']:
            reasons.append(f"Shared certifications include {', '.join(evidence['shared_certifications'][:2])}.")
        reasons.append(f"Expected learning value is {coaching['expected_learning_value']} with strong career benefits.")
        return {
            'shared_skills': evidence['shared_skills'],
            'shared_career_goals': evidence['shared_career_goals'],
            'shared_technologies': evidence['shared_technologies'],
            'shared_industry': evidence['industry'],
            'shared_company_interests': evidence['shared_company_interests'],
            'shared_projects': evidence['shared_projects'],
            'shared_certifications': evidence['shared_certifications'],
            'expected_learning_value': coaching['expected_learning_value'],
            'career_benefits': coaching['career_benefits'],
            'summary': ' '.join(reasons),
        }

    def _mentor_insights(self, mentor: Student, evidence: dict[str, Any]) -> dict[str, Any]:
        experience_count = len(self._normalized_list(getattr(mentor, 'experience', None)))
        top_companies = evidence['shared_company_interests'] or self._normalized_list(getattr(mentor, 'preferred_companies', None))[:5]
        success_rate = min(96, 58 + experience_count * 6 + len(evidence['shared_skills']) * 2)
        response_time = max(4, 48 - experience_count * 3)
        session_length = evidence['availability']['session_duration_minutes']
        stories = [
            'Helped students strengthen resumes and convert more recruiter screens.',
            'Guided project improvements that improved interview storytelling.',
            'Supported role transitions through targeted skill-building plans.',
        ]
        return {
            'mentorship_success_rate': success_rate,
            'average_rating': evidence['mentorship_rating'],
            'student_success_stories': stories,
            'top_skills_taught': evidence['mentor_expertise'][:6],
            'top_companies_mentored_into': top_companies[:5],
            'average_response_time_hours': response_time,
            'average_session_length_minutes': session_length,
        }

    def _ai_explanations(self, top_items: list[dict[str, Any]]) -> dict[str, Any]:
        items = []
        for mentor in top_items[:20]:
            items.append({
                'mentor': mentor['mentor_name'],
                'why_recommended': mentor['why_this_mentor']['summary'],
                'expected_career_impact': mentor['success_predictions'],
                'supporting_evidence': {
                    'shared_skills': mentor['why_this_mentor']['shared_skills'],
                    'shared_technologies': mentor['why_this_mentor']['shared_technologies'],
                    'shared_projects': mentor['why_this_mentor']['shared_projects'],
                    'services': mentor['mentorship_services'],
                },
                'confidence_score': min(97, mentor['mentor_compatibility_score'] + 4),
            })
        return {'items': items}

    def _timezone(self, mentor: Student) -> str:
        location = str(getattr(mentor, 'preferred_location', None) or getattr(mentor, 'location', None) or '').lower()
        if 'india' in location or 'chennai' in location or 'bangalore' in location or 'hyderabad' in location:
            return 'IST'
        if 'singapore' in location:
            return 'SGT'
        if 'germany' in location or 'france' in location or 'europe' in location:
            return 'CET'
        if 'california' in location or 'seattle' in location or 'san francisco' in location:
            return 'PST'
        if 'new york' in location or 'boston' in location:
            return 'EST'
        return TIMEZONES[len(self._normalized_list(getattr(mentor, 'skills', None))) % len(TIMEZONES)]

    def _student_name(self, student: Student) -> str:
        for field in ('full_name', 'name'):
            value = getattr(student, field, None)
            if value:
                return str(value)
        first = getattr(student, 'first_name', None)
        last = getattr(student, 'last_name', None)
        if first or last:
            return ' '.join([part for part in [str(first or '').strip(), str(last or '').strip()] if part])
        return 'Mentor'

    def _normalized_list(self, value: Any) -> list[str]:
        if isinstance(value, dict):
            return [str(key) for key in value.keys() if str(key).strip()]
        if isinstance(value, (list, tuple, set)):
            return [str(item) for item in value if str(item).strip()]
        if value in (None, ''):
            return []
        return [str(value)]


class MentorRecommendationGenerator:
    def __init__(self, config: AppConfig = CONFIG, engine: MentorRecommendationEngine | None = None) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 21000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 21000)
            self.faker.seed_instance(config.generation.seed + 21000)
        self.engine = engine or DefaultMentorRecommendationEngine()

    def generate(
        self,
        students: Sequence[Student],
        companies: Sequence[Company],
        recruiters: Sequence[Recruiter],
        jobs: Sequence[Job],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
        career_reports: Sequence[CareerReport],
        skill_gaps: Sequence[SkillGap],
        learning_roadmaps: Sequence[Any],
        resume_analyses: Sequence[ResumeAnalysis],
        job_matches: Sequence[JobMatch],
        recruiter_recommendations: Sequence[RecruiterRecommendation],
        company_recommendations: Sequence[CompanyRecommendation],
        networking_recommendations: Sequence[NetworkingRecommendation],
    ) -> MentorRecommendationGenerationResult:
        if not students:
            raise ValueError('Mentor recommendation generation requires students.')

        interviews_by_student = self._records_by_student(interviews, 'student', application_fallback=True)
        offers_by_student = self._records_by_student(offers, 'student', application_fallback=True)
        jobs_by_student = self._jobs_by_student(students, jobs, interviews, offers)
        reports_by_student = {self._student_key(item.student): item for item in career_reports if getattr(item, 'student', None) is not None}
        gaps_by_student = {self._student_key(item.student): item for item in skill_gaps if getattr(item, 'student', None) is not None}
        roadmaps_by_student = {self._student_key(item.student): item for item in learning_roadmaps if getattr(item, 'student', None) is not None}
        resumes_by_student = {self._student_key(item.student): item for item in resume_analyses if getattr(item, 'student', None) is not None}
        matches_by_student = {self._student_key(item.student): item for item in job_matches if getattr(item, 'student', None) is not None}
        recruiter_recommendations_by_student = {self._student_key(item.student): item for item in recruiter_recommendations if getattr(item, 'student', None) is not None}
        company_recommendations_by_student = {self._student_key(item.student): item for item in company_recommendations if getattr(item, 'student', None) is not None}
        networking_recommendations_by_student = {self._student_key(item.student): item for item in networking_recommendations if getattr(item, 'student', None) is not None}

        results: list[MentorRecommendation] = []
        for student in students:
            key = self._student_key(student)
            ctx = MentorRecommendationContext(
                student=student,
                students=list(students),
                companies=list(companies),
                recruiters=list(recruiters),
                jobs=jobs_by_student.get(key, []),
                interviews=interviews_by_student.get(key, []),
                offers=offers_by_student.get(key, []),
                career_report=reports_by_student.get(key),
                skill_gap=gaps_by_student.get(key),
                learning_roadmap=roadmaps_by_student.get(key),
                resume_analysis=resumes_by_student.get(key),
                job_match=matches_by_student.get(key),
                recruiter_recommendation=recruiter_recommendations_by_student.get(key),
                company_recommendation=company_recommendations_by_student.get(key),
                networking_recommendation=networking_recommendations_by_student.get(key),
            )
            results.append(self.engine.recommend(ctx))
        return MentorRecommendationGenerationResult(mentor_recommendations=results)

    def _jobs_by_student(
        self,
        students: Sequence[Student],
        jobs: Sequence[Job],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
    ) -> dict[str, list[Job]]:
        mapping: dict[str, list[Job]] = defaultdict(list)
        for record in list(interviews) + list(offers):
            student = getattr(record, 'student', None)
            if student is None:
                application = getattr(record, 'application', None)
                student = getattr(application, 'student', None) if application is not None else None
            job = getattr(record, 'job', None)
            if job is None:
                application = getattr(record, 'application', None)
                job = getattr(application, 'job', None) if application is not None else None
            if student is None or job is None:
                continue
            mapping[self._student_key(student)].append(job)
        for student in students:
            key = self._student_key(student)
            if not mapping.get(key):
                mapping[key] = self._best_jobs_for_student(student, jobs)
        return mapping

    def _records_by_student(self, records: Sequence[Any], attr: str, application_fallback: bool = False) -> dict[str, list[Any]]:
        mapping: dict[str, list[Any]] = defaultdict(list)
        for record in records:
            student = getattr(record, attr, None)
            if student is None and application_fallback:
                application = getattr(record, 'application', None)
                student = getattr(application, 'student', None) if application is not None else None
            if student is None:
                continue
            mapping[self._student_key(student)].append(record)
        return mapping

    def _best_jobs_for_student(self, student: Student, jobs: Sequence[Job]) -> list[Job]:
        student_skills = {str(item).strip().lower() for item in self._normalized_list(getattr(student, 'skills', None))}
        career_goal = str(getattr(student, 'career_goal', '') or '').lower()
        preferred_location = str(getattr(student, 'preferred_location', '') or '').lower()
        ranked = []
        for job in jobs:
            required = {str(item).strip().lower() for item in self._normalized_list(getattr(job, 'skills_required', None))}
            preferred = {str(item).strip().lower() for item in self._normalized_list(getattr(job, 'preferred_skills', None))}
            role = str(getattr(job, 'role', None) or getattr(job, 'title', None) or getattr(job, 'job_title', None) or '').lower()
            location = ' '.join([
                str(getattr(job, 'location_city', None) or ''),
                str(getattr(job, 'location_country', None) or ''),
            ]).lower()
            score = len(student_skills & required) * 5 + len(student_skills & preferred) * 2
            if career_goal and any(token in role for token in career_goal.split() if len(token) > 2):
                score += 6
            if preferred_location and preferred_location in location:
                score += 4
            ranked.append((score, job))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [job for _, job in ranked[:60]]

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))

    def _normalized_list(self, value: Any) -> list[str]:
        if isinstance(value, dict):
            return [str(key) for key in value.keys() if str(key).strip()]
        if isinstance(value, (list, tuple, set)):
            return [str(item) for item in value if str(item).strip()]
        if value in (None, ''):
            return []
        return [str(value)]


def generate_mentor_recommendations(
    students: Sequence[Student],
    companies: Sequence[Company],
    recruiters: Sequence[Recruiter],
    jobs: Sequence[Job],
    interviews: Sequence[Interview],
    offers: Sequence[Offer],
    career_reports: Sequence[CareerReport],
    skill_gaps: Sequence[SkillGap],
    learning_roadmaps: Sequence[Any],
    resume_analyses: Sequence[ResumeAnalysis],
    job_matches: Sequence[JobMatch],
    recruiter_recommendations: Sequence[RecruiterRecommendation],
    company_recommendations: Sequence[CompanyRecommendation],
    networking_recommendations: Sequence[NetworkingRecommendation],
    config: AppConfig = CONFIG,
) -> MentorRecommendationGenerationResult:
    generator = MentorRecommendationGenerator(config=config)
    return generator.generate(
        students=students,
        companies=companies,
        recruiters=recruiters,
        jobs=jobs,
        interviews=interviews,
        offers=offers,
        career_reports=career_reports,
        skill_gaps=skill_gaps,
        learning_roadmaps=learning_roadmaps,
        resume_analyses=resume_analyses,
        job_matches=job_matches,
        recruiter_recommendations=recruiter_recommendations,
        company_recommendations=company_recommendations,
        networking_recommendations=networking_recommendations,
    )


