@dataclass(slots=True)
class MessageGenerationResult:
    threads: list[MessageThread]
    messages: list[Message]


class MessageGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 7000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 7000)
            self.faker.seed_instance(config.generation.seed + 7000)

    def generate(self, users: Sequence[Any]) -> MessageGenerationResult:
        if not users:
            raise ValueError('Message generation requires at least one user-like object.')

        pools = self._build_role_pools(users)
        threads: list[MessageThread] = []
        messages: list[Message] = []

        for thread_index in range(self.config.counts.conversations):
            conversation_type = self.random.choice(CONVERSATION_TYPES)
            participant_pattern = self._pattern_for_conversation(conversation_type)
            participants = self._select_participants(participant_pattern, pools)
            if participants is None:
                continue
            thread = self._build_thread(thread_index, conversation_type, participants)
            thread_messages = self._build_messages(thread, conversation_type, participants)
            threads.append(thread)
            messages.extend(thread_messages)

        return MessageGenerationResult(threads=threads, messages=messages)

    def _build_role_pools(self, users: Sequence[Any]) -> dict[str, list[Any]]:
        pools: dict[str, list[Any]] = {
            'Student': [], 'Recruiter': [], 'Mentor': [], 'Hiring Manager': [], 'University': [], 'Employer': [], 'Admin': [], 'User': []
        }
        for user in users:
            role_name = self._role_name(user)
            pools['User'].append(user)
            if role_name == 'student':
                pools['Student'].append(user)
            elif role_name == 'recruiter':
                pools['Recruiter'].append(user)
                pools['Hiring Manager'].append(user)
                pools['Employer'].append(user)
            elif role_name == 'mentor':
                pools['Mentor'].append(user)
            elif role_name == 'admin':
                pools['Admin'].append(user)
            elif role_name == 'university':
                pools['University'].append(user)
            else:
                if getattr(user, 'company', None) is not None:
                    pools['Employer'].append(user)
                pools['Mentor'].append(user)
        if not pools['Mentor']:
            pools['Mentor'] = pools['Recruiter'][:]
        if not pools['University']:
            pools['University'] = pools['Admin'][:] or pools['Recruiter'][:]
        if not pools['Admin']:
            pools['Admin'] = pools['Recruiter'][:1] or pools['User'][:1]
        if not pools['Employer']:
            pools['Employer'] = pools['Recruiter'][:]
        if not pools['Hiring Manager']:
            pools['Hiring Manager'] = pools['Recruiter'][:]
        return pools

    def _role_name(self, user: Any) -> str:
        role = getattr(user, 'role', None)
        if role is None:
            return str(getattr(user, 'user_type', '')).lower()
        value = getattr(role, 'value', None) or getattr(role, 'name', None) or str(role)
        return str(value).lower()

    def _pattern_for_conversation(self, conversation_type: str) -> tuple[str, str]:
        preferred: dict[str, list[tuple[str, str]]] = {
            'Job Inquiry': [('Student', 'Recruiter')],
            'Interview Scheduling': [('Student', 'Recruiter')],
            'Offer Discussion': [('Student', 'Recruiter')],
            'Campus Hiring': [('Recruiter', 'University'), ('Employer', 'University')],
            'Referral Request': [('Student', 'Recruiter'), ('Student', 'Mentor')],
            'Networking': [('Student', 'Mentor'), ('Student', 'Student')],
            'Mentorship': [('Student', 'Mentor')],
            'Portfolio Review': [('Student', 'Mentor'), ('Student', 'Recruiter')],
            'Resume Review': [('Student', 'Recruiter'), ('Student', 'Mentor')],
            'Career Advice': [('Student', 'Mentor')],
            'Internship Discussion': [('Student', 'Recruiter')],
            'Placement Coordination': [('Recruiter', 'University'), ('Employer', 'University')],
            'Technical Discussion': [('Student', 'Mentor'), ('Recruiter', 'Hiring Manager')],
            'Event Registration': [('University', 'Student')],
            'Support Ticket': [('Admin', 'User')],
            'General Networking': [('Student', 'Student'), ('Recruiter', 'Recruiter')],
        }
        options = preferred.get(conversation_type, list(PARTICIPANT_PATTERNS))
        return self.random.choice(options)

    def _select_participants(self, pattern: tuple[str, str], pools: dict[str, list[Any]]) -> tuple[Any, Any] | None:
        left_candidates = pools.get(pattern[0], [])
        right_candidates = pools.get(pattern[1], [])
        if not left_candidates or not right_candidates:
            return None
        left = self.random.choice(left_candidates)
        right = self.random.choice(right_candidates)
        attempts = 0
        while left is right and attempts < 5:
            right = self.random.choice(right_candidates)
            attempts += 1
        if left is right:
            return None
        return left, right

    def _search_metadata(self, conversation_type: str) -> dict[str, Any]:
        return {'conversation_type': conversation_type, 'indexed': True}

    def _build_thread(self, thread_index: int, conversation_type: str, participants: tuple[Any, Any]) -> MessageThread:
        left, right = participants
        created_at = datetime.utcnow() - timedelta(days=self.random.randint(1, 120), hours=self.random.randint(0, 23))
        category = self._category(conversation_type)
        subject = self._thread_subject(conversation_type, left, right)
        search_metadata = self._search_metadata(conversation_type)
        ai_metadata = self._thread_ai_metadata(conversation_type)
        analytics = self._thread_analytics()
        network = self._network_metadata(participants)
        notifications = self._thread_notifications_seed(created_at)
        gemini = self._gemini_metadata(conversation_type)

        thread = MessageThread(
            subject=subject,
            conversation_type=conversation_type,
            category=category,
            created_at=created_at,
            updated_at=created_at,
            participant_one=left,
            participant_two=right,
            is_archived=self.random.random() < 0.12,
            is_pinned=self.random.random() < 0.16,
        )
        thread.search_metadata = search_metadata
        thread.ai_metadata = ai_metadata
        thread.analytics_metadata = analytics
        thread.network_metadata = network
        thread.notification_metadata = notifications
        thread.future_ai_metadata = gemini
        return thread

    def _build_messages(self, thread: MessageThread, conversation_type: str, participants: tuple[Any, Any]) -> list[Message]:
        left, right = participants
        template_messages = TOPIC_LIBRARY[conversation_type]
        message_target = max(4, min(self.config.counts.messages_per_conversation, len(template_messages) + self.random.randint(0, 3)))
        started_at = thread.created_at
        role_map = {
            'Student': left if self._participant_label(left) == 'Student' else right,
            'Recruiter': left if self._participant_label(left) == 'Recruiter' else right,
            'Mentor': left if self._participant_label(left) == 'Mentor' else right,
            'University': left if self._participant_label(left) == 'University' else right,
            'Admin': left if self._participant_label(left) == 'Admin' else right,
            'Employer': left if self._participant_label(left) == 'Employer' else right,
            'Hiring Manager': left if self._participant_label(left) == 'Hiring Manager' else right,
            'User': left,
        }
        context = self._message_context(thread, participants)
        built: list[Message] = []
        current_time = started_at

        for index in range(message_target):
            template = template_messages[index % len(template_messages)]
            sender = role_map.get(template['speaker']) or (left if index % 2 == 0 else right)
            receiver = right if sender is left else left
            current_time = current_time + timedelta(hours=self.random.randint(2, 18), minutes=self.random.randint(3, 58))
            body = template['text'].format(**context)
            attachments = self._attachments_for_template(template['attachments'], sender, current_time)
            status_metadata = self._message_status(current_time)
            ai_writing = self._ai_writing_support(body, conversation_type)
            search_metadata = self._message_search_metadata(conversation_type, body, attachments, index)
            meeting_metadata = self._meeting_metadata(template['attachments'], current_time, context)
            notifications = self._message_notifications(status_metadata, current_time)
            analytics = self._message_analytics(status_metadata)
            ai_metadata = self._message_ai_metadata(conversation_type, body)
            future_ai = self._future_message_ai_metadata(body, conversation_type)
            message_type = self._message_type(attachments)

            message = Message(
                thread=thread,
                sender=sender,
                recipient=receiver,
                body=body,
                sent_at=current_time,
                delivered_at=status_metadata['delivered_at'],
                read_at=status_metadata['read_at'],
                message_type=message_type,
                is_edited=status_metadata['edited'],
                is_deleted=status_metadata['deleted'],
                is_pinned=status_metadata['pinned'],
                is_archived=status_metadata['archived'],
                is_starred=status_metadata['starred'],
            )
            message.attachments_metadata = attachments
            message.ai_writing_support_metadata = ai_writing
            message.search_metadata = search_metadata
            message.meeting_metadata = meeting_metadata
            message.notification_metadata = notifications
            message.analytics_metadata = analytics
            message.ai_metadata = ai_metadata
            message.future_ai_metadata = future_ai
            built.append(message)

        if built:
            thread.updated_at = built[-1].sent_at
            thread.analytics_metadata['conversation_length'] = len(built)
            thread.analytics_metadata['average_messages'] = len(built)
            thread.analytics_metadata['engagement_score'] = self._engagement_score(built)
        return built

    def _participant_label(self, participant: Any) -> str:
        role_name = self._role_name(participant)
        if role_name == 'student':
            return 'Student'
        if role_name == 'recruiter':
            return 'Recruiter'
        if role_name == 'mentor':
            return 'Mentor'
        if role_name == 'admin':
            return 'Admin'
        if role_name == 'university':
            return 'University'
        if getattr(participant, 'company', None) is not None:
            return 'Employer'
        return 'User'

    def _message_context(self, thread: MessageThread, participants: tuple[Any, Any]) -> dict[str, str]:
        left, right = participants
        company = getattr(left, 'company', None) or getattr(right, 'company', None)
        job_title = getattr(company, 'name', None)
        if hasattr(left, 'job_title'):
            job_title = getattr(left, 'job_title')
        role = self.random.choice([
            'Software Engineer', 'Data Analyst', 'Machine Learning Engineer', 'Frontend Engineer', 'Product Designer', 'Associate Product Manager'
        ])
        return {
            'role': role,
            'company': getattr(company, 'name', 'CareerBridge Partner'),
            'skill': self.random.choice(['Python', 'React', 'SQL', 'System Design', 'AWS', 'Java']),
            'department': self.random.choice(['Engineering', 'Data', 'Product', 'Design', 'Cloud', 'Operations']),
            'interview_type': self.random.choice(['technical interview', 'behavioral round', 'recruiter call', 'manager round']),
            'timezone': self.random.choice(['Asia/Kolkata', 'Europe/London', 'America/Los_Angeles', 'America/Toronto']),
            'month': self.random.choice(['May', 'June', 'July', 'August']),
        }

    def _attachments_for_template(self, attachment_keys: list[str], sender: Any, sent_at: datetime) -> list[dict[str, Any]]:
        attachments: list[dict[str, Any]] = []
        sender_key = self._slug(str(getattr(sender, 'id', None) or getattr(sender, 'email', 'user')))
        stamp = sent_at.strftime('%Y%m%d')
        for key in attachment_keys:
            if key == 'resume':
                attachments.append({'type': 'Resume Metadata', 'file_name': f'{sender_key}_resume_{stamp}.pdf', 'size_kb': self.random.randint(180, 540)})
            elif key == 'portfolio':
                attachments.append({'type': 'Portfolio Link', 'url': f'https://portfolio.example.dev/{sender_key}'})
            elif key == 'offer_letter':
                attachments.append({'type': 'Offer Letter', 'file_name': f'{sender_key}_offer_letter_{stamp}.pdf', 'size_kb': self.random.randint(280, 760)})
            elif key == 'calendar_invite':
                attachments.append({'type': 'Calendar Invite', 'file_name': f'{sender_key}_meeting_invite_{stamp}.ics'})
            elif key == 'interview_invite':
                attachments.append({'type': 'Interview Invite', 'meeting_link': f'https://meet.example.dev/{sender_key}/{stamp}', 'platform': self.random.choice(['Google Meet', 'Zoom', 'Microsoft Teams'])})
            elif key == 'presentation':
                attachments.append({'type': 'PDF Metadata', 'file_name': f'{sender_key}_event_overview_{stamp}.pdf', 'size_kb': self.random.randint(900, 2400)})
            elif key == 'pdf':
                attachments.append({'type': 'PDF Metadata', 'file_name': f'{sender_key}_document_{stamp}.pdf', 'size_kb': self.random.randint(200, 1200)})
        if self.random.random() < 0.08:
            attachments.append({'type': 'Voice Placeholder', 'voice_token': f'voice-{sender_key}-{stamp}'})
        if self.random.random() < 0.04:
            attachments.append({'type': 'Video Placeholder', 'video_token': f'video-{sender_key}-{stamp}'})
        return attachments

    def _message_status(self, sent_at: datetime) -> dict[str, Any]:
        delivered_at = sent_at + timedelta(seconds=self.random.randint(5, 180))
        read = self.random.random() < 0.82
        read_at = delivered_at + timedelta(minutes=self.random.randint(1, 240)) if read else None
        edited = self.random.random() < 0.08
        deleted = self.random.random() < 0.02
        return {
            'status': 'read' if read else 'delivered',
            'delivered_at': delivered_at,
            'read_at': read_at,
            'edited': edited,
            'deleted': deleted,
            'pinned': self.random.random() < 0.06,
            'archived': self.random.random() < 0.05,
            'starred': self.random.random() < 0.11,
        }

    def _ai_writing_support(self, body: str, conversation_type: str) -> dict[str, Any]:
        return {
            'suggested_replies': self._suggested_replies(conversation_type),
            'professional_tone': body,
            'friendly_tone': body.replace('Thank you', 'Thanks').replace('I would like to', 'I would love to'),
            'formal_tone': body.replace('Thanks', 'Thank you').replace('Happy to', 'I would be pleased to'),
            'follow_up_suggestions': [
                'Send a concise follow-up within two business days if there is no response.',
                'Acknowledge receipt of important updates and clarify next steps.',
            ],
            'interview_reply_suggestions': [
                'Confirm your slot and mention timezone clearly.',
                'Ask for preparation guidance if the interview format is not clear.',
            ],
            'salary_negotiation_suggestions': [
                'Anchor the discussion around total compensation and role scope.',
                'Keep negotiation polite, concise, and evidence-based.',
            ],
        }

    def _suggested_replies(self, conversation_type: str) -> list[str]:
        bank = {
            'Interview Scheduling': ['Thursday morning works for me. Please share the meeting details.', 'Thank you. I confirm the slot and will join early.'],
            'Offer Discussion': ['Thank you for sharing the offer. I am reviewing the details and will respond shortly.', 'I appreciate the offer. Could we discuss compensation structure and joining timeline?'],
            'Resume Review': ['Thank you for the feedback. I will revise the resume accordingly.', 'That is very helpful. I will update the project bullets and reshare.'],
        }
        return bank.get(conversation_type, ['Thank you for the update.', 'That is helpful. I will review and respond shortly.'])

    def _message_search_metadata(self, conversation_type: str, body: str, attachments: list[dict[str, Any]], index: int) -> dict[str, Any]:
        tags = [self._category(conversation_type), conversation_type.lower().replace(' ', '_')]
        if attachments:
            tags.append('attachment')
        return {
            'keywords': self._keywords(body),
            'tags': tags,
            'category': self._category(conversation_type),
            'importance': self.random.choice(PRIORITY_VALUES),
            'pinned': self.random.random() < 0.08,
            'unread': self.random.random() < 0.18 if index > 0 else False,
            'follow_up_required': any(term in body.lower() for term in ['review', 'confirm', 'respond', 'share', 'available']),
        }

    def _meeting_metadata(self, attachment_keys: list[dict[str, Any]] | list[str], sent_at: datetime, context: dict[str, str]) -> dict[str, Any] | None:
        keys = attachment_keys if attachment_keys and isinstance(attachment_keys[0], str) else [] if not attachment_keys else []
        flat_keys = keys if keys else []
        if 'calendar_invite' not in flat_keys and 'interview_invite' not in flat_keys:
            return None
        platform = self.random.choice(['Google Meet', 'Zoom', 'Microsoft Teams'])
        return {
            'interview_invite': 'interview_invite' in flat_keys,
            'google_meet_placeholder': f'https://meet.example.dev/{self._slug(context["company"])}-{sent_at.strftime("%H%M")}' if platform == 'Google Meet' else None,
            'zoom_placeholder': f'https://zoom.example.dev/{self._slug(context["company"])}-{sent_at.strftime("%H%M")}' if platform == 'Zoom' else None,
            'teams_placeholder': f'https://teams.example.dev/{self._slug(context["company"])}-{sent_at.strftime("%H%M")}' if platform == 'Microsoft Teams' else None,
            'calendar_invite': f'{self._slug(context["company"])}-{sent_at.strftime("%Y%m%d")}.ics',
            'reminder': (sent_at + timedelta(hours=12)).isoformat(),
        }

    def _message_notifications(self, status_metadata: dict[str, Any], sent_at: datetime) -> list[dict[str, Any]]:
        items = [{'type': 'Reply', 'timestamp': sent_at.isoformat()}]
        if status_metadata['read_at'] is None:
            items.append({'type': 'Unread', 'timestamp': (sent_at + timedelta(hours=2)).isoformat()})
        if status_metadata['pinned']:
            items.append({'type': 'Mention', 'timestamp': sent_at.isoformat()})
        return items

    def _message_analytics(self, status_metadata: dict[str, Any]) -> dict[str, Any]:
        read_time = None
        if status_metadata['read_at'] is not None:
            read_time = int((status_metadata['read_at'] - status_metadata['delivered_at']).total_seconds() // 60)
        return {
            'response_time_minutes': self.random.randint(18, 480),
            'response_rate': self.random.randint(62, 97),
            'read_time_minutes': read_time,
            'engagement_score': self.random.randint(52, 96),
            'recruiter_responsiveness': self.random.randint(58, 95),
            'mentor_responsiveness': self.random.randint(64, 98),
        }

    def _message_ai_metadata(self, conversation_type: str, body: str) -> dict[str, Any]:
        return {
            'conversation_sentiment': self.random.choice(SENTIMENT_VALUES),
            'professionalism_score': self.random.randint(78, 98),
            'spam_score': self.random.randint(0, 14),
            'response_prediction': self.random.randint(54, 96),
            'conversation_category': conversation_type,
            'priority': self.random.choice(PRIORITY_VALUES),
            'urgency': self.random.choice(['low', 'moderate', 'high']),
            'meeting_probability': self.random.randint(18, 88) if any(term in body.lower() for term in ['interview', 'meeting', 'schedule']) else self.random.randint(4, 34),
            'offer_probability': self.random.randint(12, 74) if any(term in body.lower() for term in ['offer', 'compensation', 'joining']) else self.random.randint(2, 22),
        }

    def _future_message_ai_metadata(self, body: str, conversation_type: str) -> dict[str, Any]:
        return {
            'ai_chat_assistant': True,
            'auto_reply': self._suggested_replies(conversation_type)[:1],
            'conversation_summary': body[:160],
            'meeting_summary': 'Meeting details discussed.' if any(term in body.lower() for term in ['meeting', 'interview', 'schedule']) else None,
            'interview_preparation': 'Review role fundamentals, recent projects, and structured behavioral examples.' if 'interview' in body.lower() else None,
            'follow_up_generator': 'Send a concise follow-up within 48 hours if no response is received.',
            'grammar_check': 'clean',
            'tone_improvement': 'Slightly shorten the opening sentence for crisper professional tone.' if len(body) > 170 else 'Tone is appropriately professional.',
            'message_translation': {'supported': True, 'target_languages': ['English', 'Hindi', 'Tamil', 'German']},
        }

    def _category(self, conversation_type: str) -> str:
        mapping = {
            'Job Inquiry': 'recruiting',
            'Interview Scheduling': 'recruiting',
            'Offer Discussion': 'offers',
            'Campus Hiring': 'placement',
            'Referral Request': 'networking',
            'Networking': 'networking',
            'Mentorship': 'mentorship',
            'Portfolio Review': 'career_support',
            'Resume Review': 'career_support',
            'Career Advice': 'mentorship',
            'Internship Discussion': 'recruiting',
            'Placement Coordination': 'placement',
            'Technical Discussion': 'technical',
            'Event Registration': 'events',
            'Support Ticket': 'support',
            'General Networking': 'networking',
        }
        return mapping.get(conversation_type, 'general')

    def _thread_subject(self, conversation_type: str, left: Any, right: Any) -> str:
        left_name = self._display_name(left)
        right_name = self._display_name(right)
        subjects = {
            'Job Inquiry': 'Question about current role alignment',
            'Interview Scheduling': 'Interview availability and scheduling',
            'Offer Discussion': 'Offer review and next steps',
            'Campus Hiring': 'Campus hiring collaboration discussion',
            'Referral Request': 'Referral request for an open role',
            'Networking': 'Connecting on career direction',
            'Mentorship': 'Career guidance conversation',
            'Portfolio Review': 'Portfolio feedback request',
            'Resume Review': 'Resume review and recommendations',
            'Career Advice': 'Career path advice',
            'Internship Discussion': 'Internship opportunity discussion',
            'Placement Coordination': 'Placement planning and coordination',
            'Technical Discussion': 'Technical preparation discussion',
            'Event Registration': 'Event registration follow-up',
            'Support Ticket': 'Support request update',
            'General Networking': 'Professional networking conversation',
        }
        return f"{subjects.get(conversation_type, conversation_type)} - {left_name} / {right_name}"

    def _thread_ai_metadata(self, conversation_type: str) -> dict[str, Any]:
        return {
            'conversation_sentiment': self.random.choice(SENTIMENT_VALUES),
            'professionalism_score': self.random.randint(80, 98),
            'spam_score': self.random.randint(0, 10),
            'response_prediction': self.random.randint(58, 96),
            'conversation_category': conversation_type,
            'priority': self.random.choice(PRIORITY_VALUES),
            'urgency': self.random.choice(['low', 'moderate', 'high']),
            'meeting_probability': self.random.randint(12, 88),
            'offer_probability': self.random.randint(4, 72),
        }

    def _thread_analytics(self) -> dict[str, Any]:
        return {
            'response_time_minutes': self.random.randint(24, 720),
            'response_rate': self.random.randint(64, 98),
            'conversation_length': 0,
            'read_time_minutes': self.random.randint(2, 180),
            'average_messages': 0,
            'engagement_score': 0,
            'recruiter_responsiveness': self.random.randint(60, 96),
            'mentor_responsiveness': self.random.randint(66, 98),
        }

    def _network_metadata(self, participants: tuple[Any, Any]) -> dict[str, Any]:
        return {
            'connections': [self._display_name(participants[0]), self._display_name(participants[1])],
            'mentors': [self._display_name(p) for p in participants if self._participant_label(p) == 'Mentor'],
            'recruiters': [self._display_name(p) for p in participants if self._participant_label(p) == 'Recruiter'],
            'hiring_managers': [self._display_name(p) for p in participants if self._participant_label(p) == 'Hiring Manager'],
            'universities': [self._display_name(p) for p in participants if self._participant_label(p) == 'University'],
            'communities': self.random.sample(['Graduate Talent Circle', 'Campus Hiring Network', 'AI Career Community', 'Women in Tech Forum'], k=self.random.randint(1, 2)),
        }

    def _thread_notifications_seed(self, created_at: datetime) -> list[dict[str, Any]]:
        return [{'type': 'Unread', 'timestamp': created_at.isoformat()}]

    def _gemini_metadata(self, conversation_type: str) -> dict[str, Any]:
        return {
            'ai_chat_assistant': True,
            'auto_reply': self._suggested_replies(conversation_type)[:1],
            'conversation_summary': f'{conversation_type} conversation thread.',
            'meeting_summary': 'Available when scheduling-related messages are detected.',
            'interview_preparation': 'Enabled for interview and offer-related conversations.',
            'follow_up_generator': 'Enabled',
            'grammar_check': 'enabled',
            'tone_improvement': 'enabled',
            'message_translation': {'enabled': True, 'languages': ['English', 'Hindi', 'Tamil', 'German']},
        }

    def _keywords(self, body: str) -> list[str]:
        tokens = re.findall(r'[A-Za-z]{4,}', body.lower())
        unique: list[str] = []
        for token in tokens:
            if token not in unique:
                unique.append(token)
            if len(unique) >= 8:
                break
        return unique

    def _engagement_score(self, messages: list[Message]) -> int:
        read_count = sum(1 for message in messages if getattr(message, 'read_at', None) is not None)
        pinned_count = sum(1 for message in messages if getattr(message, 'is_pinned', False))
        attachment_count = sum(len(getattr(message, 'attachments_metadata', []) or []) for message in messages)
        score = 50 + read_count * 4 + pinned_count * 3 + min(18, attachment_count * 2)
        return min(98, score)

    def _message_type(self, attachments: list[dict[str, Any]]) -> str:
        if not attachments:
            return 'Text'
        attachment_type = attachments[0].get('type', 'Text')
        if attachment_type in {'Portfolio Link', 'GitHub Link'}:
            return attachment_type
        return attachment_type if attachment_type != 'PDF Metadata' else 'Text'

    def _display_name(self, participant: Any) -> str:
        full_name = getattr(participant, 'full_name', None)
        if full_name:
            return str(full_name)
        first_name = getattr(participant, 'first_name', None)
        last_name = getattr(participant, 'last_name', None)
        if first_name or last_name:
            return f"{first_name or ''} {last_name or ''}".strip()
        email = getattr(participant, 'email', None)
        if email:
            return str(email).split('@')[0]
        return 'User'

    def _slug(self, value: str) -> str:
        slug = re.sub(r'[^a-z0-9]+', '-', value.lower()).strip('-')
        return slug or 'item'


def generate_messages(users: Sequence[Any], config: AppConfig = CONFIG) -> MessageGenerationResult:
    generator = MessageGenerator(config=config)
    return generator.generate(users)


