class DefaultRelationshipScoringEngine:
    def score(self, student: Student, candidate: Any, context: dict[str, Any]) -> dict[str, int]:
        shared_skills = len(context.get('shared_skills', []))
        shared_communities = len(context.get('shared_communities', []))
        mutual_connections = int(context.get('mutual_connections', 0))
        shared_university = 1 if context.get('shared_university') else 0
        same_goal = 1 if context.get('shared_career_goals') else 0
        candidate_strength = int(context.get('candidate_strength', 55))
        connection_strength = self._clamp(38 + shared_skills * 7 + shared_communities * 6 + mutual_connections * 3 + shared_university * 10)
        career_relevance = self._clamp(42 + shared_skills * 6 + same_goal * 12 + candidate_strength * 0.22)
        knowledge_value = self._clamp(45 + candidate_strength * 0.28 + len(context.get('shared_technologies', [])) * 5)
        mentorship_value = self._clamp(36 + int(context.get('mentorship_signal', 0)) * 18 + shared_university * 8 + len(context.get('shared_projects', [])) * 5)
        referral_potential = self._clamp(32 + int(context.get('referral_signal', 0)) * 20 + mutual_connections * 4 + candidate_strength * 0.20)
        collaboration_potential = self._clamp(40 + len(context.get('shared_projects', [])) * 9 + shared_skills * 5 + len(context.get('shared_interests', [])) * 4)
        response_probability = self._clamp(34 + connection_strength * 0.25 + referral_potential * 0.18 + int(context.get('message_signal', 0)) * 8)
        overall = self._clamp(mean([
            connection_strength,
            career_relevance,
            knowledge_value,
            mentorship_value,
            referral_potential,
            collaboration_potential,
            response_probability,
        ]))
        return {
            'connection_strength': int(round(connection_strength)),
            'career_relevance': int(round(career_relevance)),
            'knowledge_value': int(round(knowledge_value)),
            'mentorship_value': int(round(mentorship_value)),
            'referral_potential': int(round(referral_potential)),
            'collaboration_potential': int(round(collaboration_potential)),
            'response_probability': int(round(response_probability)),
            'overall_network_score': int(round(overall)),
        }

    def _clamp(self, value: float) -> float:
        return max(25.0, min(98.0, value))


class DefaultConnectionRecommendationEngine:
    def __init__(self, scoring_engine: RelationshipScoringEngine | None = None) -> None:
        self.scoring_engine = scoring_engine or DefaultRelationshipScoringEngine()

    def build(self, ctx: NetworkingRecommendationContext) -> dict[str, list[dict[str, Any]]]:
        return {
            'suggested_connections': self._suggested_students(ctx, limit=50),
            'suggested_recruiters': self._suggested_recruiters(ctx, limit=30),
            'suggested_mentors': self._suggested_mentors(ctx, limit=25),
            'suggested_alumni': self._suggested_alumni(ctx, limit=25),
            'suggested_students': self._suggested_students(ctx, limit=30),
            'suggested_industry_experts': self._suggested_industry_experts(ctx, limit=20),
            'suggested_hiring_managers': self._suggested_hiring_managers(ctx, limit=20),
        }

    def _suggested_students(self, ctx: NetworkingRecommendationContext, limit: int) -> list[dict[str, Any]]:
        ranked = []
        for candidate in ctx.students:
            if self._student_key(candidate) == self._student_key(ctx.student):
                continue
            shared = self._shared_student_context(ctx.student, candidate, ctx)
            scores = self.scoring_engine.score(ctx.student, candidate, shared)
            ranked.append((scores['overall_network_score'], self._student_payload(candidate, shared, scores, 'Student')))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [payload for _, payload in ranked[:limit]]

    def _suggested_alumni(self, ctx: NetworkingRecommendationContext, limit: int) -> list[dict[str, Any]]:
        current_university = self._student_university(ctx.student).lower()
        ranked = []
        for candidate in ctx.students:
            if self._student_key(candidate) == self._student_key(ctx.student):
                continue
            if self._student_university(candidate).lower() != current_university:
                continue
            grad_year = int(getattr(candidate, 'graduation_year', 0) or 0)
            student_grad_year = int(getattr(ctx.student, 'graduation_year', 0) or 0)
            if grad_year <= 0 or student_grad_year <= 0 or grad_year >= student_grad_year:
                continue
            shared = self._shared_student_context(ctx.student, candidate, ctx)
            shared['mentorship_signal'] = 1
            shared['referral_signal'] = 1
            scores = self.scoring_engine.score(ctx.student, candidate, shared)
            ranked.append((scores['overall_network_score'], self._student_payload(candidate, shared, scores, 'Alumni')))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [payload for _, payload in ranked[:limit]]

    def _suggested_mentors(self, ctx: NetworkingRecommendationContext, limit: int) -> list[dict[str, Any]]:
        ranked = []
        for candidate in ctx.students:
            if self._student_key(candidate) == self._student_key(ctx.student):
                continue
            experience_count = len(self._normalized_list(getattr(candidate, 'experience', None)))
            if experience_count < 2:
                continue
            shared = self._shared_student_context(ctx.student, candidate, ctx)
            shared['mentorship_signal'] = 1
            shared['candidate_strength'] += experience_count * 6
            scores = self.scoring_engine.score(ctx.student, candidate, shared)
            payload = self._student_payload(candidate, shared, scores, 'Mentor')
            payload['mentorship_focus'] = self._mentorship_focus(candidate)
            ranked.append((scores['overall_network_score'], payload))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [payload for _, payload in ranked[:limit]]

    def _suggested_recruiters(self, ctx: NetworkingRecommendationContext, limit: int) -> list[dict[str, Any]]:
        ranked = []
        for recruiter in ctx.recruiters:
            shared = self._shared_recruiter_context(ctx, recruiter)
            shared['referral_signal'] = 1
            scores = self.scoring_engine.score(ctx.student, recruiter, shared)
            ranked.append((scores['overall_network_score'], self._recruiter_payload(recruiter, shared, scores)))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [payload for _, payload in ranked[:limit]]

    def _suggested_industry_experts(self, ctx: NetworkingRecommendationContext, limit: int) -> list[dict[str, Any]]:
        ranked = []
        target_industry = str(getattr(ctx.student, 'preferred_industry', '') or '').lower()
        for recruiter in ctx.recruiters:
            company = getattr(recruiter, 'company', None)
            industry = str(getattr(company, 'industry', None) or getattr(recruiter, 'industry', None) or '').lower()
            if target_industry and target_industry not in industry:
                continue
            shared = self._shared_recruiter_context(ctx, recruiter)
            shared['candidate_strength'] += 8
            scores = self.scoring_engine.score(ctx.student, recruiter, shared)
            payload = self._recruiter_payload(recruiter, shared, scores)
            payload['expertise_area'] = getattr(recruiter, 'hiring_domain', None) or getattr(recruiter, 'department', None) or industry.title()
            payload['recommendation_type'] = 'Industry Expert'
            ranked.append((scores['overall_network_score'], payload))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [payload for _, payload in ranked[:limit]]

    def _suggested_hiring_managers(self, ctx: NetworkingRecommendationContext, limit: int) -> list[dict[str, Any]]:
        ranked = []
        for recruiter in ctx.recruiters:
            role_text = str(getattr(recruiter, 'role', None) or getattr(recruiter, 'title', None) or '').lower()
            department = str(getattr(recruiter, 'department', None) or '').lower()
            if 'manager' not in role_text and 'head' not in role_text and 'lead' not in role_text and 'manager' not in department:
                continue
            shared = self._shared_recruiter_context(ctx, recruiter)
            shared['referral_signal'] = 1
            shared['candidate_strength'] += 10
            scores = self.scoring_engine.score(ctx.student, recruiter, shared)
            payload = self._recruiter_payload(recruiter, shared, scores)
            payload['recommendation_type'] = 'Hiring Manager'
            ranked.append((scores['overall_network_score'], payload))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [payload for _, payload in ranked[:limit]]

    def _student_payload(self, candidate: Student, shared: dict[str, Any], scores: dict[str, int], recommendation_type: str) -> dict[str, Any]:
        payload = {
            'name': self._student_name(candidate),
            'headline': str(getattr(candidate, 'headline', None) or getattr(candidate, 'career_goal', None) or 'CareerBridge member'),
            'university': self._student_university(candidate),
            'department': str(getattr(candidate, 'department', None) or ''),
            'graduation_year': getattr(candidate, 'graduation_year', None),
            'languages': self._normalized_list(getattr(candidate, 'languages', None))[:6],
            'shared_skills': shared['shared_skills'],
            'shared_technologies': shared['shared_technologies'],
            'shared_projects': shared['shared_projects'],
            'shared_communities': shared['shared_communities'],
            'shared_interests': shared['shared_interests'],
            'shared_university': shared['shared_university'],
            'shared_career_goals': shared['shared_career_goals'],
            'mutual_connections': shared['mutual_connections'],
            'networking_benefits': self._networking_benefits(shared, recommendation_type),
            'network_scores': scores,
            'smart_introductions': self._smart_introductions(self._student_name(candidate), recommendation_type, shared),
            'engagement': self._engagement(scores),
            'career_impact': self._career_impact(scores),
            'recommendation_type': recommendation_type,
            'why_this_connection': self._why_this_connection(shared, recommendation_type, scores),
        }
        return payload

    def _recruiter_payload(self, recruiter: Recruiter, shared: dict[str, Any], scores: dict[str, int]) -> dict[str, Any]:
        company = getattr(recruiter, 'company', None)
        role = str(getattr(recruiter, 'role', None) or getattr(recruiter, 'title', None) or 'Recruiter')
        payload = {
            'name': self._recruiter_name(recruiter),
            'company': str(getattr(company, 'name', None) or getattr(recruiter, 'company_name', None) or ''),
            'role': role,
            'department': str(getattr(recruiter, 'department', None) or getattr(recruiter, 'hiring_domain', None) or ''),
            'location': str(getattr(recruiter, 'location', None) or getattr(company, 'headquarters', None) or ''),
            'languages': self._normalized_list(getattr(recruiter, 'languages', None))[:6],
            'shared_skills': shared['shared_skills'],
            'shared_technologies': shared['shared_technologies'],
            'shared_projects': shared['shared_projects'],
            'shared_communities': shared['shared_communities'],
            'shared_interests': shared['shared_interests'],
            'shared_university': shared['shared_university'],
            'shared_career_goals': shared['shared_career_goals'],
            'mutual_connections': shared['mutual_connections'],
            'networking_benefits': self._networking_benefits(shared, 'Recruiter'),
            'network_scores': scores,
            'smart_introductions': self._smart_introductions(self._recruiter_name(recruiter), 'Recruiter', shared, role),
            'engagement': self._engagement(scores),
            'career_impact': self._career_impact(scores),
            'recommendation_type': 'Recruiter',
            'why_this_connection': self._why_this_connection(shared, 'Recruiter', scores),
        }
        return payload

    def _shared_student_context(self, student: Student, candidate: Student, ctx: NetworkingRecommendationContext) -> dict[str, Any]:
        student_skills = set(self._normalized_list(getattr(student, 'skills', None), lower=True))
        candidate_skills = set(self._normalized_list(getattr(candidate, 'skills', None), lower=True))
        student_projects = self._normalized_list(getattr(student, 'projects', None), lower=True)
        candidate_projects = self._normalized_list(getattr(candidate, 'projects', None), lower=True)
        shared_projects = [project for project in candidate_projects if any(token in project for token in student_projects[:8])][:5]
        student_communities = set(self._communities_from_context(student, ctx))
        candidate_communities = set(self._normalized_list(getattr(candidate, 'communities', None)))
        student_goal = str(getattr(student, 'career_goal', '') or '')
        candidate_goal = str(getattr(candidate, 'career_goal', '') or '')
        shared_goal = student_goal if student_goal and candidate_goal and any(token in candidate_goal.lower() for token in student_goal.lower().split() if len(token) > 2) else ''
        shared_interests = self._shared_interests(student, candidate)
        mutual_connections = min(18, len(student_skills & candidate_skills) // 2 + len(student_communities & candidate_communities) + self._message_signal(student, candidate, ctx.messages))
        return {
            'shared_skills': sorted(student_skills & candidate_skills)[:8],
            'shared_technologies': [skill for skill in sorted(student_skills & candidate_skills) if skill in {'python', 'java', 'react', 'node.js', 'sql', 'aws', 'docker', 'kubernetes', 'tensorflow', 'pytorch', 'go', 'rust'}][:8],
            'shared_projects': shared_projects,
            'shared_communities': sorted(student_communities & candidate_communities)[:6],
            'shared_interests': shared_interests[:6],
            'shared_university': self._student_university(student) if self._student_university(student).lower() == self._student_university(candidate).lower() else None,
            'shared_career_goals': shared_goal,
            'mutual_connections': mutual_connections,
            'candidate_strength': 54 + len(candidate_skills) * 2 + len(self._normalized_list(getattr(candidate, 'experience', None))) * 5,
            'mentorship_signal': 1 if len(self._normalized_list(getattr(candidate, 'experience', None))) >= 2 else 0,
            'referral_signal': 1 if len(self._normalized_list(getattr(candidate, 'experience', None))) >= 1 else 0,
            'message_signal': self._message_signal(student, candidate, ctx.messages),
        }

    def _shared_recruiter_context(self, ctx: NetworkingRecommendationContext, recruiter: Recruiter) -> dict[str, Any]:
        student_skills = set(self._normalized_list(getattr(ctx.student, 'skills', None), lower=True))
        recruiter_skills = set(self._normalized_list(getattr(recruiter, 'preferred_skills', None), lower=True))
        student_projects = self._normalized_list(getattr(ctx.student, 'projects', None), lower=True)
        recruiter_communities = set(self._normalized_list(getattr(recruiter, 'communities', None)))
        student_communities = set(self._communities_from_context(ctx.student, ctx))
        company_rec_names = {str(item.get('company_name', '')).lower() for item in (getattr(ctx.company_recommendation, 'top_companies', None) or []) if isinstance(item, dict)} if ctx.company_recommendation is not None else set()
        recruiter_company = str(getattr(getattr(recruiter, 'company', None), 'name', None) or getattr(recruiter, 'company_name', None) or '').lower()
        target_roles = [str(item.get('job_title', '')).lower() for item in (getattr(ctx.job_match, 'top_job_matches', None) or [])[:10]] if ctx.job_match is not None else []
        role_text = str(getattr(recruiter, 'role', None) or getattr(recruiter, 'title', None) or '')
        domain = str(getattr(recruiter, 'hiring_domain', None) or getattr(recruiter, 'department', None) or '')
        student_goal = str(getattr(ctx.student, 'career_goal', '') or '')
        shared_goal = student_goal if student_goal and any(token in f"{role_text} {domain}".lower() for token in student_goal.lower().split() if len(token) > 2) else ''
        return {
            'shared_skills': sorted(student_skills & recruiter_skills)[:8],
            'shared_technologies': [skill for skill in sorted(student_skills & recruiter_skills) if skill in {'python', 'java', 'react', 'node.js', 'sql', 'aws', 'docker', 'kubernetes', 'tensorflow', 'pytorch', 'go', 'rust'}][:8],
            'shared_projects': [project for project in student_projects if any(token in project for token in f"{role_text} {domain}".lower().split() if len(token) > 2)][:5],
            'shared_communities': sorted(student_communities & recruiter_communities)[:6],
            'shared_interests': [student_goal] if shared_goal else [title for title in target_roles if any(token in title for token in f"{role_text} {domain}".lower().split() if len(token) > 2)][:3],
            'shared_university': self._student_university(ctx.student) if self._student_university(ctx.student).lower() in {item.lower() for item in self._normalized_list(getattr(recruiter, 'preferred_universities', None))} else None,
            'shared_career_goals': shared_goal,
            'mutual_connections': min(18, len(student_skills & recruiter_skills) + (3 if recruiter_company in company_rec_names else 0)),
            'candidate_strength': 60 + int(getattr(recruiter, 'years_of_experience', None) or getattr(recruiter, 'experience_years', None) or 5) * 4,
            'mentorship_signal': 1 if int(getattr(recruiter, 'years_of_experience', None) or getattr(recruiter, 'experience_years', None) or 0) >= 6 else 0,
            'referral_signal': 1 if recruiter_company in company_rec_names else 0,
            'message_signal': 1 if recruiter_company in company_rec_names else 0,
        }

    def _networking_benefits(self, shared: dict[str, Any], recommendation_type: str) -> list[str]:
        benefits = []
        if shared['shared_skills']:
            benefits.append('Can exchange role-relevant technical knowledge.')
        if shared['shared_projects']:
            benefits.append('Strong basis for project collaboration or portfolio feedback.')
        if shared['shared_communities']:
            benefits.append('Shared communities improve discovery and response likelihood.')
        if shared['shared_university']:
            benefits.append('Shared university background increases trust and context.')
        if recommendation_type in {'Recruiter', 'Hiring Manager', 'Industry Expert'}:
            benefits.append('Can improve recruiter visibility and referral access.')
        if recommendation_type in {'Mentor', 'Alumni'}:
            benefits.append('Can provide mentorship, interview prep, and career navigation support.')
        return benefits[:5]

    def _smart_introductions(self, name: str, recommendation_type: str, shared: dict[str, Any], role: str | None = None) -> dict[str, str]:
        skills = ', '.join(shared['shared_skills'][:3]) if shared['shared_skills'] else 'relevant skills'
        shared_goal = shared['shared_career_goals'] or 'career growth'
        return {
            'connection_request': f"Hi {name}, I noticed we share {skills} and an interest in {shared_goal}. I\'d love to connect and learn from your experience.",
            'icebreaker_message': f"Hello {name}, your background stood out because of our overlap in {skills}. I\'m exploring similar paths and wanted to start a conversation.",
            'mentorship_request': f"Hi {name}, I\'m building toward {shared_goal} and your background looks highly relevant. Would you be open to a short mentorship conversation?",
            'recruiter_introduction': f"Hi {name}, I\'m exploring opportunities aligned with {shared_goal}{f' in {role}' if role else ''}. My profile includes {skills}, and I\'d value connecting.",
            'project_collaboration_request': f"Hi {name}, I noticed overlap in our project and technology interests around {skills}. I\'d enjoy collaborating or exchanging feedback on current work.",
            'referral_request': f"Hi {name}, I\'m targeting roles related to {shared_goal} and saw strong alignment with your network. Would you be open to sharing guidance or a referral if appropriate?",
            'follow_up_message': f"Hi {name}, following up on my earlier note. I\'m continuing to develop around {skills} and would appreciate staying connected.",
        }

    def _engagement(self, scores: dict[str, int]) -> dict[str, Any]:
        index = scores['response_probability'] % len(BEST_CONTACT_WINDOWS)
        day, window = BEST_CONTACT_WINDOWS[index]
        expected_response_rate = min(96, max(28, scores['response_probability'] + 4))
        networking_confidence = min(97, max(35, round(mean([scores['connection_strength'], scores['career_relevance'], scores['response_probability']]))))
        interaction_frequency = 'High' if scores['overall_network_score'] >= 78 else 'Moderate' if scores['overall_network_score'] >= 62 else 'Occasional'
        return {
            'best_time_to_connect': f'{day} {window}',
            'expected_response_rate': expected_response_rate,
            'engagement_score': scores['overall_network_score'],
            'networking_confidence': networking_confidence,
            'interaction_frequency': interaction_frequency,
        }

    def _career_impact(self, scores: dict[str, int]) -> dict[str, Any]:
        return {
            'career_score_improvement': max(2, min(15, round(scores['career_relevance'] * 0.12))),
            'referral_probability': scores['referral_potential'],
            'interview_probability': min(97, round(mean([scores['career_relevance'], scores['response_probability'], scores['referral_potential']]))),
            'offer_probability': min(94, round(mean([scores['career_relevance'], scores['knowledge_value'], scores['referral_potential']]))),
            'learning_opportunities': 'High' if scores['knowledge_value'] >= 72 else 'Moderate',
            'industry_exposure': 'High' if scores['career_relevance'] >= 75 else 'Moderate',
        }

    def _why_this_connection(self, shared: dict[str, Any], recommendation_type: str, scores: dict[str, int]) -> dict[str, Any]:
        reasons = []
        if shared['shared_skills']:
            reasons.append(f"Shared skills include {', '.join(shared['shared_skills'][:3])}.")
        if shared['shared_technologies']:
            reasons.append(f"Shared technologies include {', '.join(shared['shared_technologies'][:3])}.")
        if shared['shared_projects']:
            reasons.append('There is meaningful overlap in project interests and work samples.')
        if shared['shared_communities']:
            reasons.append('Shared communities improve the chance of a warm interaction.')
        if shared['shared_university']:
            reasons.append('A shared university background provides strong networking context.')
        if shared['shared_career_goals']:
            reasons.append('Career goals are closely aligned.')
        reasons.append(f"Expected networking value is {scores['overall_network_score']} based on relevance, collaboration, and response potential.")
        return {
            'summary': ' '.join(reasons),
            'expected_networking_value': scores['overall_network_score'],
            'benefit_to_student': 'Improves access to knowledge, collaboration, mentorship, and referrals.',
            'confidence_score': min(97, max(55, scores['overall_network_score'] + 4)),
            'recommendation_type': recommendation_type,
        }

    def _communities_from_context(self, student: Student, ctx: NetworkingRecommendationContext) -> list[str]:
        communities = set(self._normalized_list(getattr(student, 'communities', None)))
        if ctx.recruiter_recommendation is not None:
            metadata = getattr(ctx.recruiter_recommendation, 'network_quality_metadata', None) or {}
            for item in metadata.get('shared_communities_summary', [])[:6]:
                if isinstance(item, dict) and item.get('name'):
                    communities.add(str(item['name']))
        return sorted(communities)

    def _shared_interests(self, student: Student, candidate: Student) -> list[str]:
        interests = []
        for field in ('career_goal', 'preferred_industry', 'preferred_location', 'preferred_work_type'):
            left = str(getattr(student, field, '') or '').strip()
            right = str(getattr(candidate, field, '') or '').strip()
            if left and right and left.lower() == right.lower():
                interests.append(left)
        return interests

    def _message_signal(self, student: Student, candidate: Student, messages: Sequence[Message]) -> int:
        student_name = self._student_name(student).lower()
        candidate_name = self._student_name(candidate).lower()
        count = 0
        for message in messages:
            sender = str(getattr(message, 'sender_name', None) or getattr(getattr(message, 'sender', None), 'name', None) or '').lower()
            recipient = str(getattr(message, 'recipient_name', None) or getattr(getattr(message, 'recipient', None), 'name', None) or '').lower()
            if {sender, recipient} == {student_name, candidate_name}:
                count += 1
        return min(3, count)

    def _mentorship_focus(self, candidate: Student) -> list[str]:
        focus = []
        experience = ' '.join(self._normalized_list(getattr(candidate, 'experience', None), lower=True))
        if 'data' in experience or 'analyst' in experience:
            focus.append('Data and analytics career guidance')
        if 'frontend' in experience or 'react' in experience:
            focus.append('Frontend portfolio and project review')
        if 'backend' in experience or 'api' in experience:
            focus.append('Backend systems and interview preparation')
        if 'cloud' in experience or 'devops' in experience:
            focus.append('Cloud certification and infrastructure path')
        if not focus:
            focus.append('General early-career mentoring')
        return focus[:4]

    def _student_university(self, student: Student) -> str:
        return str(getattr(student, 'university', None) or getattr(getattr(student, 'university_ref', None), 'name', None) or '')

    def _student_name(self, student: Student) -> str:
        for field in ('full_name', 'name'):
            value = getattr(student, field, None)
            if value:
                return str(value)
        first = getattr(student, 'first_name', None)
        last = getattr(student, 'last_name', None)
        if first or last:
            return ' '.join([part for part in [str(first or '').strip(), str(last or '').strip()] if part])
        return 'CareerBridge Member'

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))

    def _recruiter_name(self, recruiter: Recruiter) -> str:
        for field in ('full_name', 'name'):
            value = getattr(recruiter, field, None)
            if value:
                return str(value)
        first = getattr(recruiter, 'first_name', None)
        last = getattr(recruiter, 'last_name', None)
        if first or last:
            return ' '.join([part for part in [str(first or '').strip(), str(last or '').strip()] if part])
        return 'Recruiter'

    def _normalized_list(self, value: Any, lower: bool = False) -> list[str]:
        if isinstance(value, dict):
            items = [str(key) for key in value.keys() if str(key).strip()]
        elif isinstance(value, (list, tuple, set)):
            items = [str(item) for item in value if str(item).strip()]
        elif value in (None, ''):
            items = []
        else:
            items = [str(value)]
        return [item.lower() if lower else item for item in items]


class DefaultMentorshipEngine:
    def __init__(self, connection_engine: DefaultConnectionRecommendationEngine | None = None) -> None:
        self.connection_engine = connection_engine or DefaultConnectionRecommendationEngine()

    def build(self, ctx: NetworkingRecommendationContext) -> list[dict[str, Any]]:
        mentors = self.connection_engine._suggested_mentors(ctx, limit=20)
        alumni = self.connection_engine._suggested_alumni(ctx, limit=15)
        combined = mentors + [item for item in alumni if item['name'] not in {mentor['name'] for mentor in mentors}]
        combined.sort(key=lambda item: item['network_scores']['mentorship_value'], reverse=True)
        return combined[:25]


class DefaultCommunityRecommendationEngine:
    def build(self, ctx: NetworkingRecommendationContext) -> dict[str, list[dict[str, Any]]]:
        student_skills = set(self._normalized_list(getattr(ctx.student, 'skills', None), lower=True))
        student_goal = str(getattr(ctx.student, 'career_goal', '') or '').lower()
        target_industry = str(getattr(ctx.student, 'preferred_industry', '') or '').lower()
        communities = []
        for community_type in COMMUNITY_TYPES:
            score = 52
            lowered = community_type.lower()
            if 'ai' in lowered and ({'python', 'tensorflow', 'pytorch', 'machine learning', 'deep learning'} & student_skills):
                score += 26
            if 'cloud' in lowered and ({'aws', 'azure', 'gcp', 'docker', 'kubernetes'} & student_skills):
                score += 24
            if 'cybersecurity' in lowered and ({'security', 'network security', 'siem', 'linux'} & student_skills):
                score += 24
            if 'frontend' in lowered and ({'react', 'javascript', 'typescript', 'css', 'html'} & student_skills):
                score += 24
            if 'backend' in lowered and ({'python', 'java', 'node.js', 'sql', 'api'} & student_skills):
                score += 24
            if 'devops' in lowered and ({'docker', 'kubernetes', 'terraform', 'aws', 'ci/cd'} & student_skills):
                score += 24
            if 'startup' in lowered and 'startup' in target_industry:
                score += 16
            if 'research' in lowered and ('research' in student_goal or 'ai' in student_goal or 'ml' in student_goal):
                score += 14
            communities.append({
                'name': community_type,
                'match_score': min(97, score),
                'reason': self._community_reason(community_type, student_skills, student_goal),
                'expected_value': 'High' if score >= 76 else 'Moderate',
            })
        communities.sort(key=lambda item: item['match_score'], reverse=True)

        events = []
        top_companies = [item.get('company_name') for item in (getattr(ctx.company_recommendation, 'top_companies', None) or [])[:8] if isinstance(item, dict)] if ctx.company_recommendation is not None else []
        preferred_location = str(getattr(ctx.student, 'preferred_location', '') or 'Global')
        for index, event_type in enumerate(EVENT_TYPES):
            score = 58 + index
            if 'Hackathon' in event_type and any(skill in student_skills for skill in {'python', 'react', 'node.js', 'aws', 'java'}):
                score += 16
            if 'Career Fair' in event_type and top_companies:
                score += 12
            if 'University Event' in event_type and self._student_university(ctx.student):
                score += 10
            if 'Webinar' in event_type and ctx.skill_gap is not None:
                score += 8
            events.append({
                'name': f"{preferred_location} {event_type}",
                'event_type': event_type,
                'match_score': min(97, score),
                'expected_outcome': 'Strong networking and learning exposure' if score >= 75 else 'Good visibility and discovery opportunity',
                'recommended_companies': top_companies[:4],
            })
        events.sort(key=lambda item: item['match_score'], reverse=True)

        study_groups = self._study_groups(student_skills, student_goal)
        clubs = self._clubs(student_skills, target_industry)
        open_source_projects = self._open_source_projects(student_skills, student_goal)

        return {
            'suggested_communities': communities[:20],
            'suggested_study_groups': study_groups[:12],
            'suggested_clubs': clubs[:12],
            'suggested_open_source_projects': open_source_projects[:12],
            'suggested_events': events[:20],
        }

    def _study_groups(self, skills: set[str], student_goal: str) -> list[dict[str, Any]]:
        groups = []
        candidates = [
            ('DSA Interview Circle', {'python', 'java', 'c++', 'data structures'}),
            ('SQL Analytics Study Group', {'sql', 'python', 'power bi', 'tableau'}),
            ('Frontend Build Club', {'react', 'javascript', 'typescript', 'css'}),
            ('Cloud Practitioner Sprint', {'aws', 'azure', 'gcp', 'docker'}),
            ('ML Reading Group', {'python', 'tensorflow', 'pytorch', 'machine learning'}),
            ('System Design Lab', {'java', 'python', 'node.js', 'api', 'aws'}),
        ]
        for name, group_skills in candidates:
            overlap = len(skills & group_skills)
            score = 52 + overlap * 10 + (8 if any(token in name.lower() for token in student_goal.split() if len(token) > 2) else 0)
            groups.append({'name': name, 'match_score': min(97, score), 'focus': ', '.join(sorted(group_skills)[:4])})
        groups.sort(key=lambda item: item['match_score'], reverse=True)
        return groups

    def _clubs(self, skills: set[str], industry: str) -> list[dict[str, Any]]:
        clubs = []
        candidates = [
            ('AI & Robotics Club', {'python', 'tensorflow', 'pytorch'}),
            ('Cloud and DevOps Club', {'aws', 'azure', 'docker', 'kubernetes'}),
            ('Cyber Defense Club', {'security', 'linux', 'network security'}),
            ('Product Builders Club', {'react', 'node.js', 'sql'}),
            ('Startup Founders Circle', {'product', 'growth', 'startup'}),
            ('Research Scholars Forum', {'research', 'python', 'data analysis'}),
        ]
        for name, club_skills in candidates:
            overlap = len(skills & club_skills)
            score = 50 + overlap * 11 + (10 if industry and industry in name.lower() else 0)
            clubs.append({'name': name, 'match_score': min(97, score), 'focus': ', '.join(sorted(club_skills)[:4])})
        clubs.sort(key=lambda item: item['match_score'], reverse=True)
        return clubs

    def _open_source_projects(self, skills: set[str], student_goal: str) -> list[dict[str, Any]]:
        projects = []
        candidates = [
            ('OpenML Toolkit', {'python', 'pytorch', 'tensorflow'}),
            ('Cloud Infra Templates', {'aws', 'terraform', 'docker'}),
            ('React Component Library', {'react', 'typescript', 'css'}),
            ('Data Pipeline Framework', {'python', 'sql', 'airflow'}),
            ('Secure API Gateway', {'node.js', 'security', 'api'}),
            ('Observability Stack', {'go', 'docker', 'kubernetes'}),
        ]
        for name, project_skills in candidates:
            overlap = len(skills & project_skills)
            score = 48 + overlap * 12 + (8 if any(token in name.lower() for token in student_goal.split() if len(token) > 2) else 0)
            projects.append({'name': name, 'match_score': min(97, score), 'tech_focus': ', '.join(sorted(project_skills)[:4])})
        projects.sort(key=lambda item: item['match_score'], reverse=True)
        return projects

    def _community_reason(self, community_type: str, skills: set[str], student_goal: str) -> str:
        matched = []
        for token in community_type.lower().replace('communities', '').replace('groups', '').split():
            if token in skills or token in student_goal:
                matched.append(token)
        if matched:
            return f"Aligned with your skills and goals in {', '.join(matched[:3])}."
        return 'Relevant for network expansion, peer learning, and opportunity discovery.'

    def _student_university(self, student: Student) -> str:
        return str(getattr(student, 'university', None) or getattr(getattr(student, 'university_ref', None), 'name', None) or '')

    def _normalized_list(self, value: Any, lower: bool = False) -> list[str]:
        if isinstance(value, dict):
            items = [str(key) for key in value.keys() if str(key).strip()]
        elif isinstance(value, (list, tuple, set)):
            items = [str(item) for item in value if str(item).strip()]
        elif value in (None, ''):
            items = []
        else:
            items = [str(value)]
        return [item.lower() if lower else item for item in items]


class DefaultNetworkingEngine:
    def __init__(
        self,
        connection_engine: ConnectionRecommendationEngine | None = None,
        mentorship_engine: MentorshipEngine | None = None,
        community_engine: CommunityRecommendationEngine | None = None,
        relationship_scoring_engine: RelationshipScoringEngine | None = None,
    ) -> None:
        self.relationship_scoring_engine = relationship_scoring_engine or DefaultRelationshipScoringEngine()
        self.connection_engine = connection_engine or DefaultConnectionRecommendationEngine(self.relationship_scoring_engine)
        self.mentorship_engine = mentorship_engine or DefaultMentorshipEngine(self.connection_engine)
        self.community_engine = community_engine or DefaultCommunityRecommendationEngine()

    def recommend(self, ctx: NetworkingRecommendationContext) -> NetworkingRecommendation:
        connections = self.connection_engine.build(ctx)
        mentors = self.mentorship_engine.build(ctx)
        communities = self.community_engine.build(ctx)
        ai_explanations = self._ai_explanations(connections, mentors, communities)
        recommendation = NetworkingRecommendation(
            student=ctx.student,
            generated_at=datetime.utcnow(),
            suggested_connections=connections['suggested_connections'][:50],
        )
        recommendation.suggested_recruiters_metadata = connections['suggested_recruiters'][:30]
        recommendation.suggested_mentors_metadata = mentors[:25]
        recommendation.suggested_alumni_metadata = connections['suggested_alumni'][:25]
        recommendation.suggested_students_metadata = connections['suggested_students'][:30]
        recommendation.suggested_industry_experts_metadata = connections['suggested_industry_experts'][:20]
        recommendation.suggested_hiring_managers_metadata = connections['suggested_hiring_managers'][:20]
        recommendation.suggested_communities_metadata = communities['suggested_communities'][:20]
        recommendation.suggested_study_groups_metadata = communities['suggested_study_groups'][:12]
        recommendation.suggested_clubs_metadata = communities['suggested_clubs'][:12]
        recommendation.suggested_open_source_projects_metadata = communities['suggested_open_source_projects'][:12]
        recommendation.suggested_events_metadata = communities['suggested_events'][:20]
        recommendation.network_score_metadata = self._network_score_summary(connections)
        recommendation.engagement_metadata = self._engagement_summary(connections, mentors)
        recommendation.career_impact_metadata = self._career_impact_summary(connections, mentors)
        recommendation.ai_explanations_metadata = ai_explanations
        recommendation.engine_metadata = {
            'networking_engine': self.__class__.__name__,
            'connection_recommendation_engine': self.connection_engine.__class__.__name__,
            'mentorship_engine': self.mentorship_engine.__class__.__name__,
            'community_recommendation_engine': self.community_engine.__class__.__name__,
            'relationship_scoring_engine': self.relationship_scoring_engine.__class__.__name__,
            'gemini_replaceable': True,
            'frontend_contract_stable': True,
        }
        return recommendation

    def _network_score_summary(self, connections: dict[str, list[dict[str, Any]]]) -> dict[str, Any]:
        pool = connections['suggested_connections'][:20] + connections['suggested_recruiters'][:10]
        if not pool:
            return {'average_network_score': 0, 'top_connections': []}
        average_score = round(mean([item['network_scores']['overall_network_score'] for item in pool]))
        top_connections = [
            {
                'name': item['name'],
                'type': item['recommendation_type'],
                'overall_network_score': item['network_scores']['overall_network_score'],
            }
            for item in sorted(pool, key=lambda x: x['network_scores']['overall_network_score'], reverse=True)[:10]
        ]
        return {
            'average_network_score': average_score,
            'top_connections': top_connections,
        }

    def _engagement_summary(self, connections: dict[str, list[dict[str, Any]]], mentors: list[dict[str, Any]]) -> dict[str, Any]:
        pool = connections['suggested_connections'][:15] + connections['suggested_recruiters'][:10] + mentors[:10]
        if not pool:
            return {'average_response_rate': 0, 'recommended_contact_windows': []}
        average_response = round(mean([item['engagement']['expected_response_rate'] for item in pool]))
        windows = Counter(item['engagement']['best_time_to_connect'] for item in pool)
        return {
            'average_response_rate': average_response,
            'recommended_contact_windows': [{'window': name, 'count': count} for name, count in windows.most_common(5)],
        }

    def _career_impact_summary(self, connections: dict[str, list[dict[str, Any]]], mentors: list[dict[str, Any]]) -> dict[str, Any]:
        pool = connections['suggested_connections'][:10] + connections['suggested_recruiters'][:10] + mentors[:10]
        if not pool:
            return {'career_score_improvement': 0, 'referral_probability': 0, 'interview_probability': 0, 'offer_probability': 0}
        return {
            'career_score_improvement': round(mean([item['career_impact']['career_score_improvement'] for item in pool])),
            'referral_probability': round(mean([item['career_impact']['referral_probability'] for item in pool])),
            'interview_probability': round(mean([item['career_impact']['interview_probability'] for item in pool])),
            'offer_probability': round(mean([item['career_impact']['offer_probability'] for item in pool])),
            'learning_opportunities': 'High' if any(item['career_impact']['learning_opportunities'] == 'High' for item in pool) else 'Moderate',
            'industry_exposure': 'High' if any(item['career_impact']['industry_exposure'] == 'High' for item in pool) else 'Moderate',
        }

    def _ai_explanations(self, connections: dict[str, list[dict[str, Any]]], mentors: list[dict[str, Any]], communities: dict[str, list[dict[str, Any]]]) -> dict[str, Any]:
        items = []
        for item in (connections['suggested_connections'][:10] + connections['suggested_recruiters'][:10] + mentors[:10]):
            items.append({
                'name': item['name'],
                'type': item['recommendation_type'],
                'why_recommended': item['why_this_connection']['summary'],
                'benefit_to_student': item['why_this_connection']['benefit_to_student'],
                'expected_networking_value': item['why_this_connection']['expected_networking_value'],
                'confidence_score': item['why_this_connection']['confidence_score'],
            })
        for community in communities['suggested_communities'][:5]:
            items.append({
                'name': community['name'],
                'type': 'Community',
                'why_recommended': community['reason'],
                'benefit_to_student': 'Improves network breadth, knowledge access, and peer discovery.',
                'expected_networking_value': community['match_score'],
                'confidence_score': min(96, community['match_score'] + 3),
            })
        return {'items': items}


class NetworkingRecommendationGenerator:
    def __init__(self, config: AppConfig = CONFIG, engine: NetworkingEngine | None = None) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 20000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 20000)
            self.faker.seed_instance(config.generation.seed + 20000)
        self.engine = engine or DefaultNetworkingEngine()

    def generate(
        self,
        students: Sequence[Student],
        companies: Sequence[Company],
        recruiters: Sequence[Recruiter],
        jobs: Sequence[Job],
        applications: Sequence[Application],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
        messages: Sequence[Message],
        career_reports: Sequence[CareerReport],
        skill_gaps: Sequence[SkillGap],
        learning_roadmaps: Sequence[Any],
        resume_analyses: Sequence[ResumeAnalysis],
        job_matches: Sequence[JobMatch],
        recruiter_recommendations: Sequence[RecruiterRecommendation],
        company_recommendations: Sequence[CompanyRecommendation],
    ) -> NetworkingRecommendationGenerationResult:
        if not students:
            raise ValueError('Networking recommendation generation requires students.')

        applications_by_student = self._records_by_student(applications, 'student')
        interviews_by_student = self._records_by_student(interviews, 'student', application_fallback=True)
        offers_by_student = self._records_by_student(offers, 'student', application_fallback=True)
        messages_by_student = self._messages_by_student(messages)
        jobs_by_student = self._jobs_by_student(students, jobs, applications, interviews, offers)
        recruiters_by_student = self._recruiters_by_student(recruiters, applications, jobs_by_student)
        reports_by_student = {self._student_key(item.student): item for item in career_reports if getattr(item, 'student', None) is not None}
        gaps_by_student = {self._student_key(item.student): item for item in skill_gaps if getattr(item, 'student', None) is not None}
        roadmaps_by_student = {self._student_key(item.student): item for item in learning_roadmaps if getattr(item, 'student', None) is not None}
        resumes_by_student = {self._student_key(item.student): item for item in resume_analyses if getattr(item, 'student', None) is not None}
        matches_by_student = {self._student_key(item.student): item for item in job_matches if getattr(item, 'student', None) is not None}
        recruiter_recommendations_by_student = {self._student_key(item.student): item for item in recruiter_recommendations if getattr(item, 'student', None) is not None}
        company_recommendations_by_student = {self._student_key(item.student): item for item in company_recommendations if getattr(item, 'student', None) is not None}

        results: list[NetworkingRecommendation] = []
        for student in students:
            key = self._student_key(student)
            ctx = NetworkingRecommendationContext(
                student=student,
                students=list(students),
                companies=list(companies),
                recruiters=recruiters_by_student.get(key, list(recruiters)),
                jobs=jobs_by_student.get(key, []),
                applications=applications_by_student.get(key, []),
                interviews=interviews_by_student.get(key, []),
                offers=offers_by_student.get(key, []),
                messages=messages_by_student.get(key, []),
                career_report=reports_by_student.get(key),
                skill_gap=gaps_by_student.get(key),
                learning_roadmap=roadmaps_by_student.get(key),
                resume_analysis=resumes_by_student.get(key),
                job_match=matches_by_student.get(key),
                recruiter_recommendation=recruiter_recommendations_by_student.get(key),
                company_recommendation=company_recommendations_by_student.get(key),
            )
            results.append(self.engine.recommend(ctx))
        return NetworkingRecommendationGenerationResult(networking_recommendations=results)

    def _jobs_by_student(
        self,
        students: Sequence[Student],
        jobs: Sequence[Job],
        applications: Sequence[Application],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
    ) -> dict[str, list[Job]]:
        mapping: dict[str, list[Job]] = defaultdict(list)
        for record in list(applications) + list(interviews) + list(offers):
            student = getattr(record, 'student', None)
            if student is None:
                application = getattr(record, 'application', None)
                student = getattr(application, 'student', None) if application is not None else None
            job = getattr(record, 'job', None)
            if job is None:
                application = getattr(record, 'application', None)
                job = getattr(application, 'job', None) if application is not None else None
            if student is None or job is None:
                continue
            mapping[self._student_key(student)].append(job)
        for student in students:
            key = self._student_key(student)
            if not mapping.get(key):
                mapping[key] = self._best_jobs_for_student(student, jobs)
        return mapping

    def _recruiters_by_student(self, recruiters: Sequence[Recruiter], applications: Sequence[Application], jobs_by_student: dict[str, list[Job]]) -> dict[str, list[Recruiter]]:
        mapping: dict[str, list[Recruiter]] = defaultdict(list)
        recruiter_lookup = {str(getattr(recruiter, 'name', '')): recruiter for recruiter in recruiters}
        for application in applications:
            student = getattr(application, 'student', None)
            recruiter = getattr(application, 'recruiter', None)
            if student is None or recruiter is None:
                continue
            mapping[self._student_key(student)].append(recruiter)
        for student_key, student_jobs in jobs_by_student.items():
            seen = {str(getattr(recruiter, 'name', '')) for recruiter in mapping.get(student_key, [])}
            for job in student_jobs:
                recruiter = getattr(job, 'recruiter', None)
                recruiter_name = str(getattr(recruiter, 'name', None) or getattr(job, 'recruiter_name', None) or '')
                if recruiter is not None and recruiter_name not in seen:
                    mapping[student_key].append(recruiter)
                    seen.add(recruiter_name)
                elif recruiter_name and recruiter_name in recruiter_lookup and recruiter_name not in seen:
                    mapping[student_key].append(recruiter_lookup[recruiter_name])
                    seen.add(recruiter_name)
        return mapping

    def _messages_by_student(self, messages: Sequence[Message]) -> dict[str, list[Message]]:
        mapping: dict[str, list[Message]] = defaultdict(list)
        for message in messages:
            student = getattr(message, 'student', None)
            if student is not None:
                mapping[self._student_key(student)].append(message)
                continue
            sender = getattr(message, 'sender', None)
            recipient = getattr(message, 'recipient', None)
            for actor in (sender, recipient):
                if actor is not None and hasattr(actor, 'student_id') or hasattr(actor, 'email'):
                    mapping[self._student_key(actor)].append(message)
        return mapping

    def _records_by_student(self, records: Sequence[Any], attr: str, application_fallback: bool = False) -> dict[str, list[Any]]:
        mapping: dict[str, list[Any]] = defaultdict(list)
        for record in records:
            student = getattr(record, attr, None)
            if student is None and application_fallback:
                application = getattr(record, 'application', None)
                student = getattr(application, 'student', None) if application is not None else None
            if student is None:
                continue
            mapping[self._student_key(student)].append(record)
        return mapping

    def _best_jobs_for_student(self, student: Student, jobs: Sequence[Job]) -> list[Job]:
        student_skills = {str(item).strip().lower() for item in self._normalized_list(getattr(student, 'skills', None))}
        career_goal = str(getattr(student, 'career_goal', '') or '').lower()
        preferred_location = str(getattr(student, 'preferred_location', '') or '').lower()
        ranked = []
        for job in jobs:
            required = {str(item).strip().lower() for item in self._normalized_list(getattr(job, 'skills_required', None))}
            preferred = {str(item).strip().lower() for item in self._normalized_list(getattr(job, 'preferred_skills', None))}
            role = str(getattr(job, 'role', None) or getattr(job, 'title', None) or getattr(job, 'job_title', None) or '').lower()
            location = ' '.join([
                str(getattr(job, 'location_city', None) or ''),
                str(getattr(job, 'location_country', None) or ''),
            ]).lower()
            score = len(student_skills & required) * 5 + len(student_skills & preferred) * 2
            if career_goal and any(token in role for token in career_goal.split() if len(token) > 2):
                score += 6
            if preferred_location and preferred_location in location:
                score += 4
            ranked.append((score, job))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [job for _, job in ranked[:60]]

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))

    def _normalized_list(self, value: Any) -> list[str]:
        if isinstance(value, dict):
            return [str(key) for key in value.keys() if str(key).strip()]
        if isinstance(value, (list, tuple, set)):
            return [str(item) for item in value if str(item).strip()]
        if value in (None, ''):
            return []
        return [str(value)]


def generate_networking_recommendations(
    students: Sequence[Student],
    companies: Sequence[Company],
    recruiters: Sequence[Recruiter],
    jobs: Sequence[Job],
    applications: Sequence[Application],
    interviews: Sequence[Interview],
    offers: Sequence[Offer],
    messages: Sequence[Message],
    career_reports: Sequence[CareerReport],
    skill_gaps: Sequence[SkillGap],
    learning_roadmaps: Sequence[Any],
    resume_analyses: Sequence[ResumeAnalysis],
    job_matches: Sequence[JobMatch],
    recruiter_recommendations: Sequence[RecruiterRecommendation],
    company_recommendations: Sequence[CompanyRecommendation],
    config: AppConfig = CONFIG,
) -> NetworkingRecommendationGenerationResult:
    generator = NetworkingRecommendationGenerator(config=config)
    return generator.generate(
        students=students,
        companies=companies,
        recruiters=recruiters,
        jobs=jobs,
        applications=applications,
        interviews=interviews,
        offers=offers,
        messages=messages,
        career_reports=career_reports,
        skill_gaps=skill_gaps,
        learning_roadmaps=learning_roadmaps,
        resume_analyses=resume_analyses,
        job_matches=job_matches,
        recruiter_recommendations=recruiter_recommendations,
        company_recommendations=company_recommendations,
    )


