@dataclass(slots=True)
class NotificationGenerationResult:
    notifications: list[Notification]


class NotificationGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 8000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 8000)
            self.faker.seed_instance(config.generation.seed + 8000)

    def generate(self, users: Sequence[Any]) -> NotificationGenerationResult:
        if not users:
            raise ValueError('Notification generation requires existing users.')

        notifications: list[Notification] = []
        for index in range(self.config.counts.notifications):
            user = users[index % len(users)] if len(users) >= self.config.counts.notifications else self.random.choice(users)
            notification_type = self._weighted_notification_type()
            created_at = self._created_at()
            priority = self._priority(notification_type)
            status = self._status(notification_type, created_at)
            category = CATEGORY_MAP[notification_type]
            context = self._context(user, notification_type, created_at)
            title, body = self._content(notification_type, context)
            channels = self._channels(notification_type, priority)
            cta = self._cta(category, notification_type, context)
            timeline = self._timeline(created_at, status, channels)
            grouping = self._grouping(created_at, category, priority, status)
            ux = self._ux_metadata(status)
            analytics = self._analytics(priority, status)
            ai = self._ai_metadata(notification_type, category, priority, created_at, title, body)
            gemini = self._future_gemini(title, body, priority, category, created_at)

            notification = Notification(
                user=user,
                notification_type=notification_type,
                title=title,
                body=body,
                category=category,
                priority=priority,
                status=status,
                icon=ICONS[notification_type],
                created_at=created_at,
                delivered_at=timeline['delivered_at'],
                opened_at=timeline['opened_at'],
                clicked_at=timeline['clicked_at'],
                action_url=cta['action_url'],
                deep_link=cta['deep_link'],
                cta_label=cta['cta_label'],
            )
            notification.delivery_channels_metadata = channels
            notification.timeline_metadata = timeline
            notification.grouping_metadata = grouping
            notification.user_experience_metadata = ux
            notification.analytics_metadata = analytics
            notification.ai_metadata = ai
            notification.future_ai_metadata = gemini
            notifications.append(notification)

        return NotificationGenerationResult(notifications=notifications)

    def _weighted_notification_type(self) -> str:
        weighted = {
            'Applications': 8,
            'Interview Scheduled': 6,
            'Interview Reminder': 7,
            'Interview Feedback': 4,
            'Interview Cancelled': 2,
            'Offer Received': 4,
            'Offer Accepted': 2,
            'Offer Rejected': 2,
            'Offer Expiring': 3,
            'Recruiter Message': 8,
            'Mentor Message': 5,
            'Connection Request': 6,
            'Connection Accepted': 4,
            'Job Recommendation': 9,
            'Saved Job Reminder': 5,
            'Application Deadline': 6,
            'Campus Drive': 4,
            'Career Fair': 4,
            'Hackathon': 3,
            'Workshop': 4,
            'Certificate Earned': 2,
            'Resume Analysis': 5,
            'Resume Uploaded': 2,
            'Resume Viewed': 4,
            'Resume Downloaded': 2,
            'ATS Score Updated': 5,
            'Career Score Updated': 5,
            'Skill Gap Report': 4,
            'Learning Recommendation': 5,
            'Mock Interview Ready': 4,
            'Mock Interview Feedback': 4,
            'Community Invitation': 3,
            'Community Update': 3,
            'System Maintenance': 1,
            'Password Changed': 1,
            'Security Alert': 1,
            'New Device Login': 1,
            'Subscription Reminder': 1,
            'Employer Announcement': 2,
            'University Announcement': 2,
            'Admin Broadcast': 1,
            'Support Ticket Update': 2,
            'Payment Success': 1,
            'Payment Failed': 1,
        }
        return self.random.choices(list(weighted.keys()), weights=list(weighted.values()), k=1)[0]

    def _created_at(self) -> datetime:
        return datetime.utcnow() - timedelta(days=self.random.randint(0, 90), hours=self.random.randint(0, 23), minutes=self.random.randint(0, 59))

    def _priority(self, notification_type: str) -> str:
        if notification_type in {'Security Alert', 'Payment Failed'}:
            return 'critical'
        if notification_type in {'Interview Scheduled', 'Interview Reminder', 'Offer Received', 'Offer Expiring', 'New Device Login'}:
            return 'high'
        if notification_type in {'Recruiter Message', 'Applications', 'Application Deadline', 'Support Ticket Update'}:
            return self.random.choice(['high', 'medium'])
        if notification_type in {'System Maintenance', 'Admin Broadcast', 'University Announcement', 'Employer Announcement'}:
            return self.random.choice(['medium', 'informational'])
        if notification_type in {'Career Score Updated', 'ATS Score Updated', 'Learning Recommendation', 'Job Recommendation'}:
            return self.random.choice(['medium', 'low'])
        return self.random.choice(PRIORITIES)

    def _status(self, notification_type: str, created_at: datetime) -> str:
        age_days = (datetime.utcnow() - created_at).days
        if notification_type in {'Offer Expiring', 'Application Deadline'} and age_days > 7:
            return 'expired'
        if age_days > 45:
            return self.random.choice(['archived', 'read', 'dismissed'])
        return self.random.choices(STATUSES, weights=[28, 34, 10, 6, 12, 10], k=1)[0]

    def _context(self, user: Any, notification_type: str, created_at: datetime) -> dict[str, str]:
        role = self.random.choice([
            'Software Engineer', 'Data Analyst', 'Machine Learning Engineer', 'Frontend Engineer', 'Backend Engineer', 'Product Analyst'
        ])
        company = self.random.choice([
            'Google', 'Microsoft', 'Amazon', 'Stripe', 'OpenAI', 'Netflix', 'Zoho', 'Infosys', 'TCS', 'Freshworks'
        ])
        interview_type = self.random.choice(['Technical Interview', 'Behavioral Round', 'Manager Round', 'Recruiter Call'])
        sender_name = self._display_name(user) if notification_type not in {'Recruiter Message', 'Mentor Message', 'Connection Request', 'Connection Accepted'} else self.faker.name()
        return {
            'role': role,
            'company': company,
            'interview_type': interview_type,
            'sender_name': sender_name,
            'date_label': (created_at + timedelta(days=self.random.randint(1, 10))).strftime('%d %b %Y'),
            'time_window': self.random.choice(['30 minutes', '1 hour', 'tomorrow morning', 'later today']),
        }

    def _content(self, notification_type: str, context: dict[str, str]) -> tuple[str, str]:
        title_template, body_template = self.random.choice(TITLE_BODY_LIBRARY[notification_type])
        return title_template.format(**context), body_template.format(**context)

    def _channels(self, notification_type: str, priority: str) -> dict[str, Any]:
        selected = {'in_app'}
        if priority in {'critical', 'high'}:
            selected.add('email')
            selected.add('push')
        if notification_type in {'Security Alert', 'Payment Failed', 'Interview Reminder'}:
            selected.add('sms')
        if self.random.random() < 0.38:
            selected.add('desktop')
        if self.random.random() < 0.44:
            selected.add('browser')
        if self.random.random() < 0.08:
            selected.add('webhook')
        return {
            'channels': sorted(selected),
            'delivery_preferences': {
                'quiet_hours_respected': priority not in {'critical'},
                'batched': priority in {'low', 'informational'},
                'digest_eligible': CATEGORY_MAP[notification_type] in {'jobs', 'career_ai', 'community'},
            },
        }

    def _cta(self, category: str, notification_type: str, context: dict[str, str]) -> dict[str, str]:
        cta_label = self.random.choice(ACTION_LABELS[category])
        slug_category = self._slug(category)
        role_slug = self._slug(context['role'])
        company_slug = self._slug(context['company'])
        return {
            'cta_label': cta_label,
            'action_url': f'/app/{slug_category}/{company_slug}/{role_slug}',
            'deep_link': f'careerbridge://{slug_category}/{company_slug}/{role_slug}/{self._slug(notification_type)}',
        }

    def _timeline(self, created_at: datetime, status: str, channels: dict[str, Any]) -> dict[str, Any]:
        delivered_at = created_at + timedelta(seconds=self.random.randint(3, 180))
        opened_at = None
        clicked_at = None
        completed_at = None
        archived_at = None
        if status in {'read', 'archived', 'pinned', 'dismissed'}:
            opened_at = delivered_at + timedelta(minutes=self.random.randint(1, 600))
        if status in {'read', 'pinned'} and self.random.random() < 0.58:
            clicked_at = opened_at + timedelta(minutes=self.random.randint(1, 120)) if opened_at else None
        if clicked_at is not None and self.random.random() < 0.42:
            completed_at = clicked_at + timedelta(minutes=self.random.randint(2, 240))
        if status == 'archived':
            anchor = opened_at or delivered_at
            archived_at = anchor + timedelta(hours=self.random.randint(2, 72))
        return {
            'created_at': created_at.isoformat(),
            'delivered_at': delivered_at,
            'opened_at': opened_at,
            'clicked_at': clicked_at,
            'completed_at': completed_at,
            'archived_at': archived_at,
            'delivery_channel_count': len(channels['channels']),
        }

    def _grouping(self, created_at: datetime, category: str, priority: str, status: str) -> dict[str, Any]:
        now = datetime.utcnow()
        age_days = (now.date() - created_at.date()).days
        if age_days == 0:
            bucket = 'Today'
        elif age_days == 1:
            bucket = 'Yesterday'
        elif age_days <= 7:
            bucket = 'This Week'
        else:
            bucket = 'Earlier'
        return {
            'time_group': bucket,
            'group_by_unread': status == 'unread',
            'category': category,
            'priority': priority,
        }

    def _ux_metadata(self, status: str) -> dict[str, Any]:
        return {
            'searchable': True,
            'filterable': True,
            'bulk_read_supported': True,
            'bulk_archive_supported': True,
            'bulk_delete_supported': True,
            'pin_supported': True,
            'star_supported': True,
            'reminder_supported': True,
            'snooze_supported': status not in {'expired'},
            'current_flags': {
                'pinned': status == 'pinned',
                'starred': self.random.random() < 0.16,
                'snoozed_until': (datetime.utcnow() + timedelta(hours=self.random.randint(4, 48))).isoformat() if self.random.random() < 0.12 else None,
            },
        }

    def _analytics(self, priority: str, status: str) -> dict[str, Any]:
        open_rate = self.random.randint(68, 98) if priority in {'critical', 'high'} else self.random.randint(34, 86)
        ctr = self.random.randint(18, 74) if status in {'read', 'pinned', 'archived'} else self.random.randint(0, 28)
        return {
            'open_rate': open_rate,
            'ctr': ctr,
            'read_time_seconds': self.random.randint(4, 85) if status in {'read', 'pinned', 'archived'} else None,
            'dismiss_rate': self.random.randint(2, 34),
            'engagement_score': min(99, (open_rate // 2) + ctr),
            'response_rate': self.random.randint(8, 62),
        }

    def _ai_metadata(self, notification_type: str, category: str, priority: str, created_at: datetime, title: str, body: str) -> dict[str, Any]:
        best_time = (created_at + timedelta(hours=self.random.randint(1, 18))).strftime('%Y-%m-%d %H:%M:%S')
        return {
            'ai_summary': f'{title}. {body}',
            'priority_prediction': priority,
            'best_time_to_notify': best_time,
            'smart_notification_grouping': {'group_key': f'{category}:{created_at.date().isoformat()}', 'eligible': category not in {'security', 'offers'}},
            'notification_recommendation': self._recommendation(notification_type, category),
            'ai_notification_type': notification_type in {
                'ATS Score Updated', 'Career Score Updated', 'Skill Gap Report', 'Learning Recommendation', 'Job Recommendation', 'Mock Interview Ready', 'Mock Interview Feedback'
            },
            'signals': {
                'resume_score_increased': notification_type == 'Resume Analysis' and self.random.random() < 0.45,
                'career_score_improved': notification_type == 'Career Score Updated',
                'new_skill_recommendation': notification_type == 'Learning Recommendation',
                'ai_job_match': notification_type == 'Job Recommendation',
                'learning_reminder': notification_type == 'Learning Recommendation' and self.random.random() < 0.52,
                'interview_readiness': notification_type in {'Mock Interview Ready', 'Mock Interview Feedback'},
                'certification_suggestion': notification_type == 'Certificate Earned' or (notification_type == 'Learning Recommendation' and self.random.random() < 0.31),
                'salary_insight': notification_type in {'Offer Received', 'Offer Expiring'} and self.random.random() < 0.38,
                'hiring_trend': notification_type in {'Employer Announcement', 'Job Recommendation'} and self.random.random() < 0.33,
            },
        }

    def _future_gemini(self, title: str, body: str, priority: str, category: str, created_at: datetime) -> dict[str, Any]:
        return {
            'ai_summary': f'{title}: {body}',
            'priority_prediction': priority,
            'best_time_to_notify': (created_at + timedelta(hours=self.random.randint(2, 16))).isoformat(),
            'smart_notification_grouping': {
                'recommended_group': f'{category}-{created_at.date().isoformat()}',
                'bundle_with_similar': category in {'jobs', 'career_ai', 'community', 'announcements'},
            },
            'notification_recommendation': 'Keep enabled' if priority in {'critical', 'high'} else 'Bundle in digest when user engagement is low.',
        }

    def _recommendation(self, notification_type: str, category: str) -> str:
        if category == 'career_ai':
            return 'Surface near dashboard score cards and keep actionable.'
        if category == 'interviews':
            return 'Deliver immediately across in-app and push channels.'
        if category == 'offers':
            return 'Pin to top priority until user acts or notification expires.'
        if category == 'messages':
            return 'Bundle low-priority message notifications during active sessions.'
        return f'Keep {notification_type.lower()} visible based on user engagement and urgency.'

    def _display_name(self, user: Any) -> str:
        full_name = getattr(user, 'full_name', None)
        if full_name:
            return str(full_name)
        first_name = getattr(user, 'first_name', None)
        last_name = getattr(user, 'last_name', None)
        if first_name or last_name:
            return f"{first_name or ''} {last_name or ''}".strip()
        email = getattr(user, 'email', None)
        if email:
            return str(email).split('@')[0]
        return 'User'

    def _slug(self, value: str) -> str:
        slug = re.sub(r'[^a-z0-9]+', '-', value.lower()).strip('-')
        return slug or 'item'


def generate_notifications(users: Sequence[Any], config: AppConfig = CONFIG) -> NotificationGenerationResult:
    generator = NotificationGenerator(config=config)
    return generator.generate(users)


# ================================================================================
# FILE: offer_generator.py
# ================================================================================

# from __future__ import annotations

import random
import re
import string
from dataclasses import dataclass
from datetime import date, datetime, timedelta
from decimal import Decimal
from typing import Sequence

from faker import Faker

from careerbridge_seed_engine.config import AppConfig, CONFIG
from careerbridge_seed_engine.models import Application, Company, Interview, Job, Offer, Recruiter, Student

CURRENCY_BY_COUNTRY: dict[str, str] = {
    'India': 'INR',
    'United States': 'USD',
    'United Kingdom': 'GBP',
    'Canada': 'CAD',
    'Germany': 'EUR',
    'Singapore': 'SGD',
    'Australia': 'AUD',
    'United Arab Emirates': 'AED',
    'Ireland': 'EUR',
}

OFFER_STATUSES: tuple[str, ...] = ('pending', 'accepted', 'rejected', 'expired', 'negotiating', 'withdrawn')
OFFER_TYPES: tuple[str, ...] = ('Full-Time Offer', 'Graduate Offer', 'Internship Offer', 'Contract Offer', 'Pre-Placement Offer')
WORK_MODES: tuple[str, ...] = ('remote', 'hybrid', 'onsite')
NEGOTIATION_REASONS: tuple[str, ...] = (
    'Base salary expectation higher than current offer range.',
    'Candidate requested improved joining bonus and relocation support.',
    'Candidate sought role-level clarity before making a final decision.',
    'Offer comparison with another active opportunity influenced negotiation.',
)
OFFER_DECISION_REASONS: dict[str, tuple[str, ...]] = {
    'accepted': (
        'Strong compensation and role alignment influenced the decision.',
        'The team, growth potential, and location fit well with the student preference.',
        'Offer matched career goals and expected learning opportunities.',
    ),
    'rejected': (
        'Candidate accepted another opportunity with a better domain fit.',
        'Compensation was below the candidate expectation after evaluation.',
        'Location or work model did not align with candidate preferences.',
    ),
    'expired': (
        'Candidate did not respond within the validity period.',
        'Offer lapsed while the candidate was evaluating multiple options.',
    ),
    'pending': (
        'Candidate is still reviewing compensation, benefits, and role scope.',
        'Final decision pending internal discussions and other active interviews.',
    ),
    'negotiating': (
        'Candidate requested revisions to compensation and benefits.',
        'Offer is under review after discussion with recruiter and hiring manager.',
    ),
    'withdrawn': (
        'Offer was withdrawn after role closure or internal business changes.',
        'Background verification dependency was not completed in time.',
    ),
}


@dataclass(slots=True)
class OfferGenerationResult:
    offers: list[Offer]


class OfferGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 6000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 6000)
            self.faker.seed_instance(config.generation.seed + 6000)

    def generate(
        self,
        applications: Sequence[Application],
        interviews: Sequence[Interview],
    ) -> OfferGenerationResult:
        if not applications:
            raise ValueError('Offer generation requires applications.')
        if not interviews:
            raise ValueError('Offer generation requires interviews.')

        interviews_by_application = self._group_interviews_by_application(interviews)
        eligible_applications = [
            application for application in applications
            if getattr(application, 'student', None) is not None
            and getattr(application, 'company', None) is not None
            and getattr(application, 'recruiter', None) is not None
            and getattr(application, 'job', None) is not None
            and interviews_by_application.get(self._application_key(application))
        ]
        if not eligible_applications:
            raise ValueError('Offer generation requires applications linked to interviews and related entities.')

        weighted = self._weighted_applications(eligible_applications)
        offers: list[Offer] = []

        # Offer.applicationId is unique (one offer per application), so we
        # must sample eligible applications WITHOUT replacement even though
        # selection is weighted. Cap the requested count to the number of
        # eligible applications available.
        remaining = list(weighted)
        target_count = min(self.config.counts.offers, len(remaining))
        for index in range(target_count):
            candidates = [item[0] for item in remaining]
            weights = [item[1] for item in remaining]
            application = self.random.choices(candidates, weights=weights, k=1)[0]
            remaining = [item for item in remaining if item[0] is not application]
            interview = self._select_interview(interviews_by_application[self._application_key(application)])
            offers.append(self._build_offer(index, application, interview))

        return OfferGenerationResult(offers=offers)

    def _group_interviews_by_application(self, interviews: Sequence[Interview]) -> dict[str, list[Interview]]:
        grouped: dict[str, list[Interview]] = {}
        for interview in interviews:
            application = getattr(interview, 'application', None)
            if application is None:
                continue
            grouped.setdefault(self._application_key(application), []).append(interview)
        return grouped

    def _application_key(self, application: Application) -> str:
        value = getattr(application, 'id', None) or getattr(application, 'application_reference', None) or getattr(application, 'status', None)
        return str(value)

    def _weighted_applications(self, applications: Sequence[Application]) -> list[tuple[Application, float]]:
        weighted: list[tuple[Application, float]] = []
        for application in applications:
            status = str(getattr(application, 'status', '')).lower()
            match_score = 0
            ats_metadata = getattr(application, 'ats_metadata', None) or {}
            if isinstance(ats_metadata, dict):
                match_score = int(ats_metadata.get('overall_match', 0) or 0)
            base = 1.0 + (match_score / 20.0)
            if 'offer' in status or 'accepted' in status:
                base += 6.0
            elif 'interview' in status:
                base += 4.0
            elif 'shortlisted' in status:
                base += 2.0
            weighted.append((application, base))
        return weighted

    def _select_interview(self, interviews: Sequence[Interview]) -> Interview:
        ordered = sorted(
            interviews,
            key=lambda interview: (
                0 if str(getattr(interview, 'status', '')).lower() == 'completed' else 1,
                int(getattr(interview, 'interview_round', 0) or 0) * -1,
                getattr(interview, 'scheduled_at', datetime.utcnow()),
            ),
        )
        return ordered[0]

    def _build_offer(self, index: int, application: Application, interview: Interview) -> Offer:
        student: Student = application.student
        company: Company = application.company
        recruiter: Recruiter = application.recruiter
        job: Job = application.job
        country = getattr(job, 'location_country', None) or getattr(company, 'headquarters_country', None) or 'United States'
        currency = CURRENCY_BY_COUNTRY.get(country, 'USD')
        offer_status = self._offer_status(application)
        offer_type = self._offer_type(job)
        issue_date = self._issue_date(application, interview)
        expiry_date = issue_date + timedelta(days=self.random.randint(5, 14))
        joining_date = expiry_date + timedelta(days=self.random.randint(14, 90))
        expected_response_date = issue_date + timedelta(days=self.random.randint(3, 8))
        compensation = self._compensation(job, country, currency, offer_type)
        benefits = self._benefits(company, country, offer_type)
        employment_details = self._employment_details(job, company, country)
        conditions = self._offer_conditions(country)
        negotiation = self._negotiation(offer_status, compensation, currency)
        ai_offer = self._ai_offer_analysis(compensation, country, offer_status)
        student_decision = self._student_decision(offer_status)
        offer_letter = self._offer_letter(company, student, job, issue_date)
        onboarding = self._onboarding(company, job, joining_date)
        notifications = self._notifications(offer_status, company, issue_date, expiry_date, joining_date)
        analytics = self._analytics(compensation, recruiter, offer_status)
        ai_support = self._ai_support(ai_offer, offer_status)
        offer_number = self._offer_number(company, job, index)

        offer = Offer(
            application=application,
            interview=interview,
            student=student,
            company=company,
            recruiter=recruiter,
            job=job,
            offer_number=offer_number,
            status=offer_status,
            offer_type=offer_type,
            issue_date=issue_date,
            expiry_date=expiry_date,
            joining_date=joining_date,
            expected_response_date=expected_response_date,
            base_salary=compensation['base_salary'],
            bonus=compensation['bonus'],
            joining_bonus=compensation['joining_bonus'],
            stock_options=compensation['stock_options'],
            variable_pay=compensation['variable_pay'],
            currency=currency,
        )
        offer.offer_reference = f'OFF-{offer_number}'
        offer.compensation_metadata = compensation
        offer.benefits_metadata = benefits
        offer.employment_details_metadata = employment_details
        offer.conditions_metadata = conditions
        offer.negotiation_metadata = negotiation
        offer.ai_analysis_metadata = ai_offer
        offer.student_decision_metadata = student_decision
        offer.letter_metadata = offer_letter
        offer.onboarding_metadata = onboarding
        offer.notifications_metadata = notifications
        offer.analytics_metadata = analytics
        offer.ai_support_metadata = ai_support
        return offer

    def _offer_status(self, application: Application) -> str:
        app_status = str(getattr(application, 'status', '')).lower()
        if 'accepted' in app_status:
            return self.random.choices(['accepted', 'pending', 'negotiating'], weights=[8, 1, 1], k=1)[0]
        if 'offer' in app_status:
            return self.random.choices(['pending', 'accepted', 'negotiating', 'rejected'], weights=[4, 3, 2, 1], k=1)[0]
        if 'interview' in app_status:
            return self.random.choices(['pending', 'negotiating', 'rejected', 'withdrawn'], weights=[4, 2, 2, 1], k=1)[0]
        return self.random.choices(['pending', 'expired', 'withdrawn', 'rejected'], weights=[4, 2, 1, 2], k=1)[0]

    def _offer_type(self, job: Job) -> str:
        employment_type = str(getattr(job, 'employment_type', '')).lower()
        if employment_type == 'internship':
            return 'Internship Offer'
        if employment_type == 'graduate':
            return self.random.choice(['Graduate Offer', 'Pre-Placement Offer'])
        if employment_type == 'contract':
            return 'Contract Offer'
        return 'Full-Time Offer'

    def _issue_date(self, application: Application, interview: Interview) -> date:
        scheduled_at = getattr(interview, 'scheduled_at', None)
        if scheduled_at is None:
            timeline = getattr(application, 'timeline_metadata', None) or {}
            submitted = timeline.get('submitted_at') or datetime.utcnow()
            if isinstance(submitted, str):
                submitted = datetime.fromisoformat(submitted)
            scheduled_at = submitted + timedelta(days=self.random.randint(10, 30))
        return (scheduled_at + timedelta(days=self.random.randint(1, 7))).date()

    def _compensation(self, job: Job, country: str, currency: str, offer_type: str) -> dict[str, object]:
        salary_min = Decimal(getattr(job, 'salary_min', 0) or 0)
        salary_max = Decimal(getattr(job, 'salary_max', salary_min) or salary_min)
        if salary_min == 0 and salary_max == 0:
            salary_min = Decimal('50000')
            salary_max = Decimal('70000')
        base_salary = (salary_min + (salary_max - salary_min) * Decimal(str(self.random.uniform(0.35, 0.82)))).quantize(Decimal('1.00'))
        performance_bonus = (base_salary * Decimal(str(self.random.uniform(0.04, 0.14)))).quantize(Decimal('1.00')) if offer_type != 'Internship Offer' else Decimal('0.00')
        variable_pay = (base_salary * Decimal(str(self.random.uniform(0.03, 0.10)))).quantize(Decimal('1.00')) if offer_type not in {'Internship Offer', 'Contract Offer'} else Decimal('0.00')
        joining_bonus = self._country_amount(country, internship=1500, entry=3500, experienced=7000, offer_type=offer_type)
        bonus = (performance_bonus * Decimal(str(self.random.uniform(0.65, 1.25)))).quantize(Decimal('1.00')) if performance_bonus else Decimal('0.00')
        stock_options = self._stock_options(country, offer_type)
        annual_increment = round(self.random.uniform(5.0, 14.0), 1) if offer_type != 'Internship Offer' else 0.0
        breakdown = {
            'monthly_base': (base_salary / Decimal('12')).quantize(Decimal('1.00')),
            'annual_base': base_salary,
            'annual_variable': variable_pay,
            'annual_bonus_target': bonus,
            'joining_bonus': joining_bonus,
            'esop_value_estimate': stock_options['estimated_value'],
        }
        return {
            'base_salary': base_salary,
            'bonus': bonus,
            'joining_bonus': joining_bonus,
            'stock_options': stock_options['units'],
            'esop': stock_options,
            'performance_bonus': performance_bonus,
            'annual_increment_pct': annual_increment,
            'variable_pay': variable_pay,
            'currency': currency,
            'salary_breakdown': breakdown,
        }

    def _country_amount(self, country: str, internship: int, entry: int, experienced: int, offer_type: str) -> Decimal:
        multipliers = {
            'India': 1,
            'United States': 20,
            'United Kingdom': 10,
            'Canada': 14,
            'Germany': 11,
            'Singapore': 13,
            'Australia': 15,
            'United Arab Emirates': 12,
            'Ireland': 10,
        }
        base = internship if offer_type == 'Internship Offer' else entry if offer_type in {'Graduate Offer', 'Pre-Placement Offer'} else experienced
        return Decimal(str(base * multipliers.get(country, 10))).quantize(Decimal('1.00'))

    def _stock_options(self, country: str, offer_type: str) -> dict[str, object]:
        if offer_type in {'Internship Offer', 'Contract Offer'}:
            return {'units': 0, 'plan_type': None, 'estimated_value': Decimal('0.00'), 'vesting_schedule': None}
        units = self.random.randint(100, 2500)
        price_factor = {
            'India': Decimal('45'),
            'United States': Decimal('4.5'),
            'United Kingdom': Decimal('3.2'),
            'Canada': Decimal('4.0'),
            'Germany': Decimal('3.4'),
            'Singapore': Decimal('4.2'),
            'Australia': Decimal('4.1'),
            'United Arab Emirates': Decimal('4.0'),
            'Ireland': Decimal('3.3'),
        }
        estimated_value = (Decimal(units) * price_factor.get(country, Decimal('4.0'))).quantize(Decimal('1.00'))
        return {
            'units': units,
            'plan_type': self.random.choice(['ESOP', 'RSU-like internal equity']),
            'estimated_value': estimated_value,
            'vesting_schedule': '4 years with a 1-year cliff',
        }

    def _benefits(self, company: Company, country: str, offer_type: str) -> dict[str, object]:
        company_benefits = getattr(company, 'benefits', None) or []
        paid_leave = self.random.randint(10, 28) if offer_type != 'Internship Offer' else self.random.randint(5, 12)
        remote_enabled = any('remote' in str(item).lower() for item in company_benefits) or self.random.random() < 0.58
        hybrid_enabled = any('hybrid' in str(item).lower() for item in company_benefits) or self.random.random() < 0.64
        certification_budget = self._country_amount(country, internship=100, entry=300, experienced=600, offer_type=offer_type)
        learning_budget = self._country_amount(country, internship=150, entry=500, experienced=1000, offer_type=offer_type)
        return {
            'health_insurance': True,
            'dental': country in {'United States', 'Canada', 'United Kingdom', 'Australia', 'Ireland'},
            'vision': country in {'United States', 'Canada', 'Australia'},
            'life_insurance': offer_type != 'Internship Offer',
            'remote_work': remote_enabled,
            'hybrid': hybrid_enabled,
            'relocation': offer_type != 'Internship Offer' and self.random.random() < 0.52,
            'learning_budget': learning_budget,
            'certification_budget': certification_budget,
            'gym_membership': self.random.random() < 0.46,
            'paid_leave_days': paid_leave,
            'maternity_paternity_leave': self.random.randint(30, 180) if offer_type != 'Internship Offer' else 0,
            'laptop': True,
            'internet_allowance': self._country_amount(country, internship=25, entry=60, experienced=100, offer_type=offer_type) if remote_enabled or hybrid_enabled else Decimal('0.00'),
            'travel_allowance': self._country_amount(country, internship=30, entry=80, experienced=150, offer_type=offer_type) if not remote_enabled else Decimal('0.00'),
        }

    def _employment_details(self, job: Job, company: Company, country: str) -> dict[str, object]:
        manager_name = self._manager_name(country)
        office = getattr(job, 'office_location', None) or f"{getattr(company, 'headquarters_city', 'Office')}, {country}"
        return {
            'employment_type': getattr(job, 'employment_type', 'full_time'),
            'department': getattr(job, 'department', 'General'),
            'reporting_manager': manager_name,
            'location': f"{getattr(job, 'location_city', getattr(company, 'headquarters_city', 'Remote'))}, {country}",
            'office': office,
            'probation_period_months': self.random.choice([0, 3, 6]),
            'notice_period_days': self.random.choice([0, 15, 30, 60]),
            'working_hours': self.random.choice(['09:00-18:00', '09:30-18:30', '10:00-19:00']),
            'work_mode': str(getattr(job, 'work_model', self.random.choice(WORK_MODES))).lower(),
        }

    def _manager_name(self, country: str) -> str:
        local_faker = Faker('en_IN' if country == 'India' else 'en_US')
        if self.config.generation.deterministic:
            local_faker.seed_instance(self.random.randint(1, 10_000_000))
        return local_faker.name()

    def _offer_conditions(self, country: str) -> dict[str, object]:
        return {
            'background_verification': True,
            'education_verification': True,
            'reference_check': self.random.random() < 0.72,
            'medical_check': country in {'United Arab Emirates', 'Singapore'} or self.random.random() < 0.28,
            'visa_requirement': country not in {'India'} and self.random.random() < 0.34,
            'work_authorization': self.random.choice([
                'Candidate must provide valid work authorization before joining.',
                'Work authorization required based on location and employment type.',
                'No additional work authorization documents needed for this location.',
            ]),
            'drug_test': country in {'United States', 'Canada'} and self.random.random() < 0.36,
        }

    def _negotiation(self, offer_status: str, compensation: dict[str, object], currency: str) -> dict[str, object]:
        negotiating = offer_status == 'negotiating' or self.random.random() < 0.22
        candidate_counter = None
        recruiter_counter = None
        history: list[dict[str, object]] = []
        if negotiating:
            base_salary = Decimal(compensation['base_salary'])
            requested = (base_salary * Decimal(str(self.random.uniform(1.04, 1.18)))).quantize(Decimal('1.00'))
            recruiter_reply = (base_salary * Decimal(str(self.random.uniform(1.01, 1.10)))).quantize(Decimal('1.00'))
            candidate_counter = {'base_salary': requested, 'currency': currency}
            recruiter_counter = {'base_salary': recruiter_reply, 'currency': currency}
            history = [
                {'timestamp': (datetime.utcnow() - timedelta(days=4)).isoformat(), 'actor': 'candidate', 'action': 'Counter offer submitted', 'reason': self.random.choice(NEGOTIATION_REASONS)},
                {'timestamp': (datetime.utcnow() - timedelta(days=2)).isoformat(), 'actor': 'recruiter', 'action': 'Revised package shared', 'reason': 'Adjusted compensation after internal review.'},
            ]
        return {
            'candidate_counter_offer': candidate_counter,
            'recruiter_counter_offer': recruiter_counter,
            'negotiation_history': history,
            'negotiation_status': 'active' if negotiating and offer_status == 'negotiating' else 'closed' if negotiating else 'not_started',
            'reason': self.random.choice(NEGOTIATION_REASONS) if negotiating else None,
        }

    def _ai_offer_analysis(self, compensation: dict[str, object], country: str, offer_status: str) -> dict[str, object]:
        competitiveness = self.random.randint(58, 96)
        market_comparison = self.random.randint(-8, 18)
        acceptance_probability = self.random.randint(38, 92) if offer_status != 'rejected' else self.random.randint(20, 48)
        return {
            'offer_competitiveness': competitiveness,
            'market_salary_comparison_pct': market_comparison,
            'acceptance_probability': acceptance_probability,
            'risk_score': self.random.randint(18, 72),
            'retention_prediction': self.random.randint(46, 91),
            'compensation_score': self.random.randint(52, 95),
            'career_growth_score': self.random.randint(55, 94),
            'country_salary_positioning': f'Positioned {"above" if market_comparison >= 0 else "below"} market median for {country}.',
        }

    def _student_decision(self, offer_status: str) -> dict[str, object]:
        return {
            'decision': offer_status,
            'reason': self.random.choice(OFFER_DECISION_REASONS[offer_status]),
            'decision_confidence': self.random.randint(54, 96),
            'decision_timestamp': (datetime.utcnow() - timedelta(days=self.random.randint(0, 8))).isoformat() if offer_status in {'accepted', 'rejected', 'withdrawn'} else None,
        }

    def _offer_letter(self, company: Company, student: Student, job: Job, issue_date: date) -> dict[str, object]:
        company_slug = self._slug(getattr(company, 'name', 'company'))
        student_slug = self._slug(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', 'student'))
        role_slug = self._slug(getattr(job, 'title', 'role'))
        stamp = issue_date.strftime('%Y%m%d')
        return {
            'offer_letter_pdf': f'{company_slug}_{student_slug}_{role_slug}_offer_letter_{stamp}.pdf',
            'employment_contract': f'{company_slug}_{student_slug}_employment_contract_{stamp}.pdf',
            'benefits_guide': f'{company_slug}_benefits_guide_{issue_date.year}.pdf',
            'onboarding_checklist': f'{company_slug}_{student_slug}_onboarding_checklist_{stamp}.pdf',
            'welcome_letter': f'{company_slug}_{student_slug}_welcome_letter_{stamp}.pdf',
            'hr_documents': [
                f'{company_slug}_policy_handbook_{issue_date.year}.pdf',
                f'{company_slug}_tax_forms_{issue_date.year}.pdf',
                f'{company_slug}_compliance_acknowledgement_{issue_date.year}.pdf',
            ],
        }

    def _onboarding(self, company: Company, job: Job, joining_date: date) -> dict[str, object]:
        training_start = joining_date + timedelta(days=1)
        orientation = joining_date
        return {
            'document_submission': {
                'deadline': (joining_date - timedelta(days=5)).isoformat(),
                'required_documents': ['Government ID', 'Academic proof', 'Tax information', 'Bank details'],
                'status': self.random.choice(['Pending', 'In Progress', 'Completed']),
            },
            'laptop_allocation': {
                'asset_tag': f'CB-{self.random.randint(10000, 99999)}',
                'allocation_date': (joining_date - timedelta(days=2)).isoformat(),
                'status': self.random.choice(['Planned', 'Allocated', 'Ready for pickup']),
            },
            'manager_assignment': self._manager_name(getattr(company, 'headquarters_country', None) or 'United States'),
            'team_assignment': getattr(job, 'department', 'General Team'),
            'training_schedule': [
                {'date': training_start.isoformat(), 'session': 'Role onboarding and tool access'},
                {'date': (training_start + timedelta(days=1)).isoformat(), 'session': 'Team workflows and delivery expectations'},
                {'date': (training_start + timedelta(days=3)).isoformat(), 'session': 'Technical or functional deep dive'},
            ],
            'orientation': {'date': orientation.isoformat(), 'session': 'Company orientation and HR introduction'},
            'first_week_tasks': [
                'Complete onboarding documentation and system access setup.',
                'Meet reporting manager and immediate team members.',
                'Review role goals, success metrics, and onboarding plan.',
                'Shadow active workflows and complete initial guided tasks.',
            ],
        }

    def _notifications(self, offer_status: str, company: Company, issue_date: date, expiry_date: date, joining_date: date) -> list[dict[str, object]]:
        company_name = getattr(company, 'name', 'the company')
        items = [
            {'type': 'Offer Released', 'timestamp': datetime.combine(issue_date, datetime.min.time()).isoformat(), 'message': f'Your offer from {company_name} has been released.'},
            {'type': 'Reminder', 'timestamp': datetime.combine(issue_date + timedelta(days=3), datetime.min.time()).isoformat(), 'message': 'Reminder: please review and respond to your offer before the deadline.'},
        ]
        if offer_status == 'negotiating':
            items.append({'type': 'Negotiation Update', 'timestamp': datetime.combine(issue_date + timedelta(days=4), datetime.min.time()).isoformat(), 'message': 'A revised compensation update is available.'})
        if offer_status == 'accepted':
            items.append({'type': 'Accepted', 'timestamp': datetime.combine(issue_date + timedelta(days=5), datetime.min.time()).isoformat(), 'message': 'Your offer acceptance has been recorded.'})
            items.append({'type': 'Joining Reminder', 'timestamp': datetime.combine(joining_date - timedelta(days=7), datetime.min.time()).isoformat(), 'message': 'Your joining date is approaching. Please complete remaining onboarding tasks.'})
        if offer_status == 'rejected':
            items.append({'type': 'Rejected', 'timestamp': datetime.combine(issue_date + timedelta(days=6), datetime.min.time()).isoformat(), 'message': 'Your final offer decision has been recorded as declined.'})
        if offer_status == 'expired':
            items.append({'type': 'Expired', 'timestamp': datetime.combine(expiry_date, datetime.min.time()).isoformat(), 'message': 'The offer validity period has ended.'})
        return items

    def _analytics(self, compensation: dict[str, object], recruiter: Recruiter, offer_status: str) -> dict[str, object]:
        base = Decimal(compensation['base_salary'])
        return {
            'offer_acceptance_rate': self.random.randint(46, 88),
            'average_compensation': base.quantize(Decimal('1.00')),
            'offer_turnaround_time_days': self.random.randint(3, 14),
            'salary_benchmark': {
                'min': (base * Decimal('0.92')).quantize(Decimal('1.00')),
                'median': base.quantize(Decimal('1.00')),
                'max': (base * Decimal('1.14')).quantize(Decimal('1.00')),
            },
            'department_acceptance': self.random.randint(42, 84),
            'university_acceptance': self.random.randint(38, 82),
            'recruiter_performance': {
                'recruiter': getattr(recruiter, 'full_name', None) or getattr(recruiter, 'email', 'Recruiter'),
                'conversion_score': self.random.randint(52, 94),
                'status_anchor': offer_status,
            },
        }

    def _ai_support(self, ai_offer_analysis: dict[str, object], offer_status: str) -> dict[str, object]:
        return {
            'offer_recommendation': 'Strongly consider acceptance if role alignment and growth are high.' if ai_offer_analysis['offer_competitiveness'] >= 78 else 'Review compensation and growth carefully before finalizing a decision.',
            'salary_negotiation_advice': 'Focus discussion on total compensation, role scope, and learning support rather than base pay alone.' if offer_status == 'negotiating' else 'Negotiation is optional; prioritize fit, growth, and long-term trajectory.',
            'career_advice': 'Evaluate the manager, team quality, learning curve, and progression path alongside compensation.',
            'market_comparison': ai_offer_analysis['country_salary_positioning'],
            'retention_prediction': ai_offer_analysis['retention_prediction'],
        }

    def _offer_number(self, company: Company, job: Job, index: int) -> str:
        company_code = re.sub(r'[^A-Z]', '', str(getattr(company, 'name', 'COMP')).upper())[:5] or 'COMP'
        job_code = re.sub(r'[^A-Z]', '', str(getattr(job, 'title', 'ROLE')).upper())[:4] or 'ROLE'
        suffix = ''.join(self.random.choices(string.digits, k=4))
        return f'{company_code}-{job_code}-{index + 1:05d}-{suffix}'

    def _slug(self, value: str) -> str:
        slug = re.sub(r'[^a-z0-9]+', '-', value.lower()).strip('-')
        return slug or 'item'


def generate_offers(
    applications: Sequence[Application],
    interviews: Sequence[Interview],
    config: AppConfig = CONFIG,
) -> OfferGenerationResult:
    generator = OfferGenerator(config=config)
    return generator.generate(applications, interviews)


