@dataclass(slots=True)
class RecruiterGenerationResult:
    users: list[User]
    recruiters: list[Recruiter]


class RecruiterGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 2000)
        self.base_faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 2000)
            self.base_faker.seed_instance(config.generation.seed + 2000)
        self._used_emails: set[str] = set()
        self._used_handles: set[str] = set()

    def generate(self, companies: Sequence[Company]) -> RecruiterGenerationResult:
        if not companies:
            raise ValueError('Recruiter generation requires at least one company record.')

        users: list[User] = []
        recruiters: list[Recruiter] = []
        weighted_companies = self._company_weights(companies)

        for index in range(self.config.counts.recruiters):
            company = self._choose_company(weighted_companies)
            faker = self._faker_for_company(company, index)
            first_name, last_name = self._name_for_company(faker, company)
            user = self._build_user(index, company, first_name, last_name)
            recruiter = self._build_recruiter(index, company, user, first_name, last_name)
            users.append(user)
            recruiters.append(recruiter)

        return RecruiterGenerationResult(users=users, recruiters=recruiters)

    def _company_weights(self, companies: Sequence[Company]) -> list[tuple[Company, float]]:
        weighted: list[tuple[Company, float]] = []
        for company in companies:
            metadata = self._company_metadata(company)
            employee_count = int(metadata.get('employee_count', 1000) or 1000)
            active_jobs = int(metadata.get('hiring_profile', {}).get('active_jobs', 8) or 8)
            score = max(1.0, (employee_count / 1500.0) + (active_jobs / 12.0))
            weighted.append((company, score))
        return weighted

    def _choose_company(self, weighted_companies: Sequence[tuple[Company, float]]) -> Company:
        companies = [item[0] for item in weighted_companies]
        weights = [item[1] for item in weighted_companies]
        return self.random.choices(companies, weights=weights, k=1)[0]

    def _faker_for_company(self, company: Company, index: int) -> Faker:
        locale = COUNTRY_LOCALE_MAP.get(company.headquarters_country or '', self.config.generation.locale)
        faker = Faker(locale)
        if self.config.generation.deterministic:
            faker.seed_instance(self.config.generation.seed + 2000 + index * 53)
        return faker

    def _name_for_company(self, faker: Faker, company: Company) -> tuple[str, str]:
        country = company.headquarters_country or ''
        if country == 'India':
            full_name = faker.name()
            tokens = [token.strip('. ') for token in full_name.replace('Mr', '').replace('Ms', '').replace('Mrs', '').replace('Dr', '').split() if token.strip('. ')]
            if len(tokens) >= 2:
                return tokens[0], tokens[-1]
        return faker.first_name(), faker.last_name()

    def _build_user(self, index: int, company: Company, first_name: str, last_name: str) -> User:
        email = self._unique_work_email(first_name, last_name, company, index)
        avatar_seed = hashlib.sha1(email.encode('utf-8')).hexdigest()[:16]
        password_hash = hashlib.sha256(f'{email}|{self.config.generation.seed}|recruiter'.encode('utf-8')).hexdigest()
        phone = self._phone(company.headquarters_country or 'United States')
        return User(
            first_name=first_name,
            last_name=last_name,
            email=email,
            password_hash=password_hash,
            role=UserRole.recruiter,
            status=UserStatus.active,
            phone=phone,
            avatar_url=f'https://api.dicebear.com/7.x/initials/svg?seed={avatar_seed}',
            email_verified=True,
            last_login_at=self._recent_datetime(30),
        )

    def _build_recruiter(self, index: int, company: Company, user: User, first_name: str, last_name: str) -> Recruiter:
        metadata = self._company_metadata(company)
        specialization = self._specialization(company)
        seniority = self._seniority(company)
        department_name = self._department_name(company, specialization)
        title = self._title_for_department(department_name, seniority)
        years_experience = self._years_experience(seniority)
        response_rate = self._response_rate(seniority)
        hiring_domains = self._hiring_domains(company, specialization, department_name)
        bio = self._bio(first_name, company.name, specialization, years_experience)
        about = self._about(company, specialization, years_experience)
        handle = self._unique_handle(first_name, last_name, company, index)
        extra = self._extended_metadata(company, specialization, seniority, department_name, years_experience, response_rate, handle)

        recruiter = Recruiter(
            user=user,
            company=company,
            email=user.email,
            title=title,
            department_name=department_name,
            hiring_domains=hiring_domains,
            years_experience=years_experience,
            response_rate=response_rate,
            bio=f'{bio} {about}',
        )
        recruiter.full_name = f'{first_name} {last_name}'
        recruiter.country = company.headquarters_country
        recruiter.city = company.headquarters_city
        recruiter.timezone = TIMEZONE_BY_COUNTRY.get(company.headquarters_country or '', self.config.generation.timezone)
        recruiter.office_location = self._office_location(company)
        recruiter.languages_spoken = self._languages(company.headquarters_country or 'United States')
        recruiter.seniority_level = seniority
        recruiter.employee_id = self._employee_id(company, index)
        recruiter.profile_photo_url = user.avatar_url
        recruiter.about_section = about
        recruiter.careerbridge_profile_url = f'https://careerbridge.example.dev/recruiters/{handle}'
        recruiter.portfolio_url = f'https://profile.example.dev/{handle}'
        recruiter.recruiter_profile_url = f'https://recruiters.example.dev/{handle}'
        recruiter.calendar_url = f'https://calendar.example.dev/{handle}'
        recruiter.ai_profile = extra['ai_profile']
        recruiter.metrics = extra['metrics']
        recruiter.calendar_metadata = extra['calendar']
        recruiter.messaging_templates = extra['messaging_templates']
        recruiter.network_metadata = extra['network']
        recruiter.verification_metadata = extra['verification']
        recruiter.preferences_metadata = extra['preferences']
        recruiter.ai_metadata = extra['ai_metadata']
        recruiter.future_relationships = extra['future_relationships']
        recruiter.favorite_technologies = extra['favorite_technologies']
        recruiter.favorite_universities = extra['favorite_universities']
        recruiter.favorite_certifications = extra['favorite_certifications']
        recruiter.favorite_interview_questions = extra['favorite_interview_questions']
        recruiter.top_hiring_skills = extra['top_hiring_skills']
        recruiter.recently_filled_roles = extra['recently_filled_roles']
        recruiter.upcoming_campus_visits = extra['upcoming_campus_visits']
        recruiter.recent_activity_feed = extra['recent_activity_feed']
        recruiter.pinned_announcement = extra['pinned_announcement']
        recruiter.professional_achievements = extra['professional_achievements']
        recruiter.awards = extra['awards']
        recruiter.internal_notes = extra['internal_notes']
        recruiter.candidate_watchlist = extra['candidate_watchlist']
        recruiter.linkedin_placeholder_handle = handle
        return recruiter

    def _company_metadata(self, company: Company) -> dict:
        metadata = getattr(company, 'metadata_json', None)
        return metadata if isinstance(metadata, dict) else {}

    def _specialization(self, company: Company) -> str:
        categories = self._company_metadata(company).get('hiring_profile', {}).get('categories', [])
        mapped = []
        for category in categories:
            if 'Software' in category:
                mapped.append('Engineering')
            elif 'Data' in category:
                mapped.append('Data')
            elif 'Cloud' in category or 'Platform' in category or 'DevOps' in category:
                mapped.append('Cloud')
            elif 'Design' in category:
                mapped.append('Design')
            elif 'Security' in category:
                mapped.append('Security')
            elif 'Product' in category:
                mapped.append('Product')
            elif 'Marketing' in category:
                mapped.append('Marketing')
            elif 'Finance' in category or 'Risk' in category:
                mapped.append('Finance')
            elif 'Operations' in category or 'Support' in category:
                mapped.append('Operations')
        pool = mapped or list(RECRUITING_SPECIALIZATIONS)
        return self.random.choice(pool)

    def _seniority(self, company: Company) -> str:
        company_size = (company.company_size or '').lower()
        if company_size == 'enterprise':
            return self.random.choices(SENIORITY_LEVELS, weights=[12, 28, 32, 18, 10], k=1)[0]
        if company_size == 'startup':
            return self.random.choices(SENIORITY_LEVELS, weights=[24, 36, 24, 12, 4], k=1)[0]
        return self.random.choices(SENIORITY_LEVELS, weights=[16, 30, 28, 18, 8], k=1)[0]

    def _department_name(self, company: Company, specialization: str) -> str:
        options = ['Talent Acquisition', 'Campus Recruiting', 'People Operations']
        if specialization in {'Engineering', 'AI', 'Cloud', 'Data', 'Security'} and self.random.random() < 0.25:
            options.append('Executive Recruiting')
        return self.random.choice(options)

    def _title_for_department(self, department_name: str, seniority: str) -> str:
        base_titles = CURRENT_POSITIONS.get(department_name, CURRENT_POSITIONS['Talent Acquisition'])
        title = self.random.choice(base_titles)
        if seniority == 'Lead' and 'Lead' not in title and 'Senior' not in title:
            return f'Lead {title}'
        if seniority == 'Principal' and 'Principal' not in title:
            return f'Principal {title}'
        if seniority == 'Associate' and 'Senior' in title:
            return title.replace('Senior ', '')
        return title

    def _years_experience(self, seniority: str) -> int:
        ranges = {
            'Associate': (1, 3),
            'Specialist': (2, 5),
            'Senior': (4, 8),
            'Lead': (7, 12),
            'Principal': (10, 18),
        }
        low, high = ranges[seniority]
        return self.random.randint(low, high)

    def _response_rate(self, seniority: str) -> int:
        base = {'Associate': 78, 'Specialist': 74, 'Senior': 70, 'Lead': 66, 'Principal': 62}[seniority]
        return max(self.config.distributions.recruiter_response_rate_min, min(self.config.distributions.recruiter_response_rate_max, int(self.random.gauss(base, 7))))

    def _hiring_domains(self, company: Company, specialization: str, department_name: str) -> dict[str, object]:
        company_meta = self._company_metadata(company)
        company_skills = company_meta.get('frequently_hired_skills') or company_meta.get('tech_stack', {}).get('frequently_hired_skills', []) or []
        target_universities = company_meta.get('preferred_universities') or self.random.sample(list(UNIVERSITY_POOL), k=4)
        open_roles = self._open_roles_for_specialization(specialization)
        hiring_regions = self._hiring_regions(company.headquarters_country or 'India')
        return {
            'specialization': specialization,
            'expertise_level': self.random.choice(['Foundational', 'Strong', 'Advanced', 'Expert']),
            'departments_handled': self._departments_handled(specialization),
            'current_open_roles': open_roles,
            'campus_hiring': department_name == 'Campus Recruiting' or self.random.random() < 0.62,
            'lateral_hiring': True,
            'executive_hiring': department_name == 'Executive Recruiting' or self.random.random() < 0.14,
            'graduate_hiring': self.random.random() < 0.72,
            'intern_hiring': self.random.random() < 0.68,
            'hiring_regions': hiring_regions,
            'target_universities': target_universities[: self.random.randint(min(3, len(target_universities)), max(min(6, len(target_universities)), min(3, len(target_universities))))] if target_universities else [],
            'preferred_skills': list(company_skills[: self.random.randint(4, min(8, len(company_skills) or 4))]) if company_skills else list(self.random.sample(SPECIALIZATION_SKILLS[specialization], k=min(5, len(SPECIALIZATION_SKILLS[specialization])))),
            'preferred_degrees': list(PREFERRED_DEGREES[specialization][: self.random.randint(2, min(4, len(PREFERRED_DEGREES[specialization])))]),
            'preferred_gpa': round(self.random.uniform(6.5, 8.8), 1),
            'preferred_certifications': list(PREFERRED_CERTIFICATIONS[specialization][: self.random.randint(1, min(3, len(PREFERRED_CERTIFICATIONS[specialization])))]),
        }

    def _bio(self, first_name: str, company_name: str, specialization: str, years_experience: int) -> str:
        return (
            f'{first_name} supports early-career and lateral hiring at {company_name}, with {years_experience} years of recruiting experience across {specialization.lower()} roles. '
            f'Known for clear communication, structured candidate evaluation, and practical hiring partnership with business teams.'
        )

    def _about(self, company: Company, specialization: str, years_experience: int) -> str:
        return (
            f'Focused on building strong talent pipelines in {specialization.lower()}, improving candidate experience, and aligning hiring decisions with team growth priorities. '
            f'Works closely with managers to calibrate expectations, support interviews, and convert promising students into successful hires.'
        )

    def _extended_metadata(
        self,
        company: Company,
        specialization: str,
        seniority: str,
        department_name: str,
        years_experience: int,
        response_rate: int,
        handle: str,
    ) -> dict[str, object]:
        company_meta = self._company_metadata(company)
        active_jobs = int(company_meta.get('hiring_profile', {}).get('active_jobs', 10) or 10)
        hires = self.random.randint(18, 260 if seniority in {'Lead', 'Principal'} else 140)
        offers_sent = max(hires, int(hires * self.random.uniform(1.15, 1.9)))
        offers_accepted = min(offers_sent, max(1, int(offers_sent * self.random.uniform(0.55, 0.86))))
        interview_success = self.random.randint(28, 74)
        acceptance_rate = int(round((offers_accepted / max(1, offers_sent)) * 100))
        time_to_hire = self.random.randint(12, 58)
        satisfaction = round(self.random.uniform(3.7, 4.9), 1)
        response_rating = round(min(5.0, max(3.5, response_rate / 20 + self.random.uniform(0.1, 0.8))), 1)
        placement_success = self.random.randint(52, 91)
        ai_profile = self._ai_profile(specialization, seniority)
        calendar = self._calendar(company.headquarters_country or 'India')
        messaging_templates = self._messaging_templates(company.name)
        network = self._network_metadata(company)
        verification = self._verification(company)
        preferences = self._preferences(company)
        ai_metadata = self._ai_metadata(specialization, seniority)
        favorite_tech = self._favorite_technologies(company, specialization)
        favorite_universities = self._favorite_universities(company)
        favorite_certifications = self._favorite_certifications(specialization)
        top_hiring_skills = self._top_hiring_skills(company, specialization)
        recently_filled_roles = self._recently_filled_roles(specialization)
        upcoming_campus_visits = self._upcoming_campus_visits(company)
        recent_activity = self._recent_activity_feed(company.name)
        return {
            'ai_profile': ai_profile,
            'metrics': {
                'candidates_hired': hires,
                'offers_sent': offers_sent,
                'offers_accepted': offers_accepted,
                'average_response_time_hours': self.random.randint(4, 34),
                'interview_success_rate_pct': interview_success,
                'acceptance_rate_pct': acceptance_rate,
                'hiring_satisfaction': satisfaction,
                'response_rating': response_rating,
                'average_time_to_hire_days': time_to_hire,
                'placement_success_pct': placement_success,
                'active_roles_managed': min(active_jobs, self.random.randint(4, max(5, active_jobs // 2 + 4))),
            },
            'calendar': calendar,
            'messaging_templates': messaging_templates,
            'network': network,
            'verification': verification,
            'preferences': preferences,
            'ai_metadata': ai_metadata,
            'future_relationships': {
                'supports_jobs': True,
                'supports_applications': True,
                'supports_messages': True,
                'supports_interviews': True,
                'supports_offers': True,
                'supports_notifications': True,
                'supports_campus_drives': True,
                'supports_analytics': True,
                'supports_dashboard': True,
            },
            'favorite_technologies': favorite_tech,
            'favorite_universities': favorite_universities,
            'favorite_certifications': favorite_certifications,
            'favorite_interview_questions': list(self.random.sample(INTERVIEW_QUESTIONS, k=3)),
            'top_hiring_skills': top_hiring_skills,
            'recently_filled_roles': recently_filled_roles,
            'upcoming_campus_visits': upcoming_campus_visits,
            'recent_activity_feed': recent_activity,
            'pinned_announcement': f'Currently hiring for {specialization.lower()} and graduate pathways at {company.name}. Candidates with strong project work and clear fundamentals are encouraged to apply.',
            'professional_achievements': list(self.random.sample(ACHIEVEMENTS, k=2)),
            'awards': list(self.random.sample(AWARDS, k=1 if seniority in {'Associate', 'Specialist'} else 2)),
            'internal_notes': f'Prefers calibrated interview loops, structured scorecards, and strong candidate follow-through for {specialization.lower()} hiring.',
            'candidate_watchlist': self._candidate_watchlist(handle),
        }

    def _open_roles_for_specialization(self, specialization: str) -> list[str]:
        mapping = {
            'Engineering': ['Software Engineer I', 'Backend Engineer', 'Full Stack Engineer', 'Platform Engineer'],
            'Design': ['Product Designer', 'UX Designer', 'Design Systems Associate'],
            'AI': ['ML Engineer', 'AI Associate', 'Applied AI Engineer'],
            'Cloud': ['Cloud Engineer', 'DevOps Engineer', 'Platform Associate'],
            'Product': ['Associate Product Manager', 'Product Analyst', 'Growth Product Associate'],
            'Data': ['Data Analyst', 'Data Engineer', 'BI Analyst'],
            'Security': ['Security Analyst', 'Cloud Security Associate', 'SOC Analyst'],
            'Marketing': ['Marketing Analyst', 'Lifecycle Specialist', 'Campaign Associate'],
            'Finance': ['Financial Analyst', 'Risk Analyst', 'FP&A Associate'],
            'Operations': ['Operations Analyst', 'Technical Support Associate', 'Program Operations Associate'],
        }
        roles = mapping[specialization]
        return self.random.sample(roles, k=min(len(roles), self.random.randint(2, 4)))

    def _departments_handled(self, specialization: str) -> list[str]:
        mapping = {
            'Engineering': ['Platform Engineering', 'Product Engineering', 'Infrastructure'],
            'Design': ['Product Design', 'UX Research', 'Design Systems'],
            'AI': ['Applied AI', 'Data Science', 'ML Platform'],
            'Cloud': ['Cloud Platform', 'Infrastructure', 'SRE'],
            'Product': ['Product Management', 'Growth', 'Customer Experience'],
            'Data': ['Analytics', 'Data Platform', 'Business Intelligence'],
            'Security': ['Security Engineering', 'Trust and Safety', 'Risk'],
            'Marketing': ['Growth Marketing', 'Brand Operations', 'Lifecycle'],
            'Finance': ['Finance Operations', 'Risk', 'Corporate Planning'],
            'Operations': ['Business Operations', 'Customer Support', 'Program Management'],
        }
        choices = mapping[specialization]
        return self.random.sample(choices, k=min(len(choices), self.random.randint(2, len(choices))))

    def _hiring_regions(self, country: str) -> list[str]:
        region_map = {
            'India': ['South India', 'West India', 'North India', 'Pan-India'],
            'United States': ['West Coast', 'Central US', 'East Coast'],
            'United Kingdom': ['London', 'North West England', 'UK-wide'],
            'Canada': ['Ontario', 'British Columbia', 'Canada-wide'],
            'Germany': ['Berlin', 'Munich', 'Germany-wide'],
            'Singapore': ['Singapore'],
            'Australia': ['Sydney', 'Melbourne', 'Australia-wide'],
            'United Arab Emirates': ['Dubai', 'Abu Dhabi', 'UAE-wide'],
            'Ireland': ['Dublin', 'Ireland-wide'],
        }
        options = region_map.get(country, [country])
        return self.random.sample(options, k=min(len(options), self.random.randint(1, len(options))))

    def _office_location(self, company: Company) -> str:
        metadata = self._company_metadata(company)
        offices = metadata.get('offices', [])
        if offices:
            office = self.random.choice(offices)
            return f"{office['city']}, {office['country']}"
        return f"{company.headquarters_city}, {company.headquarters_country}"

    def _languages(self, country: str) -> list[dict[str, str]]:
        selected = {'English'}
        if country == 'India':
            selected.add(self.random.choice(['Tamil', 'Hindi', 'Telugu', 'Kannada', 'Malayalam']))
        elif country == 'Germany':
            selected.add('German')
        elif country == 'United Arab Emirates':
            selected.update(self.random.sample(['Hindi', 'English'], k=1))
        else:
            extras = [lang for lang in LANGUAGE_POOL if lang != 'English']
            selected.update(self.random.sample(extras, k=self.random.randint(1, 2)))
        levels = ['Native', 'Professional', 'Intermediate']
        return [{'name': name, 'proficiency': levels[min(idx, len(levels) - 1)]} for idx, name in enumerate(sorted(selected))]

    def _employee_id(self, company: Company, index: int) -> str:
        prefix = re.sub(r'[^A-Z]', '', company.name.upper())[:4] or 'COMP'
        return f'{prefix}-TA-{index + 1:05d}'

    def _unique_work_email(self, first_name: str, last_name: str, company: Company, index: int) -> str:
        domain = self._company_domain(company.website_url or company.name)
        base = f'{self._slug(first_name)}.{self._slug(last_name)}'
        counter = 0
        while True:
            suffix = f'{index + 1:04d}' if counter == 0 else f'{index + 1:04d}{counter}'
            email = f'{base}.{suffix}@{domain}'.lower()
            if email not in self._used_emails:
                self._used_emails.add(email)
                return email
            counter += 1

    def _unique_handle(self, first_name: str, last_name: str, company: Company, index: int) -> str:
        base = f"{self._slug(first_name)}-{self._slug(last_name)}-{self._slug(company.name)[:10]}"
        handle = base
        counter = index + 1
        while handle in self._used_handles:
            counter += 1
            handle = f'{base}-{counter}'
        self._used_handles.add(handle)
        return handle

    def _company_domain(self, website: str) -> str:
        clean = website.replace('https://', '').replace('http://', '').strip('/').lower()
        parts = clean.split('/')
        return parts[0].replace('www.', '') or 'company.example.dev'

    def _phone(self, country: str) -> str:
        prefix = COUNTRY_PHONE_CODE.get(country, '+1')
        if country == 'India':
            return f'{prefix} {self.random.randint(6000000000, 9999999999)}'
        if country in {'United States', 'Canada'}:
            return f'{prefix}-{self.random.randint(200, 999)}-{self.random.randint(100, 999)}-{self.random.randint(1000, 9999)}'
        return f'{prefix} {self.random.randint(10000000, 999999999)}'

    def _ai_profile(self, specialization: str, seniority: str) -> dict[str, object]:
        weight_bias = {'Associate': 0.94, 'Specialist': 1.0, 'Senior': 1.06, 'Lead': 1.10, 'Principal': 1.14}[seniority]
        resume_weight = min(1.0, round(self.random.uniform(0.14, 0.24) * weight_bias, 2))
        skill_weight = min(1.0, round(self.random.uniform(0.18, 0.28) * weight_bias, 2))
        communication_weight = round(self.random.uniform(0.10, 0.20), 2)
        coding_weight = round(self.random.uniform(0.08, 0.22) if specialization in {'Engineering', 'AI', 'Cloud', 'Data', 'Security'} else self.random.uniform(0.03, 0.12), 2)
        portfolio_weight = round(self.random.uniform(0.04, 0.14), 2)
        experience_weight = round(self.random.uniform(0.10, 0.22), 2)
        interview_weight = round(max(0.08, 1.0 - (resume_weight + skill_weight + communication_weight + coding_weight + portfolio_weight + experience_weight)), 2)
        return {
            'ai_match_weight': round(self.random.uniform(0.62, 0.94), 2),
            'resume_preference': resume_weight,
            'skill_preference': skill_weight,
            'communication_weight': communication_weight,
            'coding_weight': coding_weight,
            'portfolio_weight': portfolio_weight,
            'experience_weight': experience_weight,
            'interview_weight': interview_weight,
            'ats_threshold': self.random.randint(58, 82),
            'auto_shortlist_threshold': self.random.randint(64, 88),
        }

    def _calendar(self, country: str) -> dict[str, object]:
        timezone = TIMEZONE_BY_COUNTRY.get(country, self.config.generation.timezone)
        working_hours = self.random.choice(['09:00-17:30', '09:30-18:00', '10:00-18:30'])
        slots = self._meeting_slots()
        blocked_dates = [(datetime.utcnow().date() + timedelta(days=self.random.randint(3, 75))).isoformat() for _ in range(self.random.randint(2, 5))]
        vacation = [
            {
                'start_date': (datetime.utcnow().date() + timedelta(days=self.random.randint(30, 120))).isoformat(),
                'end_date': (datetime.utcnow().date() + timedelta(days=self.random.randint(121, 145))).isoformat(),
            }
        ]
        return {
            'working_hours': working_hours,
            'available_meeting_slots': slots[:5],
            'interview_slots': slots[2:8],
            'blocked_dates': sorted(set(blocked_dates)),
            'vacation_schedule': vacation,
            'timezone': timezone,
        }

    def _meeting_slots(self) -> list[str]:
        slots = []
        for hour in range(9, 18):
            slots.append(f'{hour:02d}:00')
            if hour != 17:
                slots.append(f'{hour:02d}:30')
        self.random.shuffle(slots)
        return sorted(slots[:8])

    def _messaging_templates(self, company_name: str) -> dict[str, str]:
        return {
            'greeting_template': self.random.choice(GREETING_TEMPLATES).format(name='{{candidate_name}}', company=company_name),
            'interview_invitation_template': self.random.choice(INVITATION_TEMPLATES).format(role='{{role}}'),
            'offer_template': self.random.choice(OFFER_TEMPLATES).format(role='{{role}}', company=company_name),
            'rejection_template': self.random.choice(REJECTION_TEMPLATES),
            'followup_template': self.random.choice(FOLLOWUP_TEMPLATES),
        }

    def _network_metadata(self, company: Company) -> dict[str, object]:
        company_meta = self._company_metadata(company)
        universities = company_meta.get('preferred_universities') or self.random.sample(list(UNIVERSITY_POOL), k=4)
        return {
            'followers': self.random.randint(120, 4800),
            'connections': self.random.randint(80, 2600),
            'students_mentored': self.random.randint(8, 140),
            'universities_connected': universities[: self.random.randint(2, min(5, len(universities)))],
            'communities': self.random.sample(list(COMMUNITY_POOL), k=self.random.randint(1, 3)),
            'groups': self.random.sample(list(GROUP_POOL), k=self.random.randint(1, 3)),
        }

    def _verification(self, company: Company) -> dict[str, bool]:
        return {
            'verified_recruiter': True,
            'background_verified': True,
            'company_verified': True,
            'email_verified': True,
            'phone_verified': self.random.random() < 0.92,
            'identity_verified': self.random.random() < 0.95,
        }

    def _preferences(self, company: Company) -> dict[str, object]:
        work_model = getattr(company, 'work_model', None)
        platforms = self.random.sample(list(PREFERRED_PLATFORMS), k=self.random.randint(1, len(PREFERRED_PLATFORMS)))
        return {
            'remote_friendly': work_model.name in {'remote', 'hybrid'} if work_model is not None else True,
            'video_interviews': True,
            'onsite_interviews': self.random.random() < 0.68,
            'hybrid_interviews': self.random.random() < 0.74,
            'preferred_platforms': platforms,
        }

    def _ai_metadata(self, specialization: str, seniority: str) -> dict[str, object]:
        return {
            'recruiter_personality': self.random.choice(PERSONALITIES),
            'interview_style': self.random.choice(INTERVIEW_STYLES),
            'evaluation_style': self.random.choice(EVALUATION_STYLES),
            'bias_detection_score': self.random.randint(72, 97),
            'consistency_score': self.random.randint(74, 98),
            'hiring_confidence': self.random.randint(68, 95),
            'recruitment_quality_score': self.random.randint(70, 96),
            'specialization_alignment': specialization,
            'seniority_signal': seniority,
        }

    def _favorite_technologies(self, company: Company, specialization: str) -> list[str]:
        company_meta = self._company_metadata(company)
        skills = company_meta.get('frequently_hired_skills') or company_meta.get('tech_stack', {}).get('frequently_hired_skills', []) or []
        pool = list(dict.fromkeys(list(skills) + list(SPECIALIZATION_SKILLS[specialization])))
        return pool[: self.random.randint(4, min(7, len(pool)))]

    def _favorite_universities(self, company: Company) -> list[str]:
        company_meta = self._company_metadata(company)
        universities = company_meta.get('preferred_universities') or list(UNIVERSITY_POOL)
        return universities[: self.random.randint(min(3, len(universities)), max(min(6, len(universities)), min(3, len(universities))))] if universities else []

    def _favorite_certifications(self, specialization: str) -> list[str]:
        options = PREFERRED_CERTIFICATIONS[specialization]
        return list(options[: self.random.randint(1, min(3, len(options)))])

    def _top_hiring_skills(self, company: Company, specialization: str) -> list[str]:
        company_meta = self._company_metadata(company)
        company_skills = company_meta.get('frequently_hired_skills') or company_meta.get('tech_stack', {}).get('frequently_hired_skills', []) or []
        merged = list(dict.fromkeys(list(company_skills) + list(SPECIALIZATION_SKILLS[specialization])))
        return merged[: self.random.randint(5, min(8, len(merged)))]

    def _recently_filled_roles(self, specialization: str) -> list[str]:
        roles = self._open_roles_for_specialization(specialization)
        self.random.shuffle(roles)
        return roles[: self.random.randint(2, min(4, len(roles)))]

    def _upcoming_campus_visits(self, company: Company) -> list[dict[str, str]]:
        company_meta = self._company_metadata(company)
        universities = company_meta.get('preferred_universities') or list(UNIVERSITY_POOL)
        visits = []
        for university in universities[: self.random.randint(1, min(3, len(universities)) )]:
            visit_date = (datetime.utcnow().date() + timedelta(days=self.random.randint(7, 80))).isoformat()
            visits.append({'university': university, 'date': visit_date, 'format': self.random.choice(['Campus Drive', 'Webinar', 'Networking Session'])})
        return visits

    def _recent_activity_feed(self, company_name: str) -> list[dict[str, str]]:
        items = []
        for _ in range(self.random.randint(3, 5)):
            action = self.random.choice(RECENT_ACTIVITY_ACTIONS)
            timestamp = (datetime.utcnow() - timedelta(days=self.random.randint(1, 21), hours=self.random.randint(0, 22))).isoformat()
            items.append({'action': f'{action} at {company_name}', 'timestamp': timestamp})
        return items

    def _candidate_watchlist(self, handle: str) -> list[dict[str, object]]:
        watchlist = []
        for idx in range(self.random.randint(2, 5)):
            watchlist.append(
                {
                    'candidate_ref': f'candidate-{handle}-{idx + 1}',
                    'focus_area': self.random.choice(RECRUITING_SPECIALIZATIONS),
                    'priority': self.random.choice(['High', 'Medium']),
                    'note': self.random.choice([
                        'Strong project depth and clear communication.',
                        'Promising fundamentals with good learning agility.',
                        'Worth revisiting for future graduate openings.',
                        'Potential fit for shortlisting after profile refresh.',
                    ]),
                }
            )
        return watchlist

    def _recent_datetime(self, days: int) -> datetime:
        now = datetime.utcnow()
        return now - timedelta(days=self.random.randint(0, days), seconds=self.random.randint(0, 86400))

    def _slug(self, value: str) -> str:
        slug = re.sub(r'[^a-z0-9]+', '-', value.lower()).strip('-')
        return slug or 'profile'


def generate_recruiters(companies: Sequence[Company], config: AppConfig = CONFIG) -> RecruiterGenerationResult:
    generator = RecruiterGenerator(config=config)
    return generator.generate(companies)


