# from __future__ import annotations

import random
from collections import Counter, defaultdict
from dataclasses import dataclass
from datetime import date, datetime, timedelta
from decimal import Decimal
from statistics import mean
from typing import Any, Protocol, Sequence

from faker import Faker

from careerbridge_seed_engine.config import AppConfig, CONFIG
from careerbridge_seed_engine.models import (
    AIRecommendation,
    Application,
    CareerPrediction,
    CareerReport,
    Company,
    Interview,
    Job,
    JobMatch,
    Offer,
    Recruiter,
    RecruiterRecommendation,
    ResumeAnalysis,
    SalaryPrediction,
    SkillGap,
    Student,
)

COMMUNICATION_CHANNELS = ['Email', 'LinkedIn', 'In-App Message']
CONTACT_WINDOWS = [
    ('Tuesday', '09:00-11:00'),
    ('Wednesday', '10:00-12:00'),
    ('Thursday', '14:00-16:00'),
]


class RecruiterRecommendationEngine(Protocol):
    def recommend(self, ctx: 'RecruiterRecommendationContext') -> RecruiterRecommendation:
        ...


class NetworkingEngine(Protocol):
    def build(self, ctx: 'RecruiterRecommendationContext', top_items: list[dict[str, Any]]) -> dict[str, Any]:
        ...


class ResponsePredictionEngine(Protocol):
    def predict(self, ctx: 'RecruiterRecommendationContext', recruiter: Recruiter, score: float) -> dict[str, Any]:
        ...


class OutreachEngine(Protocol):
    def build(self, ctx: 'RecruiterRecommendationContext', recruiter_payload: dict[str, Any]) -> dict[str, Any]:
        ...


@dataclass(slots=True)
class RecruiterRecommendationContext:
    student: Student
    companies: list[Company]
    recruiters: list[Recruiter]
    jobs: list[Job]
    applications: list[Application]
    interviews: list[Interview]
    offers: list[Offer]
    career_report: CareerReport | None
    skill_gap: SkillGap | None
    learning_roadmap: Any | None
    resume_analysis: ResumeAnalysis | None
    job_match: JobMatch | None
    ai_recommendation: AIRecommendation | None
    career_prediction: CareerPrediction | None
    salary_prediction: SalaryPrediction | None


@dataclass(slots=True)
class RecruiterRecommendationGenerationResult:
    recruiter_recommendations: list[RecruiterRecommendation]


class DefaultResponsePredictionEngine:
    def predict(self, ctx: RecruiterRecommendationContext, recruiter: Recruiter, score: float) -> dict[str, Any]:
        base = max(35.0, min(96.0, score))
        readiness = float(getattr(ctx.career_report, 'interview_readiness', 0) or 58) if ctx.career_report is not None else 58.0
        recruiter_quality = self._recruiter_quality(recruiter)
        response_probability = self._clamp(base * 0.56 + readiness * 0.18 + recruiter_quality * 0.12)
        interview_probability = self._clamp(base * 0.52 + readiness * 0.28 + recruiter_quality * 0.08)
        connection_probability = self._clamp(base * 0.48 + recruiter_quality * 0.24 + 18)
        reply_probability = self._clamp(base * 0.50 + recruiter_quality * 0.20 + 16)
        referral_probability = self._clamp(base * 0.42 + readiness * 0.24 + recruiter_quality * 0.18)
        response_time = max(6, int(round(72 - response_probability * 0.5)))
        return {
            'recruiter_response_probability': int(round(response_probability)),
            'interview_invitation_probability': int(round(interview_probability)),
            'connection_acceptance_probability': int(round(connection_probability)),
            'message_reply_probability': int(round(reply_probability)),
            'referral_probability': int(round(referral_probability)),
            'expected_response_time_hours': response_time,
        }

    def _recruiter_quality(self, recruiter: Recruiter) -> float:
        history = getattr(recruiter, 'hiring_history', None) or getattr(recruiter, 'hiring_history_metadata', None) or {}
        if isinstance(history, dict):
            offers = float(history.get('offers_made', 5) or 5)
            interviews = float(history.get('interviews_conducted', 12) or 12)
            velocity = float(history.get('hiring_velocity', 6) or 6)
            return min(95.0, 45.0 + offers * 1.1 + interviews * 0.3 + velocity)
        years = float(getattr(recruiter, 'years_of_experience', None) or getattr(recruiter, 'experience_years', None) or 5)
        return min(92.0, 52.0 + years * 3.0)

    def _clamp(self, value: float) -> float:
        return max(25.0, min(98.0, value))


class DefaultNetworkingBuilder:
    def build(self, ctx: RecruiterRecommendationContext, top_items: list[dict[str, Any]]) -> dict[str, Any]:
        channels = []
        for index, item in enumerate(top_items[:10]):
            channel = COMMUNICATION_CHANNELS[index % len(COMMUNICATION_CHANNELS)]
            day, window = CONTACT_WINDOWS[index % len(CONTACT_WINDOWS)]
            channels.append({
                'recruiter': item['recruiter_name'],
                'best_day_to_contact': day,
                'best_time_to_contact': window,
                'preferred_communication_channel': channel,
                'response_pattern': 'Fast responder' if item['response_prediction']['expected_response_time_hours'] <= 24 else 'Standard responder',
                'activity_score': item['engagement']['activity_score'],
            })
        summary = Counter([item['shared_context']['shared_university'] for item in top_items if item['shared_context']['shared_university']])
        return {
            'engagement_plan': channels,
            'shared_university_clusters': [{'university': name, 'count': count} for name, count in summary.most_common(5)],
        }


class DefaultOutreachEngine:
    def build(self, ctx: RecruiterRecommendationContext, recruiter_payload: dict[str, Any]) -> dict[str, Any]:
        recruiter_name = recruiter_payload['recruiter_name']
        company_name = recruiter_payload['company']
        role = recruiter_payload['role']
        shared_skills = recruiter_payload['shared_context']['shared_skills'][:3]
        top_skill_text = ', '.join(shared_skills) if shared_skills else 'relevant technical skills'
        student_name = self._student_name(ctx.student)
        return {
            'recommended_introduction_message': (
                f"Hi {recruiter_name}, I\'m {student_name} and I\'m actively exploring {role} opportunities. "
                f"My background includes {top_skill_text}, and your hiring focus at {company_name} aligns closely with my career goal."
            ),
            'connection_request': (
                f"Hello {recruiter_name}, I\'m building toward {role} roles and noticed your recruiting focus at {company_name}. "
                f"I\'d value connecting and following your hiring updates."
            ),
            'follow_up_message': (
                f"Hi {recruiter_name}, following up on my previous note regarding {role} opportunities at {company_name}. "
                f"I\'ve continued improving my profile and would appreciate any guidance on current openings."
            ),
            'referral_request': (
                f"Hi {recruiter_name}, based on my alignment with the {role} hiring domain and recent portfolio improvements, "
                f"I wanted to ask whether a referral or recruiter screening would be appropriate for current roles at {company_name}."
            ),
            'interview_follow_up': (
                f"Hi {recruiter_name}, thank you for the interview opportunity. I appreciated the discussion and remain very interested in contributing to {company_name} as a {role}."
            ),
            'thank_you_message': (
                f"Thank you, {recruiter_name}. I appreciate your time and guidance, and I look forward to staying in touch regarding future {role} openings."
            ),
        }

    def _student_name(self, student: Student) -> str:
        for field in ('full_name', 'name'):
            value = getattr(student, field, None)
            if value:
                return str(value)
        first = getattr(student, 'first_name', None)
        last = getattr(student, 'last_name', None)
        if first or last:
            return ' '.join([part for part in [str(first or '').strip(), str(last or '').strip()] if part])
        return 'a CareerBridge student'


class DefaultRecruiterRecommendationEngine:
    def __init__(
        self,
        networking_engine: NetworkingEngine | None = None,
        response_prediction_engine: ResponsePredictionEngine | None = None,
        outreach_engine: OutreachEngine | None = None,
    ) -> None:
        self.networking_engine = networking_engine or DefaultNetworkingBuilder()
        self.response_prediction_engine = response_prediction_engine or DefaultResponsePredictionEngine()
        self.outreach_engine = outreach_engine or DefaultOutreachEngine()

    def recommend(self, ctx: RecruiterRecommendationContext) -> RecruiterRecommendation:
        ranked = self._rank_recruiters(ctx)
        top_items = [self._build_recruiter_payload(ctx, recruiter, score, evidence) for recruiter, score, evidence in ranked[:50]]
        networking = self.networking_engine.build(ctx, top_items)
        explanations = self._ai_explanations(top_items)
        recommendation = RecruiterRecommendation(
            student=ctx.student,
            generated_at=datetime.utcnow(),
            top_recruiters=top_items,
        )
        recommendation.network_quality_metadata = {
            'mutual_connections_summary': self._network_summary(top_items, 'mutual_connections'),
            'shared_skills_summary': self._aggregate_shared(top_items, 'shared_skills'),
            'shared_communities_summary': self._aggregate_shared(top_items, 'shared_communities'),
            'shared_universities_summary': self._network_summary(top_items, 'shared_university'),
            'shared_interests_summary': self._aggregate_shared(top_items, 'shared_interests'),
            'shared_companies_summary': self._aggregate_shared(top_items, 'shared_companies'),
            'shared_technologies_summary': self._aggregate_shared(top_items, 'shared_technologies'),
        }
        recommendation.outreach_assistant_metadata = {item['recruiter_name']: item['outreach'] for item in top_items[:20]}
        recommendation.engagement_metadata = networking
        recommendation.recruiter_insights_metadata = {item['recruiter_name']: item['recruiter_insights'] for item in top_items[:20]}
        recommendation.ai_explanations_metadata = explanations
        recommendation.engine_metadata = {
            'recruiter_recommendation_engine': self.__class__.__name__,
            'networking_engine': self.networking_engine.__class__.__name__,
            'response_prediction_engine': self.response_prediction_engine.__class__.__name__,
            'outreach_engine': self.outreach_engine.__class__.__name__,
            'gemini_replaceable': True,
            'frontend_contract_stable': True,
        }
        return recommendation

    def _rank_recruiters(self, ctx: RecruiterRecommendationContext) -> list[tuple[Recruiter, float, dict[str, Any]]]:
        ranked = []
        student_skills = set(self._normalized_list(getattr(ctx.student, 'skills', None), lower=True))
        student_projects = self._normalized_list(getattr(ctx.student, 'projects', None))
        student_companies = set(self._preferred_companies(ctx))
        student_industry = str(getattr(ctx.student, 'preferred_industry', '') or '').lower()
        student_location = str(getattr(ctx.student, 'preferred_location', '') or '').lower()
        student_salary = self._preferred_salary(ctx.student)
        career_goal = str(getattr(ctx.student, 'career_goal', '') or '').lower()
        resume_score = int(getattr(ctx.resume_analysis, 'resume_score', 0) or 0) if ctx.resume_analysis is not None else 55
        ats_score = int(getattr(ctx.resume_analysis, 'ats_score', 0) or 0) if ctx.resume_analysis is not None else 52
        interview_readiness = int(getattr(ctx.career_report, 'interview_readiness', 0) or 0) if ctx.career_report is not None else 56
        learning_progress = self._learning_progress(ctx)
        top_job_titles = [item.get('job_title', '').lower() for item in (getattr(ctx.job_match, 'top_job_matches', None) or [])[:20]] if ctx.job_match is not None else []
        missing_skills = set(self._missing_skills(ctx))

        for recruiter in ctx.recruiters:
            company = getattr(recruiter, 'company', None)
            company_name = str(getattr(company, 'name', None) or getattr(recruiter, 'company_name', None) or '').strip()
            industry = str(getattr(company, 'industry', None) or getattr(recruiter, 'industry', None) or '').lower()
            location = str(getattr(recruiter, 'location', None) or getattr(company, 'headquarters', None) or '').lower()
            domain = str(getattr(recruiter, 'hiring_domain', None) or getattr(recruiter, 'department', None) or '').lower()
            role = str(getattr(recruiter, 'role', None) or getattr(recruiter, 'title', None) or 'Recruiter').lower()
            years = float(getattr(recruiter, 'years_of_experience', None) or getattr(recruiter, 'experience_years', None) or 5)
            recruiter_skills = set(self._normalized_list(getattr(recruiter, 'preferred_skills', None), lower=True))
            recruiter_certs = set(self._normalized_list(getattr(recruiter, 'preferred_certifications', None), lower=True))
            recruiter_universities = set(self._normalized_list(getattr(recruiter, 'preferred_universities', None), lower=True))
            open_roles = self._open_roles_for_recruiter(ctx, recruiter)
            hiring_history = self._hiring_history(recruiter)

            score = 0.0
            evidence: dict[str, Any] = {}
            role_alignment = self._role_alignment(career_goal, role, domain, top_job_titles)
            skill_overlap = len(student_skills & recruiter_skills)
            project_alignment = self._project_alignment(student_projects, open_roles, career_goal)
            certification_alignment = len(set(self._normalized_list(getattr(ctx.student, 'certifications', None), lower=True)) & recruiter_certs)
            company_alignment = 1 if company_name.lower() in {name.lower() for name in student_companies} else 0
            industry_alignment = 1 if student_industry and student_industry in industry else 0
            location_alignment = 1 if student_location and student_location in location else 0
            salary_alignment = self._salary_alignment(student_salary, open_roles)
            education_alignment = self._education_alignment(ctx.student, recruiter_universities)
            github_portfolio_alignment = self._portfolio_alignment(ctx.student)
            application_affinity = self._application_affinity(ctx, recruiter, company_name)
            learning_alignment = max(0.0, 1.0 - min(0.4, len(missing_skills) * 0.03)) + learning_progress * 0.01

            score += role_alignment * 22
            score += skill_overlap * 4.5
            score += project_alignment * 8
            score += certification_alignment * 3.5
            score += company_alignment * 8
            score += industry_alignment * 5
            score += location_alignment * 5
            score += salary_alignment * 6
            score += education_alignment * 4
            score += github_portfolio_alignment * 5
            score += application_affinity * 7
            score += min(12, years * 1.3)
            score += (resume_score / 100) * 6
            score += (ats_score / 100) * 6
            score += (interview_readiness / 100) * 7
            score += learning_alignment
            score += min(10, hiring_history['offers_made'] * 0.35 + hiring_history['recent_hiring_activity'] * 0.25)

            evidence['role_alignment'] = role_alignment
            evidence['skill_overlap'] = skill_overlap
            evidence['project_alignment'] = project_alignment
            evidence['certification_alignment'] = certification_alignment
            evidence['company_alignment'] = company_alignment
            evidence['industry_alignment'] = industry_alignment
            evidence['location_alignment'] = location_alignment
            evidence['salary_alignment'] = salary_alignment
            evidence['education_alignment'] = education_alignment
            evidence['github_portfolio_alignment'] = github_portfolio_alignment
            evidence['application_affinity'] = application_affinity
            evidence['learning_alignment'] = learning_alignment
            evidence['hiring_history'] = hiring_history
            ranked.append((recruiter, round(score, 2), evidence))

        ranked.sort(key=lambda item: item[1], reverse=True)
        return ranked

    def _build_recruiter_payload(self, ctx: RecruiterRecommendationContext, recruiter: Recruiter, score: float, evidence: dict[str, Any]) -> dict[str, Any]:
        company = getattr(recruiter, 'company', None)
        company_name = str(getattr(company, 'name', None) or getattr(recruiter, 'company_name', None) or 'Unknown Company')
        role = str(getattr(recruiter, 'role', None) or getattr(recruiter, 'title', None) or 'Recruiter')
        department = str(getattr(recruiter, 'department', None) or getattr(recruiter, 'hiring_domain', None) or 'Talent Acquisition')
        location = str(getattr(recruiter, 'location', None) or getattr(company, 'headquarters', None) or '')
        domain = str(getattr(recruiter, 'hiring_domain', None) or department)
        years = int(getattr(recruiter, 'years_of_experience', None) or getattr(recruiter, 'experience_years', None) or 5)
        hiring_history = self._hiring_history(recruiter)
        shared_context = self._shared_context(ctx, recruiter, company_name)
        response_prediction = self.response_prediction_engine.predict(ctx, recruiter, score)
        payload = {
            'recruiter_name': self._recruiter_name(recruiter),
            'company': company_name,
            'role': role,
            'department': department,
            'location': location,
            'hiring_domain': domain,
            'years_of_experience': years,
            'hiring_history': hiring_history,
            'verification_status': self._verification_status(recruiter),
            'overall_match_score': int(min(99, max(35, round(score)))),
            'shared_context': shared_context,
            'response_prediction': response_prediction,
            'why_this_recruiter': self._why_this_recruiter(shared_context, evidence, hiring_history),
            'engagement': self._engagement_payload(response_prediction, recruiter),
            'recruiter_insights': self._recruiter_insights(ctx, recruiter, company_name, domain, hiring_history),
        }
        payload['outreach'] = self.outreach_engine.build(ctx, payload)
        return payload

    def _shared_context(self, ctx: RecruiterRecommendationContext, recruiter: Recruiter, company_name: str) -> dict[str, Any]:
        student_skills = set(self._normalized_list(getattr(ctx.student, 'skills', None)))
        recruiter_skills = set(self._normalized_list(getattr(recruiter, 'preferred_skills', None)))
        shared_skills = sorted(student_skills & recruiter_skills)
        shared_communities = self._shared_communities(ctx, recruiter)
        shared_university = self._shared_university(ctx.student, recruiter)
        shared_interests = self._shared_interests(ctx, recruiter)
        shared_companies = [company_name] if company_name.lower() in {name.lower() for name in self._preferred_companies(ctx)} else []
        shared_technologies = [skill for skill in shared_skills if skill.lower() in {'python', 'java', 'react', 'node.js', 'sql', 'aws', 'docker', 'kubernetes', 'tensorflow', 'pytorch', 'graphql'}]
        mutual_connections = self._mutual_connections(ctx, recruiter)
        return {
            'mutual_connections': mutual_connections,
            'shared_skills': shared_skills[:8],
            'shared_communities': shared_communities,
            'shared_university': shared_university,
            'shared_interests': shared_interests,
            'shared_companies': shared_companies,
            'shared_technologies': shared_technologies[:8],
        }

    def _why_this_recruiter(self, shared_context: dict[str, Any], evidence: dict[str, Any], hiring_history: dict[str, Any]) -> dict[str, Any]:
        reasons = []
        if shared_context['shared_skills']:
            reasons.append(f"Shared skills include {', '.join(shared_context['shared_skills'][:3])}.")
        if shared_context['shared_technologies']:
            reasons.append(f"Shared technologies align with the recruiter\'s hiring focus: {', '.join(shared_context['shared_technologies'][:3])}.")
        if evidence['project_alignment'] > 0:
            reasons.append('Student projects align with the recruiter\'s current hiring domain.')
        if hiring_history['offers_made'] > 0:
            reasons.append(f"Recruiter has a meaningful hiring history with {hiring_history['offers_made']} recorded offers.")
        if evidence['application_affinity'] > 0:
            reasons.append('Past application behavior suggests this recruiter is relevant to the student\'s target path.')
        return {
            'summary': ' '.join(reasons) if reasons else 'Recruiter fit is driven by role alignment, profile strength, and current hiring patterns.',
            'shared_hiring_interests': evidence['role_alignment'] >= 1,
            'shared_technologies': shared_context['shared_technologies'][:5],
            'relevant_experience': evidence['application_affinity'] > 0,
            'relevant_projects': evidence['project_alignment'] > 0,
            'hiring_history_signal': hiring_history,
        }

    def _engagement_payload(self, response_prediction: dict[str, Any], recruiter: Recruiter) -> dict[str, Any]:
        index = response_prediction['expected_response_time_hours'] % len(CONTACT_WINDOWS)
        day, window = CONTACT_WINDOWS[index]
        channel = COMMUNICATION_CHANNELS[index % len(COMMUNICATION_CHANNELS)]
        return {
            'best_time_to_contact': window,
            'best_day_to_contact': day,
            'preferred_communication_channel': channel,
            'response_pattern': 'Fast responder' if response_prediction['expected_response_time_hours'] <= 24 else 'Standard responder',
            'activity_score': min(98, 50 + int(getattr(recruiter, 'years_of_experience', None) or getattr(recruiter, 'experience_years', None) or 5) * 4),
        }

    def _recruiter_insights(self, ctx: RecruiterRecommendationContext, recruiter: Recruiter, company_name: str, domain: str, hiring_history: dict[str, Any]) -> dict[str, Any]:
        open_roles = self._open_roles_for_recruiter(ctx, recruiter)
        preferred_universities = self._normalized_list(getattr(recruiter, 'preferred_universities', None))
        preferred_certifications = self._normalized_list(getattr(recruiter, 'preferred_certifications', None))
        preferred_skills = self._normalized_list(getattr(recruiter, 'preferred_skills', None))
        interview_style = str(getattr(recruiter, 'interview_style', None) or 'Structured and role-specific')
        expectations = str(getattr(recruiter, 'candidate_expectations', None) or 'Strong fundamentals, evidence-based projects, and clear communication')
        return {
            'recent_hiring_activity': hiring_history['recent_hiring_activity'],
            'open_roles': open_roles[:8],
            'hiring_velocity': hiring_history['hiring_velocity'],
            'preferred_universities': preferred_universities[:8],
            'preferred_certifications': preferred_certifications[:8],
            'preferred_skills': preferred_skills[:10],
            'interview_style': interview_style,
            'candidate_expectations': expectations,
            'company': company_name,
            'hiring_domain': domain,
        }

    def _ai_explanations(self, top_items: list[dict[str, Any]]) -> dict[str, Any]:
        explanations = []
        for item in top_items[:20]:
            explanations.append({
                'recruiter': item['recruiter_name'],
                'why_recommended': item['why_this_recruiter']['summary'],
                'evidence_used': {
                    'shared_skills': item['shared_context']['shared_skills'],
                    'shared_technologies': item['shared_context']['shared_technologies'],
                    'hiring_history': item['hiring_history'],
                    'response_prediction': item['response_prediction'],
                },
                'confidence_score': min(97, max(60, item['overall_match_score'] + 4)),
                'expected_career_impact': 'Can improve networking reach, recruiter visibility, and interview access.',
            })
        return {'items': explanations}

    def _open_roles_for_recruiter(self, ctx: RecruiterRecommendationContext, recruiter: Recruiter) -> list[dict[str, Any]]:
        company = getattr(recruiter, 'company', None)
        company_name = str(getattr(company, 'name', None) or getattr(recruiter, 'company_name', None) or '').lower()
        domain = str(getattr(recruiter, 'hiring_domain', None) or getattr(recruiter, 'department', None) or '').lower()
        roles = []
        for job in ctx.jobs:
            job_company = getattr(job, 'company', None)
            job_company_name = str(getattr(job_company, 'name', None) or getattr(job, 'company_name', None) or '').lower()
            title = str(getattr(job, 'role', None) or getattr(job, 'title', None) or getattr(job, 'job_title', None) or '')
            skills = self._normalized_list(getattr(job, 'skills_required', None))
            if company_name and company_name == job_company_name:
                roles.append({
                    'title': title,
                    'salary_min': getattr(job, 'salary_min', None),
                    'salary_max': getattr(job, 'salary_max', None),
                    'skills': skills[:6],
                })
            elif domain and any(domain_part in title.lower() for domain_part in domain.split() if len(domain_part) > 2):
                roles.append({
                    'title': title,
                    'salary_min': getattr(job, 'salary_min', None),
                    'salary_max': getattr(job, 'salary_max', None),
                    'skills': skills[:6],
                })
        return roles

    def _hiring_history(self, recruiter: Recruiter) -> dict[str, Any]:
        history = getattr(recruiter, 'hiring_history', None) or getattr(recruiter, 'hiring_history_metadata', None) or {}
        if isinstance(history, dict):
            return {
                'offers_made': int(history.get('offers_made', 4) or 4),
                'interviews_conducted': int(history.get('interviews_conducted', 10) or 10),
                'hiring_velocity': int(history.get('hiring_velocity', 6) or 6),
                'recent_hiring_activity': int(history.get('recent_hiring_activity', 5) or 5),
            }
        years = int(getattr(recruiter, 'years_of_experience', None) or getattr(recruiter, 'experience_years', None) or 5)
        return {
            'offers_made': max(2, years * 2),
            'interviews_conducted': max(8, years * 5),
            'hiring_velocity': max(3, years),
            'recent_hiring_activity': max(3, years - 1),
        }

    def _role_alignment(self, career_goal: str, role: str, domain: str, top_job_titles: list[str]) -> float:
        goal_tokens = {token for token in career_goal.split() if len(token) > 2}
        score = 0.0
        if any(token in role for token in goal_tokens):
            score += 1.2
        if any(token in domain for token in goal_tokens):
            score += 1.0
        if any(token in title for token in goal_tokens for title in top_job_titles):
            score += 0.8
        return min(3.0, score)

    def _project_alignment(self, projects: list[str], open_roles: list[dict[str, Any]], career_goal: str) -> float:
        if not projects:
            return 0.0
        project_text = ' '.join(projects).lower()
        score = 0.0
        for role in open_roles[:5]:
            title = str(role.get('title', '')).lower()
            if any(token in project_text for token in title.split() if len(token) > 2):
                score += 0.6
        if career_goal and any(token in project_text for token in career_goal.lower().split() if len(token) > 2):
            score += 0.8
        return min(2.0, score)

    def _salary_alignment(self, preferred_salary: dict[str, Decimal], open_roles: list[dict[str, Any]]) -> float:
        if not open_roles:
            return 0.5
        preferred_min = preferred_salary['min']
        preferred_max = preferred_salary['max']
        if preferred_min == 0 and preferred_max == 0:
            return 0.8
        aligned = 0
        checked = 0
        for role in open_roles[:8]:
            minimum = self._to_decimal(role.get('salary_min'))
            maximum = self._to_decimal(role.get('salary_max'))
            if minimum <= 0 or maximum <= 0:
                continue
            checked += 1
            if preferred_max == 0:
                if minimum >= preferred_min * Decimal('0.85'):
                    aligned += 1
            elif minimum <= preferred_max and maximum >= preferred_min:
                aligned += 1
        if checked == 0:
            return 0.8
        return aligned / checked

    def _education_alignment(self, student: Student, preferred_universities: set[str]) -> float:
        university = str(getattr(student, 'university', None) or getattr(getattr(student, 'university_ref', None), 'name', None) or '').lower()
        cgpa = Decimal(str(getattr(student, 'cgpa', None) or 0))
        score = 0.4 if cgpa >= Decimal('7.0') else 0.2
        if university and university in preferred_universities:
            score += 0.6
        return min(1.0, score)

    def _portfolio_alignment(self, student: Student) -> float:
        score = 0.0
        if getattr(student, 'portfolio', None) or getattr(student, 'portfolio_url', None):
            score += 0.5
        if getattr(student, 'github', None) or getattr(student, 'github_url', None):
            score += 0.5
        return score

    def _application_affinity(self, ctx: RecruiterRecommendationContext, recruiter: Recruiter, company_name: str) -> float:
        score = 0.0
        recruiter_name = self._recruiter_name(recruiter).lower()
        for application in ctx.applications:
            company = getattr(application, 'company', None) or getattr(getattr(application, 'job', None), 'company', None)
            app_company_name = str(getattr(company, 'name', None) or getattr(application, 'company_name', None) or '').lower()
            app_recruiter = getattr(application, 'recruiter', None)
            app_recruiter_name = self._recruiter_name(app_recruiter).lower() if app_recruiter is not None else ''
            if app_company_name and app_company_name == company_name.lower():
                score += 0.6
            if recruiter_name and recruiter_name == app_recruiter_name:
                score += 0.8
        return min(2.0, score)

    def _learning_progress(self, ctx: RecruiterRecommendationContext) -> int:
        if ctx.ai_recommendation is not None:
            metadata = getattr(ctx.ai_recommendation, 'business_impact_metadata', None) or {}
            return int(metadata.get('career_score_increase', 8) or 8)
        if ctx.career_report is not None:
            return int(getattr(ctx.career_report, 'weekly_progress', 6) or 6)
        return 6

    def _missing_skills(self, ctx: RecruiterRecommendationContext) -> list[str]:
        if ctx.skill_gap is None:
            return []
        metadata = getattr(ctx.skill_gap, 'ranked_skills_metadata', None) or []
        if isinstance(metadata, dict):
            metadata = metadata.get('items', metadata.get('skills', []))
        return [str(item.get('skill')) for item in metadata if isinstance(item, dict) and item.get('skill')]

    def _preferred_companies(self, ctx: RecruiterRecommendationContext) -> list[str]:
        value = getattr(ctx.student, 'preferred_companies', None)
        if isinstance(value, (list, tuple, set)):
            return [str(item) for item in value if str(item).strip()]
        if value not in (None, ''):
            return [str(value)]
        if ctx.job_match is not None:
            return [item.get('company') for item in (getattr(ctx.job_match, 'top_companies', None) or [])[:5] if item.get('company')]
        return []

    def _preferred_salary(self, student: Student) -> dict[str, Decimal]:
        minimum = Decimal(str(getattr(student, 'expected_salary_min', None) or 0))
        maximum = Decimal(str(getattr(student, 'expected_salary_max', None) or 0))
        expected = getattr(student, 'expected_salary', None)
        if minimum == 0 and maximum == 0 and expected not in (None, ''):
            amount = Decimal(str(expected))
            minimum = amount * Decimal('0.9')
            maximum = amount * Decimal('1.1')
        return {'min': minimum, 'max': maximum}

    def _shared_communities(self, ctx: RecruiterRecommendationContext, recruiter: Recruiter) -> list[str]:
        student_communities = set()
        if ctx.ai_recommendation is not None:
            for item in getattr(ctx.ai_recommendation, 'community_recommendations', None) or []:
                if isinstance(item, dict) and item.get('name'):
                    student_communities.add(str(item['name']))
        recruiter_communities = set(self._normalized_list(getattr(recruiter, 'communities', None)))
        return sorted(student_communities & recruiter_communities)[:5]

    def _shared_university(self, student: Student, recruiter: Recruiter) -> str | None:
        student_university = str(getattr(student, 'university', None) or getattr(getattr(student, 'university_ref', None), 'name', None) or '').strip()
        preferred_universities = {item.lower() for item in self._normalized_list(getattr(recruiter, 'preferred_universities', None))}
        if student_university and student_university.lower() in preferred_universities:
            return student_university
        return None

    def _shared_interests(self, ctx: RecruiterRecommendationContext, recruiter: Recruiter) -> list[str]:
        interests = []
        student_goal = str(getattr(ctx.student, 'career_goal', '') or '')
        recruiter_domain = str(getattr(recruiter, 'hiring_domain', None) or getattr(recruiter, 'department', None) or '')
        if student_goal and recruiter_domain and any(token in recruiter_domain.lower() for token in student_goal.lower().split() if len(token) > 2):
            interests.append(student_goal)
        if ctx.career_prediction is not None:
            trend_metadata = getattr(ctx.career_prediction, 'trend_analysis_metadata', None) or {}
            for item in trend_metadata.get('hot_technologies', [])[:3]:
                recruiter_skills = {skill.lower() for skill in self._normalized_list(getattr(recruiter, 'preferred_skills', None))}
                if str(item).lower() in recruiter_skills:
                    interests.append(str(item))
        deduped = []
        for interest in interests:
            if interest not in deduped:
                deduped.append(interest)
        return deduped[:5]

    def _mutual_connections(self, ctx: RecruiterRecommendationContext, recruiter: Recruiter) -> int:
        base = 1
        if ctx.ai_recommendation is not None:
            networking = getattr(ctx.ai_recommendation, 'networking_recommendations', None) or []
            base += min(5, len(networking))
        years = int(getattr(recruiter, 'years_of_experience', None) or getattr(recruiter, 'experience_years', None) or 5)
        return min(18, base + years // 2)

    def _verification_status(self, recruiter: Recruiter) -> str:
        for field in ('verification_status', 'verified'):
            value = getattr(recruiter, field, None)
            if isinstance(value, bool):
                return 'Verified' if value else 'Pending'
            if value:
                return str(value)
        return 'Verified'

    def _recruiter_name(self, recruiter: Recruiter | None) -> str:
        if recruiter is None:
            return ''
        for field in ('full_name', 'name'):
            value = getattr(recruiter, field, None)
            if value:
                return str(value)
        first = getattr(recruiter, 'first_name', None)
        last = getattr(recruiter, 'last_name', None)
        if first or last:
            return ' '.join([part for part in [str(first or '').strip(), str(last or '').strip()] if part])
        return 'Recruiter'

    def _network_summary(self, items: list[dict[str, Any]], field: str) -> list[dict[str, Any]]:
        counter = Counter()
        for item in items:
            value = item['shared_context'].get(field) if field.startswith('shared_') else item['shared_context'].get(field)
            if isinstance(value, list):
                for entry in value:
                    counter[str(entry)] += 1
            elif value:
                counter[str(value)] += 1
        return [{'name': name, 'count': count} for name, count in counter.most_common(8)]

    def _aggregate_shared(self, items: list[dict[str, Any]], field: str) -> list[dict[str, Any]]:
        counter = Counter()
        for item in items:
            for entry in item['shared_context'].get(field, []):
                counter[str(entry)] += 1
        return [{'name': name, 'count': count} for name, count in counter.most_common(10)]

    def _normalized_list(self, value: Any, lower: bool = False) -> list[str]:
        if isinstance(value, dict):
            items = [str(key) for key in value.keys() if str(key).strip()]
        elif isinstance(value, (list, tuple, set)):
            items = [str(item) for item in value if str(item).strip()]
        elif value in (None, ''):
            items = []
        else:
            items = [str(value)]
        return [item.lower() if lower else item for item in items]

    def _to_decimal(self, value: Any) -> Decimal:
        if value in (None, ''):
            return Decimal('0.00')
        return Decimal(str(value))


class RecruiterRecommendationGenerator:
    def __init__(self, config: AppConfig = CONFIG, engine: RecruiterRecommendationEngine | None = None) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 18000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 18000)
            self.faker.seed_instance(config.generation.seed + 18000)
        self.engine = engine or DefaultRecruiterRecommendationEngine()

    def generate(
        self,
        students: Sequence[Student],
        companies: Sequence[Company],
        recruiters: Sequence[Recruiter],
        jobs: Sequence[Job],
        applications: Sequence[Application],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
        career_reports: Sequence[CareerReport],
        skill_gaps: Sequence[SkillGap],
        learning_roadmaps: Sequence[Any],
        resume_analyses: Sequence[ResumeAnalysis],
        job_matches: Sequence[JobMatch],
        ai_recommendations: Sequence[AIRecommendation],
        career_predictions: Sequence[CareerPrediction],
        salary_predictions: Sequence[SalaryPrediction],
    ) -> RecruiterRecommendationGenerationResult:
        if not students:
            raise ValueError('Recruiter recommendation generation requires students.')

        applications_by_student = self._records_by_student(applications, 'student')
        interviews_by_student = self._records_by_student(interviews, 'student', application_fallback=True)
        offers_by_student = self._records_by_student(offers, 'student', application_fallback=True)
        jobs_by_student = self._jobs_by_student(students, jobs, applications, interviews, offers)
        companies_by_student = self._companies_by_student(companies, jobs_by_student, applications)
        recruiters_by_student = self._recruiters_by_student(recruiters, applications, jobs_by_student)
        reports_by_student = {self._student_key(item.student): item for item in career_reports if getattr(item, 'student', None) is not None}
        gaps_by_student = {self._student_key(item.student): item for item in skill_gaps if getattr(item, 'student', None) is not None}
        roadmaps_by_student = {self._student_key(item.student): item for item in learning_roadmaps if getattr(item, 'student', None) is not None}
        resumes_by_student = {self._student_key(item.student): item for item in resume_analyses if getattr(item, 'student', None) is not None}
        matches_by_student = {self._student_key(item.student): item for item in job_matches if getattr(item, 'student', None) is not None}
        ai_by_student = {self._student_key(item.student): item for item in ai_recommendations if getattr(item, 'student', None) is not None}
        career_predictions_by_student = {self._student_key(item.student): item for item in career_predictions if getattr(item, 'student', None) is not None}
        salary_predictions_by_student = {self._student_key(item.student): item for item in salary_predictions if getattr(item, 'student', None) is not None}

        results: list[RecruiterRecommendation] = []
        for student in students:
            key = self._student_key(student)
            ctx = RecruiterRecommendationContext(
                student=student,
                companies=companies_by_student.get(key, []),
                recruiters=recruiters_by_student.get(key) or list(recruiters),
                jobs=jobs_by_student.get(key, []),
                applications=applications_by_student.get(key, []),
                interviews=interviews_by_student.get(key, []),
                offers=offers_by_student.get(key, []),
                career_report=reports_by_student.get(key),
                skill_gap=gaps_by_student.get(key),
                learning_roadmap=roadmaps_by_student.get(key),
                resume_analysis=resumes_by_student.get(key),
                job_match=matches_by_student.get(key),
                ai_recommendation=ai_by_student.get(key),
                career_prediction=career_predictions_by_student.get(key),
                salary_prediction=salary_predictions_by_student.get(key),
            )
            results.append(self.engine.recommend(ctx))
        return RecruiterRecommendationGenerationResult(recruiter_recommendations=results)

    def _jobs_by_student(
        self,
        students: Sequence[Student],
        jobs: Sequence[Job],
        applications: Sequence[Application],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
    ) -> dict[str, list[Job]]:
        mapping: dict[str, list[Job]] = defaultdict(list)
        for record in list(applications) + list(interviews) + list(offers):
            student = getattr(record, 'student', None)
            if student is None:
                application = getattr(record, 'application', None)
                student = getattr(application, 'student', None) if application is not None else None
            job = getattr(record, 'job', None)
            if job is None:
                application = getattr(record, 'application', None)
                job = getattr(application, 'job', None) if application is not None else None
            if student is None or job is None:
                continue
            mapping[self._student_key(student)].append(job)
        for student in students:
            key = self._student_key(student)
            if not mapping.get(key):
                mapping[key] = self._best_jobs_for_student(student, jobs)
        return mapping

    def _companies_by_student(self, companies: Sequence[Company], jobs_by_student: dict[str, list[Job]], applications: Sequence[Application]) -> dict[str, list[Company]]:
        mapping: dict[str, list[Company]] = defaultdict(list)
        company_lookup = {str(getattr(company, 'name', '')): company for company in companies}
        for application in applications:
            student = getattr(application, 'student', None)
            company = getattr(application, 'company', None) or getattr(getattr(application, 'job', None), 'company', None)
            if student is None or company is None:
                continue
            mapping[self._student_key(student)].append(company)
        for student_key, student_jobs in jobs_by_student.items():
            seen = {str(getattr(company, 'name', '')) for company in mapping.get(student_key, [])}
            for job in student_jobs:
                company = getattr(job, 'company', None)
                company_name = str(getattr(company, 'name', None) or getattr(job, 'company_name', None) or '')
                if company is not None and company_name not in seen:
                    mapping[student_key].append(company)
                    seen.add(company_name)
                elif company_name and company_name in company_lookup and company_name not in seen:
                    mapping[student_key].append(company_lookup[company_name])
                    seen.add(company_name)
        return mapping

    def _recruiters_by_student(self, recruiters: Sequence[Recruiter], applications: Sequence[Application], jobs_by_student: dict[str, list[Job]]) -> dict[str, list[Recruiter]]:
        mapping: dict[str, list[Recruiter]] = defaultdict(list)
        recruiter_lookup = {str(getattr(recruiter, 'name', '')): recruiter for recruiter in recruiters}
        for application in applications:
            student = getattr(application, 'student', None)
            recruiter = getattr(application, 'recruiter', None)
            if student is None or recruiter is None:
                continue
            mapping[self._student_key(student)].append(recruiter)
        for student_key, student_jobs in jobs_by_student.items():
            seen = {str(getattr(recruiter, 'name', '')) for recruiter in mapping.get(student_key, [])}
            for job in student_jobs:
                recruiter = getattr(job, 'recruiter', None)
                recruiter_name = str(getattr(recruiter, 'name', None) or getattr(job, 'recruiter_name', None) or '')
                if recruiter is not None and recruiter_name not in seen:
                    mapping[student_key].append(recruiter)
                    seen.add(recruiter_name)
                elif recruiter_name and recruiter_name in recruiter_lookup and recruiter_name not in seen:
                    mapping[student_key].append(recruiter_lookup[recruiter_name])
                    seen.add(recruiter_name)
        return mapping

    def _records_by_student(self, records: Sequence[Any], attr: str, application_fallback: bool = False) -> dict[str, list[Any]]:
        mapping: dict[str, list[Any]] = defaultdict(list)
        for record in records:
            student = getattr(record, attr, None)
            if student is None and application_fallback:
                application = getattr(record, 'application', None)
                student = getattr(application, 'student', None) if application is not None else None
            if student is None:
                continue
            mapping[self._student_key(student)].append(record)
        return mapping

    def _best_jobs_for_student(self, student: Student, jobs: Sequence[Job]) -> list[Job]:
        student_skills = {str(item).strip().lower() for item in self._normalized_list(getattr(student, 'skills', None))}
        career_goal = str(getattr(student, 'career_goal', '') or '').lower()
        preferred_location = str(getattr(student, 'preferred_location', '') or '').lower()
        ranked = []
        for job in jobs:
            required = {str(item).strip().lower() for item in self._normalized_list(getattr(job, 'skills_required', None))}
            preferred = {str(item).strip().lower() for item in self._normalized_list(getattr(job, 'preferred_skills', None))}
            role = str(getattr(job, 'role', None) or getattr(job, 'title', None) or getattr(job, 'job_title', None) or '').lower()
            location = ' '.join([
                str(getattr(job, 'location_city', None) or ''),
                str(getattr(job, 'location_country', None) or ''),
            ]).lower()
            score = len(student_skills & required) * 5 + len(student_skills & preferred) * 2
            if career_goal and any(token in role for token in career_goal.split() if len(token) > 2):
                score += 6
            if preferred_location and preferred_location in location:
                score += 4
            ranked.append((score, job))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [job for _, job in ranked[:60]]

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))

    def _normalized_list(self, value: Any) -> list[str]:
        if isinstance(value, dict):
            return [str(key) for key in value.keys() if str(key).strip()]
        if isinstance(value, (list, tuple, set)):
            return [str(item) for item in value if str(item).strip()]
        if value in (None, ''):
            return []
        return [str(value)]


def generate_recruiter_recommendations(
    students: Sequence[Student],
    companies: Sequence[Company],
    recruiters: Sequence[Recruiter],
    jobs: Sequence[Job],
    applications: Sequence[Application],
    interviews: Sequence[Interview],
    offers: Sequence[Offer],
    career_reports: Sequence[CareerReport],
    skill_gaps: Sequence[SkillGap],
    learning_roadmaps: Sequence[Any],
    resume_analyses: Sequence[ResumeAnalysis],
    job_matches: Sequence[JobMatch],
    ai_recommendations: Sequence[AIRecommendation],
    career_predictions: Sequence[CareerPrediction],
    salary_predictions: Sequence[SalaryPrediction],
    config: AppConfig = CONFIG,
) -> RecruiterRecommendationGenerationResult:
    generator = RecruiterRecommendationGenerator(config=config)
    return generator.generate(
        students=students,
        companies=companies,
        recruiters=recruiters,
        jobs=jobs,
        applications=applications,
        interviews=interviews,
        offers=offers,
        career_reports=career_reports,
        skill_gaps=skill_gaps,
        learning_roadmaps=learning_roadmaps,
        resume_analyses=resume_analyses,
        job_matches=job_matches,
        ai_recommendations=ai_recommendations,
        career_predictions=career_predictions,
        salary_predictions=salary_predictions,
    )


