TREND_BUCKETS: dict[str, tuple[str, ...]] = {
    'ai': ('Machine Learning', 'Deep Learning', 'LLM Evaluation', 'TensorFlow', 'PyTorch', 'AI Engineering'),
    'cloud': ('AWS', 'Azure', 'Google Cloud', 'Docker', 'Kubernetes', 'Cloud Security'),
    'security': ('Cybersecurity', 'OWASP', 'Zero Trust', 'IAM', 'Threat Modeling', 'Security Automation'),
    'frontend': ('React', 'TypeScript', 'Accessibility', 'Frontend Performance', 'Design Systems', 'State Management'),
    'backend': ('Node.js', 'Java', 'Python', 'System Design', 'REST API', 'Microservices'),
    'devops': ('Docker', 'Kubernetes', 'CI/CD', 'Observability', 'Terraform', 'Platform Engineering'),
}
DECLINING_SKILLS: tuple[str, ...] = ('jQuery-heavy development', 'Legacy monolith-only deployment', 'Manual server provisioning', 'Spreadsheet-only analytics')
FUTURE_SKILLS: tuple[str, ...] = ('Agentic Workflows', 'MLOps', 'Platform Engineering', 'Prompt Evaluation', 'AI Product Instrumentation', 'Cloud Security')
SOFT_SKILLS: tuple[str, ...] = ('Communication', 'Leadership', 'Problem Solving', 'Collaboration', 'Ownership', 'Adaptability', 'Presentation')


@dataclass(slots=True)
class SkillGapGenerationResult:
    skill_gaps: list[SkillGap]


class SkillGapGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed + 10000)
        self.faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed + 10000)
            self.faker.seed_instance(config.generation.seed + 10000)

    def generate(
        self,
        students: Sequence[Student],
        companies: Sequence[Company],
        recruiters: Sequence[Recruiter],
        jobs: Sequence[Job],
        applications: Sequence[Application],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
        career_reports: Sequence[CareerReport],
    ) -> SkillGapGenerationResult:
        if not students:
            raise ValueError('Skill gap generation requires students.')
        if not jobs:
            raise ValueError('Skill gap generation requires jobs.')

        jobs_by_student = self._jobs_by_student(students, jobs, applications)
        recruiters_by_student = self._recruiters_by_student(applications, recruiters)
        companies_by_student = self._companies_by_student(applications, companies)
        interviews_by_student = self._records_by_student(interviews, ('student',), fallback_application_attr='application')
        offers_by_student = self._records_by_student(offers, ('student',), fallback_application_attr='application')
        reports_by_student = {self._student_key(report.student): report for report in career_reports if getattr(report, 'student', None) is not None}

        industry_trends = self._industry_trends(jobs, companies)
        skill_gaps: list[SkillGap] = []

        for student in students:
            key = self._student_key(student)
            student_jobs = jobs_by_student.get(key) or self._best_candidate_jobs(student, jobs)
            student_recruiters = recruiters_by_student.get(key, [])
            student_companies = companies_by_student.get(key, [])
            student_interviews = interviews_by_student.get(key, [])
            student_offers = offers_by_student.get(key, [])
            report = reports_by_student.get(key)
            skill_gap = self._build_skill_gap(
                student=student,
                jobs=student_jobs,
                recruiters=student_recruiters,
                companies=student_companies,
                interviews=student_interviews,
                offers=student_offers,
                report=report,
                industry_trends=industry_trends,
            )
            skill_gaps.append(skill_gap)

        return SkillGapGenerationResult(skill_gaps=skill_gaps)

    def _build_skill_gap(
        self,
        student: Student,
        jobs: Sequence[Job],
        recruiters: Sequence[Recruiter],
        companies: Sequence[Company],
        interviews: Sequence[Interview],
        offers: Sequence[Offer],
        report: CareerReport | None,
        industry_trends: dict[str, Any],
    ) -> SkillGap:
        student_skills = self._student_skill_set(student)
        student_skill_titles = self._student_skill_titles(student)
        target_skill_counter, critical_counter, company_requirements = self._target_skill_profiles(jobs, recruiters, companies)
        missing_ranked = [skill for skill, _ in target_skill_counter.most_common() if skill not in student_skills]
        mastered_ranked = [skill for skill in target_skill_counter if skill in student_skills]
        soft_missing = [skill for skill in SOFT_SKILLS if skill.lower() not in student_skills and self._soft_skill_needed(skill, recruiters, interviews)]
        technology_missing = [skill for skill in missing_ranked if skill in RESOURCE_CATALOG][:8]
        certification_missing = self._missing_certifications(student, jobs)
        missing_experience = self._missing_experience(student, jobs, offers)
        missing_portfolio = self._missing_portfolio_requirements(student, jobs)
        missing_github = self._missing_github_activity(student, jobs)
        critical_skills = [skill for skill in missing_ranked if critical_counter[skill] >= 4][:6]
        important_skills = [skill for skill in missing_ranked if skill not in critical_skills][:8]
        optional_skills = [skill for skill in missing_ranked[8:16] if skill not in critical_skills and skill not in important_skills]
        overall_gap_pct = self._overall_skill_gap_pct(target_skill_counter, student_skills, report)
        ranked_missing = self._ranked_missing_skills(
            missing_ranked=missing_ranked,
            target_skill_counter=target_skill_counter,
            critical_counter=critical_counter,
            jobs=jobs,
            companies=companies,
            report=report,
        )
        learning_estimations = self._learning_estimations(ranked_missing)
        resources = self._learning_resources(ranked_missing)
        job_impact = self._job_impact(ranked_missing, report, jobs)
        industry_analysis = self._student_industry_analysis(industry_trends, jobs)
        roadmap = self._roadmap(ranked_missing)
        certifications = self._certification_recommendations(student, ranked_missing)
        project_recommendations = self._project_recommendations(ranked_missing)
        ai_metadata = self._ai_metadata(ranked_missing, jobs, companies)
        explanations = self._explanations(ranked_missing, jobs, companies, company_requirements)

        gap = SkillGap(
            student=student,
            generated_at=datetime.utcnow(),
            overall_skill_gap_pct=overall_gap_pct,
            critical_skills=critical_skills,
            important_skills=important_skills,
            optional_skills=optional_skills,
            already_mastered_skills=mastered_ranked[:12],
            missing_technologies=technology_missing,
            missing_soft_skills=soft_missing,
            missing_certifications=certification_missing,
            missing_experience=missing_experience,
            missing_portfolio_requirements=missing_portfolio,
            missing_github_activity=missing_github,
        )
        gap.ranked_skills_metadata = ranked_missing
        gap.learning_estimations_metadata = learning_estimations
        gap.learning_resources_metadata = resources
        gap.job_impact_metadata = job_impact
        gap.industry_analysis_metadata = industry_analysis
        gap.roadmap_metadata = roadmap
        gap.certification_recommendations_metadata = certifications
        gap.project_recommendations_metadata = project_recommendations
        gap.ai_metadata = ai_metadata
        gap.explanations_metadata = explanations
        gap.source_metadata = {
            'student_skills': sorted(student_skill_titles),
            'matched_jobs_count': len(jobs),
            'recruiter_count': len(recruiters),
            'company_count': len(companies),
            'interview_count': len(interviews),
            'offer_count': len(offers),
            'career_report_attached': report is not None,
        }
        return gap

    def _student_skill_set(self, student: Student) -> set[str]:
        skills = self._list_value(getattr(student, 'skills', None))
        return {str(skill).strip().lower() for skill in skills if str(skill).strip()}

    def _student_skill_titles(self, student: Student) -> set[str]:
        skills = self._list_value(getattr(student, 'skills', None))
        return {str(skill).strip() for skill in skills if str(skill).strip()}

    def _target_skill_profiles(
        self,
        jobs: Sequence[Job],
        recruiters: Sequence[Recruiter],
        companies: Sequence[Company],
    ) -> tuple[Counter[str], Counter[str], dict[str, list[str]]]:
        target_counter: Counter[str] = Counter()
        critical_counter: Counter[str] = Counter()
        company_requirements: dict[str, list[str]] = defaultdict(list)
        for job in jobs:
            required = self._normalized_list(getattr(job, 'skills_required', None) or getattr(job, 'skills_required_metadata', None) or [])
            preferred = self._normalized_list(getattr(job, 'preferred_skills', None) or [])
            company_name = str(getattr(getattr(job, 'company', None), 'name', None) or getattr(job, 'company_name', 'Company'))
            for skill in required:
                target_counter[skill] += 3
                critical_counter[skill] += 1
                company_requirements[skill].append(company_name)
            for skill in preferred:
                target_counter[skill] += 1
                company_requirements[skill].append(company_name)
        for recruiter in recruiters:
            preferences = self._normalized_list(
                getattr(recruiter, 'specialties', None)
                or getattr(recruiter, 'skills_focus', None)
                or getattr(recruiter, 'recruiting_focus', None)
                or []
            )
            for skill in preferences:
                target_counter[skill] += 1
        for company in companies:
            stack = self._normalized_list(getattr(company, 'tech_stack', None) or getattr(company, 'recruiting_focus', None) or [])
            for skill in stack:
                target_counter[skill] += 1
                company_requirements[skill].append(str(getattr(company, 'name', 'Company')))
        return target_counter, critical_counter, company_requirements

    def _overall_skill_gap_pct(self, target_counter: Counter[str], student_skills: set[str], report: CareerReport | None) -> int:
        target_skills = {skill for skill in target_counter if skill}
        if not target_skills:
            return 0
        matched = len([skill for skill in target_skills if skill in student_skills])
        gap_pct = round((1 - (matched / len(target_skills))) * 100)
        if report is not None:
            job_match_score = int(getattr(report, 'job_match_score', 0) or 0)
            ats_score = int(getattr(report, 'ats_score', 0) or 0)
            adjustment = round(((100 - job_match_score) * 0.18) + ((100 - ats_score) * 0.10))
            gap_pct = round((gap_pct * 0.72) + adjustment)
        return max(0, min(100, gap_pct))

    def _ranked_missing_skills(
        self,
        missing_ranked: Sequence[str],
        target_skill_counter: Counter[str],
        critical_counter: Counter[str],
        jobs: Sequence[Job],
        companies: Sequence[Company],
        report: CareerReport | None,
    ) -> list[dict[str, Any]]:
        results: list[dict[str, Any]] = []
        total_jobs = max(1, len(jobs))
        base_job_match = int(getattr(report, 'job_match_score', 0) or 0) if report is not None else 50
        base_ats = int(getattr(report, 'ats_score', 0) or 0) if report is not None else 50
        base_interview = int(getattr(report, 'interview_readiness', 0) or 0) if report is not None else 45
        base_career = int(getattr(report, 'career_score', 0) or 0) if report is not None else 50
        for order, skill in enumerate(missing_ranked[:16], start=1):
            demand = target_skill_counter[skill]
            critical_hits = critical_counter[skill]
            company_hits = self._companies_requiring(skill, companies, jobs)
            priority = self._priority_label(demand, critical_hits, company_hits)
            resource = RESOURCE_CATALOG.get(skill, DEFAULT_RESOURCE)
            hours = int(resource['hours'])
            results.append({
                'skill': skill,
                'priority': priority,
                'why_it_matters': self._why_skill_matters(skill, demand, critical_hits, total_jobs),
                'estimated_hours': hours,
                'difficulty': self._difficulty(hours),
                'prerequisites': resource['prerequisites'],
                'expected_completion_date': (date.today() + timedelta(days=max(7, hours // 2 + order * 3))).isoformat(),
                'learning_order': order,
                'career_score_improvement': self._bounded_improvement(priority, 4, 10, demand),
                'ats_improvement': self._bounded_improvement(priority, 3, 8, demand),
                'interview_improvement': self._bounded_improvement(priority, 3, 9, demand),
                'job_match_improvement': self._bounded_improvement(priority, 5, 14, demand),
                'expected_salary_improvement': self._salary_improvement(priority, demand),
                'hiring_probability_increase': self._bounded_improvement(priority, 2, 10, demand),
                'baseline_job_match': base_job_match,
                'baseline_ats': base_ats,
                'baseline_interview': base_interview,
                'baseline_career': base_career,
                'companies_requiring_it': company_hits,
                'jobs_requiring_it': self._jobs_requiring(skill, jobs),
            })
        results.sort(key=lambda item: (-PRIORITY_ORDER[item['priority']], -item['job_match_improvement'], item['learning_order']))
        return results

    def _learning_estimations(self, ranked_missing: Sequence[dict[str, Any]]) -> dict[str, Any]:
        return {
            'total_estimated_hours': sum(int(item['estimated_hours']) for item in ranked_missing),
            'items': [
                {
                    'skill': item['skill'],
                    'estimated_hours': item['estimated_hours'],
                    'difficulty': item['difficulty'],
                    'prerequisites': item['prerequisites'],
                    'expected_completion_date': item['expected_completion_date'],
                    'learning_order': item['learning_order'],
                }
                for item in ranked_missing
            ],
        }

    def _learning_resources(self, ranked_missing: Sequence[dict[str, Any]]) -> dict[str, Any]:
        items = []
        for item in ranked_missing:
            resource = RESOURCE_CATALOG.get(item['skill'], DEFAULT_RESOURCE)
            items.append({
                'skill': item['skill'],
                'official_documentation': resource['official_documentation'],
                'open_source_projects': resource['open_source_projects'],
                'practice_problems': resource['practice_problems'],
                'coding_challenges': resource['coding_challenges'],
                'books': resource['books'],
                'courses': resource['courses'],
                'videos': resource['videos'],
                'labs': resource['labs'],
                'hackathons': resource['hackathons'],
                'community_projects': resource['community_projects'],
            })
        return {'resources': items}

    def _job_impact(self, ranked_missing: Sequence[dict[str, Any]], report: CareerReport | None, jobs: Sequence[Job]) -> dict[str, Any]:
        baseline_salary = Decimal('0.00')
        if report is not None:
            predictions = getattr(report, 'predictions_metadata', None) or {}
            expected_salary = predictions.get('expected_salary', {})
            if isinstance(expected_salary, dict):
                baseline_salary = Decimal(expected_salary.get('expected', 0) or 0)
        if baseline_salary <= 0:
            salary_mins = [Decimal(getattr(job, 'salary_min', 0) or 0) for job in jobs if Decimal(getattr(job, 'salary_min', 0) or 0) > 0]
            baseline_salary = Decimal(str(round(mean([float(v) for v in salary_mins]), 2))) if salary_mins else Decimal('0.00')
        return {
            'baseline_salary': baseline_salary.quantize(Decimal('1.00')),
            'skills': [
                {
                    'skill': item['skill'],
                    'career_score_improvement': item['career_score_improvement'],
                    'ats_improvement': item['ats_improvement'],
                    'interview_improvement': item['interview_improvement'],
                    'job_match_improvement': item['job_match_improvement'],
                    'expected_salary_improvement': item['expected_salary_improvement'],
                    'hiring_probability_increase': item['hiring_probability_increase'],
                }
                for item in ranked_missing
            ],
        }

    def _student_industry_analysis(self, industry_trends: dict[str, Any], jobs: Sequence[Job]) -> dict[str, Any]:
        role_skill_counter = Counter()
        for job in jobs:
            for skill in self._normalized_list(getattr(job, 'skills_required', None) or getattr(job, 'preferred_skills', None) or []):
                role_skill_counter[skill] += 1
        return {
            'trending_skills': [skill for skill, _ in role_skill_counter.most_common(8)] or industry_trends['trending_skills'],
            'declining_skills': list(DECLINING_SKILLS),
            'future_skills': list(FUTURE_SKILLS),
            'ai_skills': list(TREND_BUCKETS['ai']),
            'cloud_skills': list(TREND_BUCKETS['cloud']),
            'security_skills': list(TREND_BUCKETS['security']),
            'frontend_skills': list(TREND_BUCKETS['frontend']),
            'backend_skills': list(TREND_BUCKETS['backend']),
            'devops_skills': list(TREND_BUCKETS['devops']),
        }

    def _roadmap(self, ranked_missing: Sequence[dict[str, Any]]) -> dict[str, Any]:
        roadmap = []
        start = date.today()
        for week, item in enumerate(ranked_missing[:6], start=1):
            roadmap.append({
                'week': week,
                'skill': item['skill'],
                'milestones': [
                    f'Review official documentation for {item["skill"]}.',
                    f'Complete one guided exercise and one practical build using {item["skill"]}.',
                    f'Document outcomes and add evidence to the profile or portfolio.',
                ],
                'checkpoints': [
                    'Core concepts understood',
                    'Practice challenge completed',
                    'Portfolio artifact published',
                ],
                'progress': 0 if week > 1 else 15,
                'completion_pct': 0 if week > 1 else 10,
                'expected_outcome': f'Improved readiness for roles requiring {item["skill"]}.',
                'deadline': (start + timedelta(days=week * 7)).isoformat(),
            })
        return {'week_by_week_roadmap': roadmap}

    def _certification_recommendations(self, student: Student, ranked_missing: Sequence[dict[str, Any]]) -> dict[str, Any]:
        career_goal = str(getattr(student, 'career_goal', '') or '').lower()
        bucket_order = self._career_goal_buckets(career_goal)
        recommended: list[dict[str, str]] = []
        seen: set[str] = set()
        for bucket in bucket_order:
            for item in CERTIFICATION_CATALOG.get(bucket, []):
                key = f"{item['provider']}::{item['name']}"
                if key not in seen:
                    recommended.append(item)
                    seen.add(key)
                if len(recommended) >= 5:
                    break
            if len(recommended) >= 5:
                break
        if not recommended:
            for skill_item in ranked_missing[:3]:
                skill = skill_item['skill'].lower()
                if 'aws' in skill or 'cloud' in skill or 'docker' in skill or 'kubernetes' in skill:
                    recommended.extend(CERTIFICATION_CATALOG['cloud'][:2])
                elif 'machine' in skill or 'ai' in skill or 'tensorflow' in skill or 'pytorch' in skill:
                    recommended.extend(CERTIFICATION_CATALOG['ai'][:2])
        filtered = []
        seen.clear()
        for item in recommended:
            key = f"{item['provider']}::{item['name']}"
            if key not in seen:
                filtered.append(item)
                seen.add(key)
        return {'recommendations': filtered[:5]}

    def _project_recommendations(self, ranked_missing: Sequence[dict[str, Any]]) -> dict[str, Any]:
        projects = []
        for item in ranked_missing[:6]:
            skill = item['skill']
            projects.append({
                'skill': skill,
                'title': self._project_title(skill),
                'difficulty': item['difficulty'],
                'estimated_hours': max(10, item['estimated_hours'] + 6),
                'technologies': self._project_technologies(skill),
                'portfolio_value': self._portfolio_value(skill, item['priority']),
            })
        return {'projects': projects}

    def _ai_metadata(self, ranked_missing: Sequence[dict[str, Any]], jobs: Sequence[Job], companies: Sequence[Company]) -> dict[str, Any]:
        demand_scores = [self._market_demand(item['companies_requiring_it'], jobs) for item in ranked_missing]
        avg_demand = round(mean(demand_scores)) if demand_scores else 0
        return {
            'confidence_score': min(99, 68 + len(ranked_missing) * 2),
            'recommendation_confidence': min(98, 70 + len([item for item in ranked_missing if item['priority'] in {'Critical', 'High'}]) * 3),
            'market_confidence': min(98, 60 + avg_demand // 2),
            'demand_score': avg_demand,
            'future_demand_score': min(99, avg_demand + 8),
        }

    def _explanations(
        self,
        ranked_missing: Sequence[dict[str, Any]],
        jobs: Sequence[Job],
        companies: Sequence[Company],
        company_requirements: dict[str, list[str]],
    ) -> dict[str, Any]:
        items = []
        for item in ranked_missing:
            skill = item['skill']
            items.append({
                'skill': skill,
                'why_missing': f'{skill} appears in target job requirements but is not present in the student profile evidence.',
                'why_it_affects_hiring': f'{skill} influences ATS match, recruiter screening, and interview depth for role-relevant workflows.',
                'companies_requiring_it': sorted(set(company_requirements.get(skill, [])))[:8],
                'jobs_requiring_it': item['jobs_requiring_it'],
                'expected_career_impact': {
                    'career_score_improvement': item['career_score_improvement'],
                    'job_match_improvement': item['job_match_improvement'],
                    'hiring_probability_increase': item['hiring_probability_increase'],
                },
            })
        return {'items': items}

    def _jobs_by_student(self, students: Sequence[Student], jobs: Sequence[Job], applications: Sequence[Application]) -> dict[str, list[Job]]:
        mapping: dict[str, list[Job]] = defaultdict(list)
        for application in applications:
            student = getattr(application, 'student', None)
            job = getattr(application, 'job', None)
            if student is None or job is None:
                continue
            mapping[self._student_key(student)].append(job)
        for student in students:
            key = self._student_key(student)
            if key not in mapping or not mapping[key]:
                mapping[key] = self._best_candidate_jobs(student, jobs)
        return mapping

    def _recruiters_by_student(self, applications: Sequence[Application], recruiters: Sequence[Recruiter]) -> dict[str, list[Recruiter]]:
        mapping: dict[str, list[Recruiter]] = defaultdict(list)
        for application in applications:
            student = getattr(application, 'student', None)
            recruiter = getattr(application, 'recruiter', None)
            if student is None or recruiter is None:
                continue
            mapping[self._student_key(student)].append(recruiter)
        return mapping

    def _companies_by_student(self, applications: Sequence[Application], companies: Sequence[Company]) -> dict[str, list[Company]]:
        mapping: dict[str, list[Company]] = defaultdict(list)
        for application in applications:
            student = getattr(application, 'student', None)
            company = getattr(application, 'company', None) or getattr(getattr(application, 'job', None), 'company', None)
            if student is None or company is None:
                continue
            mapping[self._student_key(student)].append(company)
        return mapping

    def _records_by_student(self, records: Sequence[Any], direct_attrs: tuple[str, ...], fallback_application_attr: str | None = None) -> dict[str, list[Any]]:
        mapping: dict[str, list[Any]] = defaultdict(list)
        for record in records:
            student = None
            for attr in direct_attrs:
                student = getattr(record, attr, None)
                if student is not None:
                    break
            if student is None and fallback_application_attr is not None:
                application = getattr(record, fallback_application_attr, None)
                student = getattr(application, 'student', None) if application is not None else None
            if student is None:
                continue
            mapping[self._student_key(student)].append(record)
        return mapping

    def _best_candidate_jobs(self, student: Student, jobs: Sequence[Job]) -> list[Job]:
        student_skills = self._student_skill_set(student)
        preferred_location = str(getattr(student, 'preferred_location', '') or '').lower()
        ranked: list[tuple[int, Job]] = []
        for job in jobs:
            required = {skill.lower() for skill in self._normalized_list(getattr(job, 'skills_required', None) or [])}
            preferred = {skill.lower() for skill in self._normalized_list(getattr(job, 'preferred_skills', None) or [])}
            overlap = len(student_skills & required) * 3 + len(student_skills & preferred)
            location_text = f"{getattr(job, 'location_city', '')} {getattr(job, 'location_country', '')}".lower()
            if preferred_location and preferred_location in location_text:
                overlap += 2
            ranked.append((overlap, job))
        ranked.sort(key=lambda item: item[0], reverse=True)
        return [job for _, job in ranked[:20]]

    def _industry_trends(self, jobs: Sequence[Job], companies: Sequence[Company]) -> dict[str, Any]:
        skill_counter = Counter()
        for job in jobs:
            for skill in self._normalized_list(getattr(job, 'skills_required', None) or getattr(job, 'preferred_skills', None) or []):
                skill_counter[skill] += 1
        return {
            'trending_skills': [skill for skill, _ in skill_counter.most_common(10)],
            'industry_count': len({str(getattr(company, 'industry', 'Technology')) for company in companies}),
        }

    def _missing_certifications(self, student: Student, jobs: Sequence[Job]) -> list[str]:
        certifications = {str(item).lower() for item in self._list_value(getattr(student, 'certifications', None))}
        candidate_recommendations: list[str] = []
        joined_text = ' '.join(self._normalized_list(getattr(student, 'career_goal', None) or ''))
        if any(term in joined_text for term in ('cloud', 'devops', 'platform')):
            candidate_recommendations.extend([item['name'] for item in CERTIFICATION_CATALOG['cloud'][:3]])
        if any(term in joined_text for term in ('ai', 'ml', 'data science')):
            candidate_recommendations.extend([item['name'] for item in CERTIFICATION_CATALOG['ai'][:2]])
        if any(term in joined_text for term in ('security', 'cyber')):
            candidate_recommendations.extend([item['name'] for item in CERTIFICATION_CATALOG['security'][:2]])
        if any(term in joined_text for term in ('frontend', 'ui')):
            candidate_recommendations.extend([item['name'] for item in CERTIFICATION_CATALOG['frontend'][:1]])
        if any(term in joined_text for term in ('backend', 'software engineer', 'developer')):
            candidate_recommendations.extend([item['name'] for item in CERTIFICATION_CATALOG['backend'][:2]])
        missing = [name for name in candidate_recommendations if name.lower() not in certifications]
        seen: set[str] = set()
        unique: list[str] = []
        for item in missing:
            if item not in seen:
                unique.append(item)
                seen.add(item)
        return unique[:5]

    def _missing_experience(self, student: Student, jobs: Sequence[Job], offers: Sequence[Offer]) -> list[str]:
        experience_items = [str(item).lower() for item in self._list_value(getattr(student, 'experience', None))]
        gaps: list[str] = []
        if not experience_items:
            gaps.append('No internship, freelance, or formal work evidence found for target roles.')
        if not any(any(term in item for term in ('intern', 'engineer', 'analyst', 'assistant')) for item in experience_items):
            gaps.append('Limited role-aligned practical experience for recruiter screening.')
        if not offers and len(jobs) >= 5:
            gaps.append('No offer conversion evidence yet despite active job alignment opportunities.')
        return gaps[:4]

    def _missing_portfolio_requirements(self, student: Student, jobs: Sequence[Job]) -> list[str]:
        portfolio = getattr(student, 'portfolio_url', None) or getattr(student, 'portfolio', None) or getattr(student, 'website_url', None)
        projects = self._list_value(getattr(student, 'projects', None))
        gaps: list[str] = []
        role_text = ' '.join(str(getattr(job, 'title', '')) for job in jobs).lower()
        if not portfolio:
            gaps.append('Portfolio or personal website is missing for discovery and recruiter validation.')
        if len(projects) < 2:
            gaps.append('Not enough publicly explainable projects for strong portfolio proof.')
        if any(term in role_text for term in ('frontend', 'design', 'product')) and not portfolio:
            gaps.append('Target roles benefit from visual or case-study based project presentation.')
        return gaps[:4]

    def _missing_github_activity(self, student: Student, jobs: Sequence[Job]) -> list[str]:
        github = getattr(student, 'github_url', None) or getattr(student, 'github', None)
        projects = [str(item).lower() for item in self._list_value(getattr(student, 'projects', None))]
        coding_roles = any(any(term in str(getattr(job, 'title', '')).lower() for term in ('engineer', 'developer', 'backend', 'frontend', 'data', 'ml', 'ai')) for job in jobs)
        gaps: list[str] = []
        if coding_roles and not github:
            gaps.append('GitHub profile is missing for code credibility and recruiter review.')
        if github and len(projects) < 2:
            gaps.append('GitHub exists but lacks enough project evidence to support target roles.')
        return gaps[:3]

    def _priority_label(self, demand: int, critical_hits: int, companies: list[str]) -> str:
        company_count = len(set(companies))
        if critical_hits >= 4 or (demand >= 10 and company_count >= 3):
            return 'Critical'
        if critical_hits >= 2 or demand >= 7:
            return 'High'
        if demand >= 4:
            return 'Medium'
        return 'Low'

    def _why_skill_matters(self, skill: str, demand: int, critical_hits: int, total_jobs: int) -> str:
        demand_pct = round((critical_hits / max(1, total_jobs)) * 100)
        if critical_hits >= 4:
            return f'{skill} appears as a repeated core requirement across target jobs and directly influences interview progression and ATS ranking.'
        if demand >= 7:
            return f'{skill} shows up frequently in recruiter and job requirements, affecting role alignment and hiring competitiveness.'
        return f'{skill} improves breadth for relevant job families and can increase profile credibility for adjacent opportunities.'

    def _difficulty(self, hours: int) -> str:
        if hours <= 16:
            return 'Low'
        if hours <= 28:
            return 'Medium'
        return 'High'

    def _bounded_improvement(self, priority: str, low: int, high: int, demand: int) -> int:
        weight = {'Critical': 1.0, 'High': 0.8, 'Medium': 0.55, 'Low': 0.35}[priority]
        demand_bonus = min(4, demand // 3)
        return round(low + ((high - low) * weight) + demand_bonus)

    def _salary_improvement(self, priority: str, demand: int) -> Decimal:
        base = {'Critical': 1400, 'High': 1000, 'Medium': 650, 'Low': 300}[priority]
        return Decimal(str(base + demand * 120)).quantize(Decimal('1.00'))

    def _companies_requiring(self, skill: str, companies: Sequence[Company], jobs: Sequence[Job]) -> list[str]:
        names: set[str] = set()
        for job in jobs:
            required = {item.lower() for item in self._normalized_list(getattr(job, 'skills_required', None) or [])}
            preferred = {item.lower() for item in self._normalized_list(getattr(job, 'preferred_skills', None) or [])}
            if skill.lower() in required or skill.lower() in preferred:
                company_name = str(getattr(getattr(job, 'company', None), 'name', None) or getattr(job, 'company_name', 'Company'))
                names.add(company_name)
        for company in companies:
            stack = {item.lower() for item in self._normalized_list(getattr(company, 'tech_stack', None) or getattr(company, 'recruiting_focus', None) or [])}
            if skill.lower() in stack:
                names.add(str(getattr(company, 'name', 'Company')))
        return sorted(names)[:8]

    def _jobs_requiring(self, skill: str, jobs: Sequence[Job]) -> list[str]:
        titles: list[str] = []
        for job in jobs:
            required = {item.lower() for item in self._normalized_list(getattr(job, 'skills_required', None) or [])}
            preferred = {item.lower() for item in self._normalized_list(getattr(job, 'preferred_skills', None) or [])}
            if skill.lower() in required or skill.lower() in preferred:
                titles.append(str(getattr(job, 'title', getattr(job, 'role_title', 'Role'))))
        seen: set[str] = set()
        unique: list[str] = []
        for title in titles:
            if title not in seen:
                unique.append(title)
                seen.add(title)
        return unique[:8]

    def _career_goal_buckets(self, career_goal: str) -> list[str]:
        if any(term in career_goal for term in ('ai', 'ml', 'machine learning', 'data scientist')):
            return ['ai', 'cloud', 'data']
        if any(term in career_goal for term in ('cloud', 'devops', 'platform', 'sre')):
            return ['cloud', 'backend', 'security']
        if any(term in career_goal for term in ('security', 'cyber')):
            return ['security', 'cloud']
        if any(term in career_goal for term in ('frontend', 'ui', 'design engineer')):
            return ['frontend', 'backend']
        if any(term in career_goal for term in ('data', 'analytics', 'analyst')):
            return ['data', 'cloud']
        return ['backend', 'cloud']

    def _project_title(self, skill: str) -> str:
        mapping = {
            'Docker': 'Containerized Multi-Service Job Tracker',
            'AWS': 'Cloud-Native Career Analytics Platform',
            'System Design': 'Scalable Interview Scheduling System Design',
            'SQL': 'Applicant Funnel Analytics Warehouse',
            'React': 'Interactive Candidate Insights Dashboard',
            'Node.js': 'Recruiter Workflow API Platform',
            'Machine Learning': 'Offer Probability Prediction Pipeline',
            'Cybersecurity': 'Secure Authentication and Audit Monitoring Suite',
        }
        return mapping.get(skill, f'{skill} Role-Readiness Portfolio Project')

    def _project_technologies(self, skill: str) -> list[str]:
        mapping = {
            'Docker': ['Docker', 'Linux', 'CI/CD'],
            'AWS': ['AWS', 'CloudWatch', 'IAM'],
            'System Design': ['APIs', 'PostgreSQL', 'Caching'],
            'SQL': ['SQL', 'PostgreSQL', 'BI'],
            'React': ['React', 'TypeScript', 'REST API'],
            'Node.js': ['Node.js', 'Express', 'PostgreSQL'],
            'Machine Learning': ['Python', 'scikit-learn', 'Pandas'],
            'Cybersecurity': ['OWASP', 'IAM', 'Logging'],
        }
        return mapping.get(skill, [skill])

    def _portfolio_value(self, skill: str, priority: str) -> str:
        if priority == 'Critical':
            return f'High portfolio value because {skill} directly affects target job screening and interview depth.'
        if priority == 'High':
            return f'Strong portfolio value for proving practical ability in {skill}.'
        return f'Useful portfolio signal that broadens role fit around {skill}.'

    def _market_demand(self, companies_requiring: list[str], jobs: Sequence[Job]) -> int:
        company_factor = len(set(companies_requiring)) * 10
        job_factor = min(40, len(jobs) * 2)
        return min(100, 30 + company_factor + job_factor)

    def _soft_skill_needed(self, skill: str, recruiters: Sequence[Recruiter], interviews: Sequence[Interview]) -> bool:
        skill_l = skill.lower()
        recruiter_signals = 0
        for recruiter in recruiters:
            text = ' '.join(self._normalized_list(getattr(recruiter, 'recruiting_focus', None) or getattr(recruiter, 'specialties', None) or []))
            if skill_l in text.lower():
                recruiter_signals += 1
        interview_signals = 0
        for interview in interviews:
            interview_type = str(getattr(interview, 'interview_type', '')).lower()
            if any(term in interview_type for term in ('behavioral', 'manager', 'culture', 'hr', 'leadership')):
                interview_signals += 1
        return recruiter_signals > 0 or interview_signals > 0

    def _normalized_list(self, value: Any) -> list[str]:
        if isinstance(value, dict):
            value = list(value.keys())
        elif isinstance(value, str):
            value = [value]
        elif value is None:
            value = []
        elif not isinstance(value, (list, tuple, set)):
            value = [value]
        results: list[str] = []
        for item in value:
            text = str(item).strip()
            if text:
                results.append(text)
        return results

    def _list_value(self, value: Any) -> list[Any]:
        return list(value) if isinstance(value, (list, tuple, set)) else ([] if value in (None, '') else [value])

    def _student_key(self, student: Student) -> str:
        return str(getattr(student, 'id', None) or getattr(student, 'student_id', None) or getattr(student, 'email', None) or id(student))


def generate_skill_gaps(
    students: Sequence[Student],
    companies: Sequence[Company],
    recruiters: Sequence[Recruiter],
    jobs: Sequence[Job],
    applications: Sequence[Application],
    interviews: Sequence[Interview],
    offers: Sequence[Offer],
    career_reports: Sequence[CareerReport],
    config: AppConfig = CONFIG,
) -> SkillGapGenerationResult:
    generator = SkillGapGenerator(config=config)
    return generator.generate(
        students=students,
        companies=companies,
        recruiters=recruiters,
        jobs=jobs,
        applications=applications,
        interviews=interviews,
        offers=offers,
        career_reports=career_reports,
    )


