@dataclass(slots=True)
class StudentGenerationResult:
    users: list[User]
    students: list[StudentProfile]
    skills: list[StudentSkill]
    projects: list[StudentProject]
    experiences: list[StudentExperience]
    education_records: list[StudentEducation]
    certifications: list[StudentCertification]
    resumes: list[Resume]


class StudentGenerator:
    def __init__(self, config: AppConfig = CONFIG) -> None:
        self.config = config
        self.random = random.Random(config.generation.seed)
        self.global_faker = Faker(config.generation.locale)
        if config.generation.deterministic:
            Faker.seed(config.generation.seed)
            self.global_faker.seed_instance(config.generation.seed)
        self._used_emails: set[str] = set()

    def generate(self, universities: Sequence[University]) -> StudentGenerationResult:
        if not universities:
            raise ValueError('Student generation requires at least one university record.')

        users: list[User] = []
        students: list[StudentProfile] = []
        skills: list[StudentSkill] = []
        projects: list[StudentProject] = []
        experiences: list[StudentExperience] = []
        education_records: list[StudentEducation] = []
        certifications: list[StudentCertification] = []
        resumes: list[Resume] = []

        weighted_universities = self._build_university_weights(universities)

        for index in range(self.config.counts.students):
            university = self._choose_university(weighted_universities)
            faker = self._faker_for_country(university.country, index)
            first_name, last_name = self._generate_name(faker, university.country)
            user = self._build_user(index, faker, university, first_name, last_name)
            student = self._build_student_profile(index, faker, user, university)
            student_skills = self._build_student_skills(student)
            student_projects = self._build_student_projects(student, student_skills, faker)
            student_experiences = self._build_student_experiences(student, faker)
            student_education = self._build_student_education(student, university)
            student_certifications = self._build_student_certifications(student, student_skills)
            resume = self._build_resume(student, student_skills, student_projects, student_experiences, student_certifications)

            users.append(user)
            students.append(student)
            skills.extend(student_skills)
            projects.extend(student_projects)
            experiences.extend(student_experiences)
            education_records.extend(student_education)
            certifications.extend(student_certifications)
            resumes.append(resume)

        return StudentGenerationResult(
            users=users,
            students=students,
            skills=skills,
            projects=projects,
            experiences=experiences,
            education_records=education_records,
            certifications=certifications,
            resumes=resumes,
        )

    def _build_university_weights(self, universities: Sequence[University]) -> list[tuple[University, float]]:
        weighted: list[tuple[University, float]] = []
        for university in universities:
            population = university.student_population or 8000
            placement_boost = {
                'elite': 1.35,
                'strong': 1.18,
                'growing': 1.0,
                'emerging': 0.88,
            }.get((university.placement_strength or '').lower(), 1.0)
            weight = max(1.0, math.log(population + 10, 10) * placement_boost)
            weighted.append((university, weight))
        return weighted

    def _choose_university(self, weighted_universities: Sequence[tuple[University, float]]) -> University:
        universities = [item[0] for item in weighted_universities]
        weights = [item[1] for item in weighted_universities]
        return self.random.choices(universities, weights=weights, k=1)[0]

    def _faker_for_country(self, country: str, index: int) -> Faker:
        locale = COUNTRY_LOCALE_MAP.get(country, self.config.generation.locale)
        faker = Faker(locale)
        if self.config.generation.deterministic:
            faker.seed_instance(self.config.generation.seed + index * 97)
        return faker

    def _generate_name(self, faker: Faker, country: str) -> tuple[str, str]:
        if country == 'India':
            full_name = faker.name()
            tokens = [token.strip('. ') for token in full_name.replace('Dr', '').replace('Mr', '').replace('Ms', '').split() if token.strip('. ')]
            if len(tokens) >= 2:
                return tokens[0], tokens[-1]
        return faker.first_name(), faker.last_name()

    def _build_user(self, index: int, faker: Faker, university: University, first_name: str, last_name: str) -> User:
        email = self._generate_unique_email(first_name, last_name, university, index)
        avatar_seed = hashlib.sha1(email.encode('utf-8')).hexdigest()[:16]
        password_hash = hashlib.sha256(f'{email}|{self.config.generation.seed}'.encode('utf-8')).hexdigest()
        phone = self._generate_phone(university.country)
        return User(
            first_name=first_name,
            last_name=last_name,
            email=email,
            password_hash=password_hash,
            role=UserRole.student,
            status=UserStatus.active,
            avatar_url=f'https://api.dicebear.com/7.x/initials/svg?seed={avatar_seed}',
            phone=phone,
            email_verified=True,
            last_login_at=self._recent_datetime(days=45),
        )

    def _build_student_profile(self, index: int, faker: Faker, user: User, university: University) -> StudentProfile:
        department = self._choose_department(university)
        degree = self._choose_degree_for_department(department.name if department else None)
        graduation_year = self.random.randint(
            self.config.generation.graduation_year_start,
            self.config.generation.graduation_year_end,
        )
        cgpa = self._generate_cgpa(department.name if department else degree)
        preferred_role = self._choose_preferred_role(department.name if department else None)
        salary_min, salary_max = self._generate_salary_expectation(university.country, preferred_role, cgpa)
        preferred_location = self.random.choice(self.config.generation.preferred_locations)
        preferred_work_mode = self._choose_work_mode(preferred_location)
        links = self._generate_profile_links(user.first_name, user.last_name, index)
        focus = self._focus_phrase_for_role(preferred_role)
        bio = self.random.choice(BIO_TEMPLATES).format(
            degree=degree,
            department=department.name if department else 'the selected discipline',
            focus=focus,
            role=preferred_role,
            university=university.name,
        )
        headline = self._build_headline(preferred_role, department.name if department else None, graduation_year)
        languages = self._generate_languages(university.country)
        profile = StudentProfile(
            user=user,
            university=university,
            department=department,
            headline=headline,
            bio=bio,
            degree=degree,
            graduation_year=graduation_year,
            cgpa=cgpa,
            date_of_birth=self._generate_birth_date(graduation_year),
            city=university.city or self.random.choice(self.config.generation.preferred_locations),
            country=university.country,
            phone=user.phone,
            portfolio_url=links['portfolio_url'],
            github_url=links['github_url'],
            linkedin_url=links['linkedin_url'],
            website_url=links['website_url'],
            preferred_role=preferred_role,
            preferred_salary_min=salary_min,
            preferred_salary_max=salary_max,
            preferred_location=preferred_location,
            preferred_work_mode=preferred_work_mode,
            career_goal=self.random.choice(CAREER_GOAL_TEMPLATES).format(role=preferred_role.lower()),
            languages=languages,
            profile_completion=0,
        )
        return profile

    def _build_student_skills(self, student: StudentProfile) -> list[StudentSkill]:
        preferred_role = student.preferred_role or 'Software Engineering'
        role_skills = list(dict.fromkeys(ROLE_SKILL_MAP.get(preferred_role, self.config.generation.skill_taxonomy[:10])))
        taxonomy = list(self.config.generation.skill_taxonomy)
        total = self.random.randint(
            self.config.distributions.min_skills_per_student,
            min(20, self.config.distributions.max_skills_per_student),
        )
        selected: list[str] = []
        self.random.shuffle(role_skills)
        selected.extend(role_skills[: min(len(role_skills), max(4, total // 2))])
        remaining = [skill for skill in taxonomy if skill not in selected]
        self.random.shuffle(remaining)
        selected.extend(remaining[: max(0, total - len(selected))])
        selected = selected[:total]

        primary_skills = set(selected[: min(4, len(selected))])
        skill_objects: list[StudentSkill] = []
        for skill_name in selected:
            proficiency = self._skill_proficiency(student.cgpa, skill_name in primary_skills)
            years = max(Decimal('0.2'), Decimal(str(round(self.random.uniform(0.3, 2.8), 1))))
            skill_objects.append(
                StudentSkill(
                    student=student,
                    skill_name=skill_name,
                    category=self._skill_category(skill_name),
                    proficiency=proficiency,
                    years_of_experience=years,
                    is_primary=skill_name in primary_skills,
                )
            )
        return skill_objects

    def _build_student_projects(self, student: StudentProfile, student_skills: Sequence[StudentSkill], faker: Faker) -> list[StudentProject]:
        count = self.random.randint(
            self.config.distributions.min_projects_per_student,
            self.config.distributions.max_projects_per_student,
        )
        top_skills = [skill.skill_name for skill in sorted(student_skills, key=lambda item: (-item.proficiency, item.skill_name))]
        projects: list[StudentProject] = []
        for idx in range(count):
            stack_size = min(len(top_skills), self.random.randint(3, 6))
            stack = self.random.sample(top_skills, k=stack_size)
            title = f"{self.random.choice(PROJECT_PREFIXES)} {self.random.choice(PROJECT_NOUNS)}"
            start_date = self._project_start_date(student.graduation_year)
            end_date = start_date + timedelta(days=self.random.randint(45, 180))
            summary = self._project_summary(student.preferred_role or 'Software Engineering', stack)
            impact = self._project_impact()
            project = StudentProject(
                student=student,
                title=title,
                summary=summary,
                project_url=f'https://demo.{self.random.choice(self.config.generation.portfolio_domains)}/{self._slugify(title)}-{idx + 1}',
                repository_url=f'{student.github_url}/{self._slugify(title)}',
                tech_stack={'skills': stack},
                start_date=start_date,
                end_date=end_date,
                impact_metrics=impact,
            )
            projects.append(project)
        return projects

    def _build_student_experiences(self, student: StudentProfile, faker: Faker) -> list[StudentExperience]:
        count = self.random.randint(
            self.config.distributions.min_experience_per_student,
            self.config.distributions.max_experience_per_student,
        )
        role = student.preferred_role or 'Software Engineering'
        title_options = {
            'Software Engineering': ('Software Engineering Intern', 'Backend Intern', 'Full Stack Intern'),
            'Data Analytics': ('Data Analyst Intern', 'Business Intelligence Intern', 'Analytics Intern'),
            'Data Engineering': ('Data Engineering Intern', 'Data Platform Intern'),
            'Product Management': ('Product Intern', 'Associate Product Intern'),
            'Quality Assurance': ('QA Intern', 'Test Engineering Intern'),
            'Cloud Engineering': ('Cloud Operations Intern', 'DevOps Intern'),
            'Cybersecurity': ('Security Operations Intern', 'Cybersecurity Intern'),
            'UI/UX Design': ('Product Design Intern', 'UX Design Intern'),
            'Business Analysis': ('Business Analyst Intern', 'Operations Analyst Intern'),
            'Technical Support': ('Technical Support Intern', 'IT Support Intern'),
        }
        experiences: list[StudentExperience] = []
        for _ in range(count):
            start = self._experience_start(student.graduation_year)
            end = start + timedelta(days=self.random.randint(70, 210))
            description = ' '.join(self.random.sample(EXPERIENCE_BULLETS, k=3))
            experiences.append(
                StudentExperience(
                    student=student,
                    company=None,
                    title=self.random.choice(title_options.get(role, ('Intern', 'Student Associate'))),
                    employment_type=EmploymentType.internship,
                    location=student.preferred_location,
                    description=description,
                    start_date=start,
                    end_date=end,
                    is_current=False,
                )
            )
        return experiences

    def _build_student_education(self, student: StudentProfile, university: University) -> list[StudentEducation]:
        start_year = student.graduation_year - self._degree_duration(student.degree)
        field_of_study = student.department.name if student.department else student.degree
        return [
            StudentEducation(
                student=student,
                institution_name=university.name,
                degree=student.degree,
                field_of_study=field_of_study,
                start_year=start_year,
                end_year=student.graduation_year,
                grade=str(student.cgpa),
                description=f'Academic record focused on {field_of_study} with applied coursework and project-based learning.',
            )
        ]

    def _build_student_certifications(self, student: StudentProfile, student_skills: Sequence[StudentSkill]) -> list[StudentCertification]:
        count = self.random.randint(
            self.config.distributions.min_certificates_per_student,
            self.config.distributions.max_certificates_per_student,
        )
        if count == 0:
            return []
        top_skills = [skill.skill_name for skill in sorted(student_skills, key=lambda item: (-item.proficiency, item.skill_name))[:8]]
        providers = ['Google Cloud Skills', 'Microsoft Learn', 'AWS Training', 'IBM Skills Network', 'Coursera', 'Cisco Networking Academy']
        records: list[StudentCertification] = []
        for idx in range(count):
            skill_focus = self.random.choice(top_skills)
            issued_by = self.random.choice(providers)
            name = f"{self.random.choice(CERTIFICATION_PREFIXES)} {skill_focus}"
            issue_date = self._recent_date(days=720)
            expiry = issue_date + timedelta(days=365 * self.random.randint(1, 3)) if self.random.random() < 0.45 else None
            records.append(
                StudentCertification(
                    student=student,
                    name=name,
                    issued_by=issued_by,
                    issue_date=issue_date,
                    expiry_date=expiry,
                    credential_id=self._credential_id(student.user.email, idx),
                    credential_url=f'https://credentials.example.dev/{self._slugify(issued_by)}/{self._slugify(name)}-{idx + 1}',
                    skills_covered={'skills': sorted(set(self.random.sample(top_skills, k=min(len(top_skills), self.random.randint(2, 4)))))},
                )
            )
        return records

    def _build_resume(
        self,
        student: StudentProfile,
        student_skills: Sequence[StudentSkill],
        student_projects: Sequence[StudentProject],
        student_experiences: Sequence[StudentExperience],
        student_certifications: Sequence[StudentCertification],
    ) -> Resume:
        profile_completion = self._calculate_profile_completion(student, student_skills, student_projects, student_experiences, student_certifications)
        student.profile_completion = profile_completion
        resume_score = self._calculate_resume_score(student, student_skills, student_projects, student_experiences, student_certifications)
        ats_score = self._calculate_ats_score(student, student_skills, student_projects, student_experiences)
        job_match = self._calculate_job_match_baseline(student, student_skills, student_projects, student_experiences)
        interview_readiness = self._calculate_interview_readiness(student, student_projects, student_experiences, student_certifications)
        career_score = self._calculate_career_score(profile_completion, resume_score, ats_score, job_match, interview_readiness)

        metadata_json = {
            'sections_present': self._resume_sections(student, student_skills, student_projects, student_experiences, student_certifications),
            'keywords': [skill.skill_name for skill in student_skills if skill.is_primary][:8],
            'project_count': len(student_projects),
            'experience_count': len(student_experiences),
            'certification_count': len(student_certifications),
            'word_count_estimate': 280 + len(student_skills) * 8 + len(student_projects) * 55 + len(student_experiences) * 60,
            'profile_completion': profile_completion,
            'resume_score': resume_score,
            'ats_score': ats_score,
            'career_score': career_score,
            'job_match_baseline': job_match,
            'interview_readiness': interview_readiness,
            'last_updated_at': self._recent_datetime(days=30).isoformat(),
        }

        return Resume(
            student=student,
            title=f'{student.user.first_name} {student.user.last_name} Resume',
            version='1.0',
            is_primary=True,
            ats_score=ats_score,
            resume_score=resume_score,
            metadata_json=metadata_json,
        )

    def _choose_department(self, university: University):
        if university.departments:
            return self.random.choice(list(university.departments))
        return None

    def _choose_degree_for_department(self, department_name: str | None) -> str:
        if department_name in {'Business Administration', 'Commerce'}:
            return self.random.choice(['BBA', 'B.Com', 'MBA'])
        if department_name in {'Mathematics', 'Statistics', 'Data Science', 'Artificial Intelligence'}:
            return self.random.choice(['B.Sc', 'M.Sc', 'B.Tech', 'M.Tech'])
        if department_name:
            return self.random.choice(['B.Tech', 'B.E.', 'M.Tech'])
        return self.random.choice(self.config.generation.degree_programs)

    def _choose_preferred_role(self, department_name: str | None) -> str:
        if department_name and department_name in DEPARTMENT_ROLE_MAP:
            return self.random.choice(DEPARTMENT_ROLE_MAP[department_name])
        return self.random.choice(self.config.generation.role_families)

    def _generate_unique_email(self, first_name: str, last_name: str, university: University, index: int) -> str:
        base_first = self._slugify(first_name)
        base_last = self._slugify(last_name)
        university_hint = self._slugify(university.name.split()[0])[:8] or 'campus'
        domain = self.random.choice(self.config.generation.student_email_domains)
        counter = 0
        while True:
            suffix = f'{index + 1:04d}{counter}' if counter else f'{index + 1:04d}'
            email = f'{base_first}.{base_last}.{university_hint}{suffix}@{domain}'.lower()
            if email not in self._used_emails:
                self._used_emails.add(email)
                return email
            counter += 1

    def _generate_phone(self, country: str) -> str:
        prefix = COUNTRY_PHONE_CODE.get(country, '+1')
        if country == 'India':
            return f'{prefix} {self.random.randint(6000000000, 9999999999)}'
        if country in {'United States', 'Canada'}:
            return f'{prefix}-{self.random.randint(200, 999)}-{self.random.randint(100, 999)}-{self.random.randint(1000, 9999)}'
        return f'{prefix} {self.random.randint(10000000, 999999999)}'

    def _generate_cgpa(self, department_name: str | None) -> Decimal:
        dept_bias = 0.15 if department_name in {'Computer Science', 'Data Science', 'Artificial Intelligence', 'Statistics'} else 0.0
        value = min(9.8, max(6.0, self.random.gauss(7.8 + dept_bias, 0.75)))
        return Decimal(str(round(value, 2))).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)

    def _generate_birth_date(self, graduation_year: int) -> date:
        age_at_graduation = self.random.randint(20, 27)
        year = graduation_year - age_at_graduation
        month = self.random.randint(1, 12)
        day = min(self.random.randint(1, 28), 28)
        return date(year, month, day)

    def _generate_salary_expectation(self, country: str, preferred_role: str, cgpa: Decimal) -> tuple[Decimal, Decimal]:
        currency, base_min, base_max = COUNTRY_SALARY_CURRENCY.get(country, ('USD', 40000, 85000))
        role_multiplier = {
            'Software Engineering': 1.12,
            'Data Engineering': 1.10,
            'Cloud Engineering': 1.09,
            'Cybersecurity': 1.08,
            'Data Analytics': 1.00,
            'Product Management': 1.04,
            'Quality Assurance': 0.92,
            'UI/UX Design': 0.95,
            'Business Analysis': 0.94,
            'Technical Support': 0.82,
        }.get(preferred_role, 1.0)
        academic_boost = 1 + ((float(cgpa) - 7.0) * 0.035)
        midpoint = ((base_min + base_max) / 2) * role_multiplier * academic_boost
        spread = midpoint * self.random.uniform(0.12, 0.22)
        low = max(base_min, int(midpoint - spread))
        high = min(base_max * 2, int(midpoint + spread))
        if low >= high:
            high = low + max(1000, int(low * 0.1))
        return Decimal(low), Decimal(high)

    def _choose_work_mode(self, preferred_location: str) -> WorkMode:
        if preferred_location.lower().startswith('remote'):
            return WorkMode.remote
        pick = self.random.random()
        if pick < 0.2:
            return WorkMode.remote
        if pick < 0.72:
            return WorkMode.hybrid
        return WorkMode.onsite

    def _generate_profile_links(self, first_name: str, last_name: str, index: int) -> dict[str, str]:
        handle = f'{self._slugify(first_name)}-{self._slugify(last_name)}-{index + 1:03d}'
        portfolio_domain = self.random.choice(self.config.generation.portfolio_domains)
        return {
            'github_url': f'https://github.com/{handle}',
            'portfolio_url': f'https://{handle}.{portfolio_domain}',
            'linkedin_url': f'https://linkedin.example.dev/in/{handle}',
            'website_url': f'https://{handle}.site.dev',
        }

    def _generate_languages(self, country: str) -> dict[str, list[str]]:
        pool = list(self.config.generation.language_options)
        primary = 'English'
        selected = {primary}
        if country == 'India':
            selected.add(self.random.choice(['Tamil', 'Hindi', 'Telugu', 'Kannada', 'Malayalam']))
        elif country == 'Germany':
            selected.add('German')
        else:
            extras = [lang for lang in pool if lang != primary]
            selected.update(self.random.sample(extras, k=min(len(extras), self.random.randint(1, 2))))
        proficiency = ['Native', 'Professional', 'Intermediate']
        return {
            'languages': [
                {'name': lang, 'proficiency': proficiency[min(idx, len(proficiency) - 1)]}
                for idx, lang in enumerate(sorted(selected))
            ]
        }

    def _build_headline(self, preferred_role: str, department_name: str | None, graduation_year: int) -> str:
        department_label = department_name or 'Technology'
        return f'{department_label} Student | Aspiring {preferred_role} | Class of {graduation_year}'

    def _focus_phrase_for_role(self, preferred_role: str) -> str:
        focus_map = {
            'Software Engineering': 'backend services, APIs, and product development',
            'Data Analytics': 'analytics, dashboards, and data storytelling',
            'Data Engineering': 'data pipelines, warehousing, and ETL',
            'Product Management': 'user problems, prioritization, and product thinking',
            'Quality Assurance': 'test automation and product reliability',
            'Cloud Engineering': 'cloud infrastructure and delivery automation',
            'Cybersecurity': 'security operations and platform hardening',
            'UI/UX Design': 'interaction design and user-centered workflows',
            'Business Analysis': 'process analysis and stakeholder communication',
            'Technical Support': 'customer issue resolution and systems troubleshooting',
        }
        return focus_map.get(preferred_role, 'practical technology problem solving')

    def _skill_category(self, skill_name: str) -> str:
        categories = {
            'Python': 'Programming Language', 'Java': 'Programming Language', 'JavaScript': 'Programming Language',
            'TypeScript': 'Programming Language', 'SQL': 'Data', 'PostgreSQL': 'Database', 'MySQL': 'Database',
            'MongoDB': 'Database', 'Redis': 'Database', 'React': 'Frontend', 'Angular': 'Frontend', 'Vue.js': 'Frontend',
            'Node.js': 'Backend', 'Django': 'Backend', 'FastAPI': 'Backend', 'Spring Boot': 'Backend', '.NET': 'Backend',
            'AWS': 'Cloud', 'Azure': 'Cloud', 'GCP': 'Cloud', 'Docker': 'DevOps', 'Kubernetes': 'DevOps',
            'Terraform': 'DevOps', 'Git': 'Developer Tools', 'Linux': 'Systems', 'Pandas': 'Data', 'NumPy': 'Data',
            'Power BI': 'Analytics', 'Tableau': 'Analytics', 'Apache Spark': 'Data Engineering', 'Airflow': 'Data Engineering',
            'Kafka': 'Data Engineering', 'Machine Learning': 'AI/ML', 'REST APIs': 'Backend', 'GraphQL': 'Backend',
            'Figma': 'Design', 'HTML': 'Frontend', 'CSS': 'Frontend', 'Excel': 'Analytics', 'Statistics': 'Analytics',
            'Networking': 'Systems', 'A/B Testing': 'Product', 'Communication': 'Professional', 'Roadmapping': 'Product',
            'Analytics': 'Analytics', 'Documentation': 'Professional', 'Stakeholder Management': 'Professional',
            'Process Mapping': 'Business', 'Monitoring': 'DevOps', 'Shell Scripting': 'Systems', 'IAM': 'Security',
            'SIEM': 'Security', 'Risk Assessment': 'Security', 'Postman': 'QA', 'Selenium': 'QA', 'Design Systems': 'Design',
            'User Research': 'Design', 'Wireframing': 'Design', 'Prototyping': 'Design', 'Troubleshooting': 'Support',
            'Customer Communication': 'Support',
        }
        return categories.get(skill_name, 'General')

    def _skill_proficiency(self, cgpa: Decimal, is_primary: bool) -> int:
        base = 2.6 + ((float(cgpa) - 7.0) * 0.35)
        if is_primary:
            base += 0.8
        score = int(round(min(5, max(1, self.random.gauss(base, 0.7)))))
        return score

    def _project_start_date(self, graduation_year: int) -> date:
        year = max(graduation_year - self.random.randint(1, 3), graduation_year - 4)
        month = self.random.randint(1, 10)
        day = min(self.random.randint(1, 28), 28)
        return date(year, month, day)

    def _project_summary(self, preferred_role: str, stack: Sequence[str]) -> str:
        focus = {
            'Software Engineering': 'application workflows and backend services',
            'Data Analytics': 'dashboards, KPI tracking, and decision support',
            'Data Engineering': 'data movement, quality checks, and reporting pipelines',
            'Product Management': 'user flows, prioritization insights, and feature discovery',
            'Quality Assurance': 'test coverage and release confidence',
            'Cloud Engineering': 'deployment automation and observability',
            'Cybersecurity': 'access control and risk monitoring',
            'UI/UX Design': 'usable interfaces and prototype validation',
            'Business Analysis': 'process visibility and reporting accuracy',
            'Technical Support': 'issue tracking and support workflow efficiency',
        }.get(preferred_role, 'real-world problem solving')
        return f'Built an original project focused on {focus} using {", ".join(stack[:-1])} and {stack[-1]}. Improved usability, maintainability, and reporting through structured implementation and testing.'

    def _project_impact(self) -> dict[str, str]:
        return {
            'users_supported': str(self.random.randint(50, 3000)),
            'performance_gain_pct': str(self.random.randint(8, 45)),
            'delivery_weeks': str(self.random.randint(3, 14)),
        }

    def _experience_start(self, graduation_year: int) -> date:
        year = max(graduation_year - self.random.randint(1, 2), graduation_year - 3)
        month = self.random.randint(1, 9)
        day = min(self.random.randint(1, 28), 28)
        return date(year, month, day)

    def _degree_duration(self, degree: str) -> int:
        if degree in {'MBA', 'M.Tech', 'M.Sc', 'MCA'}:
            return 2
        return 4

    def _credential_id(self, email: str, index: int) -> str:
        digest = hashlib.md5(f'{email}:{index}'.encode('utf-8')).hexdigest()[:12].upper()
        return f'CB-{digest}'

    def _resume_sections(
        self,
        student: StudentProfile,
        student_skills: Sequence[StudentSkill],
        student_projects: Sequence[StudentProject],
        student_experiences: Sequence[StudentExperience],
        student_certifications: Sequence[StudentCertification],
    ) -> dict[str, bool]:
        return {
            'headline': bool(student.headline),
            'bio': bool(student.bio),
            'education': True,
            'skills': len(student_skills) > 0,
            'projects': len(student_projects) > 0,
            'experience': len(student_experiences) > 0,
            'certifications': len(student_certifications) > 0,
            'links': bool(student.github_url or student.portfolio_url or student.linkedin_url),
            'career_goal': bool(student.career_goal),
        }

    def _calculate_profile_completion(
        self,
        student: StudentProfile,
        student_skills: Sequence[StudentSkill],
        student_projects: Sequence[StudentProject],
        student_experiences: Sequence[StudentExperience],
        student_certifications: Sequence[StudentCertification],
    ) -> int:
        sections = self._resume_sections(student, student_skills, student_projects, student_experiences, student_certifications)
        total = sum(RESUME_SECTION_WEIGHTS.values())
        score = 0
        for key, weight in RESUME_SECTION_WEIGHTS.items():
            if sections.get(key):
                score += weight
        if len(student_skills) >= 10:
            score += 4
        if student.preferred_role and student.preferred_location:
            score += 3
        if student.github_url and student.portfolio_url:
            score += 3
        return max(0, min(100, score))

    def _calculate_resume_score(
        self,
        student: StudentProfile,
        student_skills: Sequence[StudentSkill],
        student_projects: Sequence[StudentProject],
        student_experiences: Sequence[StudentExperience],
        student_certifications: Sequence[StudentCertification],
    ) -> int:
        score = 34
        score += min(16, len(student_skills) * 2)
        score += min(18, len(student_projects) * 6)
        score += min(14, len(student_experiences) * 7)
        score += min(8, len(student_certifications) * 4)
        score += 4 if student.bio and len(student.bio) > 120 else 0
        score += 3 if student.github_url else 0
        score += 3 if student.portfolio_url else 0
        score += min(8, max(0, int((float(student.cgpa) - 7.0) * 4)))
        return max(40, min(98, score))

    def _calculate_ats_score(
        self,
        student: StudentProfile,
        student_skills: Sequence[StudentSkill],
        student_projects: Sequence[StudentProject],
        student_experiences: Sequence[StudentExperience],
    ) -> int:
        target_skills = set(ROLE_SKILL_MAP.get(student.preferred_role or '', ()))
        student_skill_names = {skill.skill_name for skill in student_skills}
        overlap = len(target_skills & student_skill_names)
        coverage_ratio = overlap / max(1, len(target_skills))
        score = 38 + int(coverage_ratio * 34)
        score += min(10, len(student_projects) * 3)
        score += min(8, len(student_experiences) * 4)
        score += 5 if student.headline else 0
        score += 5 if student.bio else 0
        return max(35, min(97, score))

    def _calculate_job_match_baseline(
        self,
        student: StudentProfile,
        student_skills: Sequence[StudentSkill],
        student_projects: Sequence[StudentProject],
        student_experiences: Sequence[StudentExperience],
    ) -> int:
        role_skills = set(ROLE_SKILL_MAP.get(student.preferred_role or '', ()))
        student_primary = {skill.skill_name for skill in student_skills if skill.is_primary}
        student_all = {skill.skill_name for skill in student_skills}
        primary_overlap = len(student_primary & role_skills)
        total_overlap = len(student_all & role_skills)
        score = 35 + primary_overlap * 8 + total_overlap * 3
        score += min(8, len(student_projects) * 2)
        score += min(10, len(student_experiences) * 5)
        return max(30, min(96, score))

    def _calculate_interview_readiness(
        self,
        student: StudentProfile,
        student_projects: Sequence[StudentProject],
        student_experiences: Sequence[StudentExperience],
        student_certifications: Sequence[StudentCertification],
    ) -> int:
        score = 28
        score += min(18, len(student_projects) * 5)
        score += min(24, len(student_experiences) * 10)
        score += min(10, len(student_certifications) * 3)
        score += 6 if student.github_url else 0
        score += 6 if student.bio and len(student.bio.split()) >= 20 else 0
        return max(25, min(95, score))

    def _calculate_career_score(
        self,
        profile_completion: int,
        resume_score: int,
        ats_score: int,
        job_match: int,
        interview_readiness: int,
    ) -> int:
        weighted = (
            profile_completion * 0.24
            + resume_score * 0.20
            + ats_score * 0.18
            + job_match * 0.20
            + interview_readiness * 0.18
        )
        return max(30, min(98, int(round(weighted))))

    def _recent_datetime(self, days: int) -> datetime:
        now = datetime.utcnow()
        delta_days = self.random.randint(0, days)
        delta_seconds = self.random.randint(0, 86399)
        return now - timedelta(days=delta_days, seconds=delta_seconds)


    def _recent_date(self, days: int) -> date:
        return (datetime.utcnow() - timedelta(days=self.random.randint(0, days))).date()

    def _slugify(self, value: str) -> str:
        sanitized = ''.join(ch.lower() if ch.isalnum() else '-' for ch in value)
        while '--' in sanitized:
            sanitized = sanitized.replace('--', '-')
        return sanitized.strip('-') or 'profile'


def generate_students(universities: Sequence[University], config: AppConfig = CONFIG) -> StudentGenerationResult:
    generator = StudentGenerator(config=config)
    return generator.generate(universities)

